/* AUTO-GENERATED — Georgia Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["GA"] = {"code":"GA","name":"Georgia","agency":"Georgia DDS","agencyShort":"DDS","handbook":"https://dds.georgia.gov/cdl-study-guide","links":{},"en":[{"q":"On Georgia highways, what is the maximum total outside width of a vehicle and its load, excluding mirrors and accessories?","options":["96 inches","102 inches","108 inches","120 inches"],"answer":1,"explanation":"O.C.G.A. §32-6-23 provides that no vehicle shall exceed a total outside width, including any load, of 102 inches, exclusive of mirrors and accessories, on any street, road, or highway in Georgia. (Source: O.C.G.A. §32-6-23; GA DDS CDL Manual)","handbook":"","hbref":""},{"q":"Except where a higher limit is authorized, what is the maximum height of a vehicle, unladen or with a load, on Georgia roads?","options":["12 feet 6 inches","13 feet 0 inches","14 feet 6 inches","13 feet 6 inches"],"answer":3,"explanation":"O.C.G.A. §32-6-22(a) states that, except as authorized by permit, no vehicle unladen or with a load shall exceed a height of 13 feet, 6 inches on Georgia roads. (Source: O.C.G.A. §32-6-22)","handbook":"","hbref":""},{"q":"In Georgia, what is the maximum length of a semitrailer in a truck tractor-semitrailer combination, absent posted restrictions?","options":["45 feet","48 feet","53 feet","57 feet"],"answer":2,"explanation":"O.C.G.A. §32-6-24(b)(1)(B) provides that truck tractor-semitrailer combinations shall have semitrailers that do not exceed 53 feet in length, unless signs are posted indicating semitrailer length restrictions. (Source: O.C.G.A. §32-6-24)","handbook":"","hbref":""},{"q":"In a Georgia truck tractor-semitrailer-trailer (twin trailer) combination, what is the maximum length of each trailer and semitrailer?","options":["24 feet","28 feet","33 feet","40 feet"],"answer":1,"explanation":"O.C.G.A. §32-6-24(b)(1)(A) provides that truck tractor-semitrailer-trailer combinations shall have trailers and semitrailers that do not exceed 28 feet in length each. (Source: O.C.G.A. §32-6-24)","handbook":"","hbref":""},{"q":"On Georgia roads other than the interstate or STAA system, what is the maximum overall length of a truck tractor-semitrailer or truck tractor-semitrailer-trailer combination, absent posted restrictions?","options":["65 feet","75 feet","100 feet","110 feet"],"answer":2,"explanation":"O.C.G.A. §32-6-24(b)(2)(C) provides that, on roads other than the interstate or STAA system, such combinations shall have an overall length not exceeding 100 feet, unless signs are posted indicating length restrictions. (Source: O.C.G.A. §32-6-24)","handbook":"","hbref":""},{"q":"What is the maximum total gross weight authorized for any vehicle and load on Georgia highways?","options":["73,280 pounds","88,000 pounds","100,000 pounds","80,000 pounds"],"answer":3,"explanation":"O.C.G.A. §32-6-26(c)(1)(A) and (d)(1)(A) both cap the maximum total gross weight authorized for any vehicle and load at 80,000 pounds, on national and non-national highways alike. (Source: O.C.G.A. §32-6-26; GA DDS CDL Manual)","handbook":"","hbref":""},{"q":"On a Georgia national highway (such as an interstate), what is the maximum load authorized on a tandem axle?","options":["30,000 pounds","40,680 pounds","46,000 pounds","34,000 pounds"],"answer":3,"explanation":"O.C.G.A. §32-6-26(d)(1)(B) sets the maximum load on any tandem axle on Georgia national highways at 34,000 pounds, matching the federal limit. (Source: O.C.G.A. §32-6-26; GA DDS CDL Manual)","handbook":"","hbref":""},{"q":"On Georgia highways that are NOT national highways, what is the maximum load authorized on a tandem axle?","options":["34,000 pounds","37,340 pounds","40,680 pounds","46,000 pounds"],"answer":2,"explanation":"O.C.G.A. §32-6-26(c)(1)(A) sets the maximum tandem-axle load at 40,680 pounds on Georgia highways that are not national highways. (Source: O.C.G.A. §32-6-26)","handbook":"","hbref":""},{"q":"Under O.C.G.A. §32-6-26, how is a \"single axle\" defined for weight purposes in Georgia?","options":["All wheels whose centers fall between two parallel transverse vertical planes 40 inches apart","All wheels whose centers fall within 96 inches of each other","Any two consecutive axles spaced more than 40 inches apart","The single steering axle of a power unit only"],"answer":0,"explanation":"O.C.G.A. §32-6-26(a)(4) defines a \"single axle\" as all the wheels whose centers may be included between two parallel transverse vertical planes 40 inches apart. (Source: O.C.G.A. §32-6-26)","handbook":"","hbref":""},{"q":"Under current Georgia law, how is a \"tandem axle\" defined for weight purposes?","options":["Two or more consecutive axles whose centers are spaced more than 40 but not more than 96 inches apart","Two or more consecutive axles, excluding the steering axle, whose centers are spaced more than 40 but not more than 216 inches apart","Exactly two axles spaced no more than 8 feet apart, including the steering axle","Any group of axles within 12 feet of each other regardless of the steering axle"],"answer":1,"explanation":"O.C.G.A. §32-6-26(a)(7) defines a \"tandem axle\" (after April 1, 1988) as two or more consecutive axles, excluding the steering axle, whose centers may be included between parallel vertical planes spaced more than 40 inches but not more than 216 inches apart. (Source: O.C.G.A. §32-6-26)","handbook":"","hbref":""},{"q":"Which formula does Georgia use to determine the maximum gross weight allowed on a group of two or more consecutive axles?","options":["The federal bridge formula","The gross combination weight rating formula","The Georgia axle-spacing tariff","The 18,000-pound-per-axle rule"],"answer":0,"explanation":"O.C.G.A. §32-6-26(a)(1) and (d) adopt the federal bridge formula, W = 500((LN/N-1) + 12N + 36), to determine the maximum gross weight on any group of two or more consecutive axles on Georgia national highways. (Source: O.C.G.A. §32-6-26; GA DDS CDL Manual)","handbook":"","hbref":""},{"q":"In the Georgia bridge formula W = 500((LN/N-1) + 12N + 36), what does the variable \"N\" represent?","options":["The number of axles in the group under consideration","The distance in feet between the extreme axles of the group","The net weight of the load in thousands of pounds","The number of tires on the heaviest axle"],"answer":0,"explanation":"In O.C.G.A. §32-6-26(a)(1), N is the number of axles in the group under consideration, L is the distance in feet between the extreme axles of the group, and W is the gross weight on that group. (Source: O.C.G.A. §32-6-26)","handbook":"","hbref":""},{"q":"Under O.C.G.A. §32-6-26, what is the maximum total gross weight for a vehicle equipped with only four axles on non-national Georgia highways?","options":["56,000 pounds","70,000 pounds","73,280 pounds","80,000 pounds"],"answer":1,"explanation":"O.C.G.A. §32-6-26(c)(1)(C) provides that for any vehicle equipped with four axles, the maximum total gross weight authorized for the vehicle and load shall be 70,000 pounds. (Source: O.C.G.A. §32-6-26)","handbook":"","hbref":""},{"q":"On a Georgia county-road system, what is the maximum total gross weight allowed for a vehicle not making a pickup or delivery on that road?","options":["46,000 pounds","56,000 pounds","70,000 pounds","80,000 pounds"],"answer":1,"explanation":"O.C.G.A. §32-6-26(f) caps the maximum total gross weight on a county-road system at 56,000 pounds, except when the vehicle is making a pickup or delivery on such road (or on a qualifying designated local truck route). (Source: O.C.G.A. §32-6-26)","handbook":"","hbref":""},{"q":"When may a vehicle hauling forest products, live poultry, cotton, feed, granite, solid waste, or freshly mixed concrete exceed Georgia's normal axle/gross limits on a non-national highway without a permit?","options":["Never; a permit is always required to exceed the limits","Only at night and only on interstate highways","When single-axle weight stays at or below 23,000 lbs, tandem-axle at or below 46,000 lbs, and gross weight at or below 80,000 lbs","When gross weight stays at or below 100,000 lbs regardless of axle weight"],"answer":2,"explanation":"O.C.G.A. §32-6-26(g)(1) permits these specified agricultural and commodity hauls on non-national highways without a permit only when single-axle load does not exceed 23,000 lbs, tandem-axle does not exceed 46,000 lbs, and total gross weight does not exceed 80,000 lbs. (Source: O.C.G.A. §32-6-26)","handbook":"","hbref":""},{"q":"Georgia's size exemption for farming, agricultural, or forest-management EQUIPMENT (allowing it to exceed width and length limits without a permit) applies under which condition?","options":["Only on the interstate system and only at night","During daylight hours on roads not part of the interstate system, within 40 miles of the owner's or dealer's property","Anywhere in the state at any hour with no distance limit","Only when an escort vehicle with amber lights accompanies it on the interstate"],"answer":1,"explanation":"O.C.G.A. §32-6-25 exempts farming/agricultural or forest-management equipment from the width and length limits, without a permit, when operated during daylight hours on a public road not part of the interstate system within a 40-mile radius of the owner's or dealer's property. The exemption does NOT apply to vehicles hauling or transporting forest products. (Source: O.C.G.A. §32-6-25)","handbook":"","hbref":""},{"q":"Who issues a permit in Georgia authorizing a vehicle or load to exceed the maximum size or weight limits set by law?","options":["The Department of Transportation (GDOT), upon written application and good cause shown","The county sheriff where the trip begins","Any weigh-station officer at the time of inspection","The Department of Driver Services with the CDL application"],"answer":0,"explanation":"O.C.G.A. §32-6-28(a) authorizes the GDOT commissioner (or a designated official) to issue, upon written application and good cause shown, a permit allowing a vehicle and load whose weight, width, length, or height exceeds the legal maximum. Permits are obtained through GDOT/Department of Public Safety (GAPROS system). (Source: O.C.G.A. §32-6-28; GDOT)","handbook":"","hbref":""},{"q":"Under O.C.G.A. §32-6-28, a Georgia ANNUAL oversize/overweight permit may NOT be issued to authorize a vehicle whose total gross weight exceeds what amount?","options":["80,000 pounds","120,000 pounds","150,000 pounds","100,000 pounds"],"answer":3,"explanation":"O.C.G.A. §32-6-28(b)(1)(A) provides that an annual permit shall not authorize operation of a vehicle whose total gross weight exceeds 100,000 pounds (nor whose single-axle weight exceeds 25,000 lbs, length exceeds 100 ft, width exceeds 102 in / load width 144 in, or height exceeds 14 ft 6 in). (Source: O.C.G.A. §32-6-28; GDOT)","handbook":"","hbref":""},{"q":"Under Georgia's basic weight rule, what is the base maximum load on a single axle (high-pressure pneumatic tires) before the statutory tolerance is applied?","options":["12,000 pounds","18,000 pounds","20,000 pounds","16,000 pounds"],"answer":3,"explanation":"O.C.G.A. §32-6-26(b)(1) prohibits a load on any single axle (high-pressure pneumatic, solid rubber, or cushion tires) that exceeds 16,000 pounds by more than 13 percent—so the base figure is 16,000 lbs and the 13% tolerance yields about 18,080 lbs. (Source: O.C.G.A. §32-6-26)","handbook":"","hbref":""},{"q":"Under O.C.G.A. §32-6-27, before an overweight vehicle in Georgia may be allowed to move, the operator must unload all gross weight exceeding the legal limit by more than what amount?","options":["2,000 pounds","4,000 pounds","6,000 pounds","10,000 pounds"],"answer":2,"explanation":"O.C.G.A. §32-6-27(e) requires the owner/operator of an overweight vehicle, in addition to paying assessed damages, to unload all gross weight in excess of 6,000 pounds over the legal weight limit before the vehicle is allowed to move. (Source: O.C.G.A. §32-6-27)","handbook":"","hbref":""},{"q":"In Georgia, which class of CDL is required to operate a combination of vehicles with a gross combination weight rating (GCWR) of 26,001 pounds or more, where the vehicle being towed has a GVWR of more than 10,000 pounds?","options":["Class B","Class C","Class D","Class A"],"answer":3,"explanation":"A Georgia Class A CDL covers any combination of vehicles with a GCWR of 26,001+ pounds where the towed unit exceeds 10,000 pounds GVWR. A Class A holder may also operate Class B and C vehicles with the proper endorsements. Source: Georgia DDS, 'Apply for a Commercial (CDL) License (Class A, B, C).'","handbook":"","hbref":""},{"q":"Under Georgia DDS rules, a Class B CDL authorizes a driver to operate which of the following?","options":["Any combination of vehicles where the towed unit exceeds 10,000 pounds","Any single vehicle with a GVWR of 26,001+ pounds, towing a unit not over 10,000 pounds","Only vehicles designed to carry 16 or more passengers","Only vehicles placarded for hazardous materials"],"answer":1,"explanation":"A Georgia Class B CDL covers single vehicles with a GVWR of 26,001+ pounds, including those towing a vehicle not in excess of 10,000 pounds GVWR. A Class B holder may also operate Class C vehicles with proper endorsements. Source: Georgia DDS, 'Apply for a Commercial (CDL) License.'","handbook":"","hbref":""},{"q":"In Georgia, a Class C CDL is issued specifically for which type of vehicle?","options":["Any combination of vehicles over 26,001 pounds GCWR","Any single vehicle over 26,001 pounds GVWR","A single vehicle (or combination) not meeting Class A or B that carries 16+ passengers including the driver, or is placarded for hazardous materials","Any passenger car or pickup truck under 26,001 pounds"],"answer":2,"explanation":"A Georgia Class C CDL applies to a single vehicle, or combination, that does not meet the Class A or B definition but is designed to transport 16 or more passengers (including the driver) or is used to transport hazardous materials requiring placarding. Source: Georgia DDS, 'Apply for a Commercial (CDL) License.'","handbook":"","hbref":""},{"q":"What is the minimum age to apply for any Georgia CDL?","options":["18 years old","16 years old","21 years old","25 years old"],"answer":0,"explanation":"Georgia DDS requires CDL applicants to be at least 18 years of age. Applicants aged 18 to 21 are restricted to intrastate (Georgia-only) driving until they turn 21. Source: Georgia DDS, 'Apply for a Commercial (CDL) License.'","handbook":"","hbref":""},{"q":"A 19-year-old Georgia CDL holder is restricted in what way?","options":["Restricted from holding any endorsement","Restricted to intrastate (Georgia-only) driving until reaching age 21","Restricted to Class C vehicles only","Restricted from driving at night"],"answer":1,"explanation":"Georgia issues CDLs to applicants 18 and older, but drivers aged 18 to 21 carry a 'Georgia Only' (intrastate) restriction. The driver must turn 21 and visit a Customer Service Center to have the restriction removed for interstate driving. Source: Georgia DDS, 'Apply for a Commercial (CDL) License.'","handbook":"","hbref":""},{"q":"A Georgia CDL holder wants to remove the intrastate-only restriction so they can drive across state lines. What must happen?","options":["They must hold the CDL for at least five years first","They must reach their 21st birthday and visit a DDS Customer Service Center to have the 'Georgia Only' restriction removed","They must add a HazMat endorsement","They must pass an additional interstate skills test at age 18"],"answer":1,"explanation":"Drivers aged 18 to 21 are restricted to intrastate driving. To gain interstate privileges, the driver must turn 21 and visit a DDS Customer Service Center to remove the 'Georgia Only' restriction. Source: Georgia DDS, 'Apply for a Commercial (CDL) License.'","handbook":"","hbref":""},{"q":"Which endorsement is required in Georgia to drive a vehicle transporting hazardous materials in quantities requiring placards?","options":["N (Tanker) endorsement","T (Doubles/Triples) endorsement","P (Passenger) endorsement","H (HazMat) endorsement"],"answer":3,"explanation":"The H (HazMat) endorsement is required to haul hazardous materials requiring placarding. In Georgia it requires passing a knowledge test, a TSA background check, and fingerprinting for both first-time issuance and renewals. Source: Georgia DDS, 'Adding CDL Endorsements.'","handbook":"","hbref":""},{"q":"In Georgia, what additional federal requirement must be satisfied for the HazMat (H) endorsement that is NOT required for the Tanker (N) endorsement?","options":["Passing a separate skills (road) test","Holding the endorsement for 14 days before use","Passing a TSA security threat assessment with fingerprinting","Obtaining a passenger endorsement first"],"answer":2,"explanation":"The HazMat endorsement requires passing a TSA background check (security threat assessment), and fingerprints are required for first-time issuance as well as renewals. The Tanker endorsement requires only a knowledge test. Source: Georgia DDS, 'Adding CDL Endorsements.'","handbook":"","hbref":""},{"q":"According to Georgia DDS, how is the N (Tanker) endorsement obtained?","options":["By passing both a knowledge test and a skills test","By passing a skills test only","By passing a knowledge test only","By passing a TSA background check only"],"answer":2,"explanation":"In Georgia the N (Tanker) endorsement requires passing a knowledge test only and is valid for Class A and B CDLs. Source: Georgia DDS, 'Adding CDL Endorsements.'","handbook":"","hbref":""},{"q":"Which Georgia CDL endorsement is valid for a Class A CDL only and is obtained by passing a knowledge test?","options":["T (Doubles/Triples) endorsement","P (Passenger) endorsement","S (School Bus) endorsement","N (Tanker) endorsement"],"answer":0,"explanation":"The T (Double/Triple Trailer) endorsement is valid for a Class A CDL only and requires a knowledge test. It cannot be obtained on a Commercial Learner's Permit; the applicant must already hold a valid CDL. Source: Georgia DDS, 'Adding CDL Endorsements.'","handbook":"","hbref":""},{"q":"What does Georgia require to obtain the P (Passenger) endorsement?","options":["Passing a knowledge test only","Passing both a knowledge test and a skills test","Passing a skills test only","Passing a TSA background check only"],"answer":1,"explanation":"In Georgia, the P (Passenger) endorsement requires passing both a knowledge test and a skills test, and it is valid for Class A, B, and C CDLs. Source: Georgia DDS, 'Adding CDL Endorsements.'","handbook":"","hbref":""},{"q":"Which two endorsements does Georgia DDS require BOTH a knowledge test AND a skills test for?","options":["N (Tanker) and T (Doubles/Triples)","H (HazMat) and N (Tanker)","P (Passenger) and S (School Bus)","T (Doubles/Triples) and H (HazMat)"],"answer":2,"explanation":"In Georgia, the Passenger (P) and School Bus (S) endorsements each require passing both a knowledge test and a skills test. The N, T, and H endorsements require a knowledge test only. Source: Georgia DDS, 'Adding CDL Endorsements.'","handbook":"","hbref":""},{"q":"Effective February 7, 2022, which group of Georgia CDL applicants is subject to Entry-Level Driver Training (ELDT) requirements?","options":["Only applicants seeking a Class C CDL","Applicants getting a Class A or B for the first time, upgrading to a higher class, or adding a School Bus, Passenger, or HazMat endorsement","Only drivers over the age of 21","Only applicants renewing an existing CDL with no changes"],"answer":1,"explanation":"Under FMCSA ELDT rules adopted by Georgia, beginning February 7, 2022, all entry-level drivers obtaining a Class A or B CDL for the first time, upgrading to a higher class, or adding a School Bus (S), Passenger (P), or HazMat (H) endorsement must complete ELDT. Source: Georgia DDS, 'Apply for a Commercial (CDL) License' / 'Adding CDL Endorsements.'","handbook":"","hbref":""},{"q":"Where must a Georgia CDL applicant's Entry-Level Driver Training (ELDT) be completed and recorded?","options":["At any private driving school of the applicant's choice with no registry","Only at a Georgia DDS Customer Service Center","Through an online quiz with no formal provider","With a training provider listed on the FMCSA Training Provider Registry (TPR)"],"answer":3,"explanation":"ELDT must be delivered by a provider listed on the FMCSA Training Provider Registry (TPR), and the completion is reported to the registry before the driver may take the CDL skills or HazMat knowledge test. Source: FMCSA ELDT regulations referenced by Georgia DDS.","handbook":"","hbref":""},{"q":"Before applying for a full Georgia CDL, how long must an applicant hold the Commercial Learner Permit (CLP)?","options":["At least 30 days","At least 60 days","At least 14 days","At least 6 months"],"answer":2,"explanation":"Georgia requires CDL applicants to hold the Commercial Learner Permit (CLP) for a minimum of 14 days before taking the CDL skills test / applying for the full CDL. Source: Georgia DDS, 'CDL Permit' and CDL Licensing FAQs.","handbook":"","hbref":""},{"q":"What must a Georgia applicant pass to be issued a Commercial Learner Permit (CLP)?","options":["The required written knowledge exam(s)","Only the CDL skills (road) test","A TSA background check","A vision test only"],"answer":0,"explanation":"To obtain a Georgia CLP (Class AP or BP), the applicant must hold a valid regular Georgia driver's license and pass the required written knowledge exam(s). The skills test comes later, after the 14-day hold. Source: Georgia DDS, 'Apply for a Commercial Permit (Class AP or BP).'","handbook":"","hbref":""},{"q":"For a Georgia CLP issued on or after July 1, 2021, how long is the permit valid?","options":["30 days","180 days","5 years","365 days"],"answer":3,"explanation":"A Georgia Commercial Learner Permit (CLP) issued on or after July 1, 2021 is valid for 365 days. Source: Georgia DDS, 'CDL Permit.'","handbook":"","hbref":""},{"q":"Which of the following is required before a person can obtain a Georgia Commercial Learner Permit (CLP)?","options":["Holding a valid regular Georgia driver's license","Already holding a HazMat endorsement","Completing a TSA background check","Holding a Class A CDL"],"answer":0,"explanation":"Georgia DDS requires CLP applicants to hold a valid regular Georgia driver's license before applying for the commercial permit. Source: Georgia DDS, 'Apply for a Commercial Permit (Class AP or BP).'","handbook":"","hbref":""},{"q":"When applying for a Georgia CDL, which combination of documents does DDS require an applicant to provide?","options":["Proof of identity, Social Security number, lawful presence, and two proofs of Georgia residency","Only a Social Security card","Only a Georgia voter registration card","A passport only, with no residency proof"],"answer":0,"explanation":"Georgia DDS requires proof of identity (e.g., certified birth certificate or U.S. passport), proof of Social Security number, proof of lawful presence, and two documents from separate sources proving Georgia residency. Source: Georgia DDS, 'Apply for a Commercial (CDL) License.'","handbook":"","hbref":""},{"q":"A Georgia CDL driver who operates only within Georgia and must meet FMCSA driver-qualification requirements should choose which medical self-certification category?","options":["Non-excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","Non-excepted Intrastate (NA)"],"answer":3,"explanation":"Georgia DDS uses four self-certification categories: Non-excepted Interstate (NI), Excepted Interstate (EI), Non-excepted Intrastate (NA), and Excepted Intrastate (EA). A driver operating only in Georgia (intrastate) who must meet medical-qualification requirements selects Non-excepted Intrastate (NA). All CDL holders must file a self-certification with DDS. Source: Georgia DDS, 'CDL Medical Certification and Self-Certification Process.'","handbook":"","hbref":""},{"q":"In Georgia, what is the maximum blood alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle (CMV)?","options":["0.08 or above is the limit","It is illegal at 0.04 or higher","0.10 or above is the limit","Any amount over 0.02 is illegal"],"answer":1,"explanation":"It is illegal to operate a CMV in Georgia with a BAC of 0.04 or higher, half the 0.08 limit for non-commercial drivers. Source: Georgia CDL Manual (DDS), CDL Disqualifications; 49 CFR 383.51(b).","handbook":"","hbref":""},{"q":"A Georgia CDL holder is convicted of a first major offense, such as DUI in a CMV, while NOT carrying hazardous materials. For how long is the CDL disqualified?","options":["At least 60 days","At least 6 months","At least 1 year","At least 3 years"],"answer":2,"explanation":"A first major offense (DUI, BAC 0.04+, refusal, leaving the scene, felony use of a CMV, etc.) results in a disqualification of at least 1 year. Source: Georgia CDL Manual (DDS); 49 CFR 383.51(b) Table 1.","handbook":"","hbref":""},{"q":"How does the disqualification period change if a Georgia CDL driver commits a first major offense while operating a CMV that is placarded for hazardous materials?","options":["It increases to a minimum of 3 years","It stays at a minimum of 1 year","It increases to a minimum of 5 years","It results in an immediate lifetime ban"],"answer":0,"explanation":"When a first major offense occurs while transporting hazardous materials requiring placards, the minimum disqualification rises from 1 year to 3 years. Source: Georgia CDL Manual (DDS); 49 CFR 383.51(b) Table 1.","handbook":"","hbref":""},{"q":"What is the disqualification period for a Georgia CDL holder convicted of a SECOND major offense in a separate incident?","options":["An additional 3 years","An additional 10 years","An additional 120 days","Disqualification for life"],"answer":3,"explanation":"A second conviction for any combination of major offenses in separate incidents results in lifetime disqualification of the CDL. Source: Georgia CDL Manual (DDS); 49 CFR 383.51(b) Table 1.","handbook":"","hbref":""},{"q":"Under Georgia's implied consent law, what happens to a CDL holder who refuses to submit to a chemical test for alcohol or drugs after a lawful request?","options":["Nothing, since refusal cannot be used as evidence","Only a fine is imposed but the CDL is not affected","The driver is disqualified the same as if convicted of DUI","The driver receives a 60-day serious-violation penalty"],"answer":2,"explanation":"Refusing a chemical test is treated as a major offense, carrying the same disqualification as a DUI conviction: at least 1 year for a first offense and life for a second. Source: Georgia CDL Manual (DDS); O.C.G.A. 40-5-67.1 (implied consent); 49 CFR 383.51(b).","handbook":"","hbref":""},{"q":"A CDL driver in Georgia is found to have any detectable amount of alcohol below 0.04 while on duty. What is the consequence?","options":["An out-of-service order placing the driver out of service for 24 hours","Immediate 1-year disqualification of the CDL","A 60-day serious-violation disqualification","No consequence because the BAC is under 0.04"],"answer":0,"explanation":"Any detectable alcohol under 0.04 does not trigger a major-offense disqualification but does require the driver to be placed out of service for 24 hours. Source: Georgia CDL Manual (DDS); 49 CFR 392.5.","handbook":"","hbref":""},{"q":"Which of the following is classified as a \"serious traffic violation\" for a Georgia CDL holder rather than a major offense?","options":["Driving a CMV with a BAC of 0.04 or higher","Using a CMV to commit a felony","Excessive speeding of 15 mph or more over the posted limit","Leaving the scene of an accident involving a CMV"],"answer":2,"explanation":"Excessive speeding (15+ mph over the limit) is a serious traffic violation. DUI, felony use, and hit-and-run are major offenses with far harsher penalties. Source: Georgia CDL Manual (DDS); 49 CFR 383.51(c) Table 2.","handbook":"","hbref":""},{"q":"A Georgia CDL holder is convicted of TWO serious traffic violations in separate incidents within a 3-year period. What is the disqualification period?","options":["At least 30 days","At least 60 days","At least 120 days","At least 1 year"],"answer":1,"explanation":"Two serious traffic violations within 3 years result in a disqualification of at least 60 days. Source: Georgia CDL Manual (DDS); 49 CFR 383.51(c) Table 2.","handbook":"","hbref":""},{"q":"A Georgia CDL holder is convicted of THREE serious traffic violations in separate incidents within a 3-year period. What is the disqualification period?","options":["At least 60 days","At least 90 days","At least 120 days","At least 1 year"],"answer":2,"explanation":"Three serious traffic violations within 3 years result in a disqualification of at least 120 days. Source: Georgia CDL Manual (DDS); 49 CFR 383.51(c) Table 2.","handbook":"","hbref":""},{"q":"Which of these is NOT counted as a serious traffic violation that can lead to CDL disqualification in Georgia?","options":["Following the vehicle ahead too closely","Making an improper or erratic lane change","Reckless driving","Parking a CMV overnight in a rest area"],"answer":3,"explanation":"Serious traffic violations include following too closely, improper lane changes, reckless driving, and excessive speeding. Legally parking in a rest area is not a violation. Source: Georgia CDL Manual (DDS); 49 CFR 383.51(c) Table 2.","handbook":"","hbref":""},{"q":"What is the disqualification period for a Georgia CDL driver's FIRST conviction of a railroad-highway grade crossing violation?","options":["At least 30 days","At least 60 days","At least 120 days","At least 1 year"],"answer":1,"explanation":"A first railroad-highway grade crossing violation results in a disqualification of at least 60 days. Source: Georgia CDL Manual (DDS); 49 CFR 383.51(d) Table 3.","handbook":"","hbref":""},{"q":"A Georgia CDL holder commits a SECOND railroad-highway grade crossing violation within a 3-year period. What is the minimum disqualification?","options":["At least 60 days","At least 120 days","At least 6 months","At least 1 year"],"answer":1,"explanation":"A second railroad-highway grade crossing violation within 3 years results in a disqualification of at least 120 days. Source: Georgia CDL Manual (DDS); 49 CFR 383.51(d) Table 3.","handbook":"","hbref":""},{"q":"A Georgia CDL holder commits a THIRD railroad-highway grade crossing violation within a 3-year period. What is the minimum disqualification?","options":["At least 120 days","At least 6 months","At least 1 year","Disqualification for life"],"answer":2,"explanation":"A third or subsequent railroad-highway grade crossing violation within 3 years results in a disqualification of at least 1 year. Source: Georgia CDL Manual (DDS); 49 CFR 383.51(d) Table 3.","handbook":"","hbref":""},{"q":"What is the disqualification period for a Georgia CDL driver's FIRST conviction for violating an out-of-service (OOS) order, when no hazardous materials or passengers are involved?","options":["At least 60 days","At least 90 days","At least 180 days","At least 2 years"],"answer":2,"explanation":"A first conviction for violating an out-of-service order results in a disqualification of at least 180 days (up to 1 year). Source: Georgia CDL Manual (DDS); 49 CFR 383.51(e) Table 4.","handbook":"","hbref":""},{"q":"A Georgia CDL holder is convicted of a SECOND out-of-service order violation in separate incidents within a 10-year period. What is the minimum disqualification?","options":["At least 180 days","At least 1 year","At least 2 years","Disqualification for life"],"answer":2,"explanation":"A second out-of-service order violation within a 10-year period results in a disqualification of at least 2 years (up to 5 years). Source: Georgia CDL Manual (DDS); 49 CFR 383.51(e) Table 4.","handbook":"","hbref":""},{"q":"How does the penalty for a FIRST out-of-service order violation change if the Georgia CDL driver was transporting placarded hazardous materials or 16 or more passengers?","options":["It is reduced to 60 days","The minimum stays 180 days but the maximum rises to 2 years","It becomes a lifetime disqualification","It is unchanged at 180 days to 1 year"],"answer":1,"explanation":"For a first OOS violation while hauling placarded HazMat or 16+ passengers, the disqualification is at least 180 days but up to 2 years, a longer maximum than the standard case. Source: Georgia CDL Manual (DDS); 49 CFR 383.51(e) Table 4.","handbook":"","hbref":""},{"q":"Under Georgia's Super Speeder law (O.C.G.A. 40-6-189), at what speeds is a driver classified as a \"Super Speeder\"?","options":["65 mph on any road or 75 mph on a two-lane road","75 mph on a two-lane road or 85 mph on any road or highway","80 mph on a two-lane road or 90 mph on an interstate","15 mph or more over any posted speed limit"],"answer":1,"explanation":"Georgia's Super Speeder law classifies a driver convicted of 75 mph or more on a two-lane road, or 85 mph or more on any road or highway, as a Super Speeder. Source: O.C.G.A. 40-6-189.","handbook":"","hbref":""},{"q":"Under Georgia's Super Speeder law, what additional state fee does the Department of Driver Services charge a convicted Super Speeder, and what happens if it is unpaid?","options":["A $200 fee; license suspension if not paid within 120 days of notice","A $500 fee; jail time if not paid within 30 days","A $100 fee; a warning letter if not paid within 90 days","A $200 fee with no further consequence for nonpayment"],"answer":0,"explanation":"The Super Speeder law adds a $200 state fee on top of any court fines. If unpaid within 120 days of the DDS notice, the driver's license is suspended and a $50 reinstatement fee applies. Source: O.C.G.A. 40-6-189.","handbook":"","hbref":""},{"q":"Under federal rules that Georgia enforces, what happens to a CDL driver who is convicted of texting or using a hand-held phone while operating a CMV?","options":["It carries no penalty for CDL holders specifically","It is an automatic 1-year major-offense disqualification","It counts as a serious traffic violation toward disqualification","It results in an immediate lifetime disqualification"],"answer":2,"explanation":"Texting or using a hand-held phone while driving a CMV is a serious traffic violation; two within 3 years bring a 60-day disqualification and three bring 120 days. Source: 49 CFR 383.51(c); Georgia CDL Manual (DDS).","handbook":"","hbref":""},{"q":"Georgia's Hands-Free Law (O.C.G.A. 40-6-241) applies to all drivers. Which action does it prohibit while operating a vehicle, including a CMV?","options":["Using a Bluetooth or speakerphone hands-free connection","Physically holding or supporting a phone with any part of the body","Having a mounted GPS device visible on the windshield","Speaking to a passenger seated in the vehicle"],"answer":1,"explanation":"The Hands-Free Georgia Act bars drivers from holding or supporting a phone or electronic device with any part of the body; hands-free use such as Bluetooth or speakerphone remains allowed. Source: O.C.G.A. 40-6-241.","handbook":"","hbref":""},{"q":"On a Georgia interstate with two or more lanes in your direction, you approach a stationary HERO unit on the shoulder displaying flashing amber lights. What does Georgia's Move Over Law require of a commercial driver?","options":["Maintain the posted speed limit because the unit is off the roadway on the shoulder","Come to a complete stop in your lane and wait until the unit moves before proceeding","Move over one lane away from the unit if it is safe to do so; if you cannot change lanes safely, slow to below the posted speed limit and be prepared to stop","Move over only for police and fire vehicles, since HERO and utility units are not covered"],"answer":2,"explanation":"Georgia's Move Over Law (O.C.G.A. §40-6-16) requires drivers on roads with two or more lanes in the same direction to move over one lane away from a stationary emergency, utility, towing/recovery, highway-maintenance, sanitation, or HERO unit displaying flashing lights. If a lane change cannot be made safely, the driver must reduce speed below the posted limit and be prepared to stop.","handbook":"","hbref":""},{"q":"Georgia's Move Over Law applies to stationary vehicles displaying flashing lights. Which of the following vehicles is NOT covered by O.C.G.A. §40-6-16?","options":["A HERO (Highway Emergency Response Operator) unit assisting a disabled vehicle","A utility service vehicle repairing power lines with flashing amber lights","A passenger car stopped on the shoulder with its standard hazard flashers (four-way flashers) on after a flat tire","A tow truck recovering a wrecked vehicle with flashing amber lights"],"answer":2,"explanation":"O.C.G.A. §40-6-16 protects stationary emergency, towing/recovery, highway-maintenance, utility service, sanitation, and HERO units displaying flashing lights. An ordinary passenger car using only its standard four-way hazard flashers is not one of the protected classes of vehicles under the Move Over Law.","handbook":"","hbref":""},{"q":"Under the Hands-Free Georgia Act (O.C.G.A. §40-6-241), what additional restriction applies specifically to a driver operating a commercial motor vehicle on a Georgia highway?","options":["The driver may text manually as long as the vehicle is moving under 15 mph","The driver may use no more than a single button on a wireless device to start or end a voice call","The driver may hold a phone to the ear as long as the call is work related","The driver is fully exempt from the Hands-Free Act while on duty"],"answer":1,"explanation":"Under O.C.G.A. §40-6-241, while operating a commercial motor vehicle no driver may use more than a single button on a wireless telecommunications device to initiate or terminate a voice communication, nor reach for a device in a way that requires leaving a seated driving position. Holding or supporting a device with any part of the body is prohibited for all drivers.","handbook":"","hbref":""},{"q":"Which device or activity is permitted under the Hands-Free Georgia Act (O.C.G.A. §40-6-241) while driving a commercial vehicle in Georgia?","options":["Holding a smartphone in your hand to read a text message","Using a commercial two-way radio or CB radio to communicate","Watching a video on a tablet propped on the dashboard","Resting a cell phone on your shoulder against your ear during a call"],"answer":1,"explanation":"O.C.G.A. §40-6-241 expressly excludes commercial two-way radios, CB radios, amateur/ham radios, subscription-based emergency communication devices, prescribed medical devices, and factory navigation/diagnostic systems. Holding or supporting a phone with any part of the body, manual texting, and watching video are all prohibited.","handbook":"","hbref":""},{"q":"You are driving a tractor-trailer in the far-left passing lane of a Georgia interstate and notice a faster vehicle coming up behind you. Under Georgia's 'Slowpoke' / left-lane law (O.C.G.A. §40-6-184), what must you do?","options":["Maintain your position in the passing lane as long as you are at or above the posted speed limit","Speed up to match the overtaking vehicle so it no longer needs to pass","The law does not apply to commercial vehicles, so you may stay in the left lane","Move out of the passing lane to allow the overtaking vehicle to pass, unless road, traffic, weather, or a traffic-control device requires you to remain there"],"answer":3,"explanation":"Georgia's 'Slowpoke' law (O.C.G.A. §40-6-184) requires a driver in the passing lane (the leftmost lane other than an HOV lane) to move over once they know or should know they are being overtaken from the rear by a faster vehicle, unless road/traffic conditions, weather, hazards, or a traffic-control device require remaining in that lane. It applies regardless of whether you are at the speed limit.","handbook":"","hbref":""},{"q":"For purposes of Georgia's left-lane / 'Slowpoke' law (O.C.G.A. §40-6-184), how is the 'passing lane' defined?","options":["The most left-hand lane, other than a high-occupancy vehicle (HOV) lane","Any lane in which a vehicle is currently passing another","The lane closest to the right shoulder","Only the center lane of a three-lane roadway"],"answer":0,"explanation":"O.C.G.A. §40-6-184 defines the 'passing lane' as the most left-hand lane other than a high-occupancy vehicle (HOV) lane. A driver must not continue in that lane once being overtaken by a faster vehicle from the rear.","handbook":"","hbref":""},{"q":"Under O.C.G.A. §40-6-52, a 'truck' (any vehicle with more than six wheels, except buses and motorcoaches) on a Georgia roadway with three or more lanes in the same direction may generally operate in which lanes?","options":["Any lane, as long as it keeps up with the flow of traffic","Only the single most right-hand lane at all times","Only the two most right-hand lanes, except when preparing for a left turn or where lanes are otherwise designated","Only the center lanes, leaving the right lane open for merging traffic"],"answer":2,"explanation":"O.C.G.A. §40-6-52 makes it unlawful for a truck (a vehicle with more than six wheels, excluding buses and motorcoaches) on a roadway with three or more same-direction lanes to drive in any lane other than the two most right-hand lanes, except when preparing for a left turn or where the Department of Transportation has designated other lanes.","handbook":"","hbref":""},{"q":"On a Georgia highway with exactly two lanes in your direction, when may a truck subject to O.C.G.A. §40-6-52 lawfully use the left-hand lane?","options":["Whenever the right lane is busier than the left lane","When actually overtaking and passing another vehicle or preparing for a left turn","Only between sunrise and sunset","Never, under any circumstances"],"answer":1,"explanation":"Under O.C.G.A. §40-6-52, on a roadway with two same-direction lanes it is unlawful for a truck to operate in the left-hand lane except when actually overtaking and passing another vehicle, preparing for a left turn, or as otherwise provided by the statute.","handbook":"","hbref":""},{"q":"What is the maximum speed limit set by O.C.G.A. §40-6-181 for any vehicle, including a tractor-trailer, on a Georgia interstate highway where so posted?","options":["55 miles per hour","65 miles per hour","75 miles per hour","70 miles per hour"],"answer":3,"explanation":"O.C.G.A. §40-6-181 sets a maximum limit of 70 mph on highways that are part of the federal interstate system and on physically divided, full-control-of-access state highways where designated by signs. Georgia does not impose a separate, lower statewide speed limit for trucks; the posted maximum applies to all vehicles.","handbook":"","hbref":""},{"q":"Heavy through-trucks traveling on I-75, I-85, or I-20 toward Atlanta are generally required to do what, under Georgia's Atlanta truck-routing rules?","options":["Use the I-75/I-85 Downtown Connector during daylight hours only","Travel only in the HOV lanes through downtown Atlanta","Stop at a state weigh station before entering I-285","Bypass the city on I-285 unless they are picking up/delivering, going to a terminal or repair facility, or to the driver's residence inside the perimeter"],"answer":3,"explanation":"Trucks traveling through (not into) Atlanta must take I-285 around the city rather than the I-75/I-85 Downtown Connector. Exceptions exist for trucks picking up or delivering to a shipper inside I-285, going to/from a terminal or repair facility inside I-285, or for a driver going to/from a residence inside the perimeter. This is a well-signed, enforced through-truck restriction.","handbook":"","hbref":""},{"q":"On Atlanta's I-75/I-85 Downtown Connector, the inside (leftmost) lanes are reserved as HOV lanes. What does this mean for a commercial truck driver?","options":["The truck must stay out of the HOV lane and, because of lane-use limits, generally remain in the right-hand lanes","The truck may use the HOV lane any time it carries more than 6,000 lbs of freight","The truck may use the HOV lane if it pays a toll like a HOT lane","The truck may use the HOV lane because commercial vehicles are always considered high-occupancy"],"answer":0,"explanation":"The inside lanes of the I-75/I-85 Downtown Connector are HOV-restricted. Freight is not an occupant, so a truck does not qualify as a high-occupancy vehicle, and under O.C.G.A. §40-6-52 trucks must use the right-hand lanes. Georgia's HOV lanes require the minimum number of occupants, not cargo weight.","handbook":"","hbref":""},{"q":"Which commercial vehicles are required to STOP at every railroad-highway grade crossing according to the Georgia CDL Manual?","options":["Buses carrying passengers and vehicles displaying hazardous-materials placards","All commercial vehicles over 26,001 lbs regardless of cargo","Only empty cargo tankers, never loaded ones","Any truck pulling a double or triple trailer"],"answer":0,"explanation":"Per the Georgia CDL Manual (and 49 CFR 392.10), the commercial vehicles that must always stop at railroad crossings are buses carrying passengers and placarded hazardous-materials vehicles. This also includes vehicles carrying any amount of chlorine and cargo tanks used for hazardous materials, whether loaded or empty.","handbook":"","hbref":""},{"q":"When a placarded HazMat vehicle or passenger bus is required to stop at a railroad crossing in Georgia, where must it stop?","options":["Exactly 25 feet from the nearest rail","Within 50 feet but not closer than 15 feet from the nearest rail","At least 100 feet from the nearest rail","Anywhere within 10 feet of the crossing gate"],"answer":1,"explanation":"The Georgia CDL Manual states a required stop at a railroad crossing must be made no more than 50 feet and no less than 15 feet from the nearest rail. The driver should look and listen for a train, then cross only when it is safe to clear the tracks completely without stopping.","handbook":"","hbref":""},{"q":"According to the Georgia CDL Manual, what should a commercial driver NOT do while crossing railroad tracks?","options":["Use a gear low enough to cross without changing gears","Shift gears while any part of the vehicle is on the tracks","Look and listen for an approaching train before starting across","Make sure there is room to completely clear the tracks before starting across"],"answer":1,"explanation":"The Georgia CDL Manual warns drivers never to shift gears while crossing railroad tracks, because the vehicle could stall on the crossing. The driver should select a gear that allows crossing without shifting and should ensure there is enough room to clear the tracks completely before starting across.","handbook":"","hbref":""},{"q":"Under O.C.G.A. §40-6-163, when must the driver of a commercial vehicle stop for a stopped school bus that has its red lights flashing and stop arm extended?","options":["Only when traveling in the same direction as the bus, never when oncoming","Only if children are visibly present at the roadside","When meeting or overtaking the bus from either direction on an undivided roadway, until the bus resumes motion or the signals stop","Only on two-lane roads, never on roads with four or more lanes"],"answer":2,"explanation":"O.C.G.A. §40-6-163 requires the driver of a vehicle meeting or overtaking from either direction a school bus stopped on the highway with its visual signals (flashing red lights/stop arm) actuated to stop before reaching the bus and not proceed until the bus resumes motion or the signals are turned off, on undivided roadways.","handbook":"","hbref":""},{"q":"Under Georgia's school-bus law (O.C.G.A. §40-6-163), on which type of roadway is an oncoming driver NOT required to stop for a school bus loading children on the opposite side?","options":["A four-lane road where the only divider is a painted center line","A road separated only by a two-way center turn lane","Any road with two or more lanes in each direction","A highway with separate roadways divided by a grass median, unpaved area, or physical barrier"],"answer":3,"explanation":"O.C.G.A. §40-6-163 provides that a driver on a highway with separate roadways divided by a grass median, unpaved area, or physical barrier need not stop for a school bus on the other separate roadway. A painted line or a center turn lane is NOT a divider, so drivers must still stop in those cases.","handbook":"","hbref":""},{"q":"A road has two lanes in each direction separated only by a two-way center turn lane (no median or barrier). A school bus on the opposite side stops with red lights flashing. Under O.C.G.A. §40-6-163, what must an oncoming commercial driver do?","options":["Stop, because a center turn lane is not a median or physical barrier separating the roadways","Continue at reduced speed, because the turn lane counts as a divider","Stop only if the bus is in the driver's own direction of travel","Proceed normally, because oncoming traffic never stops for school buses"],"answer":0,"explanation":"Under O.C.G.A. §40-6-163, the divided-highway exception applies only to roadways separated by a grass median, unpaved area, or physical barrier. A center two-way turn lane and painted lines do not qualify, so an oncoming driver must stop for the school bus with its signals actuated.","handbook":"","hbref":""},{"q":"Per the Georgia CDL Manual, where must a truck driver place the three required emergency warning devices (reflective triangles) on a two-lane, two-way road after stopping on the shoulder?","options":["All three directly behind the vehicle within 10 feet of the rear bumper","One on the roof and two on the front bumper","About 10 feet behind the vehicle toward traffic, about 100 feet behind, and about 100 feet ahead of the vehicle","About 500 feet behind and 500 feet ahead, with none near the vehicle"],"answer":2,"explanation":"The Georgia CDL Manual requires warning devices placed within 10 minutes: one about 10 feet (4 paces) from the vehicle toward approaching traffic, one about 100 feet (40 paces) behind, and one about 100 feet (40 paces) ahead. On hills or curves, the rear device is moved farther back to give adequate warning.","handbook":"","hbref":""},{"q":"According to the Georgia CDL Manual, what is the correct technique for going down a long, steep North Georgia mountain grade to prevent brake fade?","options":["Select a low gear before the descent and use light, steady braking with the snub (apply-then-release) method at a safe speed","Stay in a high gear and ride the brakes continuously to keep speed low","Shift to neutral to save fuel and control speed with the brakes alone","Pump the brakes rapidly while accelerating to keep the engine warm"],"answer":0,"explanation":"The Georgia CDL Manual instructs drivers to choose a safe speed and a low gear BEFORE starting down a steep grade, relying on engine braking, and to use the snub braking technique (apply firmly to slow about 5 mph, then release). Riding the brakes or coasting in neutral causes brake fade and loss of control.","handbook":"","hbref":""},{"q":"On a steep North Georgia downgrade your brakes have faded and the truck is gaining speed. The Georgia CDL Manual advises that the best action is to:","options":["Pull onto the paved right shoulder and apply the parking brake hard","Steer into oncoming traffic to find an open lane","Turn off the engine to slow the vehicle down quickly","Use a runaway-truck escape ramp if one is available, as it is designed to stop a runaway vehicle safely"],"answer":3,"explanation":"The Georgia CDL Manual explains that escape ramps, built on many steep mountain downgrades with beds of loose material (and often an upgrade), are designed to stop runaway vehicles safely. If your brakes fail on a grade, taking an available escape ramp is the safest action; turning the engine off or using the parking brake at speed can cause loss of control.","handbook":"","hbref":""},{"q":"In Georgia, which state agency issues commercial driver's licenses (CDLs) and administers CDL testing?","options":["The Georgia Department of Public Safety registration division","The Georgia Department of Motor Vehicles (DMV)","The Georgia Bureau of Investigation","The Georgia Department of Driver Services (DDS)"],"answer":3,"explanation":"Georgia does not have a 'DMV.' The Georgia Department of Driver Services (DDS) is the state agency that issues all CDLs and administers CDL knowledge and skills testing. Source: GA DDS, Commercial License (CDL) program pages (dds.georgia.gov).","handbook":"","hbref":""},{"q":"How many documents proving your Georgia residential address must you bring to GA DDS when applying for a CDL?","options":["No residency documents are required for a CDL","Four documents showing your Georgia residential address","Two documents showing your current Georgia residential address","One document showing your Georgia residential address"],"answer":2,"explanation":"GA DDS requires applicants to provide two acceptable documents (such as utility bills, mortgage statements, or government documents) that show their current Georgia residential address. Source: GA DDS, 'Apply for a Commercial (CDL) License' (dds.georgia.gov).","handbook":"","hbref":""},{"q":"Which set of documents does GA DDS require to establish identity, Social Security number, and lawful status for a CDL?","options":["Only a Georgia voter registration card","Only a vehicle registration in your name","Only a signed statement of residency with no other proof","Proof of identity, your full Social Security number, and proof of U.S. citizenship or lawful presence"],"answer":3,"explanation":"GA DDS requires proof of identity (such as a U.S. birth certificate, passport, or certificate of naturalization), verification of your full Social Security number on the License/ID/Permit form, and documentation of U.S. citizenship or lawful presence, in addition to two Georgia residency documents. Source: GA DDS, CDL application requirements (dds.georgia.gov).","handbook":"","hbref":""},{"q":"Before taking the CDL skills (road) test in Georgia, how long must a driver hold the Commercial Learner's/Instructional Permit (CLP)?","options":["At least 30 days","At least 60 days","At least 14 days","There is no minimum holding period"],"answer":2,"explanation":"GA DDS requires that a CDL applicant hold the Commercial Instructional Permit (CLP) for at least 14 days before applying for and taking the full CDL skills test. This reflects the federal 14-day hold. Source: GA DDS, CDL Permit page (dds.georgia.gov).","handbook":"","hbref":""},{"q":"What must a first-time Class A or Class B CDL applicant in Georgia complete before being allowed to take the CDL skills test?","options":["A defensive driving course at any private driving school","Five years of verifiable non-commercial driving history","A college-level logistics certificate","Entry-Level Driver Training (ELDT) from a provider listed on the FMCSA Training Provider Registry"],"answer":3,"explanation":"Under federal ELDT rules enforced by GA DDS, first-time Class A and Class B CDL applicants (with a CLP obtained on or after Feb. 7, 2022) must complete Entry-Level Driver Training from a provider registered on the FMCSA Training Provider Registry before taking the skills test. Source: GA DDS CDL pages and FMCSA Training Provider Registry (tpr.fmcsa.dot.gov).","handbook":"","hbref":""},{"q":"How long is a standard (non-HazMat) Georgia CDL valid before it must be renewed?","options":["Up to 4 years","Up to 2 years","Up to 10 years","Up to 8 years"],"answer":3,"explanation":"A standard Georgia CDL is valid for up to 8 years. CDLs carrying a Hazardous Materials (H) endorsement are valid for a shorter period (5 years) because of the required background check renewal. Source: GA DDS, 'Renew a CDL' (dds.georgia.gov).","handbook":"","hbref":""},{"q":"Which are the four self-certification categories a Georgia CDL holder must choose from?","options":["Class A, Class B, Class C, Class D","Local, Regional, National, International","Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate, Excepted Intrastate","Day, Night, Hazmat, Passenger"],"answer":2,"explanation":"Every Georgia CDL holder must self-certify to one of four operation types: Non-excepted Interstate (NI), Excepted Interstate (EI), Non-excepted Intrastate (NA), and Excepted Intrastate (EA). Non-excepted drivers must maintain a valid DOT medical certificate. Source: GA DDS, 'CDL Medical Certification and Self-Certification Process' (dds.georgia.gov).","handbook":"","hbref":""},{"q":"Which self-certification category requires a Georgia CDL holder to maintain a valid DOT medical examiner's certificate?","options":["Excepted Interstate (EI)","No category requires a medical certificate","Non-excepted Interstate (NI)","Excepted Intrastate (EA)"],"answer":2,"explanation":"Drivers in the Non-excepted categories (Non-excepted Interstate and Non-excepted Intrastate) must maintain a valid DOT medical examiner's certificate. Excepted categories (EI and EA) do not require one. Source: GA DDS, CDL Medical and Self-Certification process (dds.georgia.gov).","handbook":"","hbref":""},{"q":"As of the FMCSA mandate effective June 18, 2025, how is a Georgia CDL holder's DOT medical examiner's certificate transmitted to DDS?","options":["Electronically from FMCSA's National Registry; DDS no longer accepts paper med certs","By faxing it to the DDS headquarters within 10 days","By mailing a paper copy to the nearest DDS Customer Service Center","By emailing a scanned copy to a personal DDS caseworker"],"answer":0,"explanation":"Effective June 18, 2025, medical certificates are transmitted electronically to GA DDS by FMCSA via the National Registry of Certified Medical Examiners. DDS no longer accepts med certs by mail, fax, email, online, or in person. The driver must simply use a National Registry examiner and keep certification current. Source: GA DDS press release and CDL Med Cert page (dds.georgia.gov).","handbook":"","hbref":""},{"q":"Who must perform the physical exam for a Georgia CDL driver who is required to hold a DOT medical certificate?","options":["A DDS Customer Service Center clerk","Any chiropractor regardless of certification","A medical examiner listed on the FMCSA National Registry of Certified Medical Examiners","Any pharmacist at a licensed Georgia pharmacy"],"answer":2,"explanation":"Georgia CDL drivers who require medical certification must be examined by a medical examiner listed on the FMCSA National Registry of Certified Medical Examiners. That examiner then transmits the certificate electronically. Source: GA DDS, CDL Medical Certification process (dds.georgia.gov).","handbook":"","hbref":""},{"q":"Which three components make up the Georgia CDL skills test?","options":["Cargo loading, fuel economy test, and a math exam","Written law exam, eye exam, and a personality interview","Hazmat handling, customer service, and a typing test","Pre-trip vehicle inspection, basic control skills, and an on-road driving test"],"answer":3,"explanation":"The Georgia CDL skills test has three parts administered in order: the pre-trip vehicle inspection, basic vehicle control skills, and the on-road driving test. All three must be passed to obtain the CDL. Source: GA DDS CDL Manual and Road Test pages (dds.georgia.gov).","handbook":"","hbref":""},{"q":"When taking the CDL skills (road) test in Georgia, who is responsible for providing the test vehicle?","options":["No vehicle is needed; the skills test is done on a simulator only","FMCSA ships a federal test truck to the site","GA DDS provides a fleet vehicle for every applicant","The applicant must provide an appropriate vehicle that passes a DDS safety inspection"],"answer":3,"explanation":"The applicant must bring an appropriate vehicle for the class of CDL being tested, along with proof of registration and valid insurance, and the vehicle must pass a DDS safety inspection before the road test. Source: GA DDS, Road Test page (dds.georgia.gov).","handbook":"","hbref":""},{"q":"What is the minimum age to apply for a CDL in Georgia, and what restriction applies until a certain age?","options":["21 years old, with no permit required","16 years old, with no restrictions at all","18 years old, with intrastate-only restrictions until age 21","25 years old, with no interstate driving ever allowed"],"answer":2,"explanation":"In Georgia you may apply for a CDL at 18, but drivers between 18 and 21 are generally restricted to intrastate (in-state) commercial driving until their 21st birthday. Source: GA DDS, CDL application and permit pages (dds.georgia.gov).","handbook":"","hbref":""},{"q":"How long is a Georgia Commercial Learner's Permit (CLP) issued on or after July 1, 2021 valid?","options":["90 days","Indefinitely, until the CDL is issued","30 days","365 days (one year)"],"answer":3,"explanation":"A Georgia CLP issued on or after July 1, 2021 is valid for 365 days (one year). The driver must still hold it for at least 14 days before the skills test. Source: GA DDS, CDL Permit page (dds.georgia.gov).","handbook":"","hbref":""},{"q":"When is a Commercial Instructional Permit (CLP) required in the Georgia CDL process?","options":["When applying for a new CDL, upgrading a CDL, or adding certain endorsements","Only after the CDL has already been issued","Never; Georgia issues CDLs without any permit stage","Only for drivers transferring an out-of-country license"],"answer":0,"explanation":"GA DDS requires a Commercial Instructional Permit (CLP) when applying for a new CDL, upgrading an existing CDL, or adding certain endorsements that require a skills test. The CLP must be held 14 days before the skills test. Source: GA DDS, CDL Permit page (dds.georgia.gov).","handbook":"","hbref":""},{"q":"For a first-time Hazardous Materials (H) endorsement in Georgia, when must ELDT training be completed?","options":["Only after the TSA background check is denied","Before being permitted to take the HazMat knowledge test","ELDT is never required for the HazMat endorsement","Only after passing the HazMat knowledge test"],"answer":1,"explanation":"Because the HazMat endorsement has no skills test, the ELDT theory training for first-time H applicants must be completed before the applicant is permitted to take the HazMat knowledge test. Source: FMCSA Training Provider Registry / ELDT Applicability (tpr.fmcsa.dot.gov) and GA DDS CDL pages.","handbook":"","hbref":""},{"q":"Which endorsements require first-time applicants in Georgia to complete ELDT before testing?","options":["Tanker (N), doubles/triples (T), and air-brake removal only","Only the air brakes restriction removal","No endorsements ever require ELDT","School bus (S), passenger (P), and hazardous materials (H) endorsements"],"answer":3,"explanation":"Under federal ELDT rules applied by GA DDS, first-time applicants for the School Bus (S), Passenger (P), and Hazardous Materials (H) endorsements must complete ELDT from a registered provider before taking the applicable skills or knowledge test. Source: FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) and GA DDS.","handbook":"","hbref":""},{"q":"In addition to the skills test, what must a Georgia CDL applicant pass at the DDS Customer Service Center?","options":["A physical strength test and a swimming test","Only a credit check","The required written knowledge exam(s) and a vision exam","A federal income-tax filing review"],"answer":2,"explanation":"Before the skills test, a Georgia CDL applicant must pass the required written knowledge exam(s) for the class and endorsements sought and pass a vision exam at the DDS Customer Service Center. Source: GA DDS, CDL Permit and application pages (dds.georgia.gov).","handbook":"","hbref":""},{"q":"Which statement about Georgia CDL fees is accurate?","options":["Only FMCSA collects CDL fees in Georgia","Fees are set individually by each medical examiner","All GA DDS CDL services are permanently free of charge","Exact fee amounts are set by GA DDS and can change, so applicants should verify current fees with DDS"],"answer":3,"explanation":"GA DDS charges fees for permits, testing, and licensing (for example, permit and road-test fees), but exact amounts are set by DDS and can change over time. Applicants should confirm current fees on the official DDS 'Fees and Terms' information before applying. Source: GA DDS (dds.georgia.gov).","handbook":"","hbref":""},{"q":"What must a Georgia CDL driver do at renewal regarding the type of commercial operation?","options":["Self-certify to a single type of commercial operation and, if non-excepted, keep a current DOT medical certificate on file","Re-take the full road skills test every renewal regardless of category","Surrender the CDL and reapply as a brand-new applicant","Submit a notarized letter from a former employer"],"answer":0,"explanation":"At renewal, a Georgia CDL holder must self-certify to a single type of commercial operation (one of the four categories), and non-excepted drivers must maintain a current DOT medical certificate, now transmitted electronically via FMCSA. Source: GA DDS, 'Renew a CDL' and CDL Med Cert pages (dds.georgia.gov).","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная общая внешняя ширина транспортного средства и его груза на дорогах Джорджии, не считая зеркал и аксессуаров?","options":["96 дюймов","102 дюйма","108 дюймов","120 дюймов"],"explanation":"O.C.G.A. §32-6-23 устанавливает, что ни одно транспортное средство не может превышать общую внешнюю ширину, включая любой груз, в 102 дюйма, не считая зеркал и аксессуаров, на любой улице, дороге или шоссе в Джорджии. (Источник: O.C.G.A. §32-6-23; GA DDS CDL Manual)"},"1":{"q":"За исключением случаев, когда разрешен более высокий предел, какова максимальная высота транспортного средства, без груза или с грузом, на дорогах Джорджии?","options":["12 футов 6 дюймов","13 футов 0 дюймов","14 футов 6 дюймов","13 футов 6 дюймов"],"explanation":"O.C.G.A. §32-6-22(a) гласит, что, за исключением случаев, разрешенных по разрешению, ни одно транспортное средство без груза или с грузом не может превышать высоту 13 футов 6 дюймов на дорогах Джорджии. (Источник: O.C.G.A. §32-6-22)"},"2":{"q":"Какова в Джорджии максимальная длина полуприцепа в составе автопоезда «седельный тягач — полуприцеп» при отсутствии установленных ограничений?","options":["45 футов","48 футов","53 фута","57 футов"],"explanation":"O.C.G.A. §32-6-24(b)(1)(B) устанавливает, что у автопоездов «седельный тягач — полуприцеп» полуприцепы не должны превышать 53 фута в длину, если только не установлены знаки, указывающие ограничения длины полуприцепа. (Источник: O.C.G.A. §32-6-24)"},"3":{"q":"В составе автопоезда «седельный тягач — полуприцеп — прицеп» (сдвоенные прицепы) в Джорджии какова максимальная длина каждого прицепа и полуприцепа?","options":["24 фута","28 футов","33 фута","40 футов"],"explanation":"O.C.G.A. §32-6-24(b)(1)(A) устанавливает, что у автопоездов «седельный тягач — полуприцеп — прицеп» прицепы и полуприцепы не должны превышать 28 футов в длину каждый. (Источник: O.C.G.A. §32-6-24)"},"4":{"q":"На дорогах Джорджии, отличных от системы межштатных автомагистралей или STAA, какова максимальная общая длина автопоезда «седельный тягач — полуприцеп» или «седельный тягач — полуприцеп — прицеп» при отсутствии установленных ограничений?","options":["65 футов","75 футов","100 футов","110 футов"],"explanation":"O.C.G.A. §32-6-24(b)(2)(C) устанавливает, что на дорогах, отличных от системы межштатных автомагистралей или STAA, такие автопоезда должны иметь общую длину, не превышающую 100 футов, если только не установлены знаки, указывающие ограничения длины. (Источник: O.C.G.A. §32-6-24)"},"5":{"q":"Какова максимальная общая полная масса, разрешенная для любого транспортного средства с грузом на дорогах Джорджии?","options":["73,280 фунтов","88,000 фунтов","100,000 фунтов","80,000 фунтов"],"explanation":"O.C.G.A. §32-6-26(c)(1)(A) и (d)(1)(A) ограничивают максимальную общую полную массу, разрешенную для любого транспортного средства с грузом, величиной 80,000 фунтов как на национальных, так и на ненациональных автомагистралях. (Источник: O.C.G.A. §32-6-26; GA DDS CDL Manual)"},"6":{"q":"На национальной автомагистрали Джорджии (например, межштатной) какова максимальная нагрузка, разрешенная на спаренную ось?","options":["30,000 фунтов","40,680 фунтов","46,000 фунтов","34,000 фунтов"],"explanation":"O.C.G.A. §32-6-26(d)(1)(B) устанавливает максимальную нагрузку на любую спаренную ось на национальных автомагистралях Джорджии в 34,000 фунтов, что соответствует федеральному пределу. (Источник: O.C.G.A. §32-6-26; GA DDS CDL Manual)"},"7":{"q":"На автомагистралях Джорджии, которые НЕ являются национальными, какова максимальная нагрузка, разрешенная на спаренную ось?","options":["34,000 фунтов","37,340 фунтов","40,680 фунтов","46,000 фунтов"],"explanation":"O.C.G.A. §32-6-26(c)(1)(A) устанавливает максимальную нагрузку на спаренную ось в 40,680 фунтов на автомагистралях Джорджии, которые не являются национальными. (Источник: O.C.G.A. §32-6-26)"},"8":{"q":"Согласно O.C.G.A. §32-6-26, как для целей определения массы в Джорджии определяется «одиночная ось»?","options":["Все колеса, центры которых находятся между двумя параллельными поперечными вертикальными плоскостями на расстоянии 40 дюймов друг от друга","Все колеса, центры которых находятся в пределах 96 дюймов друг от друга","Любые две последовательные оси, расположенные на расстоянии более 40 дюймов друг от друга","Только одиночная управляемая ось силового агрегата"],"explanation":"O.C.G.A. §32-6-26(a)(4) определяет «одиночную ось» как все колеса, центры которых могут быть включены между двумя параллельными поперечными вертикальными плоскостями на расстоянии 40 дюймов друг от друга. (Источник: O.C.G.A. §32-6-26)"},"9":{"q":"Согласно действующему законодательству Джорджии, как для целей определения массы определяется «спаренная ось»?","options":["Две или более последовательные оси, центры которых расположены на расстоянии более 40, но не более 96 дюймов друг от друга","Две или более последовательные оси, исключая управляемую ось, центры которых расположены на расстоянии более 40, но не более 216 дюймов друг от друга","Ровно две оси, расположенные на расстоянии не более 8 футов друг от друга, включая управляемую ось","Любая группа осей в пределах 12 футов друг от друга независимо от управляемой оси"],"explanation":"O.C.G.A. §32-6-26(a)(7) определяет «спаренную ось» (после 1 апреля 1988 года) как две или более последовательные оси, исключая управляемую ось, центры которых могут быть включены между параллельными вертикальными плоскостями, расположенными на расстоянии более 40 дюймов, но не более 216 дюймов друг от друга. (Источник: O.C.G.A. §32-6-26)"},"10":{"q":"Какую формулу использует Джорджия для определения максимальной полной массы, допустимой на группе из двух или более последовательных осей?","options":["Федеральную мостовую формулу","Формулу полной комбинированной массы","Тариф по расстоянию между осями Джорджии","Правило 18,000 фунтов на ось"],"explanation":"O.C.G.A. §32-6-26(a)(1) и (d) принимают федеральную мостовую формулу W = 500((LN/N-1) + 12N + 36) для определения максимальной полной массы на любой группе из двух или более последовательных осей на национальных автомагистралях Джорджии. (Источник: O.C.G.A. §32-6-26; GA DDS CDL Manual)"},"11":{"q":"В мостовой формуле Джорджии W = 500((LN/N-1) + 12N + 36), что обозначает переменная «N»?","options":["Число осей в рассматриваемой группе","Расстояние в футах между крайними осями группы","Чистая масса груза в тысячах фунтов","Число шин на самой тяжелой оси"],"explanation":"В O.C.G.A. §32-6-26(a)(1) N — это число осей в рассматриваемой группе, L — расстояние в футах между крайними осями группы, а W — полная масса на этой группе. (Источник: O.C.G.A. §32-6-26)"},"12":{"q":"Согласно O.C.G.A. §32-6-26, какова максимальная общая полная масса для транспортного средства, оснащенного только четырьмя осями, на ненациональных автомагистралях Джорджии?","options":["56,000 фунтов","70,000 фунтов","73,280 фунтов","80,000 фунтов"],"explanation":"O.C.G.A. §32-6-26(c)(1)(C) устанавливает, что для любого транспортного средства, оснащенного четырьмя осями, максимальная общая полная масса, разрешенная для транспортного средства с грузом, составляет 70,000 фунтов. (Источник: O.C.G.A. §32-6-26)"},"13":{"q":"В системе окружных дорог Джорджии какова максимальная общая полная масса, разрешенная для транспортного средства, не осуществляющего погрузку или доставку на этой дороге?","options":["46,000 фунтов","56,000 фунтов","70,000 фунтов","80,000 фунтов"],"explanation":"O.C.G.A. §32-6-26(f) ограничивает максимальную общую полную массу в системе окружных дорог величиной 56,000 фунтов, за исключением случаев, когда транспортное средство осуществляет погрузку или доставку на такой дороге (или на квалифицирующемся обозначенном местном грузовом маршруте). (Источник: O.C.G.A. §32-6-26)"},"14":{"q":"Когда транспортное средство, перевозящее лесную продукцию, живую птицу, хлопок, корма, гранит, твердые отходы или свежеприготовленный бетон, может превышать обычные пределы Джорджии по осевой/полной массе на ненациональной автомагистрали без разрешения?","options":["Никогда; для превышения пределов всегда требуется разрешение","Только ночью и только на межштатных автомагистралях","Когда нагрузка на одиночную ось не превышает 23,000 фунтов, на спаренную ось — 46,000 фунтов, а полная масса — 80,000 фунтов","Когда полная масса не превышает 100,000 фунтов независимо от осевой нагрузки"],"explanation":"O.C.G.A. §32-6-26(g)(1) разрешает эти конкретные сельскохозяйственные и товарные перевозки на ненациональных автомагистралях без разрешения только тогда, когда нагрузка на одиночную ось не превышает 23,000 фунтов, на спаренную ось — 46,000 фунтов, а общая полная масса — 80,000 фунтов. (Источник: O.C.G.A. §32-6-26)"},"15":{"q":"При каком условии действует освобождение Джорджии по габаритам для ОБОРУДОВАНИЯ для фермерства, сельского хозяйства или управления лесами (позволяющее ему превышать пределы ширины и длины без разрешения)?","options":["Только в системе межштатных автомагистралей и только ночью","В светлое время суток на дорогах, не входящих в систему межштатных автомагистралей, в пределах 40 миль от собственности владельца или дилера","В любом месте штата в любое время без ограничения расстояния","Только когда его сопровождает машина эскорта с желтыми огнями на межштатной автомагистрали"],"explanation":"O.C.G.A. §32-6-25 освобождает фермерское/сельскохозяйственное оборудование или оборудование для управления лесами от пределов ширины и длины без разрешения, когда оно эксплуатируется в светлое время суток на общественной дороге, не входящей в систему межштатных автомагистралей, в радиусе 40 миль от собственности владельца или дилера. Это освобождение НЕ распространяется на транспортные средства, перевозящие или транспортирующие лесную продукцию. (Источник: O.C.G.A. §32-6-25)"},"16":{"q":"Кто выдает в Джорджии разрешение, дающее транспортному средству или грузу право превышать максимальные пределы по габаритам или массе, установленные законом?","options":["Департамент транспорта (GDOT), по письменному заявлению и при наличии уважительной причины","Шериф округа, где начинается поездка","Любой сотрудник весовой станции во время проверки","Департамент водительских услуг при подаче заявления на CDL"],"explanation":"O.C.G.A. §32-6-28(a) уполномочивает комиссара GDOT (или назначенное должностное лицо) выдавать по письменному заявлению и при наличии уважительной причины разрешение, позволяющее транспортному средству с грузом, чья масса, ширина, длина или высота превышает законный максимум. Разрешения получаются через GDOT/Департамент общественной безопасности (система GAPROS). (Источник: O.C.G.A. §32-6-28; GDOT)"},"17":{"q":"Согласно O.C.G.A. §32-6-28, ГОДОВОЕ разрешение Джорджии на негабаритный/сверхтяжелый груз НЕ может быть выдано для транспортного средства, общая полная масса которого превышает какую величину?","options":["80,000 фунтов","120,000 фунтов","150,000 фунтов","100,000 фунтов"],"explanation":"O.C.G.A. §32-6-28(b)(1)(A) устанавливает, что годовое разрешение не может санкционировать эксплуатацию транспортного средства, общая полная масса которого превышает 100,000 фунтов (а также чья нагрузка на одиночную ось превышает 25,000 фунтов, длина превышает 100 футов, ширина превышает 102 дюйма / ширина груза 144 дюйма, или высота превышает 14 футов 6 дюймов). (Источник: O.C.G.A. §32-6-28; GDOT)"},"18":{"q":"Согласно базовому правилу Джорджии о массе, какова базовая максимальная нагрузка на одиночную ось (пневматические шины высокого давления) до применения установленного законом допуска?","options":["12,000 фунтов","18,000 фунтов","20,000 фунтов","16,000 фунтов"],"explanation":"O.C.G.A. §32-6-26(b)(1) запрещает нагрузку на любую одиночную ось (пневматические шины высокого давления, цельнорезиновые или подушечные шины), которая превышает 16,000 фунтов более чем на 13 процентов — таким образом, базовая величина составляет 16,000 фунтов, а допуск 13% дает около 18,080 фунтов. (Источник: O.C.G.A. §32-6-26)"},"19":{"q":"Согласно O.C.G.A. §32-6-27, прежде чем сверхтяжелому транспортному средству в Джорджии будет разрешено двигаться, оператор должен разгрузить всю полную массу, превышающую законный предел более чем на какую величину?","options":["2,000 фунтов","4,000 фунтов","6,000 фунтов","10,000 фунтов"],"explanation":"O.C.G.A. §32-6-27(e) требует, чтобы владелец/оператор сверхтяжелого транспортного средства, помимо уплаты начисленного ущерба, разгрузил всю полную массу, превышающую законный предел массы более чем на 6,000 фунтов, прежде чем транспортному средству будет разрешено двигаться. (Источник: O.C.G.A. §32-6-27)"},"20":{"q":"Какой класс CDL требуется в Джорджии для управления составом транспортных средств с полной комбинированной массой (GCWR) 26,001 фунтов или более, где буксируемое транспортное средство имеет GVWR более 10,000 фунтов?","options":["Класс B","Класс C","Класс D","Класс A"],"explanation":"CDL класса A в Джорджии охватывает любой состав транспортных средств с GCWR 26,001+ фунтов, где буксируемая единица превышает 10,000 фунтов GVWR. Держатель класса A может также управлять транспортными средствами классов B и C при наличии соответствующих эндорсментов. Источник: Georgia DDS, «Apply for a Commercial (CDL) License (Class A, B, C)»."},"21":{"q":"Согласно правилам Georgia DDS, CDL класса B дает водителю право управлять каким из следующих транспортных средств?","options":["Любым составом транспортных средств, где буксируемая единица превышает 10,000 фунтов","Любым одиночным транспортным средством с GVWR 26,001+ фунтов, буксирующим единицу не более 10,000 фунтов","Только транспортными средствами, рассчитанными на перевозку 16 или более пассажиров","Только транспортными средствами с табличками для опасных материалов"],"explanation":"CDL класса B в Джорджии охватывает одиночные транспортные средства с GVWR 26,001+ фунтов, включая буксирующие транспортное средство не более 10,000 фунтов GVWR. Держатель класса B может также управлять транспортными средствами класса C при наличии соответствующих эндорсментов. Источник: Georgia DDS, «Apply for a Commercial (CDL) License»."},"22":{"q":"В Джорджии CDL класса C выдается специально для какого типа транспортного средства?","options":["Любого состава транспортных средств свыше 26,001 фунтов GCWR","Любого одиночного транспортного средства свыше 26,001 фунтов GVWR","Одиночного транспортного средства (или состава), не подпадающего под класс A или B, которое перевозит 16+ пассажиров, включая водителя, или имеет таблички для опасных материалов","Любого легкового автомобиля или пикапа массой менее 26,001 фунтов"],"explanation":"CDL класса C в Джорджии применяется к одиночному транспортному средству или составу, которое не подпадает под определение класса A или B, но рассчитано на перевозку 16 или более пассажиров (включая водителя) или используется для перевозки опасных материалов, требующих табличек. Источник: Georgia DDS, «Apply for a Commercial (CDL) License»."},"23":{"q":"Каков минимальный возраст для подачи заявления на любой CDL в Джорджии?","options":["18 лет","16 лет","21 год","25 лет"],"explanation":"Georgia DDS требует, чтобы заявители на CDL были в возрасте не менее 18 лет. Заявители в возрасте от 18 до 21 года ограничены внутриштатным (только в пределах Джорджии) вождением до достижения 21 года. Источник: Georgia DDS, «Apply for a Commercial (CDL) License»."},"24":{"q":"Каким образом ограничен 19-летний держатель CDL в Джорджии?","options":["Ограничен в получении любого эндорсмента","Ограничен внутриштатным (только в пределах Джорджии) вождением до достижения 21 года","Ограничен только транспортными средствами класса C","Ограничен в вождении ночью"],"explanation":"Джорджия выдает CDL заявителям от 18 лет и старше, но водители в возрасте от 18 до 21 года имеют ограничение «Georgia Only» (внутриштатное). Водитель должен достичь 21 года и посетить Центр обслуживания клиентов, чтобы снять ограничение для межштатного вождения. Источник: Georgia DDS, «Apply for a Commercial (CDL) License»."},"25":{"q":"Держатель CDL в Джорджии хочет снять ограничение только на внутриштатное вождение, чтобы иметь возможность ездить через границы штатов. Что должно произойти?","options":["Он должен сначала иметь CDL не менее пяти лет","Он должен достичь своего 21-го дня рождения и посетить Центр обслуживания клиентов DDS, чтобы снять ограничение «Georgia Only»","Он должен добавить эндорсмент HazMat","Он должен сдать дополнительный экзамен по межштатным навыкам в возрасте 18 лет"],"explanation":"Водители в возрасте от 18 до 21 года ограничены внутриштатным вождением. Чтобы получить право на межштатное вождение, водитель должен достичь 21 года и посетить Центр обслуживания клиентов DDS, чтобы снять ограничение «Georgia Only». Источник: Georgia DDS, «Apply for a Commercial (CDL) License»."},"26":{"q":"Какой эндорсмент требуется в Джорджии для управления транспортным средством, перевозящим опасные материалы в количествах, требующих табличек?","options":["Эндорсмент N (Цистерна)","Эндорсмент T (Двойные/Тройные прицепы)","Эндорсмент P (Пассажирский)","Эндорсмент H (HazMat)"],"explanation":"Эндорсмент H (HazMat) требуется для перевозки опасных материалов, требующих табличек. В Джорджии он требует сдачи теста на знания, проверки TSA и снятия отпечатков пальцев как при первичной выдаче, так и при продлении. Источник: Georgia DDS, «Adding CDL Endorsements»."},"27":{"q":"Какое дополнительное федеральное требование должно быть выполнено в Джорджии для эндорсмента HazMat (H), которое НЕ требуется для эндорсмента Цистерна (N)?","options":["Сдача отдельного экзамена по навыкам (вождению)","Владение эндорсментом в течение 14 дней до использования","Прохождение оценки угрозы безопасности TSA со снятием отпечатков пальцев","Получение пассажирского эндорсмента в первую очередь"],"explanation":"Эндорсмент HazMat требует прохождения проверки TSA (оценки угрозы безопасности), и отпечатки пальцев требуются как при первичной выдаче, так и при продлении. Эндорсмент Цистерна требует только теста на знания. Источник: Georgia DDS, «Adding CDL Endorsements»."},"28":{"q":"Согласно Georgia DDS, как получается эндорсмент N (Цистерна)?","options":["Путем сдачи как теста на знания, так и экзамена по навыкам","Путем сдачи только экзамена по навыкам","Путем сдачи только теста на знания","Путем прохождения только проверки TSA"],"explanation":"В Джорджии эндорсмент N (Цистерна) требует сдачи только теста на знания и действителен для CDL классов A и B. Источник: Georgia DDS, «Adding CDL Endorsements»."},"29":{"q":"Какой эндорсмент CDL в Джорджии действителен только для CDL класса A и получается путем сдачи теста на знания?","options":["Эндорсмент T (Двойные/Тройные прицепы)","Эндорсмент P (Пассажирский)","Эндорсмент S (Школьный автобус)","Эндорсмент N (Цистерна)"],"explanation":"Эндорсмент T (Двойные/Тройные прицепы) действителен только для CDL класса A и требует теста на знания. Его нельзя получить с Commercial Learner's Permit; заявитель должен уже иметь действующий CDL. Источник: Georgia DDS, «Adding CDL Endorsements»."},"30":{"q":"Что требует Джорджия для получения эндорсмента P (Пассажирский)?","options":["Сдачу только теста на знания","Сдачу как теста на знания, так и экзамена по навыкам","Сдачу только экзамена по навыкам","Прохождение только проверки TSA"],"explanation":"В Джорджии эндорсмент P (Пассажирский) требует сдачи как теста на знания, так и экзамена по навыкам, и действителен для CDL классов A, B и C. Источник: Georgia DDS, «Adding CDL Endorsements»."},"31":{"q":"Для каких двух эндорсментов Georgia DDS требует И теста на знания, И экзамена по навыкам?","options":["N (Цистерна) и T (Двойные/Тройные прицепы)","H (HazMat) и N (Цистерна)","P (Пассажирский) и S (Школьный автобус)","T (Двойные/Тройные прицепы) и H (HazMat)"],"explanation":"В Джорджии эндорсменты Пассажирский (P) и Школьный автобус (S) каждый требуют сдачи как теста на знания, так и экзамена по навыкам. Эндорсменты N, T и H требуют только теста на знания. Источник: Georgia DDS, «Adding CDL Endorsements»."},"32":{"q":"С 7 февраля 2022 года какая группа заявителей на CDL в Джорджии подпадает под требования обучения водителей начального уровня (ELDT)?","options":["Только заявители, желающие получить CDL класса C","Заявители, впервые получающие класс A или B, переходящие на более высокий класс или добавляющие эндорсмент Школьный автобус, Пассажирский или HazMat","Только водители старше 21 года","Только заявители, продлевающие существующий CDL без изменений"],"explanation":"Согласно правилам ELDT FMCSA, принятым Джорджией, начиная с 7 февраля 2022 года, все водители начального уровня, впервые получающие CDL класса A или B, переходящие на более высокий класс или добавляющие эндорсмент Школьный автобус (S), Пассажирский (P) или HazMat (H), должны пройти ELDT. Источник: Georgia DDS, «Apply for a Commercial (CDL) License» / «Adding CDL Endorsements»."},"33":{"q":"Где должно быть пройдено и зарегистрировано обучение водителей начального уровня (ELDT) для заявителя на CDL в Джорджии?","options":["В любой частной автошколе по выбору заявителя без регистрации","Только в Центре обслуживания клиентов Georgia DDS","Через онлайн-викторину без официального провайдера","У провайдера обучения, включенного в Реестр провайдеров обучения FMCSA (TPR)"],"explanation":"ELDT должно проводиться провайдером, включенным в Реестр провайдеров обучения FMCSA (TPR), и его завершение сообщается в реестр прежде, чем водитель сможет сдать экзамен по навыкам CDL или тест на знания HazMat. Источник: правила ELDT FMCSA, на которые ссылается Georgia DDS."},"34":{"q":"Прежде чем подать заявление на полный CDL в Джорджии, как долго заявитель должен владеть Commercial Learner Permit (CLP)?","options":["Не менее 30 дней","Не менее 60 дней","Не менее 14 дней","Не менее 6 месяцев"],"explanation":"Джорджия требует, чтобы заявители на CDL владели Commercial Learner Permit (CLP) минимум 14 дней, прежде чем сдавать экзамен по навыкам CDL / подавать заявление на полный CDL. Источник: Georgia DDS, «CDL Permit» и часто задаваемые вопросы по лицензированию CDL."},"35":{"q":"Что должен сдать заявитель в Джорджии, чтобы получить Commercial Learner Permit (CLP)?","options":["Требуемый письменный экзамен(ы) на знания","Только экзамен по навыкам CDL (вождению)","Проверку TSA","Только проверку зрения"],"explanation":"Чтобы получить CLP в Джорджии (класс AP или BP), заявитель должен иметь действующие обычные водительские права Джорджии и сдать требуемый письменный экзамен(ы) на знания. Экзамен по навыкам сдается позже, после 14-дневного периода ожидания. Источник: Georgia DDS, «Apply for a Commercial Permit (Class AP or BP)»."},"36":{"q":"Для CLP в Джорджии, выданного 1 июля 2021 года или позже, как долго действует разрешение?","options":["30 дней","180 дней","5 лет","365 дней"],"explanation":"Commercial Learner Permit (CLP) в Джорджии, выданное 1 июля 2021 года или позже, действительно в течение 365 дней. Источник: Georgia DDS, «CDL Permit»."},"37":{"q":"Что из следующего требуется, прежде чем человек сможет получить Commercial Learner Permit (CLP) в Джорджии?","options":["Наличие действующих обычных водительских прав Джорджии","Наличие уже имеющегося эндорсмента HazMat","Прохождение проверки TSA","Наличие CDL класса A"],"explanation":"Georgia DDS требует, чтобы заявители на CLP имели действующие обычные водительские права Джорджии, прежде чем подавать заявление на коммерческое разрешение. Источник: Georgia DDS, «Apply for a Commercial Permit (Class AP or BP)»."},"38":{"q":"При подаче заявления на CDL в Джорджии какую комбинацию документов DDS требует предоставить заявителю?","options":["Подтверждение личности, номер социального страхования, законное присутствие и два подтверждения проживания в Джорджии","Только карту социального страхования","Только карту регистрации избирателя Джорджии","Только паспорт, без подтверждения проживания"],"explanation":"Georgia DDS требует подтверждения личности (например, заверенное свидетельство о рождении или паспорт США), подтверждения номера социального страхования, подтверждения законного присутствия и двух документов из отдельных источников, подтверждающих проживание в Джорджии. Источник: Georgia DDS, «Apply for a Commercial (CDL) License»."},"39":{"q":"Водитель CDL в Джорджии, который работает только в пределах Джорджии и должен соответствовать требованиям FMCSA к квалификации водителя, должен выбрать какую категорию медицинской самосертификации?","options":["Non-excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","Non-excepted Intrastate (NA)"],"explanation":"Georgia DDS использует четыре категории самосертификации: Non-excepted Interstate (NI), Excepted Interstate (EI), Non-excepted Intrastate (NA) и Excepted Intrastate (EA). Водитель, работающий только в Джорджии (внутриштатно), который должен соответствовать медицинским требованиям к квалификации, выбирает Non-excepted Intrastate (NA). Все держатели CDL должны подать самосертификацию в DDS. Источник: Georgia DDS, «CDL Medical Certification and Self-Certification Process»."},"40":{"q":"Какова в Джорджии максимальная концентрация алкоголя в крови (BAC), при которой человек может законно управлять коммерческим транспортным средством (CMV)?","options":["Предел составляет 0.08 или выше","Это незаконно при 0.04 или выше","Предел составляет 0.10 или выше","Любое количество свыше 0.02 является незаконным"],"explanation":"Управлять CMV в Джорджии с BAC 0.04 или выше незаконно, что составляет половину предела 0.08 для некоммерческих водителей. Источник: Georgia CDL Manual (DDS), CDL Disqualifications; 49 CFR 383.51(b)."},"41":{"q":"Держатель CDL в Джорджии осужден за первое тяжкое правонарушение, такое как DUI в CMV, при этом НЕ перевозя опасные материалы. На какой срок дисквалифицируется CDL?","options":["Не менее 60 дней","Не менее 6 месяцев","Не менее 1 года","Не менее 3 лет"],"explanation":"Первое тяжкое правонарушение (DUI, BAC 0.04+, отказ, оставление места происшествия, использование CMV в преступных целях и т. д.) приводит к дисквалификации не менее чем на 1 год. Источник: Georgia CDL Manual (DDS); 49 CFR 383.51(b) Table 1."},"42":{"q":"Как изменяется срок дисквалификации, если водитель CDL в Джорджии совершает первое тяжкое правонарушение при управлении CMV, имеющим таблички для опасных материалов?","options":["Он увеличивается до минимум 3 лет","Он остается на уровне минимум 1 года","Он увеличивается до минимум 5 лет","Это приводит к немедленному пожизненному запрету"],"explanation":"Когда первое тяжкое правонарушение происходит при перевозке опасных материалов, требующих табличек, минимальная дисквалификация возрастает с 1 года до 3 лет. Источник: Georgia CDL Manual (DDS); 49 CFR 383.51(b) Table 1."},"43":{"q":"Каков срок дисквалификации для держателя CDL в Джорджии, осужденного за ВТОРОЕ тяжкое правонарушение в отдельном инциденте?","options":["Дополнительные 3 года","Дополнительные 10 лет","Дополнительные 120 дней","Пожизненная дисквалификация"],"explanation":"Второе осуждение за любую комбинацию тяжких правонарушений в отдельных инцидентах приводит к пожизненной дисквалификации CDL. Источник: Georgia CDL Manual (DDS); 49 CFR 383.51(b) Table 1."},"44":{"q":"Согласно закону Джорджии о подразумеваемом согласии, что происходит с держателем CDL, который отказывается пройти химический тест на алкоголь или наркотики после законного запроса?","options":["Ничего, поскольку отказ не может быть использован в качестве доказательства","Налагается только штраф, но CDL не затрагивается","Водитель дисквалифицируется так же, как если бы он был осужден за DUI","Водитель получает 60-дневное наказание за серьезное нарушение"],"explanation":"Отказ от химического теста рассматривается как тяжкое правонарушение, влекущее ту же дисквалификацию, что и осуждение за DUI: не менее 1 года за первое правонарушение и пожизненно за второе. Источник: Georgia CDL Manual (DDS); O.C.G.A. 40-5-67.1 (подразумеваемое согласие); 49 CFR 383.51(b)."},"45":{"q":"У водителя CDL в Джорджии обнаружено любое определяемое количество алкоголя ниже 0.04 во время несения службы. Каковы последствия?","options":["Предписание о выводе из эксплуатации, помещающее водителя вне службы на 24 часа","Немедленная дисквалификация CDL на 1 год","60-дневная дисквалификация за серьезное нарушение","Никаких последствий, поскольку BAC ниже 0.04"],"explanation":"Любое определяемое количество алкоголя ниже 0.04 не влечет дисквалификации за тяжкое правонарушение, но требует, чтобы водитель был выведен из эксплуатации на 24 часа. Источник: Georgia CDL Manual (DDS); 49 CFR 392.5."},"46":{"q":"Что из следующего классифицируется как «серьезное нарушение правил дорожного движения» для держателя CDL в Джорджии, а не как тяжкое правонарушение?","options":["Управление CMV с BAC 0.04 или выше","Использование CMV для совершения преступления","Чрезмерное превышение скорости на 15 миль/ч или более сверх установленного предела","Оставление места происшествия с участием CMV"],"explanation":"Чрезмерное превышение скорости (на 15+ миль/ч сверх предела) является серьезным нарушением правил дорожного движения. DUI, использование в преступных целях и наезд со скрытием — это тяжкие правонарушения с гораздо более суровыми наказаниями. Источник: Georgia CDL Manual (DDS); 49 CFR 383.51(c) Table 2."},"47":{"q":"Держатель CDL в Джорджии осужден за ДВА серьезных нарушения правил дорожного движения в отдельных инцидентах в течение 3-летнего периода. Каков срок дисквалификации?","options":["Не менее 30 дней","Не менее 60 дней","Не менее 120 дней","Не менее 1 года"],"explanation":"Два серьезных нарушения правил дорожного движения в течение 3 лет приводят к дисквалификации не менее чем на 60 дней. Источник: Georgia CDL Manual (DDS); 49 CFR 383.51(c) Table 2."},"48":{"q":"Держатель CDL в Джорджии осужден за ТРИ серьезных нарушения правил дорожного движения в отдельных инцидентах в течение 3-летнего периода. Каков срок дисквалификации?","options":["Не менее 60 дней","Не менее 90 дней","Не менее 120 дней","Не менее 1 года"],"explanation":"Три серьезных нарушения правил дорожного движения в течение 3 лет приводят к дисквалификации не менее чем на 120 дней. Источник: Georgia CDL Manual (DDS); 49 CFR 383.51(c) Table 2."},"49":{"q":"Что из этого НЕ считается серьезным нарушением правил дорожного движения, которое может привести к дисквалификации CDL в Джорджии?","options":["Слишком близкое следование за движущимся впереди транспортным средством","Неправильная или беспорядочная смена полосы движения","Безрассудное вождение","Парковка CMV на ночь в зоне отдыха"],"explanation":"Серьезные нарушения правил дорожного движения включают слишком близкое следование, неправильную смену полосы, безрассудное вождение и чрезмерное превышение скорости. Законная парковка в зоне отдыха не является нарушением. Источник: Georgia CDL Manual (DDS); 49 CFR 383.51(c) Table 2."},"50":{"q":"Каков срок дисквалификации для водителя CDL из Джорджии за ПЕРВОЕ осуждение за нарушение правил проезда железнодорожного переезда?","options":["Не менее 30 дней","Не менее 60 дней","Не менее 120 дней","Не менее 1 года"],"explanation":"Первое нарушение правил проезда железнодорожного переезда влечёт дисквалификацию не менее чем на 60 дней. Источник: Руководство CDL Джорджии (DDS); 49 CFR 383.51(d), Таблица 3."},"51":{"q":"Владелец CDL из Джорджии совершает ВТОРОЕ нарушение правил проезда железнодорожного переезда в течение 3-летнего периода. Какова минимальная дисквалификация?","options":["Не менее 60 дней","Не менее 120 дней","Не менее 6 месяцев","Не менее 1 года"],"explanation":"Второе нарушение правил проезда железнодорожного переезда в течение 3 лет влечёт дисквалификацию не менее чем на 120 дней. Источник: Руководство CDL Джорджии (DDS); 49 CFR 383.51(d), Таблица 3."},"52":{"q":"Владелец CDL из Джорджии совершает ТРЕТЬЕ нарушение правил проезда железнодорожного переезда в течение 3-летнего периода. Какова минимальная дисквалификация?","options":["Не менее 120 дней","Не менее 6 месяцев","Не менее 1 года","Пожизненная дисквалификация"],"explanation":"Третье или последующее нарушение правил проезда железнодорожного переезда в течение 3 лет влечёт дисквалификацию не менее чем на 1 год. Источник: Руководство CDL Джорджии (DDS); 49 CFR 383.51(d), Таблица 3."},"53":{"q":"Каков срок дисквалификации для водителя CDL из Джорджии за ПЕРВОЕ осуждение за нарушение предписания о выводе из эксплуатации (OOS), когда не задействованы опасные материалы или пассажиры?","options":["Не менее 60 дней","Не менее 90 дней","Не менее 180 дней","Не менее 2 лет"],"explanation":"Первое осуждение за нарушение предписания о выводе из эксплуатации влечёт дисквалификацию не менее чем на 180 дней (до 1 года). Источник: Руководство CDL Джорджии (DDS); 49 CFR 383.51(e), Таблица 4."},"54":{"q":"Владелец CDL из Джорджии осуждён за ВТОРОЕ нарушение предписания о выводе из эксплуатации в отдельных инцидентах в течение 10-летнего периода. Какова минимальная дисквалификация?","options":["Не менее 180 дней","Не менее 1 года","Не менее 2 лет","Пожизненная дисквалификация"],"explanation":"Второе нарушение предписания о выводе из эксплуатации в течение 10-летнего периода влечёт дисквалификацию не менее чем на 2 года (до 5 лет). Источник: Руководство CDL Джорджии (DDS); 49 CFR 383.51(e), Таблица 4."},"55":{"q":"Как меняется наказание за ПЕРВОЕ нарушение предписания о выводе из эксплуатации, если водитель CDL из Джорджии перевозил опасные материалы с табличками или 16 и более пассажиров?","options":["Оно сокращается до 60 дней","Минимум остаётся 180 дней, но максимум возрастает до 2 лет","Оно становится пожизненной дисквалификацией","Оно не меняется и составляет от 180 дней до 1 года"],"explanation":"За первое нарушение OOS при перевозке опасных материалов с табличками или 16 и более пассажиров дисквалификация составляет не менее 180 дней, но до 2 лет, что является большим максимумом, чем в стандартном случае. Источник: Руководство CDL Джорджии (DDS); 49 CFR 383.51(e), Таблица 4."},"56":{"q":"Согласно закону Джорджии о Super Speeder (O.C.G.A. 40-6-189), при каких скоростях водитель классифицируется как «Super Speeder»?","options":["65 миль/ч на любой дороге или 75 миль/ч на двухполосной дороге","75 миль/ч на двухполосной дороге или 85 миль/ч на любой дороге или шоссе","80 миль/ч на двухполосной дороге или 90 миль/ч на межштатной автомагистрали","15 миль/ч или более сверх любого установленного ограничения скорости"],"explanation":"Закон Джорджии о Super Speeder классифицирует как Super Speeder водителя, осуждённого за движение со скоростью 75 миль/ч или более на двухполосной дороге, либо 85 миль/ч или более на любой дороге или шоссе. Источник: O.C.G.A. 40-6-189."},"57":{"q":"Согласно закону Джорджии о Super Speeder, какой дополнительный сбор штата взимает Департамент услуг водителям (DDS) с осуждённого Super Speeder, и что происходит, если он не оплачен?","options":["Сбор $200; приостановка действия прав, если не оплачен в течение 120 дней с момента уведомления","Сбор $500; тюремное заключение, если не оплачен в течение 30 дней","Сбор $100; письмо-предупреждение, если не оплачен в течение 90 дней","Сбор $200 без дальнейших последствий за неуплату"],"explanation":"Закон о Super Speeder добавляет сбор штата в размере $200 сверх любых судебных штрафов. Если он не оплачен в течение 120 дней с момента уведомления DDS, действие водительских прав приостанавливается и применяется сбор за восстановление в размере $50. Источник: O.C.G.A. 40-6-189."},"58":{"q":"Согласно федеральным правилам, которые применяет Джорджия, что происходит с водителем CDL, осуждённым за набор текста или использование телефона в руке при управлении CMV?","options":["Это не влечёт наказания конкретно для владельцев CDL","Это автоматическая дисквалификация на 1 год за тяжкое правонарушение","Это засчитывается как серьёзное нарушение ПДД для целей дисквалификации","Это влечёт немедленную пожизненную дисквалификацию"],"explanation":"Набор текста или использование телефона в руке при управлении CMV является серьёзным нарушением ПДД; два таких нарушения в течение 3 лет влекут дисквалификацию на 60 дней, а три — на 120 дней. Источник: 49 CFR 383.51(c); Руководство CDL Джорджии (DDS)."},"59":{"q":"Закон Джорджии Hands-Free (O.C.G.A. 40-6-241) распространяется на всех водителей. Какое действие он запрещает при управлении транспортным средством, включая CMV?","options":["Использование громкой связи или соединения hands-free через Bluetooth","Физическое удержание или поддержку телефона любой частью тела","Наличие установленного GPS-устройства, видимого на лобовом стекле","Разговор с пассажиром, сидящим в транспортном средстве"],"explanation":"Закон Hands-Free Georgia Act запрещает водителям держать или поддерживать телефон или электронное устройство любой частью тела; использование hands-free, например Bluetooth или громкой связи, остаётся разрешённым. Источник: O.C.G.A. 40-6-241."},"60":{"q":"На межштатной автомагистрали Джорджии с двумя или более полосами в вашем направлении вы приближаетесь к стоящему на обочине подразделению HERO с мигающими янтарными огнями. Чего требует от коммерческого водителя закон Джорджии Move Over Law?","options":["Сохранять установленное ограничение скорости, поскольку подразделение находится вне проезжей части на обочине","Полностью остановиться на своей полосе и ждать, пока подразделение не сдвинется, прежде чем продолжить движение","Перестроиться на одну полосу в сторону от подразделения, если это безопасно; если вы не можете безопасно сменить полосу, снизить скорость ниже установленного ограничения и быть готовым остановиться","Перестраиваться только для полицейских и пожарных машин, поскольку подразделения HERO и коммунальных служб не охватываются"],"explanation":"Закон Джорджии Move Over Law (O.C.G.A. §40-6-16) требует, чтобы водители на дорогах с двумя или более полосами в одном направлении перестраивались на одну полосу в сторону от стоящего подразделения экстренных служб, коммунальных служб, эвакуации/восстановления, дорожного обслуживания, санитарной службы или HERO с мигающими огнями. Если смену полосы нельзя выполнить безопасно, водитель должен снизить скорость ниже установленного ограничения и быть готовым остановиться."},"61":{"q":"Закон Джорджии Move Over Law применяется к стоящим транспортным средствам с мигающими огнями. Какое из следующих транспортных средств НЕ охватывается O.C.G.A. §40-6-16?","options":["Подразделение HERO (Highway Emergency Response Operator), помогающее неисправному транспортному средству","Коммунальный сервисный автомобиль, ремонтирующий линии электропередачи, с мигающими янтарными огнями","Легковой автомобиль, остановившийся на обочине с включённой штатной аварийной сигнализацией (четырёхсторонней сигнализацией) после прокола шины","Эвакуатор, восстанавливающий разбитое транспортное средство, с мигающими янтарными огнями"],"explanation":"O.C.G.A. §40-6-16 защищает стоящие подразделения экстренных служб, эвакуации/восстановления, дорожного обслуживания, коммунальных служб, санитарной службы и HERO с мигающими огнями. Обычный легковой автомобиль, использующий только штатную четырёхстороннюю аварийную сигнализацию, не относится к защищённым категориям транспортных средств в рамках Move Over Law."},"62":{"q":"Согласно закону Hands-Free Georgia Act (O.C.G.A. §40-6-241), какое дополнительное ограничение применяется именно к водителю, управляющему коммерческим транспортным средством на шоссе Джорджии?","options":["Водитель может вручную набирать текст, пока транспортное средство движется со скоростью менее 15 миль/ч","Водитель может использовать не более одной кнопки на беспроводном устройстве для начала или завершения голосового вызова","Водитель может держать телефон у уха, если вызов связан с работой","Водитель полностью освобождён от действия Hands-Free Act, находясь на службе"],"explanation":"Согласно O.C.G.A. §40-6-241, при управлении коммерческим транспортным средством ни один водитель не может использовать более одной кнопки на беспроводном телекоммуникационном устройстве для начала или завершения голосовой связи, а также тянуться к устройству таким образом, что требуется покинуть сидячее положение для вождения. Удержание или поддержка устройства любой частью тела запрещены для всех водителей."},"63":{"q":"Какое устройство или действие разрешено согласно закону Hands-Free Georgia Act (O.C.G.A. §40-6-241) при управлении коммерческим транспортным средством в Джорджии?","options":["Удержание смартфона в руке для чтения текстового сообщения","Использование коммерческой двусторонней радиосвязи или CB-радио для связи","Просмотр видео на планшете, установленном на приборной панели","Удержание мобильного телефона на плече у уха во время вызова"],"explanation":"O.C.G.A. §40-6-241 прямо исключает коммерческие двусторонние радиостанции, CB-радио, любительские/радиолюбительские станции, устройства экстренной связи по подписке, предписанные медицинские устройства и заводские навигационные/диагностические системы. Удержание или поддержка телефона любой частью тела, ручной набор текста и просмотр видео — всё это запрещено."},"64":{"q":"Вы ведёте тягач с прицепом в крайней левой полосе обгона на межштатной автомагистрали Джорджии и замечаете более быстрое транспортное средство, приближающееся сзади. Согласно закону Джорджии о левой полосе / «Slowpoke» (O.C.G.A. §40-6-184), что вы должны сделать?","options":["Сохранять своё положение в полосе обгона, пока вы движетесь со скоростью на уровне установленного ограничения или выше","Ускориться до скорости обгоняющего транспортного средства, чтобы ему больше не нужно было обгонять","Закон не применяется к коммерческим транспортным средствам, поэтому вы можете оставаться в левой полосе","Уйти из полосы обгона, чтобы пропустить обгоняющее транспортное средство, если только состояние дороги, движение, погода или средство управления движением не требуют оставаться там"],"explanation":"Закон Джорджии «Slowpoke» (O.C.G.A. §40-6-184) требует, чтобы водитель в полосе обгона (крайней левой полосе, кроме полосы HOV) перестроился, как только он узнаёт или должен узнать, что его обгоняет сзади более быстрое транспортное средство, если только состояние дороги/движения, погода, опасности или средство управления движением не требуют оставаться в этой полосе. Это применяется независимо от того, движетесь ли вы со скоростью установленного ограничения."},"65":{"q":"Для целей закона Джорджии о левой полосе / «Slowpoke» (O.C.G.A. §40-6-184), как определяется «полоса обгона»?","options":["Крайняя левая полоса, кроме полосы для транспортных средств с высокой заполняемостью (HOV)","Любая полоса, в которой транспортное средство в данный момент обгоняет другое","Полоса, ближайшая к правой обочине","Только центральная полоса трёхполосной дороги"],"explanation":"O.C.G.A. §40-6-184 определяет «полосу обгона» как крайнюю левую полосу, кроме полосы для транспортных средств с высокой заполняемостью (HOV). Водитель не должен продолжать движение в этой полосе, как только его обгоняет сзади более быстрое транспортное средство."},"66":{"q":"Согласно O.C.G.A. §40-6-52, «грузовик» (любое транспортное средство с более чем шестью колёсами, кроме автобусов и междугородних автобусов) на дороге Джорджии с тремя или более полосами в одном направлении, как правило, может двигаться в каких полосах?","options":["В любой полосе, пока он движется в потоке транспорта","Только в одной крайней правой полосе во всех случаях","Только в двух крайних правых полосах, за исключением случаев подготовки к левому повороту или там, где полосы обозначены иначе","Только в центральных полосах, оставляя правую полосу открытой для въезжающего транспорта"],"explanation":"O.C.G.A. §40-6-52 объявляет незаконным для грузовика (транспортного средства с более чем шестью колёсами, кроме автобусов и междугородних автобусов) на дороге с тремя или более полосами в одном направлении движение в любой полосе, кроме двух крайних правых, за исключением случаев подготовки к левому повороту или там, где Департамент транспорта обозначил другие полосы."},"67":{"q":"На шоссе Джорджии с ровно двумя полосами в вашем направлении, когда грузовик, подпадающий под O.C.G.A. §40-6-52, может на законных основаниях использовать левую полосу?","options":["Когда правая полоса более загружена, чем левая","При фактическом обгоне и проезде мимо другого транспортного средства или подготовке к левому повороту","Только между восходом и заходом солнца","Никогда, ни при каких обстоятельствах"],"explanation":"Согласно O.C.G.A. §40-6-52, на дороге с двумя полосами в одном направлении грузовику незаконно двигаться в левой полосе, за исключением случаев фактического обгона и проезда мимо другого транспортного средства, подготовки к левому повороту или иных случаев, предусмотренных законом."},"68":{"q":"Какое максимальное ограничение скорости устанавливает O.C.G.A. §40-6-181 для любого транспортного средства, включая тягач с прицепом, на межштатной автомагистрали Джорджии там, где это обозначено?","options":["55 миль в час","65 миль в час","75 миль в час","70 миль в час"],"explanation":"O.C.G.A. §40-6-181 устанавливает максимальное ограничение в 70 миль/ч на шоссе, входящих в федеральную межштатную систему, и на физически разделённых государственных шоссе с полным контролем доступа там, где это обозначено знаками. Джорджия не устанавливает отдельного, более низкого общегосударственного ограничения скорости для грузовиков; установленный максимум применяется ко всем транспортным средствам."},"69":{"q":"Тяжёлые транзитные грузовики, движущиеся по I-75, I-85 или I-20 в сторону Атланты, как правило, обязаны делать что согласно правилам маршрутизации грузовиков в Атланте, действующим в Джорджии?","options":["Использовать соединитель центра города I-75/I-85 (Downtown Connector) только в светлое время суток","Двигаться только в полосах HOV через центр Атланты","Останавливаться на государственной весовой станции перед въездом на I-285","Объезжать город по I-285, если только они не осуществляют погрузку/доставку, не направляются к терминалу или ремонтному предприятию, либо к месту жительства водителя внутри периметра"],"explanation":"Грузовики, проезжающие через Атланту (а не в неё), должны двигаться по I-285 в объезд города, а не по соединителю центра города I-75/I-85 (Downtown Connector). Исключения существуют для грузовиков, осуществляющих погрузку или доставку грузоотправителю внутри I-285, направляющихся к/от терминала или ремонтного предприятия внутри I-285, либо для водителя, направляющегося к/от места жительства внутри периметра. Это хорошо обозначенное и контролируемое ограничение на транзитный проезд грузовиков."},"70":{"q":"На соединителе центра города Атланты I-75/I-85 (Downtown Connector) внутренние (крайние левые) полосы зарезервированы как полосы HOV. Что это означает для водителя коммерческого грузовика?","options":["Грузовик должен держаться вне полосы HOV и, из-за ограничений по использованию полос, как правило, оставаться в правых полосах","Грузовик может использовать полосу HOV в любое время, когда он перевозит более 6 000 фунтов груза","Грузовик может использовать полосу HOV, если платит сбор, как на полосе HOT","Грузовик может использовать полосу HOV, потому что коммерческие транспортные средства всегда считаются высокозаполненными"],"explanation":"Внутренние полосы соединителя центра города I-75/I-85 (Downtown Connector) ограничены для HOV. Груз не является пассажиром, поэтому грузовик не квалифицируется как транспортное средство с высокой заполняемостью, и согласно O.C.G.A. §40-6-52 грузовики должны использовать правые полосы. Полосы HOV в Джорджии требуют минимального числа пассажиров, а не веса груза."},"71":{"q":"Какие коммерческие транспортные средства обязаны ОСТАНАВЛИВАТЬСЯ на каждом железнодорожном переезде согласно Руководству CDL Джорджии?","options":["Автобусы, перевозящие пассажиров, и транспортные средства с табличками опасных материалов","Все коммерческие транспортные средства весом более 26 001 фунта независимо от груза","Только пустые грузовые цистерны, никогда загруженные","Любой грузовик, тянущий двойной или тройной прицеп"],"explanation":"Согласно Руководству CDL Джорджии (и 49 CFR 392.10), коммерческие транспортные средства, которые всегда должны останавливаться на железнодорожных переездах, — это автобусы, перевозящие пассажиров, и транспортные средства с табличками опасных материалов. Сюда также относятся транспортные средства, перевозящие любое количество хлора, и грузовые цистерны, используемые для опасных материалов, как загруженные, так и пустые."},"72":{"q":"Когда транспортное средство с табличками HazMat или пассажирский автобус обязаны остановиться на железнодорожном переезде в Джорджии, где они должны остановиться?","options":["Точно в 25 футах от ближайшего рельса","В пределах 50 футов, но не ближе 15 футов от ближайшего рельса","Не менее чем в 100 футах от ближайшего рельса","В любом месте в пределах 10 футов от шлагбаума переезда"],"explanation":"Руководство CDL Джорджии указывает, что обязательная остановка на железнодорожном переезде должна быть сделана не более чем в 50 футах и не менее чем в 15 футах от ближайшего рельса. Водитель должен посмотреть и прислушаться, нет ли поезда, а затем пересекать переезд только тогда, когда можно полностью освободить пути без остановки."},"73":{"q":"Согласно Руководству CDL Джорджии, что коммерческий водитель НЕ должен делать при пересечении железнодорожных путей?","options":["Использовать достаточно низкую передачу, чтобы пересечь без переключения передач","Переключать передачи, пока какая-либо часть транспортного средства находится на путях","Смотреть и прислушиваться к приближающемуся поезду перед началом пересечения","Убедиться, что есть место для полного освобождения путей перед началом пересечения"],"explanation":"Руководство CDL Джорджии предупреждает водителей никогда не переключать передачи при пересечении железнодорожных путей, поскольку транспортное средство может заглохнуть на переезде. Водитель должен выбрать передачу, позволяющую пересечь переезд без переключения, и убедиться, что достаточно места для полного освобождения путей перед началом пересечения."},"74":{"q":"Согласно O.C.G.A. §40-6-163, когда водитель коммерческого транспортного средства обязан остановиться перед остановившимся школьным автобусом с включёнными мигающими красными огнями и выдвинутым знаком «стоп»?","options":["Только при движении в том же направлении, что и автобус, никогда — навстречу","Только если дети явно присутствуют у обочины","При встрече с автобусом или его обгоне с любого направления на неразделённой дороге, пока автобус не возобновит движение или сигналы не отключатся","Только на двухполосных дорогах, никогда — на дорогах с четырьмя и более полосами"],"explanation":"O.C.G.A. §40-6-163 требует, чтобы водитель транспортного средства, встречающего или обгоняющего с любого направления школьный автобус, остановившийся на дороге с включёнными визуальными сигналами (мигающими красными огнями/знаком «стоп»), остановился, не доезжая до автобуса, и не продолжал движение, пока автобус не возобновит движение или сигналы не будут отключены, — на неразделённых дорогах."},"75":{"q":"Согласно закону Джорджии о школьных автобусах (O.C.G.A. §40-6-163), на каком типе дороги встречный водитель НЕ обязан останавливаться перед школьным автобусом, забирающим детей на противоположной стороне?","options":["Четырёхполосная дорога, где единственным разделителем является нарисованная осевая линия","Дорога, разделённая только двусторонней центральной полосой для поворотов","Любая дорога с двумя или более полосами в каждом направлении","Шоссе с раздельными проезжими частями, разделёнными травяной разделительной полосой, немощёным участком или физическим барьером"],"explanation":"O.C.G.A. §40-6-163 предусматривает, что водитель на шоссе с раздельными проезжими частями, разделёнными травяной разделительной полосой, немощёным участком или физическим барьером, не обязан останавливаться перед школьным автобусом на другой раздельной проезжей части. Нарисованная линия или центральная полоса для поворотов разделителем НЕ являются, поэтому в таких случаях водители всё равно должны останавливаться."},"76":{"q":"Дорога имеет две полосы в каждом направлении, разделённые только двусторонней центральной полосой для поворотов (без разделительной полосы или барьера). Школьный автобус на противоположной стороне останавливается с мигающими красными огнями. Согласно O.C.G.A. §40-6-163, что должен сделать встречный коммерческий водитель?","options":["Остановиться, потому что центральная полоса для поворотов не является разделительной полосой или физическим барьером, разделяющим проезжие части","Продолжить движение со сниженной скоростью, потому что полоса для поворотов считается разделителем","Остановиться, только если автобус находится в собственном направлении движения водителя","Продолжить движение как обычно, потому что встречный транспорт никогда не останавливается перед школьными автобусами"],"explanation":"Согласно O.C.G.A. §40-6-163, исключение для разделённого шоссе применяется только к проезжим частям, разделённым травяной разделительной полосой, немощёным участком или физическим барьером. Центральная двусторонняя полоса для поворотов и нарисованные линии не подходят, поэтому встречный водитель должен остановиться перед школьным автобусом с включёнными сигналами."},"77":{"q":"Согласно Руководству CDL Джорджии, где водитель грузовика должен разместить три обязательных аварийных предупредительных устройства (светоотражающие треугольники) на двухполосной двусторонней дороге после остановки на обочине?","options":["Все три непосредственно позади транспортного средства в пределах 10 футов от заднего бампера","Один на крыше и два на переднем бампере","Примерно в 10 футах позади транспортного средства в сторону движения, примерно в 100 футах позади и примерно в 100 футах впереди транспортного средства","Примерно в 500 футах позади и 500 футах впереди, ни одного рядом с транспортным средством"],"explanation":"Руководство CDL Джорджии требует размещения предупредительных устройств в течение 10 минут: одно примерно в 10 футах (4 шага) от транспортного средства в сторону приближающегося транспорта, одно примерно в 100 футах (40 шагов) позади и одно примерно в 100 футах (40 шагов) впереди. На холмах или поворотах заднее устройство отодвигается дальше назад, чтобы обеспечить достаточное предупреждение."},"78":{"q":"Согласно Руководству CDL Джорджии, какова правильная техника спуска по длинному крутому горному уклону в Северной Джорджии для предотвращения отказа тормозов из-за перегрева?","options":["Выбрать низкую передачу перед спуском и использовать лёгкое равномерное торможение методом «snub» (нажать, затем отпустить) на безопасной скорости","Оставаться на высокой передаче и непрерывно держать тормоза нажатыми, чтобы сохранять низкую скорость","Переключиться на нейтраль для экономии топлива и контролировать скорость только тормозами","Быстро нажимать на тормоза с одновременным ускорением, чтобы двигатель оставался тёплым"],"explanation":"Руководство CDL Джорджии предписывает водителям выбирать безопасную скорость и низкую передачу ДО начала спуска по крутому уклону, полагаясь на торможение двигателем, и использовать технику торможения «snub» (нажать с усилием, чтобы снизить скорость примерно на 5 миль/ч, затем отпустить). Держание тормозов нажатыми или движение накатом на нейтрали приводит к отказу тормозов из-за перегрева и потере управления."},"79":{"q":"На крутом спуске в Северной Джорджии ваши тормоза перегрелись и отказали, и грузовик набирает скорость. Руководство CDL Джорджии советует, что наилучшим действием будет:","options":["Съехать на мощёную правую обочину и сильно затянуть стояночный тормоз","Свернуть на встречную полосу, чтобы найти свободную полосу","Выключить двигатель, чтобы быстро замедлить транспортное средство","Использовать аварийную тормозную полосу (escape ramp), если она имеется, поскольку она предназначена для безопасной остановки потерявшего управление транспортного средства"],"explanation":"Руководство CDL Джорджии объясняет, что аварийные тормозные полосы (escape ramps), построенные на многих крутых горных спусках с насыпями из рыхлого материала (и часто с подъёмом), предназначены для безопасной остановки потерявших управление транспортных средств. Если ваши тормоза отказывают на спуске, использование имеющейся аварийной тормозной полосы — самое безопасное действие; выключение двигателя или использование стояночного тормоза на скорости может привести к потере управления."},"80":{"q":"В Джорджии какое государственное ведомство выдаёт коммерческие водительские права (CDL) и проводит тестирование CDL?","options":["Регистрационное подразделение Департамента общественной безопасности Джорджии","Департамент транспортных средств Джорджии (DMV)","Бюро расследований Джорджии","Департамент услуг водителям Джорджии (DDS)"],"explanation":"В Джорджии нет «DMV». Департамент услуг водителям Джорджии (DDS) — это государственное ведомство, которое выдаёт все CDL и проводит тестирование знаний и навыков CDL. Источник: GA DDS, страницы программы Commercial License (CDL) (dds.georgia.gov)."},"81":{"q":"Сколько документов, подтверждающих ваш адрес проживания в Джорджии, вы должны принести в GA DDS при подаче заявления на CDL?","options":["Документы о проживании для CDL не требуются","Четыре документа с вашим адресом проживания в Джорджии","Два документа с вашим текущим адресом проживания в Джорджии","Один документ с вашим адресом проживания в Джорджии"],"explanation":"GA DDS требует, чтобы заявители предоставили два приемлемых документа (например, счета за коммунальные услуги, выписки по ипотеке или государственные документы), в которых указан их текущий адрес проживания в Джорджии. Источник: GA DDS, «Apply for a Commercial (CDL) License» (dds.georgia.gov)."},"82":{"q":"Какой набор документов требует GA DDS для подтверждения личности, номера социального страхования и законного статуса для CDL?","options":["Только карточку регистрации избирателя Джорджии","Только регистрацию транспортного средства на ваше имя","Только подписанное заявление о месте жительства без других доказательств","Подтверждение личности, ваш полный номер социального страхования и подтверждение гражданства США или законного пребывания"],"explanation":"GA DDS требует подтверждение личности (например, свидетельство о рождении США, паспорт или свидетельство о натурализации), проверку вашего полного номера социального страхования в форме License/ID/Permit, а также документацию о гражданстве США или законном пребывании, в дополнение к двум документам о проживании в Джорджии. Источник: GA DDS, требования к заявлению на CDL (dds.georgia.gov)."},"83":{"q":"Перед сдачей теста на навыки CDL (вождение по дороге) в Джорджии, как долго водитель должен владеть коммерческим учебным/инструкторским разрешением (CLP)?","options":["Не менее 30 дней","Не менее 60 дней","Не менее 14 дней","Минимального срока владения нет"],"explanation":"GA DDS требует, чтобы заявитель на CDL владел коммерческим инструкторским разрешением (CLP) не менее 14 дней перед подачей заявления и сдачей полного теста на навыки CDL. Это отражает федеральный 14-дневный срок владения. Источник: GA DDS, страница CDL Permit (dds.georgia.gov)."},"84":{"q":"Что должен завершить впервые подающий заявление на CDL класса A или класса B в Джорджии, прежде чем ему будет разрешено сдавать тест на навыки CDL?","options":["Курс безопасного вождения в любой частной автошколе","Пять лет подтверждённого стажа некоммерческого вождения","Сертификат уровня колледжа по логистике","Подготовку водителей начального уровня (ELDT) у поставщика, включённого в Реестр поставщиков обучения FMCSA"],"explanation":"Согласно федеральным правилам ELDT, применяемым GA DDS, впервые подающие заявление на CDL класса A и класса B (с CLP, полученным 7 февраля 2022 года или позже) должны пройти подготовку водителей начального уровня (ELDT) у поставщика, зарегистрированного в Реестре поставщиков обучения FMCSA, перед сдачей теста на навыки. Источник: страницы CDL GA DDS и Реестр поставщиков обучения FMCSA (tpr.fmcsa.dot.gov)."},"85":{"q":"Как долго действует стандартный (не HazMat) CDL Джорджии до того, как его необходимо продлить?","options":["До 4 лет","До 2 лет","До 10 лет","До 8 лет"],"explanation":"Стандартный CDL Джорджии действителен до 8 лет. CDL с подтверждением на перевозку опасных материалов (H) действительны более короткий срок (5 лет) из-за необходимости продления проверки биографических данных. Источник: GA DDS, «Renew a CDL» (dds.georgia.gov)."},"86":{"q":"Какие четыре категории самосертификации должен выбрать владелец CDL Джорджии?","options":["Класс A, Класс B, Класс C, Класс D","Местный, Региональный, Национальный, Международный","Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate, Excepted Intrastate","Дневной, Ночной, Hazmat, Пассажирский"],"explanation":"Каждый владелец CDL Джорджии должен самостоятельно сертифицировать один из четырёх типов деятельности: Non-excepted Interstate (NI), Excepted Interstate (EI), Non-excepted Intrastate (NA) и Excepted Intrastate (EA). Водители категории Non-excepted должны иметь действительный медицинский сертификат DOT. Источник: GA DDS, «CDL Medical Certification and Self-Certification Process» (dds.georgia.gov)."},"87":{"q":"Какая категория самосертификации требует, чтобы владелец CDL Джорджии имел действительный медицинский сертификат экзаменатора DOT?","options":["Excepted Interstate (EI)","Ни одна категория не требует медицинского сертификата","Non-excepted Interstate (NI)","Excepted Intrastate (EA)"],"explanation":"Водители категорий Non-excepted (Non-excepted Interstate и Non-excepted Intrastate) должны иметь действительный медицинский сертификат экзаменатора DOT. Категории Excepted (EI и EA) его не требуют. Источник: GA DDS, процесс CDL Medical и Self-Certification (dds.georgia.gov)."},"88":{"q":"Согласно мандату FMCSA, вступившему в силу 18 июня 2025 года, как медицинский сертификат экзаменатора DOT владельца CDL Джорджии передаётся в DDS?","options":["Электронно из Национального реестра FMCSA; DDS больше не принимает бумажные медсертификаты","Путём отправки факсом в штаб-квартиру DDS в течение 10 дней","Путём отправки бумажной копии по почте в ближайший Центр обслуживания клиентов DDS","Путём отправки сканированной копии по электронной почте личному куратору DDS"],"explanation":"С 18 июня 2025 года медицинские сертификаты передаются в GA DDS электронно через FMCSA посредством Национального реестра сертифицированных медицинских экзаменаторов. DDS больше не принимает медсертификаты по почте, факсу, электронной почте, онлайн или лично. Водитель должен просто обратиться к экзаменатору из Национального реестра и поддерживать сертификацию актуальной. Источник: пресс-релиз GA DDS и страница CDL Med Cert (dds.georgia.gov)."},"89":{"q":"Кто должен проводить медицинский осмотр для водителя CDL Джорджии, который обязан иметь медицинский сертификат DOT?","options":["Сотрудник Центра обслуживания клиентов DDS","Любой хиропрактик независимо от сертификации","Медицинский экзаменатор, включённый в Национальный реестр сертифицированных медицинских экзаменаторов FMCSA","Любой фармацевт в лицензированной аптеке Джорджии"],"explanation":"Водители CDL Джорджии, которым требуется медицинская сертификация, должны проходить осмотр у медицинского экзаменатора, включённого в Национальный реестр сертифицированных медицинских экзаменаторов FMCSA. Затем этот экзаменатор передаёт сертификат электронно. Источник: GA DDS, процесс CDL Medical Certification (dds.georgia.gov)."},"90":{"q":"Какие три компонента составляют тест на навыки CDL Джорджии?","options":["Погрузка груза, тест на экономию топлива и экзамен по математике","Письменный экзамен по законам, проверка зрения и собеседование о личных качествах","Обращение с Hazmat, обслуживание клиентов и тест на печать","Предрейсовый осмотр транспортного средства, базовые навыки управления и тест вождения по дороге"],"explanation":"Тест на навыки CDL Джорджии состоит из трёх частей, проводимых по порядку: предрейсовый осмотр транспортного средства, базовые навыки управления транспортным средством и тест вождения по дороге. Все три необходимо сдать для получения CDL. Источник: Руководство CDL GA DDS и страницы Road Test (dds.georgia.gov)."},"91":{"q":"При сдаче теста на навыки CDL (вождение по дороге) в Джорджии, кто несёт ответственность за предоставление тестового транспортного средства?","options":["Транспортное средство не нужно; тест на навыки проводится только на симуляторе","FMCSA доставляет федеральный тестовый грузовик на место","GA DDS предоставляет автопарковое транспортное средство каждому заявителю","Заявитель должен предоставить подходящее транспортное средство, прошедшее проверку безопасности DDS"],"explanation":"Заявитель должен привезти подходящее транспортное средство для класса CDL, по которому проводится тестирование, вместе с подтверждением регистрации и действующей страховкой, и транспортное средство должно пройти проверку безопасности DDS перед тестом вождения по дороге. Источник: GA DDS, страница Road Test (dds.georgia.gov)."},"92":{"q":"Каков минимальный возраст для подачи заявления на CDL в Джорджии, и какое ограничение применяется до определённого возраста?","options":["21 год, без необходимости разрешения","16 лет, вообще без ограничений","18 лет, с ограничением только внутриштатных перевозок до 21 года","25 лет, с запретом на межштатное вождение навсегда"],"explanation":"В Джорджии вы можете подать заявление на CDL в 18 лет, но водители в возрасте от 18 до 21 года, как правило, ограничены внутриштатными (в пределах штата) коммерческими перевозками до своего 21-го дня рождения. Источник: GA DDS, страницы заявления на CDL и разрешения (dds.georgia.gov)."},"93":{"q":"Как долго действует коммерческое учебное разрешение Джорджии (CLP), выданное 1 июля 2021 года или позже?","options":["90 дней","Бессрочно, до выдачи CDL","30 дней","365 дней (один год)"],"explanation":"CLP Джорджии, выданное 1 июля 2021 года или позже, действительно 365 дней (один год). Водитель всё равно должен владеть им не менее 14 дней перед тестом на навыки. Источник: GA DDS, страница CDL Permit (dds.georgia.gov)."},"94":{"q":"Когда требуется коммерческое инструкторское разрешение (CLP) в процессе получения CDL в Джорджии?","options":["При подаче заявления на новый CDL, повышении категории CDL или добавлении определённых подтверждений","Только после того, как CDL уже выдан","Никогда; Джорджия выдаёт CDL без какого-либо этапа разрешения","Только для водителей, переоформляющих права из другой страны"],"explanation":"GA DDS требует коммерческое инструкторское разрешение (CLP) при подаче заявления на новый CDL, повышении категории существующего CDL или добавлении определённых подтверждений, требующих теста на навыки. CLP должно быть на руках 14 дней перед тестом на навыки. Источник: GA DDS, страница CDL Permit (dds.georgia.gov)."},"95":{"q":"Для впервые получаемого подтверждения на перевозку опасных материалов (H) в Джорджии, когда должна быть завершена подготовка ELDT?","options":["Только после того, как проверка биографических данных TSA отклонена","Перед тем как будет разрешено сдавать тест на знания по HazMat","ELDT никогда не требуется для подтверждения HazMat","Только после сдачи теста на знания по HazMat"],"explanation":"Поскольку подтверждение HazMat не имеет теста на навыки, теоретическая подготовка ELDT для впервые подающих заявление на H должна быть завершена до того, как заявителю будет разрешено сдавать тест на знания по HazMat. Источник: Реестр поставщиков обучения FMCSA / ELDT Applicability (tpr.fmcsa.dot.gov) и страницы CDL GA DDS."},"96":{"q":"Какие подтверждения требуют от впервые подающих заявление в Джорджии завершить ELDT перед тестированием?","options":["Только цистерна (N), двойные/тройные прицепы (T) и снятие ограничения на воздушные тормоза","Только снятие ограничения на воздушные тормоза","Никакие подтверждения никогда не требуют ELDT","Подтверждения школьного автобуса (S), пассажирское (P) и опасных материалов (H)"],"explanation":"Согласно федеральным правилам ELDT, применяемым GA DDS, впервые подающие заявление на подтверждения школьного автобуса (S), пассажирское (P) и опасных материалов (H) должны завершить ELDT у зарегистрированного поставщика перед сдачей соответствующего теста на навыки или знания. Источник: Реестр поставщиков обучения FMCSA (tpr.fmcsa.dot.gov) и GA DDS."},"97":{"q":"Помимо теста на навыки, что должен сдать заявитель на CDL Джорджии в Центре обслуживания клиентов DDS?","options":["Тест на физическую силу и тест по плаванию","Только проверку кредитной истории","Обязательные письменные экзамены на знания и проверку зрения","Проверку подачи федеральной налоговой декларации"],"explanation":"Перед тестом на навыки заявитель на CDL Джорджии должен сдать обязательные письменные экзамены на знания для запрашиваемого класса и подтверждений и пройти проверку зрения в Центре обслуживания клиентов DDS. Источник: GA DDS, страницы CDL Permit и заявления (dds.georgia.gov)."},"98":{"q":"Какое утверждение о сборах за CDL в Джорджии является точным?","options":["Только FMCSA собирает сборы за CDL в Джорджии","Сборы устанавливаются индивидуально каждым медицинским экзаменатором","Все услуги CDL в GA DDS постоянно бесплатны","Точные суммы сборов устанавливаются GA DDS и могут меняться, поэтому заявителям следует уточнять текущие сборы в DDS"],"explanation":"GA DDS взимает сборы за разрешения, тестирование и лицензирование (например, сборы за разрешение и тест вождения по дороге), но точные суммы устанавливаются DDS и могут меняться со временем. Заявителям следует подтвердить текущие сборы в официальной информации DDS «Fees and Terms» перед подачей заявления. Источник: GA DDS (dds.georgia.gov)."},"99":{"q":"Что должен сделать водитель CDL Джорджии при продлении в отношении типа коммерческой деятельности?","options":["Самостоятельно сертифицировать один тип коммерческой деятельности и, если относится к non-excepted, иметь актуальный медицинский сертификат DOT в досье","Пересдавать полный тест на навыки вождения при каждом продлении независимо от категории","Сдать CDL и подать заявление заново как совершенно новый заявитель","Подать нотариально заверенное письмо от бывшего работодателя"],"explanation":"При продлении владелец CDL Джорджии должен самостоятельно сертифицировать один тип коммерческой деятельности (одну из четырёх категорий), а водители категории non-excepted должны иметь актуальный медицинский сертификат DOT, который теперь передаётся электронно через FMCSA. Источник: GA DDS, страницы «Renew a CDL» и CDL Med Cert (dds.georgia.gov)."}},"tr":{"0":{"q":"Georgia karayollarında, aynalar ve aksesuarlar hariç, bir aracın ve yükünün toplam dış genişliği en fazla ne kadar olabilir?","options":["96 inç","102 inç","108 inç","120 inç"],"explanation":"O.C.G.A. §32-6-23, Georgia'daki herhangi bir cadde, yol veya karayolunda hiçbir aracın, aynalar ve aksesuarlar hariç olmak üzere, herhangi bir yük dahil 102 inçlik toplam dış genişliği aşamayacağını öngörür. (Kaynak: O.C.G.A. §32-6-23; GA DDS CDL El Kitabı)"},"1":{"q":"Daha yüksek bir limitin yetkilendirildiği durumlar dışında, Georgia yollarında yüklü veya yüksüz bir aracın azami yüksekliği nedir?","options":["12 fit 6 inç","13 fit 0 inç","14 fit 6 inç","13 fit 6 inç"],"explanation":"O.C.G.A. §32-6-22(a), izinle yetkilendirilen durumlar hariç olmak üzere, Georgia yollarında yüklü veya yüksüz hiçbir aracın 13 fit 6 inç yüksekliği aşamayacağını belirtir. (Kaynak: O.C.G.A. §32-6-22)"},"2":{"q":"Georgia'da, levhayla bildirilmiş kısıtlamaların olmadığı durumlarda, çekici-yarı römork kombinasyonundaki bir yarı römorkun azami uzunluğu nedir?","options":["45 fit","48 fit","53 fit","57 fit"],"explanation":"O.C.G.A. §32-6-24(b)(1)(B), çekici-yarı römork kombinasyonlarında, yarı römork uzunluğu kısıtlamalarını belirten levhalar konulmadıkça, yarı römorkların 53 fit uzunluğu aşamayacağını öngörür. (Kaynak: O.C.G.A. §32-6-24)"},"3":{"q":"Bir Georgia çekici-yarı römork-römork (ikiz römork) kombinasyonunda, her bir römork ve yarı römorkun azami uzunluğu nedir?","options":["24 fit","28 fit","33 fit","40 fit"],"explanation":"O.C.G.A. §32-6-24(b)(1)(A), çekici-yarı römork-römork kombinasyonlarında römork ve yarı römorkların her birinin 28 fit uzunluğu aşamayacağını öngörür. (Kaynak: O.C.G.A. §32-6-24)"},"4":{"q":"Georgia'da, eyaletler arası veya STAA sistemi dışındaki yollarda, levhayla bildirilmiş kısıtlamaların olmadığı durumlarda, bir çekici-yarı römork veya çekici-yarı römork-römork kombinasyonunun azami toplam uzunluğu nedir?","options":["65 fit","75 fit","100 fit","110 fit"],"explanation":"O.C.G.A. §32-6-24(b)(2)(C), eyaletler arası veya STAA sistemi dışındaki yollarda, uzunluk kısıtlamalarını belirten levhalar konulmadıkça, bu tür kombinasyonların 100 fiti aşmayan bir toplam uzunluğa sahip olacağını öngörür. (Kaynak: O.C.G.A. §32-6-24)"},"5":{"q":"Georgia karayollarında herhangi bir araç ve yük için yetkilendirilen azami toplam brüt ağırlık nedir?","options":["73,280 lb","88,000 lb","100,000 lb","80,000 lb"],"explanation":"O.C.G.A. §32-6-26(c)(1)(A) ve (d)(1)(A), hem ulusal hem de ulusal olmayan karayollarında, herhangi bir araç ve yük için yetkilendirilen azami toplam brüt ağırlığı 80,000 lb ile sınırlar. (Kaynak: O.C.G.A. §32-6-26; GA DDS CDL El Kitabı)"},"6":{"q":"Bir Georgia ulusal karayolunda (örneğin bir eyaletler arası yolda), bir tandem aks üzerinde yetkilendirilen azami yük nedir?","options":["30,000 lb","40,680 lb","46,000 lb","34,000 lb"],"explanation":"O.C.G.A. §32-6-26(d)(1)(B), Georgia ulusal karayollarında herhangi bir tandem aks üzerindeki azami yükü, federal limitle eşleşecek şekilde 34,000 lb olarak belirler. (Kaynak: O.C.G.A. §32-6-26; GA DDS CDL El Kitabı)"},"7":{"q":"Ulusal karayolu OLMAYAN Georgia karayollarında, bir tandem aks üzerinde yetkilendirilen azami yük nedir?","options":["34,000 lb","37,340 lb","40,680 lb","46,000 lb"],"explanation":"O.C.G.A. §32-6-26(c)(1)(A), ulusal karayolu olmayan Georgia karayollarında azami tandem aks yükünü 40,680 lb olarak belirler. (Kaynak: O.C.G.A. §32-6-26)"},"8":{"q":"O.C.G.A. §32-6-26 uyarınca, Georgia'da ağırlık amaçları bakımından \"tekli aks\" nasıl tanımlanır?","options":["Merkezleri, birbirinden 40 inç uzaklıkta iki paralel enine dikey düzlem arasında kalan tüm tekerlekler","Merkezleri birbirinden 96 inç içinde kalan tüm tekerlekler","Birbirinden 40 inçten fazla aralıklı herhangi iki ardışık aks","Yalnızca bir güç ünitesinin tek direksiyon aksı"],"explanation":"O.C.G.A. §32-6-26(a)(4), \"tekli aks\"ı, merkezleri birbirinden 40 inç uzaklıkta iki paralel enine dikey düzlem arasında yer alabilen tüm tekerlekler olarak tanımlar. (Kaynak: O.C.G.A. §32-6-26)"},"9":{"q":"Mevcut Georgia yasalarına göre, ağırlık amaçları bakımından \"tandem aks\" nasıl tanımlanır?","options":["Merkezleri birbirinden 40 inçten fazla ancak 96 inçten fazla olmayacak şekilde aralıklı iki veya daha fazla ardışık aks","Direksiyon aksı hariç, merkezleri birbirinden 40 inçten fazla ancak 216 inçten fazla olmayacak şekilde aralıklı iki veya daha fazla ardışık aks","Direksiyon aksı dahil, birbirinden en fazla 8 fit aralıklı tam olarak iki aks","Direksiyon aksından bağımsız olarak, birbirinden 12 fit içinde kalan herhangi bir aks grubu"],"explanation":"O.C.G.A. §32-6-26(a)(7), \"tandem aks\"ı (1 Nisan 1988'den sonra), direksiyon aksı hariç, merkezleri birbirinden 40 inçten fazla ancak 216 inçten fazla olmayacak şekilde aralıklı paralel dikey düzlemler arasında yer alabilen iki veya daha fazla ardışık aks olarak tanımlar. (Kaynak: O.C.G.A. §32-6-26)"},"10":{"q":"İki veya daha fazla ardışık akstan oluşan bir grup üzerinde izin verilen azami brüt ağırlığı belirlemek için Georgia hangi formülü kullanır?","options":["Federal köprü formülü","Brüt kombinasyon ağırlık derecelendirme formülü","Georgia aks aralığı tarifesi","Aks başına 18,000 lb kuralı"],"explanation":"O.C.G.A. §32-6-26(a)(1) ve (d), Georgia ulusal karayollarında iki veya daha fazla ardışık akstan oluşan herhangi bir grup üzerindeki azami brüt ağırlığı belirlemek için W = 500((LN/N-1) + 12N + 36) federal köprü formülünü benimser. (Kaynak: O.C.G.A. §32-6-26; GA DDS CDL El Kitabı)"},"11":{"q":"Georgia köprü formülü W = 500((LN/N-1) + 12N + 36) içinde \"N\" değişkeni neyi temsil eder?","options":["Söz konusu gruptaki aks sayısı","Grubun en uçtaki aksları arasındaki fit cinsinden mesafe","Binlerce lb cinsinden yükün net ağırlığı","En ağır aks üzerindeki lastik sayısı"],"explanation":"O.C.G.A. §32-6-26(a)(1) içinde N söz konusu gruptaki aks sayısı, L grubun en uçtaki aksları arasındaki fit cinsinden mesafe ve W o grup üzerindeki brüt ağırlıktır. (Kaynak: O.C.G.A. §32-6-26)"},"12":{"q":"O.C.G.A. §32-6-26 uyarınca, ulusal olmayan Georgia karayollarında yalnızca dört aksla donatılmış bir araç için azami toplam brüt ağırlık nedir?","options":["56,000 lb","70,000 lb","73,280 lb","80,000 lb"],"explanation":"O.C.G.A. §32-6-26(c)(1)(C), dört aksla donatılmış herhangi bir araç için, araç ve yük için yetkilendirilen azami toplam brüt ağırlığın 70,000 lb olacağını öngörür. (Kaynak: O.C.G.A. §32-6-26)"},"13":{"q":"Bir Georgia ilçe yolu sisteminde, o yolda alım veya teslimat yapmayan bir araç için izin verilen azami toplam brüt ağırlık nedir?","options":["46,000 lb","56,000 lb","70,000 lb","80,000 lb"],"explanation":"O.C.G.A. §32-6-26(f), aracın o yolda bir alım veya teslimat yaptığı durumlar (veya uygun şekilde belirlenmiş bir yerel kamyon güzergahında) hariç, bir ilçe yolu sistemindeki azami toplam brüt ağırlığı 56,000 lb ile sınırlar. (Kaynak: O.C.G.A. §32-6-26)"},"14":{"q":"Orman ürünleri, canlı kümes hayvanı, pamuk, yem, granit, katı atık veya taze karıştırılmış beton taşıyan bir araç, ulusal olmayan bir karayolunda izin almadan Georgia'nın normal aks/brüt limitlerini ne zaman aşabilir?","options":["Hiçbir zaman; limitleri aşmak için her zaman bir izin gereklidir","Yalnızca geceleri ve yalnızca eyaletler arası karayollarında","Tekli aks ağırlığı 23,000 lb veya altında, tandem aks ağırlığı 46,000 lb veya altında ve brüt ağırlık 80,000 lb veya altında kaldığında","Aks ağırlığından bağımsız olarak brüt ağırlık 100,000 lb veya altında kaldığında"],"explanation":"O.C.G.A. §32-6-26(g)(1), bu belirtilen tarımsal ve emtia taşımalarına ulusal olmayan karayollarında izinsiz olarak yalnızca tekli aks yükü 23,000 lb'yi aşmadığında, tandem aks 46,000 lb'yi aşmadığında ve toplam brüt ağırlık 80,000 lb'yi aşmadığında izin verir. (Kaynak: O.C.G.A. §32-6-26)"},"15":{"q":"Georgia'nın tarım, ziraat veya orman yönetimi EKİPMANLARI için (genişlik ve uzunluk limitlerini izinsiz aşmasına olanak tanıyan) boyut muafiyeti hangi koşulda geçerlidir?","options":["Yalnızca eyaletler arası sistemde ve yalnızca geceleri","Eyaletler arası sistemin parçası olmayan yollarda, gündüz saatlerinde, sahibinin veya bayinin mülküne 40 mil mesafe içinde","Eyalet genelinde her saatte, mesafe sınırı olmaksızın","Yalnızca eyaletler arası yolda kehribar renkli ışıklı bir refakat aracı eşlik ettiğinde"],"explanation":"O.C.G.A. §32-6-25, tarım/ziraat veya orman yönetimi ekipmanlarını, eyaletler arası sistemin parçası olmayan bir kamu yolunda, gündüz saatlerinde, sahibinin veya bayinin mülkünün 40 millik yarıçapı içinde işletildiğinde, izinsiz olarak genişlik ve uzunluk limitlerinden muaf tutar. Muafiyet, orman ürünleri taşıyan veya nakleden araçlar için GEÇERLİ DEĞİLDİR. (Kaynak: O.C.G.A. §32-6-25)"},"16":{"q":"Georgia'da, bir aracın veya yükün yasayla belirlenen azami boyut veya ağırlık limitlerini aşmasına izin veren bir izni kim verir?","options":["Yazılı başvuru ve haklı sebep gösterilmesi üzerine Ulaştırma Bakanlığı (GDOT)","Yolculuğun başladığı ilçenin şerifi","Denetim sırasında herhangi bir tartı istasyonu görevlisi","CDL başvurusuyla birlikte Sürücü Hizmetleri Bakanlığı"],"explanation":"O.C.G.A. §32-6-28(a), GDOT komiserine (veya yetkilendirilmiş bir görevliye), yazılı başvuru ve haklı sebep gösterilmesi üzerine, ağırlığı, genişliği, uzunluğu veya yüksekliği yasal azami değeri aşan bir araç ve yüke izin veren bir izin verme yetkisi tanır. İzinler GDOT/Kamu Güvenliği Bakanlığı (GAPROS sistemi) aracılığıyla alınır. (Kaynak: O.C.G.A. §32-6-28; GDOT)"},"17":{"q":"O.C.G.A. §32-6-28 uyarınca, bir Georgia YILLIK aşırı boyut/aşırı ağırlık izni, toplam brüt ağırlığı hangi miktarı aşan bir araca yetki vermek için VERİLEMEZ?","options":["80,000 lb","120,000 lb","150,000 lb","100,000 lb"],"explanation":"O.C.G.A. §32-6-28(b)(1)(A), bir yıllık iznin, toplam brüt ağırlığı 100,000 lb'yi aşan (ya da tekli aks ağırlığı 25,000 lb'yi, uzunluğu 100 fiti, genişliği 102 inç / yük genişliği 144 inçi veya yüksekliği 14 fit 6 inçi aşan) bir aracın işletilmesine yetki veremeyeceğini öngörür. (Kaynak: O.C.G.A. §32-6-28; GDOT)"},"18":{"q":"Georgia'nın temel ağırlık kuralı uyarınca, yasal tolerans uygulanmadan önce bir tekli aks üzerindeki (yüksek basınçlı pnömatik lastikli) temel azami yük nedir?","options":["12,000 lb","18,000 lb","20,000 lb","16,000 lb"],"explanation":"O.C.G.A. §32-6-26(b)(1), herhangi bir tekli aks (yüksek basınçlı pnömatik, dolu kauçuk veya yastıklı lastikli) üzerindeki 16,000 lb'yi yüzde 13'ten fazla aşan bir yükü yasaklar; dolayısıyla temel rakam 16,000 lb'dir ve %13'lük tolerans yaklaşık 18,080 lb verir. (Kaynak: O.C.G.A. §32-6-26)"},"19":{"q":"O.C.G.A. §32-6-27 uyarınca, Georgia'da aşırı yüklü bir aracın hareket etmesine izin verilmeden önce, operatör yasal limiti hangi miktardan fazla aşan tüm brüt ağırlığı boşaltmalıdır?","options":["2,000 lb","4,000 lb","6,000 lb","10,000 lb"],"explanation":"O.C.G.A. §32-6-27(e), aşırı yüklü bir aracın sahibinin/operatörünün, takdir edilen hasarları ödemeye ek olarak, aracın hareket etmesine izin verilmeden önce yasal ağırlık limitinin 6,000 lb üzerindeki tüm brüt ağırlığı boşaltmasını gerektirir. (Kaynak: O.C.G.A. §32-6-27)"},"20":{"q":"Georgia'da, çekilen aracın 10,000 lb'den fazla GVWR'ye sahip olduğu, 26,001 lb veya daha fazla brüt kombinasyon ağırlık derecelendirmesine (GCWR) sahip bir araç kombinasyonunu işletmek için hangi sınıf CDL gereklidir?","options":["Sınıf B","Sınıf C","Sınıf D","Sınıf A"],"explanation":"Bir Georgia Sınıf A CDL, çekilen ünitenin 10,000 lb GVWR'yi aştığı, 26,001+ lb GCWR'ye sahip herhangi bir araç kombinasyonunu kapsar. Bir Sınıf A sahibi, uygun onaylarla Sınıf B ve C araçlarını da işletebilir. Kaynak: Georgia DDS, 'Ticari (CDL) Ehliyet Başvurusu (Sınıf A, B, C).'"},"21":{"q":"Georgia DDS kurallarına göre, bir Sınıf B CDL bir sürücüye aşağıdakilerden hangisini işletme yetkisi verir?","options":["Çekilen ünitenin 10,000 lb'yi aştığı herhangi bir araç kombinasyonu","26,001+ lb GVWR'ye sahip, 10,000 lb'yi aşmayan bir üniteyi çeken herhangi bir tekli araç","Yalnızca 16 veya daha fazla yolcu taşımak için tasarlanmış araçlar","Yalnızca tehlikeli maddeler için levhalı araçlar"],"explanation":"Bir Georgia Sınıf B CDL, 10,000 lb GVWR'yi aşmayan bir aracı çekenler dahil, 26,001+ lb GVWR'ye sahip tekli araçları kapsar. Bir Sınıf B sahibi, uygun onaylarla Sınıf C araçlarını da işletebilir. Kaynak: Georgia DDS, 'Ticari (CDL) Ehliyet Başvurusu.'"},"22":{"q":"Georgia'da, bir Sınıf C CDL özellikle hangi tür araç için verilir?","options":["26,001 lb GCWR'nin üzerindeki herhangi bir araç kombinasyonu","26,001 lb GVWR'nin üzerindeki herhangi bir tekli araç","Sınıf A veya B'ye uymayan ancak sürücü dahil 16+ yolcu taşıyan veya tehlikeli maddeler için levhalı olan tekli bir araç (veya kombinasyon)","26,001 lb'nin altındaki herhangi bir binek otomobil veya kamyonet"],"explanation":"Bir Georgia Sınıf C CDL, Sınıf A veya B tanımına uymayan ancak sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış ya da levha gerektiren tehlikeli madde taşımak için kullanılan tekli bir araca veya kombinasyona uygulanır. Kaynak: Georgia DDS, 'Ticari (CDL) Ehliyet Başvurusu.'"},"23":{"q":"Herhangi bir Georgia CDL'sine başvurmak için asgari yaş nedir?","options":["18 yaşında","16 yaşında","21 yaşında","25 yaşında"],"explanation":"Georgia DDS, CDL başvuru sahiplerinin en az 18 yaşında olmasını gerektirir. 18 ile 21 yaş arasındaki başvuru sahipleri, 21 yaşına gelene kadar eyalet içi (yalnızca Georgia) sürüşle kısıtlıdır. Kaynak: Georgia DDS, 'Ticari (CDL) Ehliyet Başvurusu.'"},"24":{"q":"19 yaşındaki bir Georgia CDL sahibi ne şekilde kısıtlanır?","options":["Herhangi bir onaya sahip olmaktan kısıtlanır","21 yaşına gelene kadar eyalet içi (yalnızca Georgia) sürüşle kısıtlanır","Yalnızca Sınıf C araçlarıyla kısıtlanır","Geceleri araç kullanmaktan kısıtlanır"],"explanation":"Georgia, 18 yaş ve üzeri başvuru sahiplerine CDL verir, ancak 18 ile 21 yaş arasındaki sürücüler bir 'Yalnızca Georgia' (eyalet içi) kısıtlaması taşır. Sürücü, eyaletler arası sürüş için kısıtlamanın kaldırılması amacıyla 21 yaşına gelmeli ve bir Müşteri Hizmetleri Merkezini ziyaret etmelidir. Kaynak: Georgia DDS, 'Ticari (CDL) Ehliyet Başvurusu.'"},"25":{"q":"Bir Georgia CDL sahibi, eyalet sınırları ötesinde araç kullanabilmek için eyalet içi sürüş kısıtlamasını kaldırmak istiyor. Ne olmalıdır?","options":["Önce CDL'yi en az beş yıl elinde tutmalıdır","21. yaş gününe ulaşmalı ve 'Yalnızca Georgia' kısıtlamasını kaldırmak için bir DDS Müşteri Hizmetleri Merkezini ziyaret etmelidir","Bir HazMat onayı eklemelidir","18 yaşında ek bir eyaletler arası beceri testini geçmelidir"],"explanation":"18 ile 21 yaş arasındaki sürücüler eyalet içi sürüşle kısıtlıdır. Eyaletler arası ayrıcalıklar kazanmak için sürücü 21 yaşına gelmeli ve 'Yalnızca Georgia' kısıtlamasını kaldırmak için bir DDS Müşteri Hizmetleri Merkezini ziyaret etmelidir. Kaynak: Georgia DDS, 'Ticari (CDL) Ehliyet Başvurusu.'"},"26":{"q":"Georgia'da, levha gerektiren miktarlarda tehlikeli madde taşıyan bir aracı sürmek için hangi onay gereklidir?","options":["N (Tanker) onayı","T (İkili/Üçlü) onayı","P (Yolcu) onayı","H (HazMat) onayı"],"explanation":"Levha gerektiren tehlikeli maddeleri taşımak için H (HazMat) onayı gereklidir. Georgia'da bu, hem ilk verilişte hem de yenilemelerde bir bilgi testini geçmeyi, bir TSA arka plan kontrolünü ve parmak izi alınmasını gerektirir. Kaynak: Georgia DDS, 'CDL Onaylarının Eklenmesi.'"},"27":{"q":"Georgia'da, HazMat (H) onayı için karşılanması gereken ve Tanker (N) onayı için gerekli OLMAYAN ek federal gereklilik nedir?","options":["Ayrı bir beceri (yol) testini geçmek","Onayı kullanmadan önce 14 gün elinde tutmak","Parmak izi alınmasıyla birlikte bir TSA güvenlik tehdidi değerlendirmesini geçmek","Önce bir yolcu onayı almak"],"explanation":"HazMat onayı, bir TSA arka plan kontrolünü (güvenlik tehdidi değerlendirmesi) geçmeyi gerektirir ve hem ilk veriliş hem de yenilemeler için parmak izi gereklidir. Tanker onayı yalnızca bir bilgi testi gerektirir. Kaynak: Georgia DDS, 'CDL Onaylarının Eklenmesi.'"},"28":{"q":"Georgia DDS'ye göre, N (Tanker) onayı nasıl elde edilir?","options":["Hem bir bilgi testini hem de bir beceri testini geçerek","Yalnızca bir beceri testini geçerek","Yalnızca bir bilgi testini geçerek","Yalnızca bir TSA arka plan kontrolünü geçerek"],"explanation":"Georgia'da N (Tanker) onayı yalnızca bir bilgi testini geçmeyi gerektirir ve Sınıf A ve B CDL'leri için geçerlidir. Kaynak: Georgia DDS, 'CDL Onaylarının Eklenmesi.'"},"29":{"q":"Hangi Georgia CDL onayı yalnızca bir Sınıf A CDL için geçerlidir ve bir bilgi testi geçerek elde edilir?","options":["T (İkili/Üçlü) onayı","P (Yolcu) onayı","S (Okul Otobüsü) onayı","N (Tanker) onayı"],"explanation":"T (İkili/Üçlü Römork) onayı yalnızca bir Sınıf A CDL için geçerlidir ve bir bilgi testi gerektirir. Bir Ticari Öğrenci Belgesi üzerinde elde edilemez; başvuru sahibinin zaten geçerli bir CDL'ye sahip olması gerekir. Kaynak: Georgia DDS, 'CDL Onaylarının Eklenmesi.'"},"30":{"q":"Georgia, P (Yolcu) onayını elde etmek için ne gerektirir?","options":["Yalnızca bir bilgi testini geçmek","Hem bir bilgi testini hem de bir beceri testini geçmek","Yalnızca bir beceri testini geçmek","Yalnızca bir TSA arka plan kontrolünü geçmek"],"explanation":"Georgia'da, P (Yolcu) onayı hem bir bilgi testini hem de bir beceri testini geçmeyi gerektirir ve Sınıf A, B ve C CDL'leri için geçerlidir. Kaynak: Georgia DDS, 'CDL Onaylarının Eklenmesi.'"},"31":{"q":"Georgia DDS, hangi iki onay için HEM bir bilgi testi HEM DE bir beceri testi gerektirir?","options":["N (Tanker) ve T (İkili/Üçlü)","H (HazMat) ve N (Tanker)","P (Yolcu) ve S (Okul Otobüsü)","T (İkili/Üçlü) ve H (HazMat)"],"explanation":"Georgia'da, Yolcu (P) ve Okul Otobüsü (S) onaylarının her biri hem bir bilgi testini hem de bir beceri testini geçmeyi gerektirir. N, T ve H onayları yalnızca bir bilgi testi gerektirir. Kaynak: Georgia DDS, 'CDL Onaylarının Eklenmesi.'"},"32":{"q":"7 Şubat 2022'den itibaren geçerli olmak üzere, hangi Georgia CDL başvuru sahibi grubu Giriş Seviyesi Sürücü Eğitimi (ELDT) gerekliliklerine tabidir?","options":["Yalnızca Sınıf C CDL almak isteyen başvuru sahipleri","İlk kez Sınıf A veya B alan, daha yüksek bir sınıfa yükselen ya da bir Okul Otobüsü, Yolcu veya HazMat onayı ekleyen başvuru sahipleri","Yalnızca 21 yaş üstü sürücüler","Yalnızca mevcut bir CDL'yi hiçbir değişiklik olmadan yenileyen başvuru sahipleri"],"explanation":"Georgia tarafından benimsenen FMCSA ELDT kuralları uyarınca, 7 Şubat 2022'den itibaren, ilk kez Sınıf A veya B CDL alan, daha yüksek bir sınıfa yükselen ya da bir Okul Otobüsü (S), Yolcu (P) veya HazMat (H) onayı ekleyen tüm giriş seviyesi sürücüler ELDT'yi tamamlamalıdır. Kaynak: Georgia DDS, 'Ticari (CDL) Ehliyet Başvurusu' / 'CDL Onaylarının Eklenmesi.'"},"33":{"q":"Bir Georgia CDL başvuru sahibinin Giriş Seviyesi Sürücü Eğitimi (ELDT) nerede tamamlanmalı ve kaydedilmelidir?","options":["Başvuru sahibinin seçtiği, kayıt sistemi olmayan herhangi bir özel sürücü kursunda","Yalnızca bir Georgia DDS Müşteri Hizmetleri Merkezinde","Resmi bir sağlayıcısı olmayan çevrimiçi bir test aracılığıyla","FMCSA Eğitim Sağlayıcı Kayıt Sistemi'nde (TPR) listelenen bir eğitim sağlayıcıyla"],"explanation":"ELDT, FMCSA Eğitim Sağlayıcı Kayıt Sistemi'nde (TPR) listelenen bir sağlayıcı tarafından verilmelidir ve tamamlanması, sürücü CDL beceri veya HazMat bilgi testini alabilmeden önce kayıt sistemine bildirilir. Kaynak: Georgia DDS tarafından atıfta bulunulan FMCSA ELDT düzenlemeleri."},"34":{"q":"Tam bir Georgia CDL'sine başvurmadan önce, bir başvuru sahibinin Ticari Öğrenci Belgesini (CLP) ne kadar süre elinde tutması gerekir?","options":["En az 30 gün","En az 60 gün","En az 14 gün","En az 6 ay"],"explanation":"Georgia, CDL başvuru sahiplerinin CDL beceri testini almadan / tam CDL'ye başvurmadan önce Ticari Öğrenci Belgesini (CLP) en az 14 gün elinde tutmasını gerektirir. Kaynak: Georgia DDS, 'CDL Belgesi' ve CDL Ehliyet SSS'leri."},"35":{"q":"Bir Georgia başvuru sahibi, bir Ticari Öğrenci Belgesi (CLP) alabilmek için neyi geçmelidir?","options":["Gerekli yazılı bilgi sınav(lar)ını","Yalnızca CDL beceri (yol) testini","Bir TSA arka plan kontrolünü","Yalnızca bir görme testini"],"explanation":"Bir Georgia CLP'si (Sınıf AP veya BP) almak için, başvuru sahibinin geçerli bir normal Georgia ehliyetine sahip olması ve gerekli yazılı bilgi sınav(lar)ını geçmesi gerekir. Beceri testi daha sonra, 14 günlük bekleme süresinden sonra gelir. Kaynak: Georgia DDS, 'Ticari Belge Başvurusu (Sınıf AP veya BP).'"},"36":{"q":"1 Temmuz 2021'de veya sonrasında verilen bir Georgia CLP'si için belge ne kadar süre geçerlidir?","options":["30 gün","180 gün","5 yıl","365 gün"],"explanation":"1 Temmuz 2021'de veya sonrasında verilen bir Georgia Ticari Öğrenci Belgesi (CLP) 365 gün geçerlidir. Kaynak: Georgia DDS, 'CDL Belgesi.'"},"37":{"q":"Bir kişinin Georgia Ticari Öğrenci Belgesi (CLP) alabilmesi için aşağıdakilerden hangisi gereklidir?","options":["Geçerli bir normal Georgia ehliyetine sahip olmak","Zaten bir HazMat onayına sahip olmak","Bir TSA arka plan kontrolünü tamamlamak","Bir Sınıf A CDL'ye sahip olmak"],"explanation":"Georgia DDS, CLP başvuru sahiplerinin ticari belgeye başvurmadan önce geçerli bir normal Georgia ehliyetine sahip olmasını gerektirir. Kaynak: Georgia DDS, 'Ticari Belge Başvurusu (Sınıf AP veya BP).'"},"38":{"q":"Bir Georgia CDL'sine başvururken, DDS bir başvuru sahibinin hangi belge kombinasyonunu sunmasını gerektirir?","options":["Kimlik kanıtı, Sosyal Güvenlik numarası, yasal varlık ve iki Georgia ikamet kanıtı","Yalnızca bir Sosyal Güvenlik kartı","Yalnızca bir Georgia seçmen kayıt kartı","Yalnızca bir pasaport, ikamet kanıtı olmadan"],"explanation":"Georgia DDS, kimlik kanıtı (örneğin onaylı doğum belgesi veya ABD pasaportu), Sosyal Güvenlik numarası kanıtı, yasal varlık kanıtı ve Georgia ikametini kanıtlayan ayrı kaynaklardan iki belge gerektirir. Kaynak: Georgia DDS, 'Ticari (CDL) Ehliyet Başvurusu.'"},"39":{"q":"Yalnızca Georgia içinde faaliyet gösteren ve FMCSA sürücü yeterlilik gerekliliklerini karşılaması gereken bir Georgia CDL sürücüsü, hangi tıbbi öz sertifikasyon kategorisini seçmelidir?","options":["İstisnasız Eyaletler Arası (NI)","İstisnalı Eyaletler Arası (EI)","İstisnalı Eyalet İçi (EA)","İstisnasız Eyalet İçi (NA)"],"explanation":"Georgia DDS dört öz sertifikasyon kategorisi kullanır: İstisnasız Eyaletler Arası (NI), İstisnalı Eyaletler Arası (EI), İstisnasız Eyalet İçi (NA) ve İstisnalı Eyalet İçi (EA). Yalnızca Georgia'da (eyalet içi) faaliyet gösteren ve tıbbi yeterlilik gerekliliklerini karşılaması gereken bir sürücü, İstisnasız Eyalet İçi (NA) kategorisini seçer. Tüm CDL sahipleri DDS'ye bir öz sertifikasyon sunmalıdır. Kaynak: Georgia DDS, 'CDL Tıbbi Sertifikasyon ve Öz Sertifikasyon Süreci.'"},"40":{"q":"Georgia'da, bir kişinin yasal olarak bir ticari motorlu aracı (CMV) işletebileceği azami kandaki alkol konsantrasyonu (BAC) nedir?","options":["0.08 veya üzeri limittir","0.04 veya üzerinde yasa dışıdır","0.10 veya üzeri limittir","0.02'nin üzerindeki herhangi bir miktar yasa dışıdır"],"explanation":"Georgia'da 0.04 veya daha yüksek bir BAC ile bir CMV işletmek yasa dışıdır, ki bu ticari olmayan sürücüler için olan 0.08 limitinin yarısıdır. Kaynak: Georgia CDL El Kitabı (DDS), CDL Diskalifiyeleri; 49 CFR 383.51(b)."},"41":{"q":"Bir Georgia CDL sahibi, tehlikeli madde taşıMAZken, bir CMV'de DUI gibi ilk bir büyük suçtan mahkum oluyor. CDL ne kadar süreyle diskalifiye edilir?","options":["En az 60 gün","En az 6 ay","En az 1 yıl","En az 3 yıl"],"explanation":"İlk bir büyük suç (DUI, BAC 0.04+, ret, olay yerini terk etme, bir CMV'nin suçta kullanımı vb.) en az 1 yıllık diskalifiye ile sonuçlanır. Kaynak: Georgia CDL El Kitabı (DDS); 49 CFR 383.51(b) Tablo 1."},"42":{"q":"Bir Georgia CDL sürücüsü, tehlikeli maddeler için levhalı bir CMV işletirken ilk bir büyük suç işlerse diskalifiye süresi nasıl değişir?","options":["En az 3 yıla yükselir","En az 1 yılda kalır","En az 5 yıla yükselir","Anında ömür boyu yasakla sonuçlanır"],"explanation":"İlk bir büyük suç, levha gerektiren tehlikeli madde taşırken işlendiğinde, asgari diskalifiye 1 yıldan 3 yıla yükselir. Kaynak: Georgia CDL El Kitabı (DDS); 49 CFR 383.51(b) Tablo 1."},"43":{"q":"Ayrı bir olayda İKİNCİ bir büyük suçtan mahkum olan bir Georgia CDL sahibi için diskalifiye süresi nedir?","options":["Ek 3 yıl","Ek 10 yıl","Ek 120 gün","Ömür boyu diskalifiye"],"explanation":"Ayrı olaylarda büyük suçların herhangi bir kombinasyonundan ikinci bir mahkumiyet, CDL'nin ömür boyu diskalifiyesiyle sonuçlanır. Kaynak: Georgia CDL El Kitabı (DDS); 49 CFR 383.51(b) Tablo 1."},"44":{"q":"Georgia'nın zımni rıza yasası uyarınca, yasal bir talepten sonra alkol veya uyuşturucu için kimyasal bir testi vermeyi reddeden bir CDL sahibine ne olur?","options":["Hiçbir şey, çünkü ret kanıt olarak kullanılamaz","Yalnızca bir para cezası uygulanır ancak CDL etkilenmez","Sürücü, DUI'den mahkum olmuş gibi diskalifiye edilir","Sürücü 60 günlük bir ciddi ihlal cezası alır"],"explanation":"Kimyasal bir testi reddetmek bir büyük suç olarak ele alınır ve bir DUI mahkumiyetiyle aynı diskalifiyeyi taşır: ilk suç için en az 1 yıl ve ikincisi için ömür boyu. Kaynak: Georgia CDL El Kitabı (DDS); O.C.G.A. 40-5-67.1 (zımni rıza); 49 CFR 383.51(b)."},"45":{"q":"Georgia'da bir CDL sürücüsünün görevdeyken 0.04'ün altında herhangi bir ölçülebilir miktarda alkole sahip olduğu tespit ediliyor. Sonuç nedir?","options":["Sürücüyü 24 saat hizmet dışı bırakan bir hizmet dışı emri","CDL'nin anında 1 yıllık diskalifiyesi","60 günlük bir ciddi ihlal diskalifiyesi","BAC 0.04'ün altında olduğu için sonuç yok"],"explanation":"0.04'ün altındaki herhangi bir ölçülebilir alkol, bir büyük suç diskalifiyesini tetiklemez ancak sürücünün 24 saat hizmet dışı bırakılmasını gerektirir. Kaynak: Georgia CDL El Kitabı (DDS); 49 CFR 392.5."},"46":{"q":"Aşağıdakilerden hangisi bir Georgia CDL sahibi için bir büyük suç yerine \"ciddi trafik ihlali\" olarak sınıflandırılır?","options":["0.04 veya daha yüksek bir BAC ile bir CMV sürmek","Bir suç işlemek için bir CMV kullanmak","Belirlenen limitin 15 mph veya daha fazla üzerinde aşırı hız yapmak","Bir CMV içeren bir kazada olay yerini terk etmek"],"explanation":"Aşırı hız (limitin 15+ mph üzerinde) bir ciddi trafik ihlalidir. DUI, suçta kullanım ve çarp-kaç çok daha ağır cezaları olan büyük suçlardır. Kaynak: Georgia CDL El Kitabı (DDS); 49 CFR 383.51(c) Tablo 2."},"47":{"q":"Bir Georgia CDL sahibi, 3 yıllık bir süre içinde ayrı olaylarda İKİ ciddi trafik ihlalinden mahkum oluyor. Diskalifiye süresi nedir?","options":["En az 30 gün","En az 60 gün","En az 120 gün","En az 1 yıl"],"explanation":"3 yıl içinde iki ciddi trafik ihlali, en az 60 günlük bir diskalifiye ile sonuçlanır. Kaynak: Georgia CDL El Kitabı (DDS); 49 CFR 383.51(c) Tablo 2."},"48":{"q":"Bir Georgia CDL sahibi, 3 yıllık bir süre içinde ayrı olaylarda ÜÇ ciddi trafik ihlalinden mahkum oluyor. Diskalifiye süresi nedir?","options":["En az 60 gün","En az 90 gün","En az 120 gün","En az 1 yıl"],"explanation":"3 yıl içinde üç ciddi trafik ihlali, en az 120 günlük bir diskalifiye ile sonuçlanır. Kaynak: Georgia CDL El Kitabı (DDS); 49 CFR 383.51(c) Tablo 2."},"49":{"q":"Aşağıdakilerden hangisi Georgia'da CDL diskalifiyesine yol açabilecek bir ciddi trafik ihlali olarak SAYILMAZ?","options":["Öndeki araca çok yakın takip etmek","Uygunsuz veya düzensiz şerit değiştirmek","Dikkatsiz sürüş","Bir CMV'yi gece boyunca bir dinlenme alanına park etmek"],"explanation":"Ciddi trafik ihlalleri arasında çok yakın takip, uygunsuz şerit değişiklikleri, dikkatsiz sürüş ve aşırı hız bulunur. Bir dinlenme alanına yasal olarak park etmek bir ihlal değildir. Kaynak: Georgia CDL El Kitabı (DDS); 49 CFR 383.51(c) Tablo 2."},"50":{"q":"Georgia CDL sürücüsünün demiryolu-karayolu hemzemin geçit ihlalinden İLK mahkumiyeti için diskalifiye süresi nedir?","options":["En az 30 gün","En az 60 gün","En az 120 gün","En az 1 yıl"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali en az 60 gün diskalifiye ile sonuçlanır. Kaynak: Georgia CDL Kılavuzu (DDS); 49 CFR 383.51(d) Tablo 3."},"51":{"q":"Bir Georgia CDL sahibi 3 yıllık süre içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali işler. Asgari diskalifiye süresi nedir?","options":["En az 60 gün","En az 120 gün","En az 6 ay","En az 1 yıl"],"explanation":"3 yıl içinde işlenen ikinci demiryolu-karayolu hemzemin geçit ihlali en az 120 gün diskalifiye ile sonuçlanır. Kaynak: Georgia CDL Kılavuzu (DDS); 49 CFR 383.51(d) Tablo 3."},"52":{"q":"Bir Georgia CDL sahibi 3 yıllık süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali işler. Asgari diskalifiye süresi nedir?","options":["En az 120 gün","En az 6 ay","En az 1 yıl","Ömür boyu diskalifiye"],"explanation":"3 yıl içinde işlenen üçüncü veya sonraki demiryolu-karayolu hemzemin geçit ihlali en az 1 yıl diskalifiye ile sonuçlanır. Kaynak: Georgia CDL Kılavuzu (DDS); 49 CFR 383.51(d) Tablo 3."},"53":{"q":"Tehlikeli madde veya yolcu söz konusu olmadığında, bir Georgia CDL sürücüsünün hizmet dışı (OOS) emrini ihlal etmekten İLK mahkumiyeti için diskalifiye süresi nedir?","options":["En az 60 gün","En az 90 gün","En az 180 gün","En az 2 yıl"],"explanation":"Hizmet dışı emrini ihlal etmekten ilk mahkumiyet en az 180 gün (en fazla 1 yıl) diskalifiye ile sonuçlanır. Kaynak: Georgia CDL Kılavuzu (DDS); 49 CFR 383.51(e) Tablo 4."},"54":{"q":"Bir Georgia CDL sahibi 10 yıllık süre içinde ayrı olaylarda İKİNCİ bir hizmet dışı emri ihlalinden mahkum olur. Asgari diskalifiye süresi nedir?","options":["En az 180 gün","En az 1 yıl","En az 2 yıl","Ömür boyu diskalifiye"],"explanation":"10 yıllık süre içinde işlenen ikinci hizmet dışı emri ihlali en az 2 yıl (en fazla 5 yıl) diskalifiye ile sonuçlanır. Kaynak: Georgia CDL Kılavuzu (DDS); 49 CFR 383.51(e) Tablo 4."},"55":{"q":"Georgia CDL sürücüsü plakartlı tehlikeli madde veya 16 ya da daha fazla yolcu taşıyorsa, İLK hizmet dışı emri ihlalinin cezası nasıl değişir?","options":["60 güne düşürülür","Asgari süre 180 gün olarak kalır ancak azami süre 2 yıla yükselir","Ömür boyu diskalifiye olur","180 günden 1 yıla kadar olarak değişmeden kalır"],"explanation":"Plakartlı tehlikeli madde veya 16 ya da daha fazla yolcu taşırken işlenen ilk OOS ihlali için diskalifiye en az 180 gün ancak standart duruma göre daha uzun bir azami süre olan 2 yıla kadardır. Kaynak: Georgia CDL Kılavuzu (DDS); 49 CFR 383.51(e) Tablo 4."},"56":{"q":"Georgia'nın Super Speeder yasası (O.C.G.A. 40-6-189) uyarınca, bir sürücü hangi hızlarda \"Super Speeder\" olarak sınıflandırılır?","options":["Herhangi bir yolda 65 mph veya iki şeritli bir yolda 75 mph","İki şeritli bir yolda 75 mph veya herhangi bir yol ya da karayolunda 85 mph","İki şeritli bir yolda 80 mph veya bir eyaletler arası karayolunda 90 mph","Herhangi bir belirtilen hız sınırının 15 mph veya daha fazla üzerinde"],"explanation":"Georgia'nın Super Speeder yasası, iki şeritli bir yolda 75 mph veya daha fazla, ya da herhangi bir yol veya karayolunda 85 mph veya daha fazla hızdan mahkum olan bir sürücüyü Super Speeder olarak sınıflandırır. Kaynak: O.C.G.A. 40-6-189."},"57":{"q":"Georgia'nın Super Speeder yasası uyarınca, Department of Driver Services mahkum olan bir Super Speeder'dan hangi ek eyalet ücretini tahsil eder ve ödenmezse ne olur?","options":["200 $ ücret; bildirimden itibaren 120 gün içinde ödenmezse ehliyet askıya alınır","500 $ ücret; 30 gün içinde ödenmezse hapis cezası","100 $ ücret; 90 gün içinde ödenmezse uyarı mektubu","Ödememe halinde başka bir sonucu olmayan 200 $ ücret"],"explanation":"Super Speeder yasası, herhangi bir mahkeme cezasının üzerine 200 $ eyalet ücreti ekler. DDS bildiriminden itibaren 120 gün içinde ödenmezse, sürücünün ehliyeti askıya alınır ve 50 $ yeniden etkinleştirme ücreti uygulanır. Kaynak: O.C.G.A. 40-6-189."},"58":{"q":"Georgia'nın uyguladığı federal kurallar uyarınca, bir CMV kullanırken mesaj atmaktan veya elde tutulan telefon kullanmaktan mahkum olan bir CDL sürücüsüne ne olur?","options":["Özellikle CDL sahipleri için herhangi bir cezası yoktur","Otomatik olarak 1 yıllık ağır suç diskalifiyesidir","Diskalifiyeye doğru sayılan ciddi bir trafik ihlali olarak kabul edilir","Anında ömür boyu diskalifiye ile sonuçlanır"],"explanation":"Bir CMV kullanırken mesaj atmak veya elde tutulan telefon kullanmak ciddi bir trafik ihlalidir; 3 yıl içinde iki tanesi 60 gün diskalifiye, üç tanesi 120 gün getirir. Kaynak: 49 CFR 383.51(c); Georgia CDL Kılavuzu (DDS)."},"59":{"q":"Georgia'nın Hands-Free Yasası (O.C.G.A. 40-6-241) tüm sürücüler için geçerlidir. CMV dahil bir araç kullanırken hangi eylemi yasaklar?","options":["Bluetooth veya hoparlör hands-free bağlantısı kullanmak","Bir telefonu vücudun herhangi bir parçasıyla fiziksel olarak tutmak veya desteklemek","Ön cama monte edilmiş ve görünür bir GPS cihazına sahip olmak","Araçta oturan bir yolcuyla konuşmak"],"explanation":"Hands-Free Georgia Yasası, sürücülerin bir telefonu veya elektronik cihazı vücudun herhangi bir parçasıyla tutmasını veya desteklemesini yasaklar; Bluetooth veya hoparlör gibi hands-free kullanım izinli kalmaya devam eder. Kaynak: O.C.G.A. 40-6-241."},"60":{"q":"Kendi yönünüzde iki veya daha fazla şeride sahip bir Georgia eyaletler arası karayolunda, banketin üzerinde yanıp sönen sarı ışıklar gösteren sabit bir HERO birimine yaklaşıyorsunuz. Georgia'nın Move Over Yasası ticari bir sürücüden ne yapmasını gerektirir?","options":["Birim yolun dışında, banketin üzerinde olduğundan belirtilen hız sınırını koruyun","Kendi şeridinizde tamamen durun ve birim hareket edene kadar bekleyin, ardından devam edin","Güvenliyse birimden uzağa bir şerit geçin; şerit değiştirmeyi güvenli bir şekilde yapamıyorsanız belirtilen hız sınırının altına yavaşlayın ve durmaya hazır olun","Yalnızca polis ve itfaiye araçları için geçiş yapın, çünkü HERO ve altyapı birimleri kapsam dışıdır"],"explanation":"Georgia'nın Move Over Yasası (O.C.G.A. §40-6-16), aynı yönde iki veya daha fazla şeride sahip yollardaki sürücülerin, yanıp sönen ışıklar gösteren sabit bir acil durum, altyapı, çekme/kurtarma, karayolu bakım, sanitasyon veya HERO biriminden uzağa bir şerit geçmesini gerektirir. Şerit değişikliği güvenli bir şekilde yapılamıyorsa, sürücü hızını belirtilen sınırın altına düşürmeli ve durmaya hazır olmalıdır."},"61":{"q":"Georgia'nın Move Over Yasası, yanıp sönen ışıklar gösteren sabit araçlar için geçerlidir. Aşağıdaki araçlardan hangisi O.C.G.A. §40-6-16 kapsamında DEĞİLDİR?","options":["Arızalı bir araca yardım eden bir HERO (Highway Emergency Response Operator) birimi","Yanıp sönen sarı ışıklarla elektrik hatlarını onaran bir altyapı hizmet aracı","Patlak lastik sonrası banket üzerinde standart dörtlü flaşörleri (dört yönlü flaşörler) açık şekilde duran bir binek otomobil","Yanıp sönen sarı ışıklarla hasarlı bir aracı kurtaran bir çekici"],"explanation":"O.C.G.A. §40-6-16, yanıp sönen ışıklar gösteren sabit acil durum, çekme/kurtarma, karayolu bakım, altyapı hizmet, sanitasyon ve HERO birimlerini korur. Yalnızca standart dörtlü flaşörlerini kullanan sıradan bir binek otomobil, Move Over Yasası kapsamındaki korunan araç sınıflarından biri değildir."},"62":{"q":"Hands-Free Georgia Yasası (O.C.G.A. §40-6-241) uyarınca, bir Georgia karayolunda ticari motorlu araç kullanan bir sürücüye özellikle hangi ek kısıtlama uygulanır?","options":["Sürücü, araç 15 mph altında hareket ettiği sürece manuel olarak mesaj atabilir","Sürücü, sesli bir aramayı başlatmak veya sonlandırmak için kablosuz bir cihazda en fazla tek bir düğme kullanabilir","Sürücü, arama işle ilgili olduğu sürece telefonu kulağına tutabilir","Sürücü, görevdeyken Hands-Free Yasası'ndan tamamen muaftır"],"explanation":"O.C.G.A. §40-6-241 uyarınca, ticari motorlu araç kullanırken hiçbir sürücü bir kablosuz telekomünikasyon cihazında sesli bir iletişimi başlatmak veya sonlandırmak için tek bir düğmeden fazlasını kullanamaz, ne de oturmuş sürüş pozisyonundan ayrılmayı gerektirecek şekilde bir cihaza uzanamaz. Bir cihazı vücudun herhangi bir parçasıyla tutmak veya desteklemek tüm sürücüler için yasaktır."},"63":{"q":"Georgia'da bir ticari araç kullanırken Hands-Free Georgia Yasası (O.C.G.A. §40-6-241) uyarınca hangi cihaz veya etkinliğe izin verilir?","options":["Bir mesajı okumak için elinizde bir akıllı telefon tutmak","İletişim için ticari iki yönlü telsiz veya CB telsizi kullanmak","Gösterge paneline yaslanmış bir tablette video izlemek","Arama sırasında bir cep telefonunu omzunuza dayayarak kulağınıza yaslamak"],"explanation":"O.C.G.A. §40-6-241, ticari iki yönlü telsizleri, CB telsizlerini, amatör/ham telsizleri, abonelik tabanlı acil durum iletişim cihazlarını, reçeteli tıbbi cihazları ve fabrika navigasyon/teşhis sistemlerini açıkça hariç tutar. Bir telefonu vücudun herhangi bir parçasıyla tutmak veya desteklemek, manuel mesaj atmak ve video izlemenin tümü yasaktır."},"64":{"q":"Bir Georgia eyaletler arası karayolunun en sol geçiş şeridinde bir çekici-römork kullanıyorsunuz ve arkanızdan gelen daha hızlı bir araç fark ediyorsunuz. Georgia'nın 'Slowpoke' / sol şerit yasası (O.C.G.A. §40-6-184) uyarınca ne yapmalısınız?","options":["Belirtilen hız sınırında veya üzerinde olduğunuz sürece geçiş şeridindeki konumunuzu koruyun","Geçmesine artık gerek kalmayacak şekilde sollayan araçla aynı hıza ulaşmak için hızlanın","Yasa ticari araçlar için geçerli değildir, bu nedenle sol şeritte kalabilirsiniz","Yol, trafik, hava durumu veya bir trafik kontrol cihazı orada kalmanızı gerektirmedikçe, sollayan aracın geçmesine izin vermek için geçiş şeridinden çıkın"],"explanation":"Georgia'nın 'Slowpoke' yasası (O.C.G.A. §40-6-184), geçiş şeridindeki (HOV şeridi dışındaki en soldaki şerit) bir sürücünün, arkadan daha hızlı bir araç tarafından sollandığını bildiği veya bilmesi gerektiği anda, yol/trafik koşulları, hava durumu, tehlikeler veya bir trafik kontrol cihazı o şeritte kalmayı gerektirmedikçe, geçiş yapmasını gerektirir. Hız sınırında olup olmamanızdan bağımsız olarak geçerlidir."},"65":{"q":"Georgia'nın sol şerit / 'Slowpoke' yasası (O.C.G.A. §40-6-184) amaçları doğrultusunda, 'geçiş şeridi' nasıl tanımlanır?","options":["Yüksek doluluklu araç (HOV) şeridi dışındaki en soldaki şerit","Bir aracın şu anda başka bir aracı geçtiği herhangi bir şerit","Sağ bankete en yakın şerit","Yalnızca üç şeritli bir yolun orta şeridi"],"explanation":"O.C.G.A. §40-6-184, 'geçiş şeridini' yüksek doluluklu araç (HOV) şeridi dışındaki en soldaki şerit olarak tanımlar. Bir sürücü, arkadan daha hızlı bir araç tarafından sollandıktan sonra o şeritte devam etmemelidir."},"66":{"q":"O.C.G.A. §40-6-52 uyarınca, aynı yönde üç veya daha fazla şeride sahip bir Georgia yolunda bir 'kamyon' (otobüsler ve yolcu otobüsleri hariç, altıdan fazla tekerlekli herhangi bir araç) genel olarak hangi şeritlerde seyredebilir?","options":["Trafik akışına ayak uydurduğu sürece herhangi bir şeritte","Her zaman yalnızca en sağdaki tek şeritte","Sol dönüşe hazırlanırken veya şeritlerin başka şekilde tahsis edildiği durumlar hariç, yalnızca en sağdaki iki şeritte","Sağ şeridi birleşen trafiğe açık bırakarak yalnızca orta şeritlerde"],"explanation":"O.C.G.A. §40-6-52, aynı yönde üç veya daha fazla şeride sahip bir yolda bir kamyonun (otobüsler ve yolcu otobüsleri hariç, altıdan fazla tekerlekli bir araç), sol dönüşe hazırlanırken veya Department of Transportation'ın başka şeritler tahsis ettiği durumlar hariç, en sağdaki iki şerit dışında herhangi bir şeritte seyretmesini yasa dışı kılar."},"67":{"q":"Kendi yönünüzde tam olarak iki şeride sahip bir Georgia karayolunda, O.C.G.A. §40-6-52'ye tabi bir kamyon ne zaman yasal olarak sol şeridi kullanabilir?","options":["Sağ şerit sol şeritten daha yoğun olduğunda her zaman","Fiilen başka bir aracı sollarken ve geçerken veya sol dönüşe hazırlanırken","Yalnızca gün doğumu ile gün batımı arasında","Hiçbir koşulda asla"],"explanation":"O.C.G.A. §40-6-52 uyarınca, aynı yönde iki şeride sahip bir yolda, bir kamyonun fiilen başka bir aracı sollarken ve geçerken, sol dönüşe hazırlanırken veya yasada başka şekilde öngörüldüğü durumlar hariç, sol şeritte seyretmesi yasa dışıdır."},"68":{"q":"O.C.G.A. §40-6-181 tarafından, çekici-römork dahil herhangi bir araç için, böyle bir levha bulunan bir Georgia eyaletler arası karayolunda belirlenen azami hız sınırı nedir?","options":["Saatte 55 mil","Saatte 65 mil","Saatte 75 mil","Saatte 70 mil"],"explanation":"O.C.G.A. §40-6-181, federal eyaletler arası sisteme dahil olan karayollarında ve levhalarla belirtilen, fiziksel olarak bölünmüş, tam erişim kontrollü eyalet karayollarında azami 70 mph sınırı belirler. Georgia, kamyonlar için ayrı, daha düşük bir eyalet çapında hız sınırı uygulamaz; belirtilen azami sınır tüm araçlar için geçerlidir."},"69":{"q":"Atlanta'ya doğru I-75, I-85 veya I-20 üzerinde seyahat eden ağır geçiş kamyonlarının, Georgia'nın Atlanta kamyon güzergah kuralları uyarınca genel olarak ne yapması gerekir?","options":["I-75/I-85 Downtown Connector'ı yalnızca gündüz saatlerinde kullanmak","Atlanta şehir merkezi boyunca yalnızca HOV şeritlerinde seyahat etmek","I-285'e girmeden önce bir eyalet tartı istasyonunda durmak","Mal alıyor/teslim ediyor, bir terminale ya da tamir tesisine veya sürücünün çevre içindeki ikametgahına gitmiyorlarsa I-285 üzerinden şehri atlamak"],"explanation":"Atlanta'dan geçen (şehre girmeyen) kamyonlar, I-75/I-85 Downtown Connector yerine şehrin etrafından I-285'i kullanmalıdır. I-285 içindeki bir göndericiden mal alan veya teslim eden, I-285 içindeki bir terminale/tamir tesisine giden/gelen kamyonlar için ya da çevre içindeki bir ikametgaha giden/gelen bir sürücü için istisnalar mevcuttur. Bu, iyi levhalanmış, uygulanan bir geçiş kamyonu kısıtlamasıdır."},"70":{"q":"Atlanta'nın I-75/I-85 Downtown Connector'ında, iç (en soldaki) şeritler HOV şeridi olarak ayrılmıştır. Bu, ticari bir kamyon sürücüsü için ne anlama gelir?","options":["Kamyon HOV şeridinin dışında kalmalı ve şerit kullanım sınırları nedeniyle genel olarak sağ şeritlerde kalmalıdır","Kamyon 6.000 lb'den fazla yük taşıdığında HOV şeridini istediği zaman kullanabilir","Kamyon, bir HOT şeridi gibi geçiş ücreti öderse HOV şeridini kullanabilir","Ticari araçlar her zaman yüksek doluluklu kabul edildiğinden kamyon HOV şeridini kullanabilir"],"explanation":"I-75/I-85 Downtown Connector'ın iç şeritleri HOV kısıtlamalıdır. Yük bir yolcu değildir, bu nedenle bir kamyon yüksek doluluklu araç olarak nitelendirilmez ve O.C.G.A. §40-6-52 uyarınca kamyonlar sağ şeritleri kullanmalıdır. Georgia'nın HOV şeritleri kargo ağırlığını değil, asgari sayıda yolcu gerektirir."},"71":{"q":"Georgia CDL Kılavuzu'na göre, her demiryolu-karayolu hemzemin geçidinde DURMASI gereken ticari araçlar hangileridir?","options":["Yolcu taşıyan otobüsler ve tehlikeli madde plakartları gösteren araçlar","Kargosundan bağımsız olarak 26.001 lb üzerindeki tüm ticari araçlar","Yalnızca boş kargo tankerleri, asla dolu olanlar değil","Çift veya üçlü römork çeken herhangi bir kamyon"],"explanation":"Georgia CDL Kılavuzu'na (ve 49 CFR 392.10) göre, demiryolu geçitlerinde her zaman durması gereken ticari araçlar yolcu taşıyan otobüsler ve plakartlı tehlikeli madde araçlarıdır. Bu ayrıca herhangi bir miktarda klor taşıyan araçları ve tehlikeli maddeler için kullanılan, dolu veya boş kargo tanklarını da içerir."},"72":{"q":"Georgia'da plakartlı bir tehlikeli madde aracı veya yolcu otobüsünün bir demiryolu geçidinde durması gerektiğinde, nerede durması gerekir?","options":["En yakın raydan tam olarak 25 fit","En yakın raydan 50 fit içinde ancak 15 fitten daha yakın olmamak üzere","En yakın raydan en az 100 fit","Geçit bariyerinin 10 fit içinde herhangi bir yerde"],"explanation":"Georgia CDL Kılavuzu, bir demiryolu geçidinde gerekli bir durmanın en yakın raydan en fazla 50 fit ve en az 15 fit mesafede yapılması gerektiğini belirtir. Sürücü bir tren için bakıp dinlemeli, ardından yalnızca durmadan rayları tamamen temizlemek güvenli olduğunda geçmelidir."},"73":{"q":"Georgia CDL Kılavuzu'na göre, bir ticari sürücü demiryolu raylarını geçerken NE YAPMAMALIDIR?","options":["Vites değiştirmeden geçmeye yetecek kadar düşük bir vites kullanmak","Aracın herhangi bir parçası raylar üzerindeyken vites değiştirmek","Geçmeye başlamadan önce yaklaşan bir tren için bakmak ve dinlemek","Geçmeye başlamadan önce rayları tamamen temizlemeye yer olduğundan emin olmak"],"explanation":"Georgia CDL Kılavuzu, sürücüleri demiryolu raylarını geçerken asla vites değiştirmemeleri konusunda uyarır, çünkü araç geçitte stop edebilir. Sürücü, vites değiştirmeden geçmeyi sağlayan bir vites seçmeli ve geçmeye başlamadan önce rayları tamamen temizlemeye yeterli yer olduğundan emin olmalıdır."},"74":{"q":"O.C.G.A. §40-6-163 uyarınca, kırmızı ışıkları yanıp sönen ve dur kolu açılmış duran bir okul otobüsü için ticari bir araç sürücüsü ne zaman durmalıdır?","options":["Yalnızca otobüsle aynı yönde seyahat ederken, asla karşı yönden gelirken değil","Yalnızca yol kenarında çocuklar gözle görülür şekilde varsa","Bölünmemiş bir yolda her iki yönden de otobüsle karşılaşırken veya onu sollarken, otobüs harekete geçene veya sinyaller durana kadar","Yalnızca iki şeritli yollarda, asla dört veya daha fazla şeritli yollarda değil"],"explanation":"O.C.G.A. §40-6-163, bölünmemiş yollarda, görsel sinyalleri (yanıp sönen kırmızı ışıklar/dur kolu) etkinleştirilmiş şekilde karayolunda duran bir okul otobüsüyle her iki yönden karşılaşan veya onu sollayan bir araç sürücüsünün, otobüse ulaşmadan önce durmasını ve otobüs harekete geçene ya da sinyaller kapatılana kadar devam etmemesini gerektirir."},"75":{"q":"Georgia'nın okul otobüsü yasası (O.C.G.A. §40-6-163) uyarınca, karşı yönden gelen bir sürücünün karşı tarafta çocuk alan bir okul otobüsü için durmasının GEREKMEDİĞİ yol türü hangisidir?","options":["Tek ayırıcısı boyalı bir orta çizgi olan dört şeritli bir yol","Yalnızca iki yönlü bir orta dönüş şeridiyle ayrılmış bir yol","Her yönde iki veya daha fazla şeride sahip herhangi bir yol","Çim refüj, asfaltsız alan veya fiziksel bariyerle ayrılmış ayrı yollara sahip bir karayolu"],"explanation":"O.C.G.A. §40-6-163, çim refüj, asfaltsız alan veya fiziksel bariyerle ayrılmış ayrı yollara sahip bir karayolundaki bir sürücünün, diğer ayrı yoldaki bir okul otobüsü için durmasının gerekmediğini öngörür. Boyalı bir çizgi veya bir orta dönüş şeridi bir ayırıcı DEĞİLDİR, bu nedenle sürücüler bu durumlarda yine de durmalıdır."},"76":{"q":"Bir yolun her yönde iki şeridi vardır ve yalnızca iki yönlü bir orta dönüş şeridiyle ayrılmıştır (refüj veya bariyer yoktur). Karşı taraftaki bir okul otobüsü kırmızı ışıkları yanıp sönerek durur. O.C.G.A. §40-6-163 uyarınca, karşı yönden gelen ticari bir sürücü ne yapmalıdır?","options":["Durmalı, çünkü bir orta dönüş şeridi yolları ayıran bir refüj veya fiziksel bariyer değildir","Bir ayırıcı sayıldığı için azaltılmış hızda devam etmeli, çünkü dönüş şeridi bir ayırıcı olarak kabul edilir","Yalnızca otobüs sürücünün kendi seyahat yönündeyse durmalı","Normal şekilde devam etmeli, çünkü karşı yönden gelen trafik asla okul otobüsleri için durmaz"],"explanation":"O.C.G.A. §40-6-163 uyarınca, bölünmüş karayolu istisnası yalnızca çim refüj, asfaltsız alan veya fiziksel bariyerle ayrılmış yollar için geçerlidir. Bir orta iki yönlü dönüş şeridi ve boyalı çizgiler nitelendirilmez, bu nedenle karşı yönden gelen bir sürücü sinyalleri etkinleştirilmiş okul otobüsü için durmalıdır."},"77":{"q":"Georgia CDL Kılavuzu'na göre, bir kamyon sürücüsü banket üzerinde durduktan sonra iki şeritli, çift yönlü bir yolda gerekli üç acil durum uyarı cihazını (reflektif üçgenler) nereye yerleştirmelidir?","options":["Üçünün tümü doğrudan aracın arkasında, arka tamponun 10 fit içinde","Biri tavana ve ikisi ön tampona","Aracın yaklaşık 10 fit arkasında trafiğe doğru, yaklaşık 100 fit arkasında ve aracın yaklaşık 100 fit önünde","Yaklaşık 500 fit arkada ve 500 fit önde, aracın yakınında hiçbiri olmadan"],"explanation":"Georgia CDL Kılavuzu, uyarı cihazlarının 10 dakika içinde yerleştirilmesini gerektirir: biri aracın yaklaşık 10 fit (4 adım) ilerisinde yaklaşan trafiğe doğru, biri yaklaşık 100 fit (40 adım) arkada ve biri yaklaşık 100 fit (40 adım) önde. Tepelerde veya virajlarda, yeterli uyarı sağlamak için arka cihaz daha geriye taşınır."},"78":{"q":"Georgia CDL Kılavuzu'na göre, fren sönmesini önlemek için uzun, dik bir Kuzey Georgia dağ eğiminden aşağı inmenin doğru tekniği nedir?","options":["İnişten önce düşük bir vites seçin ve güvenli bir hızda snub (uygula-sonra-bırak) yöntemiyle hafif, sabit fren kullanın","Yüksek bir viteste kalın ve hızı düşük tutmak için frenleri sürekli olarak kullanın","Yakıt tasarrufu için boşa alın ve hızı yalnızca frenlerle kontrol edin","Motoru sıcak tutmak için hızlanırken frenlere hızlıca basın"],"explanation":"Georgia CDL Kılavuzu, sürücülere dik bir eğimden aşağı inmeye başlamadan ÖNCE güvenli bir hız ve düşük bir vites seçmelerini, motor frenine güvenmelerini ve snub fren tekniğini (yaklaşık 5 mph yavaşlamak için sıkıca uygula, sonra bırak) kullanmalarını öğretir. Frenleri sürekli kullanmak veya boşta yuvarlanmak fren sönmesine ve kontrol kaybına neden olur."},"79":{"q":"Dik bir Kuzey Georgia inişinde frenleriniz sönmüş ve kamyon hız kazanıyor. Georgia CDL Kılavuzu en iyi eylemin şu olduğunu tavsiye eder:","options":["Asfaltlanmış sağ bankete çekin ve el frenini sert şekilde uygulayın","Açık bir şerit bulmak için karşı yönden gelen trafiğe doğru direksiyon kırın","Aracı hızlı şekilde yavaşlatmak için motoru kapatın","Mevcutsa bir kaçak kamyon kaçış rampasını kullanın, çünkü kaçan bir aracı güvenli şekilde durdurmak için tasarlanmıştır"],"explanation":"Georgia CDL Kılavuzu, gevşek malzeme yataklarına (ve genellikle bir yokuşa) sahip birçok dik dağ inişinde inşa edilen kaçış rampalarının, kaçan araçları güvenli şekilde durdurmak için tasarlandığını açıklar. Bir eğimde frenleriniz arıza yaparsa, mevcut bir kaçış rampasını kullanmak en güvenli eylemdir; motoru kapatmak veya hızdayken el frenini kullanmak kontrol kaybına neden olabilir."},"80":{"q":"Georgia'da hangi eyalet kurumu ticari sürücü ehliyetlerini (CDL) verir ve CDL testlerini yönetir?","options":["Georgia Department of Public Safety tescil bölümü","Georgia Department of Motor Vehicles (DMV)","Georgia Bureau of Investigation","Georgia Department of Driver Services (DDS)"],"explanation":"Georgia'nın bir 'DMV'si yoktur. Georgia Department of Driver Services (DDS), tüm CDL'leri veren ve CDL bilgi ve beceri testlerini yöneten eyalet kurumudur. Kaynak: GA DDS, Commercial License (CDL) program sayfaları (dds.georgia.gov)."},"81":{"q":"Bir CDL başvurusunda bulunurken GA DDS'e Georgia ikamet adresinizi kanıtlayan kaç belge getirmeniz gerekir?","options":["Bir CDL için ikamet belgesi gerekmez","Georgia ikamet adresinizi gösteren dört belge","Mevcut Georgia ikamet adresinizi gösteren iki belge","Georgia ikamet adresinizi gösteren bir belge"],"explanation":"GA DDS, başvuru sahiplerinin mevcut Georgia ikamet adreslerini gösteren iki kabul edilebilir belge (fatura, ipotek ekstresi veya resmi belgeler gibi) sunmasını gerektirir. Kaynak: GA DDS, 'Apply for a Commercial (CDL) License' (dds.georgia.gov)."},"82":{"q":"GA DDS, bir CDL için kimlik, Sosyal Güvenlik numarası ve yasal durumu belirlemek için hangi belge setini gerektirir?","options":["Yalnızca bir Georgia seçmen kayıt kartı","Yalnızca adınıza kayıtlı bir araç tescili","Başka kanıt olmadan yalnızca imzalı bir ikamet beyanı","Kimlik kanıtı, tam Sosyal Güvenlik numaranız ve ABD vatandaşlığı veya yasal mevcudiyet kanıtı"],"explanation":"GA DDS, iki Georgia ikamet belgesine ek olarak kimlik kanıtı (bir ABD doğum belgesi, pasaport veya vatandaşlık belgesi gibi), License/ID/Permit formunda tam Sosyal Güvenlik numaranızın doğrulanması ve ABD vatandaşlığı veya yasal mevcudiyet belgesi gerektirir. Kaynak: GA DDS, CDL başvuru gereklilikleri (dds.georgia.gov)."},"83":{"q":"Georgia'da CDL beceri (yol) testini almadan önce, bir sürücünün Commercial Learner's/Instructional Permit'i (CLP) ne kadar süre elinde tutması gerekir?","options":["En az 30 gün","En az 60 gün","En az 14 gün","Asgari bir tutma süresi yoktur"],"explanation":"GA DDS, bir CDL başvuru sahibinin, tam CDL beceri testine başvurmadan ve onu almadan önce Commercial Instructional Permit'i (CLP) en az 14 gün elinde tutmasını gerektirir. Bu, federal 14 günlük tutma süresini yansıtır. Kaynak: GA DDS, CDL Permit sayfası (dds.georgia.gov)."},"84":{"q":"Georgia'da ilk kez başvuran bir Class A veya Class B CDL başvuru sahibinin, CDL beceri testini almasına izin verilmeden önce neyi tamamlaması gerekir?","options":["Herhangi bir özel sürücü okulunda bir savunmacı sürüş kursu","Beş yıllık doğrulanabilir ticari olmayan sürüş geçmişi","Üniversite düzeyinde bir lojistik sertifikası","FMCSA Training Provider Registry'de listelenen bir sağlayıcıdan Entry-Level Driver Training (ELDT)"],"explanation":"GA DDS tarafından uygulanan federal ELDT kuralları uyarınca, ilk kez başvuran Class A ve Class B CDL başvuru sahipleri (7 Şubat 2022'de veya sonrasında alınmış bir CLP ile) beceri testini almadan önce FMCSA Training Provider Registry'ye kayıtlı bir sağlayıcıdan Entry-Level Driver Training tamamlamalıdır. Kaynak: GA DDS CDL sayfaları ve FMCSA Training Provider Registry (tpr.fmcsa.dot.gov)."},"85":{"q":"Standart (HazMat olmayan) bir Georgia CDL, yenilenmesi gerekmeden önce ne kadar süre geçerlidir?","options":["En fazla 4 yıl","En fazla 2 yıl","En fazla 10 yıl","En fazla 8 yıl"],"explanation":"Standart bir Georgia CDL en fazla 8 yıl geçerlidir. Hazardous Materials (H) onayı taşıyan CDL'ler, gerekli arka plan kontrolü yenilemesi nedeniyle daha kısa bir süre (5 yıl) geçerlidir. Kaynak: GA DDS, 'Renew a CDL' (dds.georgia.gov)."},"86":{"q":"Bir Georgia CDL sahibinin arasından seçim yapması gereken dört öz-sertifikasyon kategorisi hangileridir?","options":["Class A, Class B, Class C, Class D","Yerel, Bölgesel, Ulusal, Uluslararası","Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate, Excepted Intrastate","Gündüz, Gece, HazMat, Yolcu"],"explanation":"Her Georgia CDL sahibi, dört işletme türünden birine öz-sertifikasyon yapmalıdır: Non-excepted Interstate (NI), Excepted Interstate (EI), Non-excepted Intrastate (NA) ve Excepted Intrastate (EA). Non-excepted sürücüler geçerli bir DOT tıbbi sertifikası bulundurmalıdır. Kaynak: GA DDS, 'CDL Medical Certification and Self-Certification Process' (dds.georgia.gov)."},"87":{"q":"Hangi öz-sertifikasyon kategorisi, bir Georgia CDL sahibinin geçerli bir DOT tıbbi muayene sertifikası bulundurmasını gerektirir?","options":["Excepted Interstate (EI)","Hiçbir kategori tıbbi sertifika gerektirmez","Non-excepted Interstate (NI)","Excepted Intrastate (EA)"],"explanation":"Non-excepted kategorilerdeki sürücüler (Non-excepted Interstate ve Non-excepted Intrastate) geçerli bir DOT tıbbi muayene sertifikası bulundurmalıdır. Excepted kategoriler (EI ve EA) sertifika gerektirmez. Kaynak: GA DDS, CDL Medical ve Self-Certification süreci (dds.georgia.gov)."},"88":{"q":"18 Haziran 2025'te yürürlüğe giren FMCSA zorunluluğu itibarıyla, bir Georgia CDL sahibinin DOT tıbbi muayene sertifikası DDS'e nasıl iletilir?","options":["FMCSA'nın National Registry'sinden elektronik olarak; DDS artık kağıt tıbbi sertifikaları kabul etmez","10 gün içinde DDS merkezine faksla","En yakın DDS Customer Service Center'a kağıt bir kopya postalayarak","Kişisel bir DDS vaka çalışanına taranmış bir kopya e-postayla göndererek"],"explanation":"18 Haziran 2025 itibarıyla, tıbbi sertifikalar FMCSA tarafından National Registry of Certified Medical Examiners aracılığıyla GA DDS'e elektronik olarak iletilir. DDS artık tıbbi sertifikaları posta, faks, e-posta, çevrimiçi veya şahsen kabul etmez. Sürücünün yalnızca bir National Registry muayenecisi kullanması ve sertifikasyonunu güncel tutması gerekir. Kaynak: GA DDS basın açıklaması ve CDL Med Cert sayfası (dds.georgia.gov)."},"89":{"q":"Bir DOT tıbbi sertifikası bulundurması gereken bir Georgia CDL sürücüsü için fiziksel muayeneyi kim yapmalıdır?","options":["Bir DDS Customer Service Center memuru","Sertifikasyondan bağımsız olarak herhangi bir kayropraktör","FMCSA National Registry of Certified Medical Examiners'da listelenen bir tıbbi muayeneci","Lisanslı bir Georgia eczanesindeki herhangi bir eczacı"],"explanation":"Tıbbi sertifikasyon gerektiren Georgia CDL sürücüleri, FMCSA National Registry of Certified Medical Examiners'da listelenen bir tıbbi muayeneci tarafından muayene edilmelidir. Bu muayeneci daha sonra sertifikayı elektronik olarak iletir. Kaynak: GA DDS, CDL Medical Certification süreci (dds.georgia.gov)."},"90":{"q":"Georgia CDL beceri testini hangi üç bileşen oluşturur?","options":["Kargo yükleme, yakıt ekonomisi testi ve bir matematik sınavı","Yazılı hukuk sınavı, göz muayenesi ve bir kişilik mülakatı","HazMat işleme, müşteri hizmetleri ve bir daktilo testi","Sefer öncesi araç muayenesi, temel kontrol becerileri ve bir yolda sürüş testi"],"explanation":"Georgia CDL beceri testi, sırayla uygulanan üç bölümden oluşur: sefer öncesi araç muayenesi, temel araç kontrol becerileri ve yolda sürüş testi. CDL almak için üçünün de geçilmesi gerekir. Kaynak: GA DDS CDL Kılavuzu ve Road Test sayfaları (dds.georgia.gov)."},"91":{"q":"Georgia'da CDL beceri (yol) testini alırken, test aracını sağlamaktan kim sorumludur?","options":["Araca gerek yoktur; beceri testi yalnızca bir simülatörde yapılır","FMCSA siteye bir federal test kamyonu gönderir","GA DDS her başvuru sahibi için bir filo aracı sağlar","Başvuru sahibi, bir DDS güvenlik muayenesini geçen uygun bir araç sağlamalıdır"],"explanation":"Başvuru sahibi, test edilen CDL sınıfına uygun bir aracı, tescil kanıtı ve geçerli sigorta ile birlikte getirmelidir ve araç yol testinden önce bir DDS güvenlik muayenesini geçmelidir. Kaynak: GA DDS, Road Test sayfası (dds.georgia.gov)."},"92":{"q":"Georgia'da bir CDL'ye başvurmak için asgari yaş nedir ve belirli bir yaşa kadar hangi kısıtlama uygulanır?","options":["21 yaşında, izin gerekmeden","16 yaşında, hiçbir kısıtlama olmadan","18 yaşında, 21 yaşına kadar yalnızca eyalet içi kısıtlamalarla","25 yaşında, asla eyaletler arası sürüşe izin verilmeden"],"explanation":"Georgia'da 18 yaşında bir CDL'ye başvurabilirsiniz, ancak 18 ile 21 yaş arasındaki sürücüler genel olarak 21. yaş günlerine kadar eyalet içi (in-state) ticari sürüşle sınırlıdır. Kaynak: GA DDS, CDL başvuru ve izin sayfaları (dds.georgia.gov)."},"93":{"q":"1 Temmuz 2021'de veya sonrasında verilen bir Georgia Commercial Learner's Permit (CLP) ne kadar süre geçerlidir?","options":["90 gün","CDL verilene kadar süresiz olarak","30 gün","365 gün (bir yıl)"],"explanation":"1 Temmuz 2021'de veya sonrasında verilen bir Georgia CLP, 365 gün (bir yıl) geçerlidir. Sürücünün yine de beceri testinden önce onu en az 14 gün elinde tutması gerekir. Kaynak: GA DDS, CDL Permit sayfası (dds.georgia.gov)."},"94":{"q":"Georgia CDL sürecinde bir Commercial Instructional Permit (CLP) ne zaman gereklidir?","options":["Yeni bir CDL'ye başvururken, bir CDL'yi yükseltirken veya belirli onayları eklerken","Yalnızca CDL zaten verildikten sonra","Asla; Georgia, herhangi bir izin aşaması olmadan CDL verir","Yalnızca yurt dışı bir ehliyeti transfer eden sürücüler için"],"explanation":"GA DDS, yeni bir CDL'ye başvururken, mevcut bir CDL'yi yükseltirken veya beceri testi gerektiren belirli onayları eklerken bir Commercial Instructional Permit (CLP) gerektirir. CLP, beceri testinden önce 14 gün tutulmalıdır. Kaynak: GA DDS, CDL Permit sayfası (dds.georgia.gov)."},"95":{"q":"Georgia'da ilk kez bir Hazardous Materials (H) onayı için ELDT eğitimi ne zaman tamamlanmalıdır?","options":["Yalnızca TSA arka plan kontrolü reddedildikten sonra","HazMat bilgi testini almasına izin verilmeden önce","HazMat onayı için ELDT asla gerekli değildir","Yalnızca HazMat bilgi testini geçtikten sonra"],"explanation":"HazMat onayının bir beceri testi olmadığından, ilk kez başvuran H adayları için ELDT teori eğitimi, başvuru sahibinin HazMat bilgi testini almasına izin verilmeden önce tamamlanmalıdır. Kaynak: FMCSA Training Provider Registry / ELDT Applicability (tpr.fmcsa.dot.gov) ve GA DDS CDL sayfaları."},"96":{"q":"Georgia'da hangi onaylar, ilk kez başvuran adayların test öncesi ELDT tamamlamasını gerektirir?","options":["Yalnızca Tanker (N), çiftler/üçlüler (T) ve hava freni kaldırma","Yalnızca hava freni kısıtlaması kaldırma","Hiçbir onay asla ELDT gerektirmez","School bus (S), passenger (P) ve hazardous materials (H) onayları"],"explanation":"GA DDS tarafından uygulanan federal ELDT kuralları uyarınca, School Bus (S), Passenger (P) ve Hazardous Materials (H) onayları için ilk kez başvuran adaylar, geçerli beceri veya bilgi testini almadan önce kayıtlı bir sağlayıcıdan ELDT tamamlamalıdır. Kaynak: FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) ve GA DDS."},"97":{"q":"Beceri testine ek olarak, bir Georgia CDL başvuru sahibinin DDS Customer Service Center'da neyi geçmesi gerekir?","options":["Bir fiziksel güç testi ve bir yüzme testi","Yalnızca bir kredi kontrolü","Gerekli yazılı bilgi sınav(lar)ı ve bir görme muayenesi","Bir federal gelir vergisi beyan incelemesi"],"explanation":"Beceri testinden önce, bir Georgia CDL başvuru sahibinin, aranan sınıf ve onaylar için gerekli yazılı bilgi sınav(lar)ını geçmesi ve DDS Customer Service Center'da bir görme muayenesini geçmesi gerekir. Kaynak: GA DDS, CDL Permit ve başvuru sayfaları (dds.georgia.gov)."},"98":{"q":"Georgia CDL ücretleri hakkında hangi ifade doğrudur?","options":["Georgia'da CDL ücretlerini yalnızca FMCSA tahsil eder","Ücretler her tıbbi muayeneci tarafından bireysel olarak belirlenir","Tüm GA DDS CDL hizmetleri kalıcı olarak ücretsizdir","Tam ücret miktarları GA DDS tarafından belirlenir ve değişebilir, bu nedenle başvuru sahipleri güncel ücretleri DDS ile doğrulamalıdır"],"explanation":"GA DDS izinler, test ve lisanslama için (örneğin, izin ve yol testi ücretleri) ücret alır, ancak tam miktarlar DDS tarafından belirlenir ve zamanla değişebilir. Başvuru sahipleri, başvurmadan önce resmi DDS 'Fees and Terms' bilgilerinde güncel ücretleri onaylamalıdır. Kaynak: GA DDS (dds.georgia.gov)."},"99":{"q":"Bir Georgia CDL sürücüsü, ticari işletme türü konusunda yenileme sırasında ne yapmalıdır?","options":["Tek bir ticari işletme türüne öz-sertifikasyon yapmalı ve non-excepted ise dosyada güncel bir DOT tıbbi sertifikası tutmalıdır","Kategoriden bağımsız olarak her yenilemede tam yol beceri testini yeniden almalıdır","CDL'yi teslim etmeli ve yepyeni bir başvuru sahibi olarak yeniden başvurmalıdır","Eski bir işverenden noter onaylı bir mektup sunmalıdır"],"explanation":"Yenileme sırasında, bir Georgia CDL sahibi tek bir ticari işletme türüne (dört kategoriden birine) öz-sertifikasyon yapmalı ve non-excepted sürücüler, artık FMCSA aracılığıyla elektronik olarak iletilen güncel bir DOT tıbbi sertifikası bulundurmalıdır. Kaynak: GA DDS, 'Renew a CDL' ve CDL Med Cert sayfaları (dds.georgia.gov)."}},"es":{"0":{"q":"En las carreteras de Georgia, ¿cuál es el ancho exterior total máximo de un vehículo y su carga, excluyendo los espejos y los accesorios?","options":["96 pulgadas","102 pulgadas","108 pulgadas","120 pulgadas"],"explanation":"O.C.G.A. §32-6-23 establece que ningún vehículo podrá exceder un ancho exterior total, incluida cualquier carga, de 102 pulgadas, sin contar los espejos ni los accesorios, en ninguna calle, camino o carretera de Georgia. (Fuente: O.C.G.A. §32-6-23; Manual CDL de GA DDS)"},"1":{"q":"Salvo donde se autorice un límite mayor, ¿cuál es la altura máxima de un vehículo, vacío o con carga, en los caminos de Georgia?","options":["12 pies 6 pulgadas","13 pies 0 pulgadas","14 pies 6 pulgadas","13 pies 6 pulgadas"],"explanation":"O.C.G.A. §32-6-22(a) establece que, salvo lo autorizado mediante permiso, ningún vehículo vacío o con carga podrá exceder una altura de 13 pies 6 pulgadas en los caminos de Georgia. (Fuente: O.C.G.A. §32-6-22)"},"2":{"q":"En Georgia, ¿cuál es la longitud máxima de un semirremolque en una combinación de tractocamión-semirremolque, en ausencia de restricciones señalizadas?","options":["45 pies","48 pies","53 pies","57 pies"],"explanation":"O.C.G.A. §32-6-24(b)(1)(B) establece que las combinaciones de tractocamión-semirremolque deberán tener semirremolques que no excedan 53 pies de longitud, salvo que haya letreros que indiquen restricciones de longitud para el semirremolque. (Fuente: O.C.G.A. §32-6-24)"},"3":{"q":"En una combinación de tractocamión-semirremolque-remolque (remolques dobles) en Georgia, ¿cuál es la longitud máxima de cada remolque y semirremolque?","options":["24 pies","28 pies","33 pies","40 pies"],"explanation":"O.C.G.A. §32-6-24(b)(1)(A) establece que las combinaciones de tractocamión-semirremolque-remolque deberán tener remolques y semirremolques que no excedan 28 pies de longitud cada uno. (Fuente: O.C.G.A. §32-6-24)"},"4":{"q":"En los caminos de Georgia que no forman parte del sistema interestatal o STAA, ¿cuál es la longitud total máxima de una combinación de tractocamión-semirremolque o tractocamión-semirremolque-remolque, en ausencia de restricciones señalizadas?","options":["65 pies","75 pies","100 pies","110 pies"],"explanation":"O.C.G.A. §32-6-24(b)(2)(C) establece que, en caminos que no forman parte del sistema interestatal o STAA, dichas combinaciones deberán tener una longitud total que no exceda 100 pies, salvo que haya letreros que indiquen restricciones de longitud. (Fuente: O.C.G.A. §32-6-24)"},"5":{"q":"¿Cuál es el peso bruto total máximo autorizado para cualquier vehículo y carga en las carreteras de Georgia?","options":["73,280 libras","88,000 libras","100,000 libras","80,000 libras"],"explanation":"O.C.G.A. §32-6-26(c)(1)(A) y (d)(1)(A) limitan ambos el peso bruto total máximo autorizado para cualquier vehículo y carga a 80,000 libras, tanto en carreteras nacionales como no nacionales. (Fuente: O.C.G.A. §32-6-26; Manual CDL de GA DDS)"},"6":{"q":"En una carretera nacional de Georgia (como una interestatal), ¿cuál es la carga máxima autorizada sobre un eje tándem?","options":["30,000 libras","40,680 libras","46,000 libras","34,000 libras"],"explanation":"O.C.G.A. §32-6-26(d)(1)(B) fija la carga máxima sobre cualquier eje tándem en las carreteras nacionales de Georgia en 34,000 libras, coincidiendo con el límite federal. (Fuente: O.C.G.A. §32-6-26; Manual CDL de GA DDS)"},"7":{"q":"En las carreteras de Georgia que NO son carreteras nacionales, ¿cuál es la carga máxima autorizada sobre un eje tándem?","options":["34,000 libras","37,340 libras","40,680 libras","46,000 libras"],"explanation":"O.C.G.A. §32-6-26(c)(1)(A) fija la carga máxima del eje tándem en 40,680 libras en las carreteras de Georgia que no son carreteras nacionales. (Fuente: O.C.G.A. §32-6-26)"},"8":{"q":"Según O.C.G.A. §32-6-26, ¿cómo se define un \"eje simple\" a efectos de peso en Georgia?","options":["Todas las ruedas cuyos centros queden comprendidos entre dos planos verticales transversales paralelos separados 40 pulgadas","Todas las ruedas cuyos centros queden dentro de 96 pulgadas entre sí","Cualquier par de ejes consecutivos separados más de 40 pulgadas","Únicamente el eje de dirección de una unidad motriz"],"explanation":"O.C.G.A. §32-6-26(a)(4) define un \"eje simple\" como todas las ruedas cuyos centros puedan quedar comprendidos entre dos planos verticales transversales paralelos separados 40 pulgadas. (Fuente: O.C.G.A. §32-6-26)"},"9":{"q":"Según la ley vigente de Georgia, ¿cómo se define un \"eje tándem\" a efectos de peso?","options":["Dos o más ejes consecutivos cuyos centros estén separados más de 40 pero no más de 96 pulgadas","Dos o más ejes consecutivos, excluyendo el eje de dirección, cuyos centros estén separados más de 40 pero no más de 216 pulgadas","Exactamente dos ejes separados no más de 8 pies, incluyendo el eje de dirección","Cualquier grupo de ejes dentro de 12 pies entre sí sin importar el eje de dirección"],"explanation":"O.C.G.A. §32-6-26(a)(7) define un \"eje tándem\" (después del 1 de abril de 1988) como dos o más ejes consecutivos, excluyendo el eje de dirección, cuyos centros puedan quedar comprendidos entre planos verticales paralelos separados más de 40 pulgadas pero no más de 216 pulgadas. (Fuente: O.C.G.A. §32-6-26)"},"10":{"q":"¿Qué fórmula utiliza Georgia para determinar el peso bruto máximo permitido sobre un grupo de dos o más ejes consecutivos?","options":["La fórmula federal de puentes (federal bridge formula)","La fórmula de la clasificación de peso bruto combinado","La tarifa de espaciamiento de ejes de Georgia","La regla de 18,000 libras por eje"],"explanation":"O.C.G.A. §32-6-26(a)(1) y (d) adoptan la fórmula federal de puentes, W = 500((LN/N-1) + 12N + 36), para determinar el peso bruto máximo sobre cualquier grupo de dos o más ejes consecutivos en las carreteras nacionales de Georgia. (Fuente: O.C.G.A. §32-6-26; Manual CDL de GA DDS)"},"11":{"q":"En la fórmula de puentes de Georgia W = 500((LN/N-1) + 12N + 36), ¿qué representa la variable \"N\"?","options":["El número de ejes en el grupo considerado","La distancia en pies entre los ejes extremos del grupo","El peso neto de la carga en miles de libras","El número de neumáticos en el eje más pesado"],"explanation":"En O.C.G.A. §32-6-26(a)(1), N es el número de ejes en el grupo considerado, L es la distancia en pies entre los ejes extremos del grupo, y W es el peso bruto sobre ese grupo. (Fuente: O.C.G.A. §32-6-26)"},"12":{"q":"Según O.C.G.A. §32-6-26, ¿cuál es el peso bruto total máximo para un vehículo equipado con solo cuatro ejes en carreteras no nacionales de Georgia?","options":["56,000 libras","70,000 libras","73,280 libras","80,000 libras"],"explanation":"O.C.G.A. §32-6-26(c)(1)(C) establece que para cualquier vehículo equipado con cuatro ejes, el peso bruto total máximo autorizado para el vehículo y la carga será de 70,000 libras. (Fuente: O.C.G.A. §32-6-26)"},"13":{"q":"En un sistema de caminos de condado de Georgia, ¿cuál es el peso bruto total máximo permitido para un vehículo que no está realizando una recogida o entrega en ese camino?","options":["46,000 libras","56,000 libras","70,000 libras","80,000 libras"],"explanation":"O.C.G.A. §32-6-26(f) limita el peso bruto total máximo en un sistema de caminos de condado a 56,000 libras, salvo cuando el vehículo esté realizando una recogida o entrega en dicho camino (o en una ruta local de camiones designada que califique). (Fuente: O.C.G.A. §32-6-26)"},"14":{"q":"¿Cuándo puede un vehículo que transporta productos forestales, aves vivas, algodón, alimento para ganado, granito, residuos sólidos o concreto recién mezclado exceder los límites normales de eje/peso bruto de Georgia en una carretera no nacional sin un permiso?","options":["Nunca; siempre se requiere un permiso para exceder los límites","Solo de noche y solo en carreteras interestatales","Cuando el peso del eje simple se mantenga en 23,000 lbs o menos, el del eje tándem en 46,000 lbs o menos y el peso bruto en 80,000 lbs o menos","Cuando el peso bruto se mantenga en 100,000 lbs o menos sin importar el peso por eje"],"explanation":"O.C.G.A. §32-6-26(g)(1) permite estos transportes agrícolas y de productos básicos especificados en carreteras no nacionales sin un permiso solo cuando la carga del eje simple no exceda 23,000 lbs, la del eje tándem no exceda 46,000 lbs y el peso bruto total no exceda 80,000 lbs. (Fuente: O.C.G.A. §32-6-26)"},"15":{"q":"La exención de tamaño de Georgia para EQUIPOS agrícolas, de cultivo o de manejo forestal (que les permite exceder los límites de ancho y longitud sin un permiso) aplica bajo qué condición?","options":["Solo en el sistema interestatal y solo de noche","Durante las horas de luz diurna en caminos que no forman parte del sistema interestatal, dentro de 40 millas de la propiedad del dueño o del concesionario","En cualquier parte del estado a cualquier hora sin límite de distancia","Solo cuando un vehículo escolta con luces ámbar lo acompaña en la interestatal"],"explanation":"O.C.G.A. §32-6-25 exime a los equipos agrícolas, de cultivo o de manejo forestal de los límites de ancho y longitud, sin un permiso, cuando se operan durante las horas de luz diurna en un camino público que no forma parte del sistema interestatal dentro de un radio de 40 millas de la propiedad del dueño o del concesionario. La exención NO aplica a los vehículos que acarrean o transportan productos forestales. (Fuente: O.C.G.A. §32-6-25)"},"16":{"q":"¿Quién emite en Georgia un permiso que autoriza a un vehículo o carga a exceder los límites máximos de tamaño o peso establecidos por la ley?","options":["El Departamento de Transporte (GDOT), previa solicitud por escrito y demostración de causa justificada","El sheriff del condado donde comienza el viaje","Cualquier oficial de la estación de pesaje al momento de la inspección","El Departamento de Servicios al Conductor junto con la solicitud de la CDL"],"explanation":"O.C.G.A. §32-6-28(a) autoriza al comisionado del GDOT (o a un funcionario designado) a emitir, previa solicitud por escrito y demostración de causa justificada, un permiso que permita a un vehículo y carga cuyo peso, ancho, longitud o altura exceda el máximo legal. Los permisos se obtienen a través del GDOT/Departamento de Seguridad Pública (sistema GAPROS). (Fuente: O.C.G.A. §32-6-28; GDOT)"},"17":{"q":"Según O.C.G.A. §32-6-28, un permiso ANUAL de sobredimensión/sobrepeso de Georgia NO puede emitirse para autorizar un vehículo cuyo peso bruto total exceda qué cantidad?","options":["80,000 libras","120,000 libras","150,000 libras","100,000 libras"],"explanation":"O.C.G.A. §32-6-28(b)(1)(A) establece que un permiso anual no podrá autorizar la operación de un vehículo cuyo peso bruto total exceda 100,000 libras (ni cuyo peso de eje simple exceda 25,000 lbs, longitud exceda 100 pies, ancho exceda 102 pulgadas / ancho de carga 144 pulgadas, o altura exceda 14 pies 6 pulgadas). (Fuente: O.C.G.A. §32-6-28; GDOT)"},"18":{"q":"Según la regla básica de peso de Georgia, ¿cuál es la carga máxima base sobre un eje simple (neumáticos de alta presión) antes de aplicar la tolerancia legal?","options":["12,000 libras","18,000 libras","20,000 libras","16,000 libras"],"explanation":"O.C.G.A. §32-6-26(b)(1) prohíbe una carga sobre cualquier eje simple (neumáticos de alta presión, de caucho macizo o de amortiguación) que exceda 16,000 libras en más del 13 por ciento, por lo que la cifra base es 16,000 lbs y la tolerancia del 13% da alrededor de 18,080 lbs. (Fuente: O.C.G.A. §32-6-26)"},"19":{"q":"Según O.C.G.A. §32-6-27, antes de que se permita mover un vehículo con sobrepeso en Georgia, el operador debe descargar todo el peso bruto que exceda el límite legal en más de qué cantidad?","options":["2,000 libras","4,000 libras","6,000 libras","10,000 libras"],"explanation":"O.C.G.A. §32-6-27(e) exige al dueño/operador de un vehículo con sobrepeso, además de pagar los daños evaluados, descargar todo el peso bruto que exceda en 6,000 libras el límite legal de peso antes de que se permita mover el vehículo. (Fuente: O.C.G.A. §32-6-27)"},"20":{"q":"En Georgia, ¿qué clase de CDL se requiere para operar una combinación de vehículos con una clasificación de peso bruto combinado (GCWR) de 26,001 libras o más, donde el vehículo remolcado tiene un GVWR de más de 10,000 libras?","options":["Clase B","Clase C","Clase D","Clase A"],"explanation":"Una CDL de Clase A de Georgia cubre cualquier combinación de vehículos con un GCWR de 26,001+ libras donde la unidad remolcada excede 10,000 libras de GVWR. Un titular de Clase A también puede operar vehículos de Clase B y C con los avales correspondientes. Fuente: Georgia DDS, 'Apply for a Commercial (CDL) License (Class A, B, C).'"},"21":{"q":"Según las reglas de Georgia DDS, una CDL de Clase B autoriza a un conductor a operar ¿cuál de los siguientes?","options":["Cualquier combinación de vehículos donde la unidad remolcada excede 10,000 libras","Cualquier vehículo individual con un GVWR de 26,001+ libras, que remolque una unidad de no más de 10,000 libras","Solo vehículos diseñados para transportar 16 o más pasajeros","Solo vehículos con placas para materiales peligrosos"],"explanation":"Una CDL de Clase B de Georgia cubre vehículos individuales con un GVWR de 26,001+ libras, incluidos los que remolcan un vehículo de no más de 10,000 libras de GVWR. Un titular de Clase B también puede operar vehículos de Clase C con los avales correspondientes. Fuente: Georgia DDS, 'Apply for a Commercial (CDL) License.'"},"22":{"q":"En Georgia, una CDL de Clase C se emite específicamente para qué tipo de vehículo?","options":["Cualquier combinación de vehículos de más de 26,001 libras de GCWR","Cualquier vehículo individual de más de 26,001 libras de GVWR","Un vehículo individual (o combinación) que no cumple con la Clase A o B y que transporta 16+ pasajeros incluido el conductor, o que lleva placas para materiales peligrosos","Cualquier automóvil de pasajeros o camioneta pickup de menos de 26,001 libras"],"explanation":"Una CDL de Clase C de Georgia aplica a un vehículo individual, o combinación, que no cumple con la definición de Clase A o B pero que está diseñado para transportar 16 o más pasajeros (incluido el conductor) o que se usa para transportar materiales peligrosos que requieren placas. Fuente: Georgia DDS, 'Apply for a Commercial (CDL) License.'"},"23":{"q":"¿Cuál es la edad mínima para solicitar cualquier CDL de Georgia?","options":["18 años","16 años","21 años","25 años"],"explanation":"Georgia DDS exige que los solicitantes de CDL tengan al menos 18 años de edad. Los solicitantes de 18 a 21 años están restringidos a la conducción intraestatal (solo dentro de Georgia) hasta que cumplan 21. Fuente: Georgia DDS, 'Apply for a Commercial (CDL) License.'"},"24":{"q":"Un titular de CDL de Georgia de 19 años está restringido ¿de qué manera?","options":["Restringido de tener cualquier aval","Restringido a la conducción intraestatal (solo dentro de Georgia) hasta cumplir 21 años","Restringido solo a vehículos de Clase C","Restringido de conducir de noche"],"explanation":"Georgia emite CDL a solicitantes de 18 años o más, pero los conductores de 18 a 21 años llevan una restricción de 'Georgia Only' (intraestatal). El conductor debe cumplir 21 años y visitar un Centro de Servicio al Cliente para que se le retire la restricción para la conducción interestatal. Fuente: Georgia DDS, 'Apply for a Commercial (CDL) License.'"},"25":{"q":"Un titular de CDL de Georgia quiere retirar la restricción de solo intraestatal para poder conducir cruzando líneas estatales. ¿Qué debe ocurrir?","options":["Debe tener la CDL durante al menos cinco años primero","Debe cumplir 21 años y visitar un Centro de Servicio al Cliente de DDS para que se le retire la restricción de 'Georgia Only'","Debe agregar un aval de HazMat","Debe aprobar una prueba de habilidades interestatal adicional a los 18 años"],"explanation":"Los conductores de 18 a 21 años están restringidos a la conducción intraestatal. Para obtener privilegios interestatales, el conductor debe cumplir 21 años y visitar un Centro de Servicio al Cliente de DDS para retirar la restricción de 'Georgia Only'. Fuente: Georgia DDS, 'Apply for a Commercial (CDL) License.'"},"26":{"q":"¿Qué aval se requiere en Georgia para conducir un vehículo que transporta materiales peligrosos en cantidades que requieren placas?","options":["Aval N (Tanque)","Aval T (Dobles/Triples)","Aval P (Pasajeros)","Aval H (HazMat)"],"explanation":"El aval H (HazMat) se requiere para acarrear materiales peligrosos que requieren placas. En Georgia exige aprobar una prueba de conocimientos, una verificación de antecedentes de la TSA y la toma de huellas dactilares tanto para la emisión por primera vez como para las renovaciones. Fuente: Georgia DDS, 'Adding CDL Endorsements.'"},"27":{"q":"En Georgia, ¿qué requisito federal adicional debe cumplirse para el aval de HazMat (H) que NO se requiere para el aval de Tanque (N)?","options":["Aprobar una prueba de habilidades (de manejo) por separado","Tener el aval durante 14 días antes de usarlo","Aprobar una evaluación de amenaza a la seguridad de la TSA con toma de huellas dactilares","Obtener primero un aval de pasajeros"],"explanation":"El aval de HazMat exige aprobar una verificación de antecedentes de la TSA (evaluación de amenaza a la seguridad), y se requieren huellas dactilares tanto para la emisión por primera vez como para las renovaciones. El aval de Tanque solo requiere una prueba de conocimientos. Fuente: Georgia DDS, 'Adding CDL Endorsements.'"},"28":{"q":"Según Georgia DDS, ¿cómo se obtiene el aval N (Tanque)?","options":["Aprobando tanto una prueba de conocimientos como una prueba de habilidades","Aprobando solo una prueba de habilidades","Aprobando solo una prueba de conocimientos","Aprobando solo una verificación de antecedentes de la TSA"],"explanation":"En Georgia el aval N (Tanque) exige aprobar solo una prueba de conocimientos y es válido para las CDL de Clase A y B. Fuente: Georgia DDS, 'Adding CDL Endorsements.'"},"29":{"q":"¿Qué aval de CDL de Georgia es válido únicamente para una CDL de Clase A y se obtiene aprobando una prueba de conocimientos?","options":["Aval T (Dobles/Triples)","Aval P (Pasajeros)","Aval S (Autobús Escolar)","Aval N (Tanque)"],"explanation":"El aval T (Remolque Doble/Triple) es válido únicamente para una CDL de Clase A y requiere una prueba de conocimientos. No puede obtenerse con un Permiso de Aprendiz Comercial; el solicitante ya debe tener una CDL válida. Fuente: Georgia DDS, 'Adding CDL Endorsements.'"},"30":{"q":"¿Qué requiere Georgia para obtener el aval P (Pasajeros)?","options":["Aprobar solo una prueba de conocimientos","Aprobar tanto una prueba de conocimientos como una prueba de habilidades","Aprobar solo una prueba de habilidades","Aprobar solo una verificación de antecedentes de la TSA"],"explanation":"En Georgia, el aval P (Pasajeros) exige aprobar tanto una prueba de conocimientos como una prueba de habilidades, y es válido para las CDL de Clase A, B y C. Fuente: Georgia DDS, 'Adding CDL Endorsements.'"},"31":{"q":"¿Para qué dos avales exige Georgia DDS TANTO una prueba de conocimientos COMO una prueba de habilidades?","options":["N (Tanque) y T (Dobles/Triples)","H (HazMat) y N (Tanque)","P (Pasajeros) y S (Autobús Escolar)","T (Dobles/Triples) y H (HazMat)"],"explanation":"En Georgia, los avales de Pasajeros (P) y de Autobús Escolar (S) requieren cada uno aprobar tanto una prueba de conocimientos como una prueba de habilidades. Los avales N, T y H requieren solo una prueba de conocimientos. Fuente: Georgia DDS, 'Adding CDL Endorsements.'"},"32":{"q":"A partir del 7 de febrero de 2022, ¿qué grupo de solicitantes de CDL de Georgia está sujeto a los requisitos de Capacitación de Conductor de Nivel Inicial (ELDT)?","options":["Solo los solicitantes que buscan una CDL de Clase C","Los solicitantes que obtienen una Clase A o B por primera vez, ascienden a una clase superior o agregan un aval de Autobús Escolar, Pasajeros o HazMat","Solo los conductores mayores de 21 años","Solo los solicitantes que renuevan una CDL existente sin cambios"],"explanation":"Bajo las reglas de ELDT de la FMCSA adoptadas por Georgia, a partir del 7 de febrero de 2022, todos los conductores de nivel inicial que obtengan una CDL de Clase A o B por primera vez, asciendan a una clase superior o agreguen un aval de Autobús Escolar (S), Pasajeros (P) o HazMat (H) deben completar la ELDT. Fuente: Georgia DDS, 'Apply for a Commercial (CDL) License' / 'Adding CDL Endorsements.'"},"33":{"q":"¿Dónde debe completarse y registrarse la Capacitación de Conductor de Nivel Inicial (ELDT) de un solicitante de CDL de Georgia?","options":["En cualquier escuela de manejo privada que el solicitante elija, sin registro","Únicamente en un Centro de Servicio al Cliente de Georgia DDS","Mediante un cuestionario en línea sin un proveedor formal","Con un proveedor de capacitación incluido en el Registro de Proveedores de Capacitación (TPR) de la FMCSA"],"explanation":"La ELDT debe ser impartida por un proveedor incluido en el Registro de Proveedores de Capacitación (TPR) de la FMCSA, y la finalización se reporta al registro antes de que el conductor pueda presentar la prueba de habilidades de la CDL o la de conocimientos de HazMat. Fuente: Reglamentos de ELDT de la FMCSA referidos por Georgia DDS."},"34":{"q":"Antes de solicitar una CDL completa de Georgia, ¿durante cuánto tiempo debe un solicitante tener el Permiso de Aprendiz Comercial (CLP)?","options":["Al menos 30 días","Al menos 60 días","Al menos 14 días","Al menos 6 meses"],"explanation":"Georgia exige que los solicitantes de CDL tengan el Permiso de Aprendiz Comercial (CLP) durante un mínimo de 14 días antes de presentar la prueba de habilidades de la CDL / solicitar la CDL completa. Fuente: Georgia DDS, 'CDL Permit' y preguntas frecuentes sobre licencias CDL."},"35":{"q":"¿Qué debe aprobar un solicitante de Georgia para que se le emita un Permiso de Aprendiz Comercial (CLP)?","options":["El/los examen(es) escrito(s) de conocimientos requeridos","Solo la prueba de habilidades (de manejo) de la CDL","Una verificación de antecedentes de la TSA","Solo una prueba de la vista"],"explanation":"Para obtener un CLP de Georgia (Clase AP o BP), el solicitante debe tener una licencia de conducir regular válida de Georgia y aprobar el/los examen(es) escrito(s) de conocimientos requeridos. La prueba de habilidades viene después, tras el período de espera de 14 días. Fuente: Georgia DDS, 'Apply for a Commercial Permit (Class AP or BP).'"},"36":{"q":"Para un CLP de Georgia emitido en o después del 1 de julio de 2021, ¿durante cuánto tiempo es válido el permiso?","options":["30 días","180 días","5 años","365 días"],"explanation":"Un Permiso de Aprendiz Comercial (CLP) de Georgia emitido en o después del 1 de julio de 2021 es válido por 365 días. Fuente: Georgia DDS, 'CDL Permit.'"},"37":{"q":"¿Cuál de los siguientes se requiere antes de que una persona pueda obtener un Permiso de Aprendiz Comercial (CLP) de Georgia?","options":["Tener una licencia de conducir regular válida de Georgia","Ya tener un aval de HazMat","Completar una verificación de antecedentes de la TSA","Tener una CDL de Clase A"],"explanation":"Georgia DDS exige que los solicitantes de CLP tengan una licencia de conducir regular válida de Georgia antes de solicitar el permiso comercial. Fuente: Georgia DDS, 'Apply for a Commercial Permit (Class AP or BP).'"},"38":{"q":"Al solicitar una CDL de Georgia, ¿qué combinación de documentos exige DDS que un solicitante presente?","options":["Comprobante de identidad, número de Seguro Social, presencia legal y dos comprobantes de residencia en Georgia","Solo una tarjeta de Seguro Social","Solo una tarjeta de registro de votante de Georgia","Solo un pasaporte, sin comprobante de residencia"],"explanation":"Georgia DDS exige comprobante de identidad (p. ej., un acta de nacimiento certificada o un pasaporte de EE. UU.), comprobante del número de Seguro Social, comprobante de presencia legal y dos documentos de fuentes distintas que comprueben la residencia en Georgia. Fuente: Georgia DDS, 'Apply for a Commercial (CDL) License.'"},"39":{"q":"Un conductor con CDL de Georgia que opera únicamente dentro de Georgia y debe cumplir con los requisitos de calificación del conductor de la FMCSA debe elegir ¿qué categoría de autocertificación médica?","options":["Interestatal No Exento (NI)","Interestatal Exento (EI)","Intraestatal Exento (EA)","Intraestatal No Exento (NA)"],"explanation":"Georgia DDS usa cuatro categorías de autocertificación: Interestatal No Exento (NI), Interestatal Exento (EI), Intraestatal No Exento (NA) e Intraestatal Exento (EA). Un conductor que opera únicamente en Georgia (intraestatal) y que debe cumplir con los requisitos de calificación médica selecciona Intraestatal No Exento (NA). Todos los titulares de CDL deben presentar una autocertificación ante DDS. Fuente: Georgia DDS, 'CDL Medical Certification and Self-Certification Process.'"},"40":{"q":"En Georgia, ¿cuál es la concentración máxima de alcohol en sangre (BAC) con la que una persona puede operar legalmente un vehículo motorizado comercial (CMV)?","options":["0.08 o más es el límite","Es ilegal con 0.04 o más","0.10 o más es el límite","Cualquier cantidad superior a 0.02 es ilegal"],"explanation":"Es ilegal operar un CMV en Georgia con un BAC de 0.04 o más, la mitad del límite de 0.08 para conductores no comerciales. Fuente: Manual CDL de Georgia (DDS), Descalificaciones de la CDL; 49 CFR 383.51(b)."},"41":{"q":"Un titular de CDL de Georgia es condenado por una primera ofensa mayor, como un DUI en un CMV, mientras NO transporta materiales peligrosos. ¿Por cuánto tiempo se descalifica la CDL?","options":["Al menos 60 días","Al menos 6 meses","Al menos 1 año","Al menos 3 años"],"explanation":"Una primera ofensa mayor (DUI, BAC 0.04+, negativa, abandono del lugar, uso delictivo de un CMV, etc.) resulta en una descalificación de al menos 1 año. Fuente: Manual CDL de Georgia (DDS); 49 CFR 383.51(b) Tabla 1."},"42":{"q":"¿Cómo cambia el período de descalificación si un conductor con CDL de Georgia comete una primera ofensa mayor mientras opera un CMV con placas para materiales peligrosos?","options":["Aumenta a un mínimo de 3 años","Se mantiene en un mínimo de 1 año","Aumenta a un mínimo de 5 años","Resulta en una prohibición vitalicia inmediata"],"explanation":"Cuando una primera ofensa mayor ocurre durante el transporte de materiales peligrosos que requieren placas, la descalificación mínima aumenta de 1 año a 3 años. Fuente: Manual CDL de Georgia (DDS); 49 CFR 383.51(b) Tabla 1."},"43":{"q":"¿Cuál es el período de descalificación para un titular de CDL de Georgia condenado por una SEGUNDA ofensa mayor en un incidente separado?","options":["3 años adicionales","10 años adicionales","120 días adicionales","Descalificación de por vida"],"explanation":"Una segunda condena por cualquier combinación de ofensas mayores en incidentes separados resulta en la descalificación vitalicia de la CDL. Fuente: Manual CDL de Georgia (DDS); 49 CFR 383.51(b) Tabla 1."},"44":{"q":"Según la ley de consentimiento implícito de Georgia, ¿qué le sucede a un titular de CDL que se niega a someterse a una prueba química de alcohol o drogas tras una solicitud legal?","options":["Nada, ya que la negativa no puede usarse como evidencia","Solo se impone una multa pero la CDL no se ve afectada","El conductor es descalificado igual que si fuera condenado por DUI","El conductor recibe una penalización de 60 días por violación grave"],"explanation":"Negarse a una prueba química se trata como una ofensa mayor, conllevando la misma descalificación que una condena por DUI: al menos 1 año por una primera ofensa y de por vida por una segunda. Fuente: Manual CDL de Georgia (DDS); O.C.G.A. 40-5-67.1 (consentimiento implícito); 49 CFR 383.51(b)."},"45":{"q":"A un conductor con CDL en Georgia se le detecta cualquier cantidad medible de alcohol por debajo de 0.04 mientras está de servicio. ¿Cuál es la consecuencia?","options":["Una orden de fuera de servicio que pone al conductor fuera de servicio durante 24 horas","Descalificación inmediata de la CDL por 1 año","Una descalificación de 60 días por violación grave","Ninguna consecuencia porque el BAC es inferior a 0.04"],"explanation":"Cualquier alcohol detectable por debajo de 0.04 no activa una descalificación por ofensa mayor, pero sí exige que el conductor sea puesto fuera de servicio durante 24 horas. Fuente: Manual CDL de Georgia (DDS); 49 CFR 392.5."},"46":{"q":"¿Cuál de los siguientes se clasifica como una \"violación de tránsito grave\" para un titular de CDL de Georgia en lugar de una ofensa mayor?","options":["Conducir un CMV con un BAC de 0.04 o más","Usar un CMV para cometer un delito grave","Exceso de velocidad de 15 mph o más por encima del límite señalizado","Abandonar el lugar de un accidente que involucra un CMV"],"explanation":"El exceso de velocidad (15+ mph por encima del límite) es una violación de tránsito grave. El DUI, el uso delictivo y el abandono del lugar son ofensas mayores con penas mucho más severas. Fuente: Manual CDL de Georgia (DDS); 49 CFR 383.51(c) Tabla 2."},"47":{"q":"Un titular de CDL de Georgia es condenado por DOS violaciones de tránsito graves en incidentes separados dentro de un período de 3 años. ¿Cuál es el período de descalificación?","options":["Al menos 30 días","Al menos 60 días","Al menos 120 días","Al menos 1 año"],"explanation":"Dos violaciones de tránsito graves dentro de 3 años resultan en una descalificación de al menos 60 días. Fuente: Manual CDL de Georgia (DDS); 49 CFR 383.51(c) Tabla 2."},"48":{"q":"Un titular de CDL de Georgia es condenado por TRES violaciones de tránsito graves en incidentes separados dentro de un período de 3 años. ¿Cuál es el período de descalificación?","options":["Al menos 60 días","Al menos 90 días","Al menos 120 días","Al menos 1 año"],"explanation":"Tres violaciones de tránsito graves dentro de 3 años resultan en una descalificación de al menos 120 días. Fuente: Manual CDL de Georgia (DDS); 49 CFR 383.51(c) Tabla 2."},"49":{"q":"¿Cuál de estas NO se cuenta como una violación de tránsito grave que puede llevar a la descalificación de la CDL en Georgia?","options":["Seguir demasiado cerca al vehículo de adelante","Hacer un cambio de carril indebido o errático","Conducción imprudente","Estacionar un CMV durante la noche en un área de descanso"],"explanation":"Las violaciones de tránsito graves incluyen seguir demasiado cerca, cambios de carril indebidos, conducción imprudente y exceso de velocidad. Estacionar legalmente en un área de descanso no es una violación. Fuente: Manual CDL de Georgia (DDS); 49 CFR 383.51(c) Tabla 2."},"50":{"q":"¿Cuál es el período de descalificación para la PRIMERA condena de un conductor con CDL de Georgia por una infracción en un cruce ferroviario a nivel?","options":["Al menos 30 días","Al menos 60 días","Al menos 120 días","Al menos 1 año"],"explanation":"Una primera infracción en un cruce ferroviario a nivel resulta en una descalificación de al menos 60 días. Fuente: Manual CDL de Georgia (DDS); 49 CFR 383.51(d) Tabla 3."},"51":{"q":"Un titular de CDL de Georgia comete una SEGUNDA infracción en un cruce ferroviario a nivel dentro de un período de 3 años. ¿Cuál es la descalificación mínima?","options":["Al menos 60 días","Al menos 120 días","Al menos 6 meses","Al menos 1 año"],"explanation":"Una segunda infracción en un cruce ferroviario a nivel dentro de 3 años resulta en una descalificación de al menos 120 días. Fuente: Manual CDL de Georgia (DDS); 49 CFR 383.51(d) Tabla 3."},"52":{"q":"Un titular de CDL de Georgia comete una TERCERA infracción en un cruce ferroviario a nivel dentro de un período de 3 años. ¿Cuál es la descalificación mínima?","options":["Al menos 120 días","Al menos 6 meses","Al menos 1 año","Descalificación de por vida"],"explanation":"Una tercera o posterior infracción en un cruce ferroviario a nivel dentro de 3 años resulta en una descalificación de al menos 1 año. Fuente: Manual CDL de Georgia (DDS); 49 CFR 383.51(d) Tabla 3."},"53":{"q":"¿Cuál es el período de descalificación para la PRIMERA condena de un conductor con CDL de Georgia por violar una orden de fuera de servicio (OOS), cuando no hay materiales peligrosos ni pasajeros involucrados?","options":["Al menos 60 días","Al menos 90 días","Al menos 180 días","Al menos 2 años"],"explanation":"Una primera condena por violar una orden de fuera de servicio resulta en una descalificación de al menos 180 días (hasta 1 año). Fuente: Manual CDL de Georgia (DDS); 49 CFR 383.51(e) Tabla 4."},"54":{"q":"Un titular de CDL de Georgia es condenado por una SEGUNDA violación de una orden de fuera de servicio en incidentes separados dentro de un período de 10 años. ¿Cuál es la descalificación mínima?","options":["Al menos 180 días","Al menos 1 año","Al menos 2 años","Descalificación de por vida"],"explanation":"Una segunda violación de una orden de fuera de servicio dentro de un período de 10 años resulta en una descalificación de al menos 2 años (hasta 5 años). Fuente: Manual CDL de Georgia (DDS); 49 CFR 383.51(e) Tabla 4."},"55":{"q":"¿Cómo cambia la sanción por una PRIMERA violación de una orden de fuera de servicio si el conductor con CDL de Georgia transportaba materiales peligrosos con cartel (placarded) o 16 o más pasajeros?","options":["Se reduce a 60 días","El mínimo se mantiene en 180 días pero el máximo sube a 2 años","Se convierte en una descalificación de por vida","No cambia: se mantiene en 180 días a 1 año"],"explanation":"Para una primera violación de OOS mientras se transportan materiales peligrosos con cartel (placarded HazMat) o 16 o más pasajeros, la descalificación es de al menos 180 días pero hasta 2 años, un máximo más largo que en el caso estándar. Fuente: Manual CDL de Georgia (DDS); 49 CFR 383.51(e) Tabla 4."},"56":{"q":"Según la ley Super Speeder de Georgia (O.C.G.A. 40-6-189), ¿a qué velocidades se clasifica a un conductor como \"Super Speeder\"?","options":["65 mph en cualquier carretera o 75 mph en una carretera de dos carriles","75 mph en una carretera de dos carriles o 85 mph en cualquier carretera o autopista","80 mph en una carretera de dos carriles o 90 mph en una interestatal","15 mph o más por encima de cualquier límite de velocidad publicado"],"explanation":"La ley Super Speeder de Georgia clasifica como Super Speeder a un conductor condenado por circular a 75 mph o más en una carretera de dos carriles, o a 85 mph o más en cualquier carretera o autopista. Fuente: O.C.G.A. 40-6-189."},"57":{"q":"Según la ley Super Speeder de Georgia, ¿qué tarifa estatal adicional cobra el Department of Driver Services a un Super Speeder condenado, y qué sucede si no se paga?","options":["Una tarifa de $200; suspensión de la licencia si no se paga dentro de los 120 días posteriores al aviso","Una tarifa de $500; tiempo en la cárcel si no se paga dentro de los 30 días","Una tarifa de $100; una carta de advertencia si no se paga dentro de los 90 días","Una tarifa de $200 sin consecuencias adicionales por falta de pago"],"explanation":"La ley Super Speeder añade una tarifa estatal de $200 además de cualquier multa judicial. Si no se paga dentro de los 120 días posteriores al aviso del DDS, se suspende la licencia del conductor y se aplica una tarifa de reinstauración de $50. Fuente: O.C.G.A. 40-6-189."},"58":{"q":"Según las normas federales que Georgia hace cumplir, ¿qué le sucede a un conductor con CDL que es condenado por enviar mensajes de texto o usar un teléfono de mano mientras opera un CMV?","options":["No conlleva ninguna sanción específica para los titulares de CDL","Es una descalificación automática de 1 año por infracción mayor","Cuenta como una infracción de tránsito grave para efectos de descalificación","Resulta en una descalificación inmediata de por vida"],"explanation":"Enviar mensajes de texto o usar un teléfono de mano mientras se conduce un CMV es una infracción de tránsito grave; dos dentro de 3 años conllevan una descalificación de 60 días y tres conllevan 120 días. Fuente: 49 CFR 383.51(c); Manual CDL de Georgia (DDS)."},"59":{"q":"La Ley de Manos Libres (Hands-Free) de Georgia (O.C.G.A. 40-6-241) se aplica a todos los conductores. ¿Qué acción prohíbe mientras se opera un vehículo, incluido un CMV?","options":["Usar una conexión de manos libres por Bluetooth o altavoz","Sostener o apoyar físicamente un teléfono con cualquier parte del cuerpo","Tener un dispositivo GPS montado y visible en el parabrisas","Hablar con un pasajero sentado en el vehículo"],"explanation":"La Ley de Manos Libres (Hands-Free) de Georgia prohíbe a los conductores sostener o apoyar un teléfono o dispositivo electrónico con cualquier parte del cuerpo; el uso de manos libres como Bluetooth o altavoz sigue estando permitido. Fuente: O.C.G.A. 40-6-241."},"60":{"q":"En una interestatal de Georgia con dos o más carriles en tu dirección, te acercas a una unidad HERO estacionada en el acotamiento mostrando luces ámbar intermitentes. ¿Qué exige la Ley de Cambio de Carril (Move Over Law) de Georgia a un conductor comercial?","options":["Mantener el límite de velocidad publicado porque la unidad está fuera de la calzada en el acotamiento","Detenerse por completo en tu carril y esperar hasta que la unidad se mueva antes de continuar","Cambiarte un carril lejos de la unidad si es seguro hacerlo; si no puedes cambiar de carril con seguridad, reducir la velocidad por debajo del límite publicado y estar preparado para detenerte","Cambiar de carril solo para vehículos de policía y bomberos, ya que las unidades HERO y de servicios públicos no están cubiertas"],"explanation":"La Ley de Cambio de Carril (Move Over Law) de Georgia (O.C.G.A. §40-6-16) exige que los conductores en carreteras con dos o más carriles en la misma dirección se cambien un carril lejos de una unidad estacionada de emergencia, de servicios públicos, de remolque/recuperación, de mantenimiento de carreteras, de saneamiento o HERO que muestre luces intermitentes. Si no se puede cambiar de carril con seguridad, el conductor debe reducir la velocidad por debajo del límite publicado y estar preparado para detenerse."},"61":{"q":"La Ley de Cambio de Carril (Move Over Law) de Georgia se aplica a vehículos estacionados que muestran luces intermitentes. ¿Cuál de los siguientes vehículos NO está cubierto por O.C.G.A. §40-6-16?","options":["Una unidad HERO (Highway Emergency Response Operator) que asiste a un vehículo averiado","Un vehículo de servicios públicos que repara líneas eléctricas con luces ámbar intermitentes","Un automóvil de pasajeros detenido en el acotamiento con sus luces de emergencia estándar (intermitentes de cuatro vías) encendidas tras una llanta ponchada","Una grúa que recupera un vehículo siniestrado con luces ámbar intermitentes"],"explanation":"O.C.G.A. §40-6-16 protege a las unidades estacionadas de emergencia, de remolque/recuperación, de mantenimiento de carreteras, de servicios públicos, de saneamiento y HERO que muestran luces intermitentes. Un automóvil de pasajeros común que usa solo sus luces de emergencia estándar de cuatro vías no es una de las clases de vehículos protegidos por la Ley de Cambio de Carril."},"62":{"q":"Según la Ley de Manos Libres de Georgia (Hands-Free Georgia Act, O.C.G.A. §40-6-241), ¿qué restricción adicional se aplica específicamente a un conductor que opera un vehículo motorizado comercial en una carretera de Georgia?","options":["El conductor puede enviar mensajes de texto manualmente siempre que el vehículo se mueva a menos de 15 mph","El conductor puede usar no más de un solo botón en un dispositivo inalámbrico para iniciar o terminar una llamada de voz","El conductor puede sostener un teléfono en el oído siempre que la llamada sea relacionada con el trabajo","El conductor está totalmente exento de la Ley de Manos Libres mientras está de servicio"],"explanation":"Según O.C.G.A. §40-6-241, mientras opera un vehículo motorizado comercial ningún conductor puede usar más de un solo botón en un dispositivo de telecomunicaciones inalámbrico para iniciar o terminar una comunicación de voz, ni alcanzar un dispositivo de una manera que requiera abandonar la posición sentada de conducción. Sostener o apoyar un dispositivo con cualquier parte del cuerpo está prohibido para todos los conductores."},"63":{"q":"¿Qué dispositivo o actividad está permitido según la Ley de Manos Libres de Georgia (Hands-Free Georgia Act, O.C.G.A. §40-6-241) mientras se conduce un vehículo comercial en Georgia?","options":["Sostener un teléfono inteligente en la mano para leer un mensaje de texto","Usar un radio comercial bidireccional o un radio CB para comunicarse","Ver un video en una tableta apoyada en el tablero","Apoyar un teléfono celular en el hombro contra el oído durante una llamada"],"explanation":"O.C.G.A. §40-6-241 excluye expresamente los radios comerciales bidireccionales, los radios CB, los radios de aficionados/ham, los dispositivos de comunicación de emergencia por suscripción, los dispositivos médicos prescritos y los sistemas de navegación/diagnóstico de fábrica. Sostener o apoyar un teléfono con cualquier parte del cuerpo, enviar mensajes de texto manualmente y ver video están todos prohibidos."},"64":{"q":"Estás conduciendo un tractocamión en el carril de rebase del extremo izquierdo de una interestatal de Georgia y notas un vehículo más rápido acercándose por detrás. Según la ley del carril izquierdo / 'Slowpoke' de Georgia (O.C.G.A. §40-6-184), ¿qué debes hacer?","options":["Mantener tu posición en el carril de rebase siempre que estés en el límite de velocidad publicado o por encima de él","Acelerar para igualar al vehículo que viene atrás para que ya no necesite rebasar","La ley no se aplica a los vehículos comerciales, por lo que puedes permanecer en el carril izquierdo","Salir del carril de rebase para permitir que el vehículo que viene atrás rebase, a menos que el camino, el tránsito, el clima o un dispositivo de control de tránsito te obliguen a permanecer ahí"],"explanation":"La ley 'Slowpoke' de Georgia (O.C.G.A. §40-6-184) exige que un conductor en el carril de rebase (el carril más a la izquierda que no sea un carril HOV) se cambie de carril una vez que sabe o debería saber que está siendo alcanzado por detrás por un vehículo más rápido, a menos que las condiciones del camino/tránsito, el clima, los peligros o un dispositivo de control de tránsito exijan permanecer en ese carril. Se aplica independientemente de si estás en el límite de velocidad."},"65":{"q":"Para efectos de la ley del carril izquierdo / 'Slowpoke' de Georgia (O.C.G.A. §40-6-184), ¿cómo se define el 'carril de rebase'?","options":["El carril más a la izquierda, que no sea un carril de vehículos de alta ocupación (HOV)","Cualquier carril en el que un vehículo esté rebasando actualmente a otro","El carril más cercano al acotamiento derecho","Solo el carril central de una calzada de tres carriles"],"explanation":"O.C.G.A. §40-6-184 define el 'carril de rebase' como el carril más a la izquierda que no sea un carril de vehículos de alta ocupación (HOV). Un conductor no debe continuar en ese carril una vez que está siendo alcanzado por un vehículo más rápido por detrás."},"66":{"q":"Según O.C.G.A. §40-6-52, un 'camión' (cualquier vehículo con más de seis ruedas, excepto autobuses y autocares) en una calzada de Georgia con tres o más carriles en la misma dirección puede generalmente operar en ¿cuáles carriles?","options":["Cualquier carril, siempre que mantenga el flujo del tránsito","Solo el carril más a la derecha en todo momento","Solo los dos carriles más a la derecha, excepto cuando se prepara para un giro a la izquierda o donde los carriles estén designados de otra manera","Solo los carriles centrales, dejando el carril derecho abierto para el tránsito que se incorpora"],"explanation":"O.C.G.A. §40-6-52 establece que es ilegal que un camión (un vehículo con más de seis ruedas, excluidos autobuses y autocares) en una calzada con tres o más carriles en la misma dirección conduzca en cualquier carril que no sean los dos carriles más a la derecha, excepto cuando se prepara para un giro a la izquierda o donde el Department of Transportation haya designado otros carriles."},"67":{"q":"En una carretera de Georgia con exactamente dos carriles en tu dirección, ¿cuándo puede un camión sujeto a O.C.G.A. §40-6-52 usar legalmente el carril izquierdo?","options":["Siempre que el carril derecho esté más congestionado que el carril izquierdo","Cuando realmente esté alcanzando y rebasando a otro vehículo o preparándose para un giro a la izquierda","Solo entre el amanecer y el atardecer","Nunca, bajo ninguna circunstancia"],"explanation":"Según O.C.G.A. §40-6-52, en una calzada con dos carriles en la misma dirección es ilegal que un camión opere en el carril izquierdo excepto cuando realmente esté alcanzando y rebasando a otro vehículo, preparándose para un giro a la izquierda, o según lo dispuesto de otra manera por el estatuto."},"68":{"q":"¿Cuál es el límite de velocidad máximo establecido por O.C.G.A. §40-6-181 para cualquier vehículo, incluido un tractocamión, en una autopista interestatal de Georgia donde así esté publicado?","options":["55 millas por hora","65 millas por hora","75 millas por hora","70 millas por hora"],"explanation":"O.C.G.A. §40-6-181 establece un límite máximo de 70 mph en autopistas que forman parte del sistema interestatal federal y en carreteras estatales físicamente divididas y con control total de acceso donde esté designado por señales. Georgia no impone un límite de velocidad estatal separado y más bajo para los camiones; el máximo publicado se aplica a todos los vehículos."},"69":{"q":"A los camiones pesados de paso que viajan por la I-75, la I-85 o la I-20 hacia Atlanta generalmente se les exige hacer ¿qué cosa, según las reglas de enrutamiento de camiones de Atlanta de Georgia?","options":["Usar el Downtown Connector de la I-75/I-85 solo durante las horas de luz del día","Viajar solo en los carriles HOV a través del centro de Atlanta","Detenerse en una estación de pesaje estatal antes de ingresar a la I-285","Rodear la ciudad por la I-285 a menos que estén recogiendo/entregando, dirigiéndose a una terminal o taller de reparación, o a la residencia del conductor dentro del perímetro"],"explanation":"Los camiones que viajan a través (no hacia dentro) de Atlanta deben tomar la I-285 alrededor de la ciudad en lugar del Downtown Connector de la I-75/I-85. Existen excepciones para los camiones que recogen o entregan a un expedidor dentro de la I-285, que se dirigen hacia o desde una terminal o taller de reparación dentro de la I-285, o para un conductor que va hacia o desde una residencia dentro del perímetro. Esta es una restricción de camiones de paso bien señalizada y aplicada."},"70":{"q":"En el Downtown Connector de la I-75/I-85 de Atlanta, los carriles interiores (más a la izquierda) están reservados como carriles HOV. ¿Qué significa esto para un conductor de camión comercial?","options":["El camión debe mantenerse fuera del carril HOV y, debido a los límites de uso de carriles, generalmente permanecer en los carriles de la derecha","El camión puede usar el carril HOV en cualquier momento que transporte más de 6,000 lbs de carga","El camión puede usar el carril HOV si paga un peaje como un carril HOT","El camión puede usar el carril HOV porque los vehículos comerciales siempre se consideran de alta ocupación"],"explanation":"Los carriles interiores del Downtown Connector de la I-75/I-85 están restringidos a HOV. La carga no es un ocupante, por lo que un camión no califica como vehículo de alta ocupación, y según O.C.G.A. §40-6-52 los camiones deben usar los carriles de la derecha. Los carriles HOV de Georgia requieren el número mínimo de ocupantes, no el peso de la carga."},"71":{"q":"¿Cuáles vehículos comerciales están obligados a DETENERSE en cada cruce ferroviario a nivel según el Manual CDL de Georgia?","options":["Los autobuses que transportan pasajeros y los vehículos que muestran carteles (placards) de materiales peligrosos","Todos los vehículos comerciales de más de 26,001 lbs sin importar la carga","Solo los camiones cisterna vacíos, nunca los cargados","Cualquier camión que jale un remolque doble o triple"],"explanation":"Según el Manual CDL de Georgia (y 49 CFR 392.10), los vehículos comerciales que siempre deben detenerse en los cruces ferroviarios son los autobuses que transportan pasajeros y los vehículos con cartel (placard) de materiales peligrosos. Esto también incluye los vehículos que transportan cualquier cantidad de cloro y los camiones cisterna usados para materiales peligrosos, ya sea cargados o vacíos."},"72":{"q":"Cuando un vehículo con cartel (placard) de HazMat o un autobús de pasajeros debe detenerse en un cruce ferroviario en Georgia, ¿dónde debe detenerse?","options":["Exactamente a 25 pies del riel más cercano","A no más de 50 pies pero no más cerca de 15 pies del riel más cercano","A al menos 100 pies del riel más cercano","En cualquier lugar dentro de 10 pies de la barrera del cruce"],"explanation":"El Manual CDL de Georgia establece que una parada obligatoria en un cruce ferroviario debe hacerse a no más de 50 pies y a no menos de 15 pies del riel más cercano. El conductor debe mirar y escuchar para detectar un tren, y luego cruzar solo cuando sea seguro despejar las vías por completo sin detenerse."},"73":{"q":"Según el Manual CDL de Georgia, ¿qué NO debe hacer un conductor comercial mientras cruza vías ferroviarias?","options":["Usar una marcha lo suficientemente baja para cruzar sin cambiar de marcha","Cambiar de marcha mientras cualquier parte del vehículo está sobre las vías","Mirar y escuchar para detectar un tren que se aproxima antes de comenzar a cruzar","Asegurarse de que haya espacio para despejar completamente las vías antes de comenzar a cruzar"],"explanation":"El Manual CDL de Georgia advierte a los conductores que nunca cambien de marcha mientras cruzan vías ferroviarias, porque el vehículo podría quedarse parado en el cruce. El conductor debe seleccionar una marcha que permita cruzar sin cambios y debe asegurarse de que haya suficiente espacio para despejar las vías por completo antes de comenzar a cruzar."},"74":{"q":"Según O.C.G.A. §40-6-163, ¿cuándo debe el conductor de un vehículo comercial detenerse ante un autobús escolar detenido que tiene sus luces rojas intermitentes encendidas y el brazo de alto extendido?","options":["Solo cuando viaja en la misma dirección que el autobús, nunca cuando viene en sentido contrario","Solo si hay niños visiblemente presentes al borde del camino","Al encontrarse con el autobús o alcanzarlo desde cualquier dirección en una calzada no dividida, hasta que el autobús reanude su marcha o las señales se apaguen","Solo en carreteras de dos carriles, nunca en carreteras de cuatro o más carriles"],"explanation":"O.C.G.A. §40-6-163 exige que el conductor de un vehículo que se encuentra con un autobús escolar o lo alcanza desde cualquier dirección, detenido en la carretera con sus señales visuales (luces rojas intermitentes/brazo de alto) activadas, se detenga antes de llegar al autobús y no continúe hasta que el autobús reanude su marcha o las señales se apaguen, en calzadas no divididas."},"75":{"q":"Según la ley de autobuses escolares de Georgia (O.C.G.A. §40-6-163), ¿en qué tipo de calzada NO se exige a un conductor que viene en sentido contrario que se detenga ante un autobús escolar que carga niños en el lado opuesto?","options":["Una carretera de cuatro carriles donde el único divisor es una línea central pintada","Una carretera separada solo por un carril central de giro bidireccional","Cualquier carretera con dos o más carriles en cada dirección","Una carretera con calzadas separadas divididas por un camellón de césped, un área sin pavimentar o una barrera física"],"explanation":"O.C.G.A. §40-6-163 dispone que un conductor en una carretera con calzadas separadas divididas por un camellón de césped, un área sin pavimentar o una barrera física no necesita detenerse ante un autobús escolar en la otra calzada separada. Una línea pintada o un carril central de giro NO es un divisor, por lo que los conductores aún deben detenerse en esos casos."},"76":{"q":"Una carretera tiene dos carriles en cada dirección separados solo por un carril central de giro bidireccional (sin camellón ni barrera). Un autobús escolar en el lado opuesto se detiene con las luces rojas intermitentes encendidas. Según O.C.G.A. §40-6-163, ¿qué debe hacer un conductor comercial que viene en sentido contrario?","options":["Detenerse, porque un carril central de giro no es un camellón ni una barrera física que separe las calzadas","Continuar a velocidad reducida, porque el carril de giro cuenta como divisor","Detenerse solo si el autobús está en la propia dirección de viaje del conductor","Continuar normalmente, porque el tránsito en sentido contrario nunca se detiene ante los autobuses escolares"],"explanation":"Según O.C.G.A. §40-6-163, la excepción de carretera dividida se aplica solo a calzadas separadas por un camellón de césped, un área sin pavimentar o una barrera física. Un carril central de giro bidireccional y las líneas pintadas no califican, por lo que un conductor que viene en sentido contrario debe detenerse ante el autobús escolar con sus señales activadas."},"77":{"q":"Según el Manual CDL de Georgia, ¿dónde debe colocar un conductor de camión los tres dispositivos de advertencia de emergencia requeridos (triángulos reflectantes) en una carretera de dos carriles y doble sentido después de detenerse en el acotamiento?","options":["Los tres directamente detrás del vehículo, dentro de los 10 pies del parachoques trasero","Uno en el techo y dos en el parachoques delantero","A unos 10 pies detrás del vehículo hacia el tránsito, a unos 100 pies detrás, y a unos 100 pies por delante del vehículo","A unos 500 pies detrás y 500 pies por delante, sin ninguno cerca del vehículo"],"explanation":"El Manual CDL de Georgia exige que los dispositivos de advertencia se coloquen dentro de los 10 minutos: uno a unos 10 pies (4 pasos) del vehículo hacia el tránsito que se aproxima, uno a unos 100 pies (40 pasos) detrás, y uno a unos 100 pies (40 pasos) por delante. En pendientes o curvas, el dispositivo trasero se coloca más atrás para dar una advertencia adecuada."},"78":{"q":"Según el Manual CDL de Georgia, ¿cuál es la técnica correcta para descender una pendiente montañosa larga y empinada del norte de Georgia para prevenir el desvanecimiento de los frenos (brake fade)?","options":["Seleccionar una marcha baja antes del descenso y usar un frenado ligero y constante con el método snub (aplicar y luego soltar) a una velocidad segura","Mantenerse en una marcha alta y mantener los frenos aplicados continuamente para mantener la velocidad baja","Poner en neutral para ahorrar combustible y controlar la velocidad solo con los frenos","Bombear los frenos rápidamente mientras se acelera para mantener el motor caliente"],"explanation":"El Manual CDL de Georgia indica a los conductores que elijan una velocidad segura y una marcha baja ANTES de comenzar a descender una pendiente empinada, confiando en el freno de motor, y que usen la técnica de frenado snub (aplicar firmemente para reducir unas 5 mph, luego soltar). Mantener los frenos aplicados o ir en neutral provoca el desvanecimiento de los frenos y la pérdida de control."},"79":{"q":"En una pendiente empinada del norte de Georgia tus frenos se han desvanecido y el camión está ganando velocidad. El Manual CDL de Georgia aconseja que la mejor acción es:","options":["Salirse al acotamiento derecho pavimentado y aplicar el freno de estacionamiento con fuerza","Dirigirse hacia el tránsito en sentido contrario para encontrar un carril libre","Apagar el motor para frenar el vehículo rápidamente","Usar una rampa de escape para camiones fuera de control si hay una disponible, ya que está diseñada para detener un vehículo fuera de control de manera segura"],"explanation":"El Manual CDL de Georgia explica que las rampas de escape, construidas en muchas pendientes montañosas empinadas con lechos de material suelto (y a menudo una subida), están diseñadas para detener vehículos fuera de control de manera segura. Si tus frenos fallan en una pendiente, tomar una rampa de escape disponible es la acción más segura; apagar el motor o usar el freno de estacionamiento a velocidad puede causar la pérdida de control."},"80":{"q":"En Georgia, ¿qué agencia estatal emite las licencias de conducir comerciales (CDL) y administra las pruebas de CDL?","options":["La división de registro del Georgia Department of Public Safety","El Georgia Department of Motor Vehicles (DMV)","El Georgia Bureau of Investigation","El Georgia Department of Driver Services (DDS)"],"explanation":"Georgia no tiene un 'DMV'. El Georgia Department of Driver Services (DDS) es la agencia estatal que emite todas las CDL y administra las pruebas de conocimientos y habilidades de CDL. Fuente: GA DDS, páginas del programa de Licencia Comercial (CDL) (dds.georgia.gov)."},"81":{"q":"¿Cuántos documentos que comprueben tu domicilio residencial en Georgia debes llevar al GA DDS al solicitar una CDL?","options":["No se requieren documentos de residencia para una CDL","Cuatro documentos que muestren tu domicilio residencial en Georgia","Dos documentos que muestren tu domicilio residencial actual en Georgia","Un documento que muestre tu domicilio residencial en Georgia"],"explanation":"GA DDS exige que los solicitantes proporcionen dos documentos aceptables (como facturas de servicios públicos, estados de cuenta hipotecarios o documentos gubernamentales) que muestren su domicilio residencial actual en Georgia. Fuente: GA DDS, 'Apply for a Commercial (CDL) License' (dds.georgia.gov)."},"82":{"q":"¿Qué conjunto de documentos exige GA DDS para establecer la identidad, el número de Seguro Social y el estatus legal para una CDL?","options":["Solo una tarjeta de registro de votante de Georgia","Solo un registro de vehículo a tu nombre","Solo una declaración firmada de residencia sin ninguna otra prueba","Prueba de identidad, tu número completo de Seguro Social, y prueba de ciudadanía estadounidense o presencia legal"],"explanation":"GA DDS exige prueba de identidad (como un acta de nacimiento de EE. UU., un pasaporte o un certificado de naturalización), verificación de tu número completo de Seguro Social en el formulario de Licencia/ID/Permiso, y documentación de ciudadanía estadounidense o presencia legal, además de dos documentos de residencia en Georgia. Fuente: GA DDS, requisitos de solicitud de CDL (dds.georgia.gov)."},"83":{"q":"Antes de presentar la prueba de habilidades (de manejo) de CDL en Georgia, ¿durante cuánto tiempo debe un conductor poseer el Permiso de Aprendiz/Instrucción Comercial (CLP)?","options":["Al menos 30 días","Al menos 60 días","Al menos 14 días","No hay período mínimo de posesión"],"explanation":"GA DDS exige que un solicitante de CDL posea el Permiso de Instrucción Comercial (CLP) durante al menos 14 días antes de solicitar y presentar la prueba completa de habilidades de CDL. Esto refleja el período de espera federal de 14 días. Fuente: GA DDS, página de Permiso CDL (dds.georgia.gov)."},"84":{"q":"¿Qué debe completar un solicitante de CDL Clase A o Clase B por primera vez en Georgia antes de que se le permita presentar la prueba de habilidades de CDL?","options":["Un curso de manejo defensivo en cualquier escuela de manejo privada","Cinco años de historial de manejo no comercial verificable","Un certificado de logística de nivel universitario","Capacitación de Conductor de Nivel Básico (ELDT) de un proveedor incluido en el Training Provider Registry de la FMCSA"],"explanation":"Según las reglas federales de ELDT aplicadas por GA DDS, los solicitantes de CDL Clase A y Clase B por primera vez (con un CLP obtenido en o después del 7 de febrero de 2022) deben completar la Capacitación de Conductor de Nivel Básico (ELDT) de un proveedor registrado en el Training Provider Registry de la FMCSA antes de presentar la prueba de habilidades. Fuente: páginas de CDL de GA DDS y FMCSA Training Provider Registry (tpr.fmcsa.dot.gov)."},"85":{"q":"¿Por cuánto tiempo es válida una CDL estándar (sin HazMat) de Georgia antes de que deba renovarse?","options":["Hasta 4 años","Hasta 2 años","Hasta 10 años","Hasta 8 años"],"explanation":"Una CDL estándar de Georgia es válida por hasta 8 años. Las CDL que tienen un endoso de Materiales Peligrosos (H) son válidas por un período más corto (5 años) debido a la renovación de la verificación de antecedentes requerida. Fuente: GA DDS, 'Renew a CDL' (dds.georgia.gov)."},"86":{"q":"¿Cuáles son las cuatro categorías de autocertificación entre las que debe elegir un titular de CDL de Georgia?","options":["Clase A, Clase B, Clase C, Clase D","Local, Regional, Nacional, Internacional","Interestatal no exceptuado, Interestatal exceptuado, Intraestatal no exceptuado, Intraestatal exceptuado","Día, Noche, Hazmat, Pasajeros"],"explanation":"Todo titular de CDL de Georgia debe autocertificarse a uno de cuatro tipos de operación: Interestatal no exceptuado (NI), Interestatal exceptuado (EI), Intraestatal no exceptuado (NA), e Intraestatal exceptuado (EA). Los conductores no exceptuados deben mantener un certificado médico DOT válido. Fuente: GA DDS, 'CDL Medical Certification and Self-Certification Process' (dds.georgia.gov)."},"87":{"q":"¿Qué categoría de autocertificación exige que un titular de CDL de Georgia mantenga un certificado válido de examinador médico DOT?","options":["Interestatal exceptuado (EI)","Ninguna categoría requiere un certificado médico","Interestatal no exceptuado (NI)","Intraestatal exceptuado (EA)"],"explanation":"Los conductores en las categorías No exceptuadas (Interestatal no exceptuado e Intraestatal no exceptuado) deben mantener un certificado válido de examinador médico DOT. Las categorías exceptuadas (EI y EA) no requieren uno. Fuente: GA DDS, proceso de Certificación Médica y Autocertificación de CDL (dds.georgia.gov)."},"88":{"q":"A partir del mandato de la FMCSA vigente el 18 de junio de 2025, ¿cómo se transmite al DDS el certificado de examinador médico DOT de un titular de CDL de Georgia?","options":["Electrónicamente desde el National Registry de la FMCSA; el DDS ya no acepta certificados médicos en papel","Enviándolo por fax a la sede del DDS dentro de los 10 días","Enviando por correo una copia en papel al Centro de Servicio al Cliente del DDS más cercano","Enviando por correo electrónico una copia escaneada a un trabajador social personal del DDS"],"explanation":"A partir del 18 de junio de 2025, los certificados médicos se transmiten electrónicamente al GA DDS por la FMCSA a través del National Registry of Certified Medical Examiners. El DDS ya no acepta certificados médicos por correo, fax, correo electrónico, en línea ni en persona. El conductor simplemente debe usar un examinador del National Registry y mantener la certificación al día. Fuente: comunicado de prensa de GA DDS y página de Certificado Médico de CDL (dds.georgia.gov)."},"89":{"q":"¿Quién debe realizar el examen físico para un conductor con CDL de Georgia que está obligado a tener un certificado médico DOT?","options":["Un empleado del Centro de Servicio al Cliente del DDS","Cualquier quiropráctico sin importar su certificación","Un examinador médico incluido en el FMCSA National Registry of Certified Medical Examiners","Cualquier farmacéutico en una farmacia con licencia de Georgia"],"explanation":"Los conductores con CDL de Georgia que requieren certificación médica deben ser examinados por un examinador médico incluido en el FMCSA National Registry of Certified Medical Examiners. Ese examinador luego transmite el certificado electrónicamente. Fuente: GA DDS, proceso de Certificación Médica de CDL (dds.georgia.gov)."},"90":{"q":"¿Qué tres componentes conforman la prueba de habilidades de CDL de Georgia?","options":["Carga de mercancías, prueba de economía de combustible y un examen de matemáticas","Examen escrito de leyes, examen de la vista y una entrevista de personalidad","Manejo de hazmat, servicio al cliente y una prueba de mecanografía","Inspección del vehículo previa al viaje, habilidades básicas de control y una prueba de manejo en carretera"],"explanation":"La prueba de habilidades de CDL de Georgia tiene tres partes administradas en orden: la inspección del vehículo previa al viaje, las habilidades básicas de control del vehículo y la prueba de manejo en carretera. Las tres deben aprobarse para obtener la CDL. Fuente: Manual CDL de GA DDS y páginas de Prueba de Manejo (dds.georgia.gov)."},"91":{"q":"Al presentar la prueba de habilidades (de manejo) de CDL en Georgia, ¿quién es responsable de proporcionar el vehículo de prueba?","options":["No se necesita vehículo; la prueba de habilidades se realiza solo en un simulador","La FMCSA envía un camión de prueba federal al sitio","GA DDS proporciona un vehículo de flota para cada solicitante","El solicitante debe proporcionar un vehículo apropiado que pase una inspección de seguridad del DDS"],"explanation":"El solicitante debe llevar un vehículo apropiado para la clase de CDL que se está evaluando, junto con la prueba de registro y un seguro válido, y el vehículo debe pasar una inspección de seguridad del DDS antes de la prueba de manejo. Fuente: GA DDS, página de Prueba de Manejo (dds.georgia.gov)."},"92":{"q":"¿Cuál es la edad mínima para solicitar una CDL en Georgia, y qué restricción aplica hasta cierta edad?","options":["21 años, sin necesidad de permiso","16 años, sin ninguna restricción","18 años, con restricciones de solo intraestatal hasta los 21 años","25 años, sin que se permita nunca conducir entre estados"],"explanation":"En Georgia puedes solicitar una CDL a los 18 años, pero los conductores entre 18 y 21 años generalmente están restringidos a la conducción comercial intraestatal (dentro del estado) hasta su cumpleaños número 21. Fuente: GA DDS, páginas de solicitud y permiso de CDL (dds.georgia.gov)."},"93":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Georgia emitido en o después del 1 de julio de 2021?","options":["90 días","Indefinidamente, hasta que se emita la CDL","30 días","365 días (un año)"],"explanation":"Un CLP de Georgia emitido en o después del 1 de julio de 2021 es válido por 365 días (un año). El conductor aún debe poseerlo durante al menos 14 días antes de la prueba de habilidades. Fuente: GA DDS, página de Permiso CDL (dds.georgia.gov)."},"94":{"q":"¿Cuándo se requiere un Permiso de Instrucción Comercial (CLP) en el proceso de CDL de Georgia?","options":["Al solicitar una nueva CDL, al mejorar una CDL, o al agregar ciertos endosos","Solo después de que la CDL ya haya sido emitida","Nunca; Georgia emite CDL sin ninguna etapa de permiso","Solo para conductores que transfieren una licencia de otro país"],"explanation":"GA DDS exige un Permiso de Instrucción Comercial (CLP) al solicitar una nueva CDL, al mejorar una CDL existente, o al agregar ciertos endosos que requieren una prueba de habilidades. El CLP debe poseerse durante 14 días antes de la prueba de habilidades. Fuente: GA DDS, página de Permiso CDL (dds.georgia.gov)."},"95":{"q":"Para un endoso de Materiales Peligrosos (H) por primera vez en Georgia, ¿cuándo debe completarse la capacitación ELDT?","options":["Solo después de que se rechace la verificación de antecedentes de la TSA","Antes de que se permita presentar la prueba de conocimientos de HazMat","La ELDT nunca se requiere para el endoso de HazMat","Solo después de aprobar la prueba de conocimientos de HazMat"],"explanation":"Debido a que el endoso de HazMat no tiene prueba de habilidades, la capacitación teórica ELDT para los solicitantes de H por primera vez debe completarse antes de que se le permita al solicitante presentar la prueba de conocimientos de HazMat. Fuente: FMCSA Training Provider Registry / ELDT Applicability (tpr.fmcsa.dot.gov) y páginas de CDL de GA DDS."},"96":{"q":"¿Qué endosos exigen que los solicitantes por primera vez en Georgia completen la ELDT antes de la prueba?","options":["Solo cisterna (N), dobles/triples (T) y eliminación de frenos de aire","Solo la eliminación de la restricción de frenos de aire","Ningún endoso requiere nunca ELDT","Endosos de autobús escolar (S), pasajeros (P) y materiales peligrosos (H)"],"explanation":"Según las reglas federales de ELDT aplicadas por GA DDS, los solicitantes por primera vez de los endosos de Autobús Escolar (S), Pasajeros (P) y Materiales Peligrosos (H) deben completar la ELDT de un proveedor registrado antes de presentar la prueba de habilidades o de conocimientos correspondiente. Fuente: FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) y GA DDS."},"97":{"q":"Además de la prueba de habilidades, ¿qué debe aprobar un solicitante de CDL de Georgia en el Centro de Servicio al Cliente del DDS?","options":["Una prueba de fuerza física y una prueba de natación","Solo una verificación de crédito","Los exámenes escritos de conocimientos requeridos y un examen de la vista","Una revisión de la declaración del impuesto federal sobre la renta"],"explanation":"Antes de la prueba de habilidades, un solicitante de CDL de Georgia debe aprobar los exámenes escritos de conocimientos requeridos para la clase y los endosos solicitados y aprobar un examen de la vista en el Centro de Servicio al Cliente del DDS. Fuente: GA DDS, páginas de Permiso y solicitud de CDL (dds.georgia.gov)."},"98":{"q":"¿Cuál afirmación sobre las tarifas de CDL de Georgia es correcta?","options":["Solo la FMCSA cobra las tarifas de CDL en Georgia","Las tarifas las establece individualmente cada examinador médico","Todos los servicios de CDL de GA DDS son permanentemente gratuitos","Los montos exactos de las tarifas los establece GA DDS y pueden cambiar, por lo que los solicitantes deben verificar las tarifas actuales con el DDS"],"explanation":"GA DDS cobra tarifas por permisos, pruebas y licencias (por ejemplo, tarifas de permiso y de prueba de manejo), pero los montos exactos los establece el DDS y pueden cambiar con el tiempo. Los solicitantes deben confirmar las tarifas actuales en la información oficial de 'Fees and Terms' del DDS antes de solicitar. Fuente: GA DDS (dds.georgia.gov)."},"99":{"q":"¿Qué debe hacer un conductor con CDL de Georgia en la renovación con respecto al tipo de operación comercial?","options":["Autocertificarse a un solo tipo de operación comercial y, si es no exceptuado, mantener un certificado médico DOT actual en archivo","Volver a presentar la prueba completa de habilidades de manejo en cada renovación sin importar la categoría","Entregar la CDL y volver a solicitar como un solicitante completamente nuevo","Presentar una carta notariada de un empleador anterior"],"explanation":"En la renovación, un titular de CDL de Georgia debe autocertificarse a un solo tipo de operación comercial (una de las cuatro categorías), y los conductores no exceptuados deben mantener un certificado médico DOT actual, ahora transmitido electrónicamente a través de la FMCSA. Fuente: GA DDS, páginas de 'Renew a CDL' y Certificado Médico de CDL (dds.georgia.gov)."}},"hi":{"0":{"q":"जॉर्जिया के राजमार्गों पर, मिरर और सहायक उपकरणों को छोड़कर, किसी वाहन और उसके लोड की अधिकतम कुल बाहरी चौड़ाई कितनी होती है?","options":["96 इंच","102 इंच","108 इंच","120 इंच"],"explanation":"O.C.G.A. §32-6-23 यह प्रावधान करता है कि जॉर्जिया में किसी भी सड़क, मार्ग या राजमार्ग पर, मिरर और सहायक उपकरणों को छोड़कर, किसी भी वाहन की कुल बाहरी चौड़ाई, लोड सहित, 102 इंच से अधिक नहीं होगी। (स्रोत: O.C.G.A. §32-6-23; GA DDS CDL Manual)"},"1":{"q":"जहां अधिक सीमा अधिकृत न हो, वहां जॉर्जिया की सड़कों पर किसी वाहन की, बिना लोड या लोड के साथ, अधिकतम ऊंचाई कितनी होती है?","options":["12 फ़ुट 6 इंच","13 फ़ुट 0 इंच","14 फ़ुट 6 इंच","13 फ़ुट 6 इंच"],"explanation":"O.C.G.A. §32-6-22(a) में कहा गया है कि, परमिट द्वारा अधिकृत को छोड़कर, जॉर्जिया की सड़कों पर बिना लोड या लोड के साथ किसी भी वाहन की ऊंचाई 13 फ़ुट, 6 इंच से अधिक नहीं होगी। (स्रोत: O.C.G.A. §32-6-22)"},"2":{"q":"जॉर्जिया में, ट्रक ट्रैक्टर-सेमीट्रेलर संयोजन में सेमीट्रेलर की अधिकतम लंबाई कितनी होती है, जब कोई पोस्ट किए गए प्रतिबंध न हों?","options":["45 फ़ुट","48 फ़ुट","53 फ़ुट","57 फ़ुट"],"explanation":"O.C.G.A. §32-6-24(b)(1)(B) यह प्रावधान करता है कि ट्रक ट्रैक्टर-सेमीट्रेलर संयोजनों में ऐसे सेमीट्रेलर होंगे जिनकी लंबाई 53 फ़ुट से अधिक न हो, जब तक कि सेमीट्रेलर की लंबाई के प्रतिबंध दर्शाने वाले संकेत पोस्ट न किए गए हों। (स्रोत: O.C.G.A. §32-6-24)"},"3":{"q":"जॉर्जिया के ट्रक ट्रैक्टर-सेमीट्रेलर-ट्रेलर (ट्विन ट्रेलर) संयोजन में, प्रत्येक ट्रेलर और सेमीट्रेलर की अधिकतम लंबाई कितनी होती है?","options":["24 फ़ुट","28 फ़ुट","33 फ़ुट","40 फ़ुट"],"explanation":"O.C.G.A. §32-6-24(b)(1)(A) यह प्रावधान करता है कि ट्रक ट्रैक्टर-सेमीट्रेलर-ट्रेलर संयोजनों में ऐसे ट्रेलर और सेमीट्रेलर होंगे जिनकी लंबाई प्रत्येक 28 फ़ुट से अधिक न हो। (स्रोत: O.C.G.A. §32-6-24)"},"4":{"q":"इंटरस्टेट या STAA सिस्टम के अलावा अन्य जॉर्जिया की सड़कों पर, ट्रक ट्रैक्टर-सेमीट्रेलर या ट्रक ट्रैक्टर-सेमीट्रेलर-ट्रेलर संयोजन की अधिकतम कुल लंबाई कितनी होती है, जब कोई पोस्ट किए गए प्रतिबंध न हों?","options":["65 फ़ुट","75 फ़ुट","100 फ़ुट","110 फ़ुट"],"explanation":"O.C.G.A. §32-6-24(b)(2)(C) यह प्रावधान करता है कि, इंटरस्टेट या STAA सिस्टम के अलावा अन्य सड़कों पर, ऐसे संयोजनों की कुल लंबाई 100 फ़ुट से अधिक नहीं होगी, जब तक कि लंबाई के प्रतिबंध दर्शाने वाले संकेत पोस्ट न किए गए हों। (स्रोत: O.C.G.A. §32-6-24)"},"5":{"q":"जॉर्जिया के राजमार्गों पर किसी भी वाहन और लोड के लिए अधिकृत अधिकतम कुल सकल वज़न कितना होता है?","options":["73,280 पाउंड","88,000 पाउंड","100,000 पाउंड","80,000 पाउंड"],"explanation":"O.C.G.A. §32-6-26(c)(1)(A) और (d)(1)(A) दोनों ही किसी भी वाहन और लोड के लिए अधिकृत अधिकतम कुल सकल वज़न को 80,000 पाउंड पर सीमित करते हैं, राष्ट्रीय और गैर-राष्ट्रीय राजमार्गों दोनों पर समान रूप से। (स्रोत: O.C.G.A. §32-6-26; GA DDS CDL Manual)"},"6":{"q":"जॉर्जिया के राष्ट्रीय राजमार्ग (जैसे इंटरस्टेट) पर, टैंडम एक्सल पर अधिकृत अधिकतम लोड कितना होता है?","options":["30,000 पाउंड","40,680 पाउंड","46,000 पाउंड","34,000 पाउंड"],"explanation":"O.C.G.A. §32-6-26(d)(1)(B) जॉर्जिया के राष्ट्रीय राजमार्गों पर किसी भी टैंडम एक्सल पर अधिकतम लोड को 34,000 पाउंड पर निर्धारित करता है, जो संघीय सीमा से मेल खाता है। (स्रोत: O.C.G.A. §32-6-26; GA DDS CDL Manual)"},"7":{"q":"जॉर्जिया के उन राजमार्गों पर जो राष्ट्रीय राजमार्ग नहीं हैं, टैंडम एक्सल पर अधिकृत अधिकतम लोड कितना होता है?","options":["34,000 पाउंड","37,340 पाउंड","40,680 पाउंड","46,000 पाउंड"],"explanation":"O.C.G.A. §32-6-26(c)(1)(A) जॉर्जिया के उन राजमार्गों पर जो राष्ट्रीय राजमार्ग नहीं हैं, अधिकतम टैंडम-एक्सल लोड को 40,680 पाउंड पर निर्धारित करता है। (स्रोत: O.C.G.A. §32-6-26)"},"8":{"q":"O.C.G.A. §32-6-26 के तहत, जॉर्जिया में वज़न के प्रयोजनों के लिए \"सिंगल एक्सल\" को कैसे परिभाषित किया जाता है?","options":["वे सभी पहिए जिनके केंद्र 40 इंच की दूरी पर दो समानांतर अनुप्रस्थ ऊर्ध्वाधर तलों के बीच आते हैं","वे सभी पहिए जिनके केंद्र एक-दूसरे के 96 इंच के भीतर आते हैं","कोई भी दो लगातार एक्सल जो 40 इंच से अधिक दूरी पर हों","केवल पावर यूनिट का एकल स्टीयरिंग एक्सल"],"explanation":"O.C.G.A. §32-6-26(a)(4) \"सिंगल एक्सल\" को उन सभी पहियों के रूप में परिभाषित करता है जिनके केंद्र 40 इंच की दूरी पर दो समानांतर अनुप्रस्थ ऊर्ध्वाधर तलों के बीच शामिल किए जा सकते हैं। (स्रोत: O.C.G.A. §32-6-26)"},"9":{"q":"वर्तमान जॉर्जिया कानून के तहत, वज़न के प्रयोजनों के लिए \"टैंडम एक्सल\" को कैसे परिभाषित किया जाता है?","options":["दो या अधिक लगातार एक्सल जिनके केंद्र 40 इंच से अधिक लेकिन 96 इंच से अधिक नहीं की दूरी पर हों","दो या अधिक लगातार एक्सल, स्टीयरिंग एक्सल को छोड़कर, जिनके केंद्र 40 इंच से अधिक लेकिन 216 इंच से अधिक नहीं की दूरी पर हों","ठीक दो एक्सल जो 8 फ़ुट से अधिक दूरी पर न हों, जिसमें स्टीयरिंग एक्सल शामिल है","स्टीयरिंग एक्सल की परवाह किए बिना एक-दूसरे के 12 फ़ुट के भीतर एक्सल का कोई भी समूह"],"explanation":"O.C.G.A. §32-6-26(a)(7) \"टैंडम एक्सल\" (1 अप्रैल, 1988 के बाद) को दो या अधिक लगातार एक्सल के रूप में परिभाषित करता है, स्टीयरिंग एक्सल को छोड़कर, जिनके केंद्र 40 इंच से अधिक लेकिन 216 इंच से अधिक नहीं की दूरी पर समानांतर ऊर्ध्वाधर तलों के बीच शामिल किए जा सकते हैं। (स्रोत: O.C.G.A. §32-6-26)"},"10":{"q":"जॉर्जिया दो या अधिक लगातार एक्सल के समूह पर अनुमत अधिकतम सकल वज़न निर्धारित करने के लिए कौन सा सूत्र उपयोग करता है?","options":["संघीय ब्रिज सूत्र","सकल संयोजन वज़न रेटिंग सूत्र","जॉर्जिया एक्सल-स्पेसिंग टैरिफ","18,000-पाउंड-प्रति-एक्सल नियम"],"explanation":"O.C.G.A. §32-6-26(a)(1) और (d) जॉर्जिया के राष्ट्रीय राजमार्गों पर दो या अधिक लगातार एक्सल के किसी भी समूह पर अधिकतम सकल वज़न निर्धारित करने के लिए संघीय ब्रिज सूत्र, W = 500((LN/N-1) + 12N + 36), को अपनाते हैं। (स्रोत: O.C.G.A. §32-6-26; GA DDS CDL Manual)"},"11":{"q":"जॉर्जिया ब्रिज सूत्र W = 500((LN/N-1) + 12N + 36) में, चर \"N\" किसका प्रतिनिधित्व करता है?","options":["विचाराधीन समूह में एक्सल की संख्या","समूह के अंतिम छोर के एक्सल के बीच फ़ुट में दूरी","लोड का शुद्ध वज़न हज़ारों पाउंड में","सबसे भारी एक्सल पर टायरों की संख्या"],"explanation":"O.C.G.A. §32-6-26(a)(1) में, N विचाराधीन समूह में एक्सल की संख्या है, L समूह के अंतिम छोर के एक्सल के बीच फ़ुट में दूरी है, और W उस समूह पर सकल वज़न है। (स्रोत: O.C.G.A. §32-6-26)"},"12":{"q":"O.C.G.A. §32-6-26 के तहत, गैर-राष्ट्रीय जॉर्जिया राजमार्गों पर केवल चार एक्सल से सुसज्जित वाहन के लिए अधिकतम कुल सकल वज़न कितना होता है?","options":["56,000 पाउंड","70,000 पाउंड","73,280 पाउंड","80,000 पाउंड"],"explanation":"O.C.G.A. §32-6-26(c)(1)(C) यह प्रावधान करता है कि चार एक्सल से सुसज्जित किसी भी वाहन के लिए, वाहन और लोड के लिए अधिकृत अधिकतम कुल सकल वज़न 70,000 पाउंड होगा। (स्रोत: O.C.G.A. §32-6-26)"},"13":{"q":"जॉर्जिया काउंटी-रोड सिस्टम पर, उस सड़क पर पिकअप या डिलीवरी न करने वाले वाहन के लिए अनुमत अधिकतम कुल सकल वज़न कितना होता है?","options":["46,000 पाउंड","56,000 पाउंड","70,000 पाउंड","80,000 पाउंड"],"explanation":"O.C.G.A. §32-6-26(f) काउंटी-रोड सिस्टम पर अधिकतम कुल सकल वज़न को 56,000 पाउंड पर सीमित करता है, सिवाय जब वाहन उस सड़क पर पिकअप या डिलीवरी कर रहा हो (या किसी अर्हता प्राप्त नामित स्थानीय ट्रक मार्ग पर)। (स्रोत: O.C.G.A. §32-6-26)"},"14":{"q":"वन उत्पाद, जीवित मुर्गी, कपास, चारा, ग्रेनाइट, ठोस अपशिष्ट या ताज़ा मिश्रित कंक्रीट ढोने वाला वाहन गैर-राष्ट्रीय राजमार्ग पर बिना परमिट के जॉर्जिया की सामान्य एक्सल/सकल सीमा को कब पार कर सकता है?","options":["कभी नहीं; सीमा पार करने के लिए हमेशा परमिट की आवश्यकता होती है","केवल रात में और केवल इंटरस्टेट राजमार्गों पर","जब सिंगल-एक्सल वज़न 23,000 पाउंड या उससे कम, टैंडम-एक्सल 46,000 पाउंड या उससे कम, और सकल वज़न 80,000 पाउंड या उससे कम रहे","जब सकल वज़न एक्सल वज़न की परवाह किए बिना 100,000 पाउंड या उससे कम रहे"],"explanation":"O.C.G.A. §32-6-26(g)(1) इन निर्दिष्ट कृषि और कमोडिटी ढुलाई को गैर-राष्ट्रीय राजमार्गों पर बिना परमिट के केवल तभी अनुमति देता है जब सिंगल-एक्सल लोड 23,000 पाउंड से अधिक न हो, टैंडम-एक्सल 46,000 पाउंड से अधिक न हो, और कुल सकल वज़न 80,000 पाउंड से अधिक न हो। (स्रोत: O.C.G.A. §32-6-26)"},"15":{"q":"खेती, कृषि या वन-प्रबंधन उपकरण के लिए जॉर्जिया की आकार छूट (जो इसे बिना परमिट के चौड़ाई और लंबाई की सीमा पार करने की अनुमति देती है) किस शर्त के तहत लागू होती है?","options":["केवल इंटरस्टेट सिस्टम पर और केवल रात में","इंटरस्टेट सिस्टम का हिस्सा न होने वाली सड़कों पर दिन के उजाले के घंटों के दौरान, मालिक या डीलर की संपत्ति के 40 मील के भीतर","राज्य में कहीं भी किसी भी समय बिना किसी दूरी सीमा के","केवल जब इंटरस्टेट पर अंबर लाइट वाला एस्कॉर्ट वाहन इसके साथ हो"],"explanation":"O.C.G.A. §32-6-25 खेती/कृषि या वन-प्रबंधन उपकरण को चौड़ाई और लंबाई की सीमाओं से, बिना परमिट के, छूट देता है, जब इसे दिन के उजाले के घंटों के दौरान इंटरस्टेट सिस्टम का हिस्सा न होने वाली सार्वजनिक सड़क पर मालिक या डीलर की संपत्ति के 40 मील के दायरे में संचालित किया जाए। यह छूट वन उत्पादों को ढोने या परिवहन करने वाले वाहनों पर लागू नहीं होती। (स्रोत: O.C.G.A. §32-6-25)"},"16":{"q":"जॉर्जिया में कौन वाहन या लोड को कानून द्वारा निर्धारित अधिकतम आकार या वज़न सीमा पार करने के लिए अधिकृत करने वाला परमिट जारी करता है?","options":["परिवहन विभाग (GDOT), लिखित आवेदन और उचित कारण दर्शाए जाने पर","जहां यात्रा शुरू होती है उस काउंटी का शेरिफ़","निरीक्षण के समय कोई भी वज़न-स्टेशन अधिकारी","CDL आवेदन के साथ ड्राइवर सेवा विभाग"],"explanation":"O.C.G.A. §32-6-28(a) GDOT आयुक्त (या नामित अधिकारी) को, लिखित आवेदन और उचित कारण दर्शाए जाने पर, ऐसा परमिट जारी करने के लिए अधिकृत करता है जो ऐसे वाहन और लोड को अनुमति देता है जिसका वज़न, चौड़ाई, लंबाई या ऊंचाई कानूनी अधिकतम से अधिक हो। परमिट GDOT/Department of Public Safety (GAPROS सिस्टम) के माध्यम से प्राप्त किए जाते हैं। (स्रोत: O.C.G.A. §32-6-28; GDOT)"},"17":{"q":"O.C.G.A. §32-6-28 के तहत, जॉर्जिया का वार्षिक ओवरसाइज़/ओवरवेट परमिट ऐसे वाहन को अधिकृत करने के लिए जारी नहीं किया जा सकता जिसका कुल सकल वज़न किस राशि से अधिक हो?","options":["80,000 पाउंड","120,000 पाउंड","150,000 पाउंड","100,000 पाउंड"],"explanation":"O.C.G.A. §32-6-28(b)(1)(A) यह प्रावधान करता है कि वार्षिक परमिट ऐसे वाहन के संचालन को अधिकृत नहीं करेगा जिसका कुल सकल वज़न 100,000 पाउंड से अधिक हो (न ही जिसका सिंगल-एक्सल वज़न 25,000 पाउंड से अधिक हो, लंबाई 100 फ़ुट से अधिक हो, चौड़ाई 102 इंच / लोड चौड़ाई 144 इंच से अधिक हो, या ऊंचाई 14 फ़ुट 6 इंच से अधिक हो)। (स्रोत: O.C.G.A. §32-6-28; GDOT)"},"18":{"q":"जॉर्जिया के बुनियादी वज़न नियम के तहत, वैधानिक सहनशीलता लागू होने से पहले सिंगल एक्सल (उच्च-दबाव न्यूमेटिक टायर) पर आधार अधिकतम लोड कितना होता है?","options":["12,000 पाउंड","18,000 पाउंड","20,000 पाउंड","16,000 पाउंड"],"explanation":"O.C.G.A. §32-6-26(b)(1) किसी भी सिंगल एक्सल (उच्च-दबाव न्यूमेटिक, ठोस रबर या कुशन टायर) पर ऐसे लोड को प्रतिबंधित करता है जो 16,000 पाउंड को 13 प्रतिशत से अधिक पार करता हो—इसलिए आधार आंकड़ा 16,000 पाउंड है और 13% सहनशीलता से लगभग 18,080 पाउंड प्राप्त होता है। (स्रोत: O.C.G.A. §32-6-26)"},"19":{"q":"O.C.G.A. §32-6-27 के तहत, जॉर्जिया में किसी ओवरवेट वाहन को आगे बढ़ने की अनुमति देने से पहले, ऑपरेटर को कानूनी सीमा से किस राशि से अधिक के सभी सकल वज़न को उतारना होगा?","options":["2,000 पाउंड","4,000 पाउंड","6,000 पाउंड","10,000 पाउंड"],"explanation":"O.C.G.A. §32-6-27(e) किसी ओवरवेट वाहन के मालिक/ऑपरेटर से, निर्धारित क्षति का भुगतान करने के अलावा, वाहन को आगे बढ़ने की अनुमति देने से पहले कानूनी वज़न सीमा से 6,000 पाउंड से अधिक के सभी सकल वज़न को उतारने की आवश्यकता है। (स्रोत: O.C.G.A. §32-6-27)"},"20":{"q":"जॉर्जिया में, 26,001 पाउंड या उससे अधिक की सकल संयोजन वज़न रेटिंग (GCWR) वाले वाहनों के संयोजन को संचालित करने के लिए कौन सी श्रेणी का CDL आवश्यक होता है, जहां खींचे जाने वाले वाहन का GVWR 10,000 पाउंड से अधिक हो?","options":["Class B","Class C","Class D","Class A"],"explanation":"जॉर्जिया Class A CDL किसी भी ऐसे वाहन संयोजन को कवर करता है जिसका GCWR 26,001+ पाउंड हो जहां खींची गई यूनिट 10,000 पाउंड GVWR से अधिक हो। Class A धारक उचित एंडोर्समेंट के साथ Class B और C वाहन भी संचालित कर सकता है। स्रोत: Georgia DDS, 'Apply for a Commercial (CDL) License (Class A, B, C).'"},"21":{"q":"जॉर्जिया DDS नियमों के तहत, Class B CDL किसी ड्राइवर को निम्नलिखित में से किसे संचालित करने के लिए अधिकृत करता है?","options":["वाहनों का कोई भी संयोजन जहां खींची गई यूनिट 10,000 पाउंड से अधिक हो","26,001+ पाउंड GVWR वाला कोई भी एकल वाहन, जो 10,000 पाउंड से अधिक न होने वाली यूनिट खींचता हो","केवल 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन","केवल खतरनाक सामग्री के लिए प्लेकार्ड लगे वाहन"],"explanation":"जॉर्जिया Class B CDL 26,001+ पाउंड GVWR वाले एकल वाहनों को कवर करता है, जिनमें 10,000 पाउंड GVWR से अधिक न होने वाला वाहन खींचने वाले भी शामिल हैं। Class B धारक उचित एंडोर्समेंट के साथ Class C वाहन भी संचालित कर सकता है। स्रोत: Georgia DDS, 'Apply for a Commercial (CDL) License.'"},"22":{"q":"जॉर्जिया में, Class C CDL विशेष रूप से किस प्रकार के वाहन के लिए जारी किया जाता है?","options":["26,001 पाउंड GCWR से अधिक वाहनों का कोई भी संयोजन","26,001 पाउंड GVWR से अधिक कोई भी एकल वाहन","एक एकल वाहन (या संयोजन) जो Class A या B को पूरा नहीं करता लेकिन ड्राइवर सहित 16+ यात्रियों को ले जाता है, या खतरनाक सामग्री के लिए प्लेकार्ड लगा हो","26,001 पाउंड से कम कोई भी यात्री कार या पिकअप ट्रक"],"explanation":"जॉर्जिया Class C CDL एक एकल वाहन, या संयोजन, पर लागू होता है जो Class A या B परिभाषा को पूरा नहीं करता लेकिन ड्राइवर सहित 16 या अधिक यात्रियों को परिवहन करने के लिए डिज़ाइन किया गया है या प्लेकार्डिंग की आवश्यकता वाली खतरनाक सामग्री के परिवहन के लिए उपयोग किया जाता है। स्रोत: Georgia DDS, 'Apply for a Commercial (CDL) License.'"},"23":{"q":"किसी भी जॉर्जिया CDL के लिए आवेदन करने की न्यूनतम आयु क्या है?","options":["18 वर्ष","16 वर्ष","21 वर्ष","25 वर्ष"],"explanation":"जॉर्जिया DDS को CDL आवेदकों का कम से कम 18 वर्ष का होना आवश्यक है। 18 से 21 वर्ष की आयु के आवेदक 21 वर्ष के होने तक इंट्रास्टेट (केवल जॉर्जिया) ड्राइविंग तक सीमित रहते हैं। स्रोत: Georgia DDS, 'Apply for a Commercial (CDL) License.'"},"24":{"q":"एक 19-वर्षीय जॉर्जिया CDL धारक किस तरह से प्रतिबंधित होता है?","options":["किसी भी एंडोर्समेंट को रखने से प्रतिबंधित","21 वर्ष की आयु तक पहुंचने तक इंट्रास्टेट (केवल जॉर्जिया) ड्राइविंग तक सीमित","केवल Class C वाहनों तक सीमित","रात में ड्राइविंग से प्रतिबंधित"],"explanation":"जॉर्जिया 18 वर्ष और उससे अधिक आयु के आवेदकों को CDL जारी करता है, लेकिन 18 से 21 वर्ष की आयु के ड्राइवरों पर 'Georgia Only' (इंट्रास्टेट) प्रतिबंध लगा होता है। इंटरस्टेट ड्राइविंग के लिए प्रतिबंध हटवाने हेतु ड्राइवर को 21 वर्ष का होना चाहिए और एक Customer Service Center जाना चाहिए। स्रोत: Georgia DDS, 'Apply for a Commercial (CDL) License.'"},"25":{"q":"एक जॉर्जिया CDL धारक इंट्रास्टेट-केवल प्रतिबंध हटाना चाहता है ताकि वे राज्य की सीमाओं के पार ड्राइव कर सकें। क्या होना चाहिए?","options":["उन्हें पहले कम से कम पांच वर्षों तक CDL रखना होगा","उन्हें अपने 21वें जन्मदिन तक पहुंचना होगा और 'Georgia Only' प्रतिबंध हटवाने के लिए एक DDS Customer Service Center जाना होगा","उन्हें HazMat एंडोर्समेंट जोड़ना होगा","उन्हें 18 वर्ष की आयु में एक अतिरिक्त इंटरस्टेट स्किल्स टेस्ट पास करना होगा"],"explanation":"18 से 21 वर्ष की आयु के ड्राइवर इंट्रास्टेट ड्राइविंग तक सीमित हैं। इंटरस्टेट विशेषाधिकार प्राप्त करने के लिए, ड्राइवर को 21 वर्ष का होना चाहिए और 'Georgia Only' प्रतिबंध हटवाने के लिए एक DDS Customer Service Center जाना चाहिए। स्रोत: Georgia DDS, 'Apply for a Commercial (CDL) License.'"},"26":{"q":"जॉर्जिया में प्लेकार्ड की आवश्यकता वाली मात्रा में खतरनाक सामग्री का परिवहन करने वाले वाहन को चलाने के लिए कौन सा एंडोर्समेंट आवश्यक है?","options":["N (Tanker) एंडोर्समेंट","T (Doubles/Triples) एंडोर्समेंट","P (Passenger) एंडोर्समेंट","H (HazMat) एंडोर्समेंट"],"explanation":"प्लेकार्डिंग की आवश्यकता वाली खतरनाक सामग्री ढोने के लिए H (HazMat) एंडोर्समेंट आवश्यक है। जॉर्जिया में इसके लिए एक नॉलेज टेस्ट पास करना, एक TSA पृष्ठभूमि जांच, और पहली बार जारी करने और नवीनीकरण दोनों के लिए फ़िंगरप्रिंटिंग की आवश्यकता होती है। स्रोत: Georgia DDS, 'Adding CDL Endorsements.'"},"27":{"q":"जॉर्जिया में, HazMat (H) एंडोर्समेंट के लिए कौन सी अतिरिक्त संघीय आवश्यकता को पूरा किया जाना चाहिए जो Tanker (N) एंडोर्समेंट के लिए आवश्यक नहीं है?","options":["एक अलग स्किल्स (रोड) टेस्ट पास करना","उपयोग से पहले 14 दिन तक एंडोर्समेंट रखना","फ़िंगरप्रिंटिंग के साथ एक TSA सुरक्षा खतरा मूल्यांकन पास करना","पहले एक पैसेंजर एंडोर्समेंट प्राप्त करना"],"explanation":"HazMat एंडोर्समेंट के लिए एक TSA पृष्ठभूमि जांच (सुरक्षा खतरा मूल्यांकन) पास करना आवश्यक है, और पहली बार जारी करने के साथ-साथ नवीनीकरण के लिए भी फ़िंगरप्रिंट आवश्यक हैं। Tanker एंडोर्समेंट के लिए केवल एक नॉलेज टेस्ट आवश्यक है। स्रोत: Georgia DDS, 'Adding CDL Endorsements.'"},"28":{"q":"जॉर्जिया DDS के अनुसार, N (Tanker) एंडोर्समेंट कैसे प्राप्त किया जाता है?","options":["एक नॉलेज टेस्ट और एक स्किल्स टेस्ट दोनों पास करके","केवल एक स्किल्स टेस्ट पास करके","केवल एक नॉलेज टेस्ट पास करके","केवल एक TSA पृष्ठभूमि जांच पास करके"],"explanation":"जॉर्जिया में N (Tanker) एंडोर्समेंट के लिए केवल एक नॉलेज टेस्ट पास करना आवश्यक है और यह Class A और B CDL के लिए मान्य है। स्रोत: Georgia DDS, 'Adding CDL Endorsements.'"},"29":{"q":"कौन सा जॉर्जिया CDL एंडोर्समेंट केवल Class A CDL के लिए मान्य है और एक नॉलेज टेस्ट पास करके प्राप्त किया जाता है?","options":["T (Doubles/Triples) एंडोर्समेंट","P (Passenger) एंडोर्समेंट","S (School Bus) एंडोर्समेंट","N (Tanker) एंडोर्समेंट"],"explanation":"T (Double/Triple Trailer) एंडोर्समेंट केवल Class A CDL के लिए मान्य है और इसके लिए एक नॉलेज टेस्ट आवश्यक है। इसे Commercial Learner's Permit पर प्राप्त नहीं किया जा सकता; आवेदक के पास पहले से ही एक मान्य CDL होना चाहिए। स्रोत: Georgia DDS, 'Adding CDL Endorsements.'"},"30":{"q":"P (Passenger) एंडोर्समेंट प्राप्त करने के लिए जॉर्जिया को क्या आवश्यक है?","options":["केवल एक नॉलेज टेस्ट पास करना","एक नॉलेज टेस्ट और एक स्किल्स टेस्ट दोनों पास करना","केवल एक स्किल्स टेस्ट पास करना","केवल एक TSA पृष्ठभूमि जांच पास करना"],"explanation":"जॉर्जिया में, P (Passenger) एंडोर्समेंट के लिए एक नॉलेज टेस्ट और एक स्किल्स टेस्ट दोनों पास करना आवश्यक है, और यह Class A, B, और C CDL के लिए मान्य है। स्रोत: Georgia DDS, 'Adding CDL Endorsements.'"},"31":{"q":"जॉर्जिया DDS किन दो एंडोर्समेंट के लिए एक नॉलेज टेस्ट और एक स्किल्स टेस्ट दोनों की आवश्यकता रखता है?","options":["N (Tanker) और T (Doubles/Triples)","H (HazMat) और N (Tanker)","P (Passenger) और S (School Bus)","T (Doubles/Triples) और H (HazMat)"],"explanation":"जॉर्जिया में, Passenger (P) और School Bus (S) एंडोर्समेंट में से प्रत्येक के लिए एक नॉलेज टेस्ट और एक स्किल्स टेस्ट दोनों पास करना आवश्यक है। N, T, और H एंडोर्समेंट के लिए केवल एक नॉलेज टेस्ट आवश्यक है। स्रोत: Georgia DDS, 'Adding CDL Endorsements.'"},"32":{"q":"7 फरवरी, 2022 से प्रभावी, जॉर्जिया CDL आवेदकों का कौन सा समूह Entry-Level Driver Training (ELDT) आवश्यकताओं के अधीन है?","options":["केवल Class C CDL चाहने वाले आवेदक","पहली बार Class A या B प्राप्त करने वाले, उच्च श्रेणी में अपग्रेड करने वाले, या School Bus, Passenger, या HazMat एंडोर्समेंट जोड़ने वाले आवेदक","केवल 21 वर्ष से अधिक आयु के ड्राइवर","केवल बिना किसी बदलाव के मौजूदा CDL का नवीनीकरण करने वाले आवेदक"],"explanation":"जॉर्जिया द्वारा अपनाए गए FMCSA ELDT नियमों के तहत, 7 फरवरी, 2022 से, पहली बार Class A या B CDL प्राप्त करने वाले, उच्च श्रेणी में अपग्रेड करने वाले, या School Bus (S), Passenger (P), या HazMat (H) एंडोर्समेंट जोड़ने वाले सभी एंट्री-लेवल ड्राइवरों को ELDT पूरा करना होगा। स्रोत: Georgia DDS, 'Apply for a Commercial (CDL) License' / 'Adding CDL Endorsements.'"},"33":{"q":"जॉर्जिया CDL आवेदक का Entry-Level Driver Training (ELDT) कहां पूरा और दर्ज किया जाना चाहिए?","options":["आवेदक की पसंद के किसी भी निजी ड्राइविंग स्कूल में बिना किसी रजिस्ट्री के","केवल किसी जॉर्जिया DDS Customer Service Center में","बिना किसी औपचारिक प्रदाता के एक ऑनलाइन क्विज़ के माध्यम से","FMCSA Training Provider Registry (TPR) पर सूचीबद्ध किसी प्रशिक्षण प्रदाता के साथ"],"explanation":"ELDT को FMCSA Training Provider Registry (TPR) पर सूचीबद्ध किसी प्रदाता द्वारा प्रदान किया जाना चाहिए, और ड्राइवर द्वारा CDL स्किल्स या HazMat नॉलेज टेस्ट देने से पहले इसकी पूर्णता रजिस्ट्री में रिपोर्ट की जाती है। स्रोत: Georgia DDS द्वारा संदर्भित FMCSA ELDT विनियम।"},"34":{"q":"पूर्ण जॉर्जिया CDL के लिए आवेदन करने से पहले, आवेदक को कितने समय तक Commercial Learner Permit (CLP) रखना होगा?","options":["कम से कम 30 दिन","कम से कम 60 दिन","कम से कम 14 दिन","कम से कम 6 महीने"],"explanation":"जॉर्जिया को CDL आवेदकों से CDL स्किल्स टेस्ट देने / पूर्ण CDL के लिए आवेदन करने से पहले कम से कम 14 दिन तक Commercial Learner Permit (CLP) रखना आवश्यक है। स्रोत: Georgia DDS, 'CDL Permit' और CDL Licensing FAQs।"},"35":{"q":"जॉर्जिया आवेदक को Commercial Learner Permit (CLP) जारी किए जाने के लिए क्या पास करना होगा?","options":["आवश्यक लिखित नॉलेज परीक्षा(एं)","केवल CDL स्किल्स (रोड) टेस्ट","एक TSA पृष्ठभूमि जांच","केवल एक विज़न टेस्ट"],"explanation":"जॉर्जिया CLP (Class AP या BP) प्राप्त करने के लिए, आवेदक के पास एक मान्य नियमित जॉर्जिया ड्राइवर लाइसेंस होना चाहिए और आवश्यक लिखित नॉलेज परीक्षा(एं) पास करनी होंगी। स्किल्स टेस्ट बाद में, 14-दिन की प्रतीक्षा अवधि के बाद आता है। स्रोत: Georgia DDS, 'Apply for a Commercial Permit (Class AP or BP).'"},"36":{"q":"1 जुलाई, 2021 को या उसके बाद जारी किए गए जॉर्जिया CLP के लिए, परमिट कितने समय तक मान्य रहता है?","options":["30 दिन","180 दिन","5 वर्ष","365 दिन"],"explanation":"1 जुलाई, 2021 को या उसके बाद जारी किया गया जॉर्जिया Commercial Learner Permit (CLP) 365 दिनों के लिए मान्य है। स्रोत: Georgia DDS, 'CDL Permit.'"},"37":{"q":"किसी व्यक्ति द्वारा जॉर्जिया Commercial Learner Permit (CLP) प्राप्त करने से पहले निम्नलिखित में से क्या आवश्यक है?","options":["एक मान्य नियमित जॉर्जिया ड्राइवर लाइसेंस रखना","पहले से ही एक HazMat एंडोर्समेंट रखना","एक TSA पृष्ठभूमि जांच पूरी करना","एक Class A CDL रखना"],"explanation":"जॉर्जिया DDS को CLP आवेदकों से कमर्शियल परमिट के लिए आवेदन करने से पहले एक मान्य नियमित जॉर्जिया ड्राइवर लाइसेंस रखना आवश्यक है। स्रोत: Georgia DDS, 'Apply for a Commercial Permit (Class AP or BP).'"},"38":{"q":"जॉर्जिया CDL के लिए आवेदन करते समय, DDS आवेदक से दस्तावेज़ों के किस संयोजन को प्रदान करना आवश्यक है?","options":["पहचान का प्रमाण, सोशल सिक्योरिटी नंबर, वैध उपस्थिति, और जॉर्जिया निवास के दो प्रमाण","केवल एक सोशल सिक्योरिटी कार्ड","केवल एक जॉर्जिया मतदाता पंजीकरण कार्ड","केवल एक पासपोर्ट, बिना किसी निवास प्रमाण के"],"explanation":"जॉर्जिया DDS को पहचान का प्रमाण (जैसे प्रमाणित जन्म प्रमाणपत्र या U.S. पासपोर्ट), सोशल सिक्योरिटी नंबर का प्रमाण, वैध उपस्थिति का प्रमाण, और जॉर्जिया निवास साबित करने वाले अलग-अलग स्रोतों से दो दस्तावेज़ आवश्यक हैं। स्रोत: Georgia DDS, 'Apply for a Commercial (CDL) License.'"},"39":{"q":"एक जॉर्जिया CDL ड्राइवर जो केवल जॉर्जिया के भीतर संचालन करता है और जिसे FMCSA ड्राइवर-योग्यता आवश्यकताओं को पूरा करना होता है, उसे कौन सी मेडिकल स्व-प्रमाणन श्रेणी चुननी चाहिए?","options":["Non-excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","Non-excepted Intrastate (NA)"],"explanation":"जॉर्जिया DDS चार स्व-प्रमाणन श्रेणियां उपयोग करता है: Non-excepted Interstate (NI), Excepted Interstate (EI), Non-excepted Intrastate (NA), और Excepted Intrastate (EA)। केवल जॉर्जिया में (इंट्रास्टेट) संचालन करने वाला ड्राइवर जिसे मेडिकल-योग्यता आवश्यकताओं को पूरा करना है, वह Non-excepted Intrastate (NA) का चयन करता है। सभी CDL धारकों को DDS के पास एक स्व-प्रमाणन दाखिल करना होगा। स्रोत: Georgia DDS, 'CDL Medical Certification and Self-Certification Process.'"},"40":{"q":"जॉर्जिया में, किस अधिकतम रक्त अल्कोहल सांद्रता (BAC) पर कोई व्यक्ति वैध रूप से कमर्शियल मोटर वाहन (CMV) संचालित कर सकता है?","options":["0.08 या उससे अधिक सीमा है","0.04 या उससे अधिक पर यह अवैध है","0.10 या उससे अधिक सीमा है","0.02 से अधिक कोई भी मात्रा अवैध है"],"explanation":"जॉर्जिया में 0.04 या उससे अधिक BAC के साथ CMV संचालित करना अवैध है, जो गैर-कमर्शियल ड्राइवरों के लिए 0.08 सीमा का आधा है। स्रोत: Georgia CDL Manual (DDS), CDL Disqualifications; 49 CFR 383.51(b)।"},"41":{"q":"एक जॉर्जिया CDL धारक को पहले बड़े अपराध, जैसे CMV में DUI, के लिए दोषी ठहराया जाता है, जबकि वे खतरनाक सामग्री नहीं ले जा रहे थे। CDL कितने समय के लिए अयोग्य ठहराया जाता है?","options":["कम से कम 60 दिन","कम से कम 6 महीने","कम से कम 1 वर्ष","कम से कम 3 वर्ष"],"explanation":"पहला बड़ा अपराध (DUI, BAC 0.04+, इनकार, घटनास्थल छोड़ना, CMV का गंभीर अपराध में उपयोग, आदि) कम से कम 1 वर्ष की अयोग्यता का परिणाम देता है। स्रोत: Georgia CDL Manual (DDS); 49 CFR 383.51(b) Table 1।"},"42":{"q":"यदि कोई जॉर्जिया CDL ड्राइवर खतरनाक सामग्री के लिए प्लेकार्ड लगे CMV को संचालित करते समय पहला बड़ा अपराध करता है, तो अयोग्यता अवधि कैसे बदलती है?","options":["यह कम से कम 3 वर्ष तक बढ़ जाती है","यह कम से कम 1 वर्ष पर ही रहती है","यह कम से कम 5 वर्ष तक बढ़ जाती है","इसका परिणाम तत्काल आजीवन प्रतिबंध होता है"],"explanation":"जब पहला बड़ा अपराध प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री का परिवहन करते समय होता है, तो न्यूनतम अयोग्यता 1 वर्ष से बढ़कर 3 वर्ष हो जाती है। स्रोत: Georgia CDL Manual (DDS); 49 CFR 383.51(b) Table 1।"},"43":{"q":"एक अलग घटना में दूसरे बड़े अपराध के लिए दोषी ठहराए गए जॉर्जिया CDL धारक के लिए अयोग्यता अवधि क्या है?","options":["अतिरिक्त 3 वर्ष","अतिरिक्त 10 वर्ष","अतिरिक्त 120 दिन","आजीवन अयोग्यता"],"explanation":"अलग घटनाओं में बड़े अपराधों के किसी भी संयोजन के लिए दूसरी दोषसिद्धि CDL की आजीवन अयोग्यता का परिणाम देती है। स्रोत: Georgia CDL Manual (DDS); 49 CFR 383.51(b) Table 1।"},"44":{"q":"जॉर्जिया के निहित सहमति कानून के तहत, एक CDL धारक जो वैध अनुरोध के बाद अल्कोहल या ड्रग्स के लिए रासायनिक परीक्षण से इनकार करता है, उसके साथ क्या होता है?","options":["कुछ नहीं, क्योंकि इनकार को साक्ष्य के रूप में उपयोग नहीं किया जा सकता","केवल जुर्माना लगाया जाता है लेकिन CDL प्रभावित नहीं होता","ड्राइवर को उसी तरह अयोग्य ठहराया जाता है जैसे DUI के लिए दोषी ठहराए जाने पर","ड्राइवर को 60-दिन की गंभीर-उल्लंघन सज़ा मिलती है"],"explanation":"रासायनिक परीक्षण से इनकार करने को एक बड़े अपराध के रूप में माना जाता है, जो DUI दोषसिद्धि के समान अयोग्यता वहन करता है: पहले अपराध के लिए कम से कम 1 वर्ष और दूसरे के लिए आजीवन। स्रोत: Georgia CDL Manual (DDS); O.C.G.A. 40-5-67.1 (निहित सहमति); 49 CFR 383.51(b)।"},"45":{"q":"जॉर्जिया में एक CDL ड्राइवर ड्यूटी पर रहते हुए 0.04 से कम किसी भी पता लगाने योग्य मात्रा में अल्कोहल के साथ पाया जाता है। इसका परिणाम क्या होता है?","options":["एक आउट-ऑफ-सर्विस आदेश जो ड्राइवर को 24 घंटे के लिए सेवा से बाहर रखता है","CDL की तत्काल 1-वर्ष की अयोग्यता","एक 60-दिन की गंभीर-उल्लंघन अयोग्यता","कोई परिणाम नहीं क्योंकि BAC 0.04 से कम है"],"explanation":"0.04 से कम कोई भी पता लगाने योग्य अल्कोहल किसी बड़े-अपराध अयोग्यता को ट्रिगर नहीं करता लेकिन ड्राइवर को 24 घंटे के लिए सेवा से बाहर रखे जाने की आवश्यकता होती है। स्रोत: Georgia CDL Manual (DDS); 49 CFR 392.5।"},"46":{"q":"निम्नलिखित में से किसे जॉर्जिया CDL धारक के लिए बड़े अपराध के बजाय \"गंभीर ट्रैफ़िक उल्लंघन\" के रूप में वर्गीकृत किया गया है?","options":["0.04 या उससे अधिक BAC के साथ CMV चलाना","किसी अपराध को अंजाम देने के लिए CMV का उपयोग करना","पोस्ट की गई सीमा से 15 mph या अधिक का अत्यधिक तेज़ गति से चलना","CMV से जुड़ी दुर्घटना के घटनास्थल को छोड़ना"],"explanation":"अत्यधिक तेज़ गति (सीमा से 15+ mph अधिक) एक गंभीर ट्रैफ़िक उल्लंघन है। DUI, अपराध में उपयोग, और हिट-एंड-रन कहीं अधिक कठोर दंडों वाले बड़े अपराध हैं। स्रोत: Georgia CDL Manual (DDS); 49 CFR 383.51(c) Table 2।"},"47":{"q":"एक जॉर्जिया CDL धारक को 3-वर्ष की अवधि के भीतर अलग घटनाओं में दो गंभीर ट्रैफ़िक उल्लंघनों के लिए दोषी ठहराया जाता है। अयोग्यता अवधि क्या है?","options":["कम से कम 30 दिन","कम से कम 60 दिन","कम से कम 120 दिन","कम से कम 1 वर्ष"],"explanation":"3 वर्षों के भीतर दो गंभीर ट्रैफ़िक उल्लंघन कम से कम 60 दिन की अयोग्यता का परिणाम देते हैं। स्रोत: Georgia CDL Manual (DDS); 49 CFR 383.51(c) Table 2।"},"48":{"q":"एक जॉर्जिया CDL धारक को 3-वर्ष की अवधि के भीतर अलग घटनाओं में तीन गंभीर ट्रैफ़िक उल्लंघनों के लिए दोषी ठहराया जाता है। अयोग्यता अवधि क्या है?","options":["कम से कम 60 दिन","कम से कम 90 दिन","कम से कम 120 दिन","कम से कम 1 वर्ष"],"explanation":"3 वर्षों के भीतर तीन गंभीर ट्रैफ़िक उल्लंघन कम से कम 120 दिन की अयोग्यता का परिणाम देते हैं। स्रोत: Georgia CDL Manual (DDS); 49 CFR 383.51(c) Table 2।"},"49":{"q":"इनमें से किसे एक गंभीर ट्रैफ़िक उल्लंघन के रूप में नहीं गिना जाता जो जॉर्जिया में CDL अयोग्यता का कारण बन सकता है?","options":["आगे चल रहे वाहन का बहुत करीब से पीछा करना","अनुचित या अनियमित लेन परिवर्तन करना","लापरवाही से ड्राइविंग","रेस्ट एरिया में रात भर CMV पार्क करना"],"explanation":"गंभीर ट्रैफ़िक उल्लंघनों में बहुत करीब से पीछा करना, अनुचित लेन परिवर्तन, लापरवाही से ड्राइविंग, और अत्यधिक तेज़ गति शामिल हैं। रेस्ट एरिया में वैध रूप से पार्क करना एक उल्लंघन नहीं है। स्रोत: Georgia CDL Manual (DDS); 49 CFR 383.51(c) Table 2।"},"50":{"q":"रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के पहले दोषसिद्धि (FIRST conviction) पर जॉर्जिया CDL ड्राइवर के लिए अयोग्यता (disqualification) की अवधि क्या है?","options":["कम से कम 30 दिन","कम से कम 60 दिन","कम से कम 120 दिन","कम से कम 1 साल"],"explanation":"पहले रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन पर कम से कम 60 दिन की अयोग्यता होती है। स्रोत: Georgia CDL Manual (DDS); 49 CFR 383.51(d) Table 3।"},"51":{"q":"एक जॉर्जिया CDL धारक 3 साल की अवधि के भीतर दूसरा (SECOND) रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन करता है। न्यूनतम अयोग्यता क्या है?","options":["कम से कम 60 दिन","कम से कम 120 दिन","कम से कम 6 महीने","कम से कम 1 साल"],"explanation":"3 साल के भीतर दूसरे रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन पर कम से कम 120 दिन की अयोग्यता होती है। स्रोत: Georgia CDL Manual (DDS); 49 CFR 383.51(d) Table 3।"},"52":{"q":"एक जॉर्जिया CDL धारक 3 साल की अवधि के भीतर तीसरा (THIRD) रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन करता है। न्यूनतम अयोग्यता क्या है?","options":["कम से कम 120 दिन","कम से कम 6 महीने","कम से कम 1 साल","आजीवन अयोग्यता"],"explanation":"3 साल के भीतर तीसरे या उसके बाद के रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन पर कम से कम 1 साल की अयोग्यता होती है। स्रोत: Georgia CDL Manual (DDS); 49 CFR 383.51(d) Table 3।"},"53":{"q":"जब कोई खतरनाक पदार्थ (hazardous materials) या यात्री शामिल न हों, तब आउट-ऑफ-सर्विस (OOS) आदेश के उल्लंघन के पहले दोषसिद्धि (FIRST conviction) पर जॉर्जिया CDL ड्राइवर के लिए अयोग्यता की अवधि क्या है?","options":["कम से कम 60 दिन","कम से कम 90 दिन","कम से कम 180 दिन","कम से कम 2 साल"],"explanation":"आउट-ऑफ-सर्विस आदेश के उल्लंघन के पहले दोषसिद्धि पर कम से कम 180 दिन (अधिकतम 1 साल तक) की अयोग्यता होती है। स्रोत: Georgia CDL Manual (DDS); 49 CFR 383.51(e) Table 4।"},"54":{"q":"एक जॉर्जिया CDL धारक को 10 साल की अवधि के भीतर अलग-अलग घटनाओं में दूसरे (SECOND) आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए दोषी ठहराया जाता है। न्यूनतम अयोग्यता क्या है?","options":["कम से कम 180 दिन","कम से कम 1 साल","कम से कम 2 साल","आजीवन अयोग्यता"],"explanation":"10 साल की अवधि के भीतर दूसरे आउट-ऑफ-सर्विस आदेश उल्लंघन पर कम से कम 2 साल (अधिकतम 5 साल तक) की अयोग्यता होती है। स्रोत: Georgia CDL Manual (DDS); 49 CFR 383.51(e) Table 4।"},"55":{"q":"यदि जॉर्जिया CDL ड्राइवर प्लेकार्ड लगे खतरनाक पदार्थ (placarded hazardous materials) या 16 या अधिक यात्रियों को ले जा रहा था, तो पहले (FIRST) आउट-ऑफ-सर्विस आदेश उल्लंघन के दंड में क्या बदलाव होता है?","options":["यह घटाकर 60 दिन कर दिया जाता है","न्यूनतम 180 दिन ही रहता है पर अधिकतम बढ़कर 2 साल हो जाता है","यह आजीवन अयोग्यता बन जाती है","यह 180 दिन से 1 साल पर अपरिवर्तित रहता है"],"explanation":"प्लेकार्ड लगे HazMat या 16+ यात्रियों को ले जाते समय पहले OOS उल्लंघन पर अयोग्यता कम से कम 180 दिन पर रहती है पर अधिकतम 2 साल तक हो सकती है, जो सामान्य मामले से अधिक है। स्रोत: Georgia CDL Manual (DDS); 49 CFR 383.51(e) Table 4।"},"56":{"q":"जॉर्जिया के Super Speeder कानून (O.C.G.A. §40-6-189) के तहत, किन गतियों पर एक ड्राइवर को \"Super Speeder\" के रूप में वर्गीकृत किया जाता है?","options":["किसी भी सड़क पर 65 mph या दो-लेन सड़क पर 75 mph","दो-लेन सड़क पर 75 mph या किसी भी सड़क या हाईवे पर 85 mph","दो-लेन सड़क पर 80 mph या इंटरस्टेट पर 90 mph","किसी भी पोस्ट की गई गति सीमा से 15 mph या अधिक"],"explanation":"जॉर्जिया का Super Speeder कानून किसी दो-लेन सड़क पर 75 mph या अधिक, या किसी भी सड़क या हाईवे पर 85 mph या अधिक के लिए दोषी ठहराए गए ड्राइवर को Super Speeder के रूप में वर्गीकृत करता है। स्रोत: O.C.G.A. §40-6-189।"},"57":{"q":"जॉर्जिया के Super Speeder कानून के तहत, Department of Driver Services एक दोषी Super Speeder से कौन-सा अतिरिक्त राज्य शुल्क लेता है, और यदि यह अदा न किया जाए तो क्या होता है?","options":["$200 शुल्क; यदि सूचना के 120 दिनों के भीतर भुगतान न किया जाए तो लाइसेंस निलंबन","$500 शुल्क; यदि 30 दिनों के भीतर भुगतान न किया जाए तो जेल","$100 शुल्क; यदि 90 दिनों के भीतर भुगतान न किया जाए तो चेतावनी पत्र","$200 शुल्क, भुगतान न करने पर कोई और परिणाम नहीं"],"explanation":"Super Speeder कानून किसी भी अदालती जुर्माने के ऊपर $200 का राज्य शुल्क जोड़ता है। यदि DDS सूचना के 120 दिनों के भीतर भुगतान न किया जाए, तो ड्राइवर का लाइसेंस निलंबित कर दिया जाता है और $50 का पुनर्बहाली शुल्क लागू होता है। स्रोत: O.C.G.A. §40-6-189।"},"58":{"q":"जॉर्जिया द्वारा लागू किए जाने वाले संघीय नियमों के तहत, उस CDL ड्राइवर का क्या होता है जिसे CMV चलाते समय टेक्स्टिंग करने या हाथ में पकड़े फोन का उपयोग करने के लिए दोषी ठहराया जाता है?","options":["इसमें विशेष रूप से CDL धारकों के लिए कोई दंड नहीं है","यह एक स्वतः 1-साल की प्रमुख-अपराध (major-offense) अयोग्यता है","यह अयोग्यता की ओर एक गंभीर यातायात उल्लंघन के रूप में गिना जाता है","इसके परिणामस्वरूप तत्काल आजीवन अयोग्यता होती है"],"explanation":"CMV चलाते समय टेक्स्टिंग करना या हाथ में पकड़े फोन का उपयोग करना एक गंभीर यातायात उल्लंघन है; 3 साल के भीतर दो उल्लंघन 60 दिन की अयोग्यता लाते हैं और तीन 120 दिन लाते हैं। स्रोत: 49 CFR 383.51(c); Georgia CDL Manual (DDS)।"},"59":{"q":"जॉर्जिया का Hands-Free कानून (O.C.G.A. §40-6-241) सभी ड्राइवरों पर लागू होता है। यह CMV सहित किसी वाहन को चलाते समय कौन-सा कार्य प्रतिबंधित करता है?","options":["Bluetooth या स्पीकरफोन हैंड्स-फ्री कनेक्शन का उपयोग करना","शरीर के किसी भी हिस्से से फोन को शारीरिक रूप से पकड़ना या सहारा देना","विंडशील्ड पर एक माउंटेड GPS डिवाइस दिखाई देना","वाहन में बैठे यात्री से बात करना"],"explanation":"Hands-Free Georgia Act ड्राइवरों को शरीर के किसी भी हिस्से से फोन या इलेक्ट्रॉनिक डिवाइस पकड़ने या सहारा देने से रोकता है; Bluetooth या स्पीकरफोन जैसे हैंड्स-फ्री उपयोग की अनुमति बनी रहती है। स्रोत: O.C.G.A. §40-6-241।"},"60":{"q":"आपकी दिशा में दो या अधिक लेन वाले जॉर्जिया इंटरस्टेट पर, आप शोल्डर पर पीली चमकती बत्तियाँ दिखाते एक स्थिर HERO यूनिट के पास पहुँचते हैं। जॉर्जिया का Move Over कानून एक वाणिज्यिक ड्राइवर से क्या अपेक्षा करता है?","options":["पोस्ट की गई गति सीमा बनाए रखें क्योंकि यूनिट सड़क से हटकर शोल्डर पर है","अपनी लेन में पूरी तरह रुक जाएँ और यूनिट के हटने तक प्रतीक्षा करें","यदि सुरक्षित रूप से संभव हो तो यूनिट से एक लेन दूर हट जाएँ; यदि आप सुरक्षित रूप से लेन नहीं बदल सकते, तो पोस्ट की गई गति सीमा से कम पर धीमे हों और रुकने के लिए तैयार रहें","केवल पुलिस और अग्निशमन वाहनों के लिए हटें, क्योंकि HERO और उपयोगिता (utility) यूनिट शामिल नहीं हैं"],"explanation":"जॉर्जिया का Move Over कानून (O.C.G.A. §40-6-16) समान दिशा में दो या अधिक लेन वाली सड़कों पर ड्राइवरों से चमकती बत्तियाँ दिखाने वाली स्थिर आपातकालीन, उपयोगिता, टोइंग/रिकवरी, हाईवे-रखरखाव, स्वच्छता, या HERO यूनिट से एक लेन दूर हटने की अपेक्षा करता है। यदि लेन परिवर्तन सुरक्षित रूप से नहीं किया जा सकता, तो ड्राइवर को पोस्ट की गई सीमा से कम गति करनी होगी और रुकने के लिए तैयार रहना होगा।"},"61":{"q":"जॉर्जिया का Move Over कानून चमकती बत्तियाँ दिखाने वाले स्थिर वाहनों पर लागू होता है। निम्नलिखित में से कौन-सा वाहन O.C.G.A. §40-6-16 द्वारा कवर नहीं किया गया है?","options":["एक खराब वाहन की सहायता करती हुई HERO (Highway Emergency Response Operator) यूनिट","पीली चमकती बत्तियों के साथ बिजली की लाइनें ठीक करता एक उपयोगिता सेवा वाहन","फ्लैट टायर के बाद अपनी मानक हैज़र्ड फ्लैशर (four-way flashers) चालू करके शोल्डर पर रुकी एक यात्री कार","पीली चमकती बत्तियों के साथ एक दुर्घटनाग्रस्त वाहन को रिकवर करता एक टो ट्रक"],"explanation":"O.C.G.A. §40-6-16 चमकती बत्तियाँ दिखाने वाली स्थिर आपातकालीन, टोइंग/रिकवरी, हाईवे-रखरखाव, उपयोगिता सेवा, स्वच्छता, और HERO यूनिटों की रक्षा करता है। केवल अपनी मानक four-way हैज़र्ड फ्लैशर का उपयोग करने वाली एक साधारण यात्री कार Move Over कानून के तहत संरक्षित वाहनों के वर्गों में से एक नहीं है।"},"62":{"q":"Hands-Free Georgia Act (O.C.G.A. §40-6-241) के तहत, जॉर्जिया हाईवे पर वाणिज्यिक मोटर वाहन चलाने वाले ड्राइवर पर विशेष रूप से कौन-सा अतिरिक्त प्रतिबंध लागू होता है?","options":["ड्राइवर मैन्युअल रूप से टेक्स्ट कर सकता है जब तक वाहन 15 mph से कम पर चल रहा हो","ड्राइवर किसी वॉयस कॉल को शुरू या समाप्त करने के लिए वायरलेस डिवाइस पर एक से अधिक बटन का उपयोग नहीं कर सकता","ड्राइवर फोन को कान से लगाकर पकड़ सकता है जब तक कॉल काम से संबंधित हो","ड्राइवर ड्यूटी पर रहते हुए Hands-Free Act से पूरी तरह छूट प्राप्त है"],"explanation":"O.C.G.A. §40-6-241 के तहत, वाणिज्यिक मोटर वाहन चलाते समय कोई भी ड्राइवर वॉयस संचार शुरू या समाप्त करने के लिए वायरलेस दूरसंचार डिवाइस पर एक से अधिक बटन का उपयोग नहीं कर सकता, और न ही किसी डिवाइस तक इस तरह पहुँच सकता है जिसके लिए बैठी हुई ड्राइविंग स्थिति छोड़नी पड़े। शरीर के किसी भी हिस्से से डिवाइस पकड़ना या सहारा देना सभी ड्राइवरों के लिए प्रतिबंधित है।"},"63":{"q":"जॉर्जिया में वाणिज्यिक वाहन चलाते समय Hands-Free Georgia Act (O.C.G.A. §40-6-241) के तहत कौन-सा डिवाइस या गतिविधि अनुमत है?","options":["टेक्स्ट संदेश पढ़ने के लिए स्मार्टफोन को हाथ में पकड़ना","संचार के लिए एक वाणिज्यिक टू-वे रेडियो या CB रेडियो का उपयोग करना","डैशबोर्ड पर टिकाए टैबलेट पर वीडियो देखना","कॉल के दौरान सेल फोन को कंधे पर कान से सटाकर रखना"],"explanation":"O.C.G.A. §40-6-241 स्पष्ट रूप से वाणिज्यिक टू-वे रेडियो, CB रेडियो, एमेच्योर/हैम रेडियो, सब्सक्रिप्शन-आधारित आपातकालीन संचार डिवाइस, निर्धारित चिकित्सा डिवाइस, और फैक्ट्री नेविगेशन/डायग्नोस्टिक सिस्टम को बाहर रखता है। शरीर के किसी भी हिस्से से फोन पकड़ना या सहारा देना, मैन्युअल टेक्स्टिंग, और वीडियो देखना सभी प्रतिबंधित हैं।"},"64":{"q":"आप जॉर्जिया इंटरस्टेट की सबसे बाईं पासिंग लेन में एक ट्रैक्टर-ट्रेलर चला रहे हैं और देखते हैं कि एक तेज़ वाहन आपके पीछे आ रहा है। जॉर्जिया के 'Slowpoke' / लेफ्ट-लेन कानून (O.C.G.A. §40-6-184) के तहत आपको क्या करना चाहिए?","options":["पासिंग लेन में अपनी स्थिति बनाए रखें जब तक आप पोस्ट की गई गति सीमा पर या उससे ऊपर हों","ओवरटेक करने वाले वाहन की गति से मेल खाने के लिए तेज़ हो जाएँ ताकि उसे पास करने की आवश्यकता न रहे","कानून वाणिज्यिक वाहनों पर लागू नहीं होता, इसलिए आप बाईं लेन में रह सकते हैं","ओवरटेक करने वाले वाहन को पास करने देने के लिए पासिंग लेन से हट जाएँ, जब तक सड़क, यातायात, मौसम, या किसी यातायात-नियंत्रण डिवाइस के कारण आपको वहीं रहना न पड़े"],"explanation":"जॉर्जिया का 'Slowpoke' कानून (O.C.G.A. §40-6-184) पासिंग लेन (HOV लेन के अलावा सबसे बाईं लेन) में ड्राइवर से अपेक्षा करता है कि जैसे ही उसे पता चले या पता होना चाहिए कि उसे पीछे से एक तेज़ वाहन ओवरटेक कर रहा है, वह हट जाए, जब तक सड़क/यातायात की स्थिति, मौसम, खतरे, या यातायात-नियंत्रण डिवाइस के कारण उस लेन में रहना आवश्यक न हो। यह इस बात पर लागू होता है चाहे आप गति सीमा पर हों या नहीं।"},"65":{"q":"जॉर्जिया के लेफ्ट-लेन / 'Slowpoke' कानून (O.C.G.A. §40-6-184) के प्रयोजनों के लिए, 'पासिंग लेन' को कैसे परिभाषित किया गया है?","options":["सबसे बाईं लेन, जो हाई-ऑक्यूपेंसी वाहन (HOV) लेन के अलावा हो","कोई भी लेन जिसमें कोई वाहन वर्तमान में दूसरे को पास कर रहा हो","दाएँ शोल्डर के सबसे निकट की लेन","तीन-लेन सड़क की केवल केंद्र लेन"],"explanation":"O.C.G.A. §40-6-184 'पासिंग लेन' को हाई-ऑक्यूपेंसी वाहन (HOV) लेन के अलावा सबसे बाईं लेन के रूप में परिभाषित करता है। पीछे से एक तेज़ वाहन द्वारा ओवरटेक किए जाने पर ड्राइवर को उस लेन में जारी नहीं रहना चाहिए।"},"66":{"q":"O.C.G.A. §40-6-52 के तहत, समान दिशा में तीन या अधिक लेन वाली जॉर्जिया सड़क पर एक 'ट्रक' (छह से अधिक पहियों वाला कोई भी वाहन, बसों और मोटरकोचों को छोड़कर) आम तौर पर किन लेनों में चल सकता है?","options":["कोई भी लेन, जब तक यह यातायात के प्रवाह के साथ बना रहे","हर समय केवल सबसे दाईं एकमात्र लेन","केवल दो सबसे दाईं लेन, सिवाय बाएँ मुड़ने की तैयारी करते समय या जहाँ लेन अन्यथा निर्दिष्ट हों","केवल केंद्र की लेन, जिससे दाईं लेन मर्जिंग यातायात के लिए खुली रहे"],"explanation":"O.C.G.A. §40-6-52 के अनुसार समान दिशा में तीन या अधिक लेन वाली सड़क पर एक ट्रक (छह से अधिक पहियों वाला वाहन, बसों और मोटरकोचों को छोड़कर) के लिए दो सबसे दाईं लेनों के अलावा किसी भी लेन में चलना अवैध है, सिवाय बाएँ मुड़ने की तैयारी करते समय या जहाँ Department of Transportation ने अन्य लेन निर्दिष्ट की हों।"},"67":{"q":"आपकी दिशा में ठीक दो लेन वाले जॉर्जिया हाईवे पर, O.C.G.A. §40-6-52 के अधीन एक ट्रक कब वैध रूप से बाईं लेन का उपयोग कर सकता है?","options":["जब भी दाईं लेन बाईं लेन से अधिक व्यस्त हो","जब वास्तव में किसी अन्य वाहन को ओवरटेक करके पास कर रहा हो या बाएँ मुड़ने की तैयारी कर रहा हो","केवल सूर्योदय और सूर्यास्त के बीच","कभी नहीं, किसी भी परिस्थिति में"],"explanation":"O.C.G.A. §40-6-52 के तहत, समान दिशा में दो लेन वाली सड़क पर एक ट्रक के लिए बाईं लेन में चलना अवैध है सिवाय जब वास्तव में किसी अन्य वाहन को ओवरटेक करके पास कर रहा हो, बाएँ मुड़ने की तैयारी कर रहा हो, या जैसा कि क़ानून द्वारा अन्यथा प्रदान किया गया हो।"},"68":{"q":"जहाँ इस तरह पोस्ट किया गया हो, वहाँ जॉर्जिया इंटरस्टेट हाईवे पर ट्रैक्टर-ट्रेलर सहित किसी भी वाहन के लिए O.C.G.A. §40-6-181 द्वारा निर्धारित अधिकतम गति सीमा क्या है?","options":["55 मील प्रति घंटा","65 मील प्रति घंटा","75 मील प्रति घंटा","70 मील प्रति घंटा"],"explanation":"O.C.G.A. §40-6-181 संघीय इंटरस्टेट प्रणाली का हिस्सा होने वाले हाईवे पर और भौतिक रूप से विभाजित, पूर्ण-पहुँच-नियंत्रण वाले राज्य हाईवे पर, जहाँ संकेतों द्वारा निर्दिष्ट हो, 70 mph की अधिकतम सीमा निर्धारित करता है। जॉर्जिया ट्रकों के लिए एक अलग, कम राज्यव्यापी गति सीमा नहीं लगाता; पोस्ट की गई अधिकतम सीमा सभी वाहनों पर लागू होती है।"},"69":{"q":"I-75, I-85, या I-20 पर Atlanta की ओर यात्रा करने वाले भारी थ्रू-ट्रकों को जॉर्जिया के Atlanta ट्रक-रूटिंग नियमों के तहत आम तौर पर क्या करना आवश्यक है?","options":["केवल दिन के उजाले के घंटों में I-75/I-85 Downtown Connector का उपयोग करें","केवल downtown Atlanta में HOV लेनों में यात्रा करें","I-285 में प्रवेश करने से पहले एक राज्य वज़न स्टेशन पर रुकें","I-285 पर शहर को बायपास करें जब तक वे पिकअप/डिलीवरी नहीं कर रहे, किसी टर्मिनल या मरम्मत सुविधा पर नहीं जा रहे, या परिधि के भीतर ड्राइवर के निवास पर नहीं जा रहे"],"explanation":"Atlanta से होकर (शहर में नहीं) यात्रा करने वाले ट्रकों को I-75/I-85 Downtown Connector के बजाय शहर के चारों ओर I-285 लेना चाहिए। अपवाद मौजूद हैं उन ट्रकों के लिए जो I-285 के भीतर किसी शिपर को पिकअप या डिलीवरी कर रहे हैं, I-285 के भीतर किसी टर्मिनल या मरम्मत सुविधा से आ-जा रहे हैं, या परिधि के भीतर किसी निवास से आ-जा रहे ड्राइवर के लिए। यह एक सुस्पष्ट रूप से चिह्नित, प्रवर्तित थ्रू-ट्रक प्रतिबंध है।"},"70":{"q":"Atlanta के I-75/I-85 Downtown Connector पर, अंदरूनी (सबसे बाईं) लेन HOV लेनों के रूप में आरक्षित हैं। इसका वाणिज्यिक ट्रक ड्राइवर के लिए क्या अर्थ है?","options":["ट्रक को HOV लेन से बाहर रहना चाहिए और, लेन-उपयोग सीमाओं के कारण, आम तौर पर दाईं लेनों में रहना चाहिए","ट्रक HOV लेन का उपयोग किसी भी समय कर सकता है जब वह 6,000 lbs से अधिक माल ले जा रहा हो","ट्रक HOV लेन का उपयोग कर सकता है यदि वह HOT लेन की तरह टोल चुकाए","ट्रक HOV लेन का उपयोग कर सकता है क्योंकि वाणिज्यिक वाहन हमेशा हाई-ऑक्यूपेंसी माने जाते हैं"],"explanation":"I-75/I-85 Downtown Connector की अंदरूनी लेन HOV-प्रतिबंधित हैं। माल कोई सवार नहीं है, इसलिए एक ट्रक हाई-ऑक्यूपेंसी वाहन के रूप में योग्य नहीं होता, और O.C.G.A. §40-6-52 के तहत ट्रकों को दाईं लेनों का उपयोग करना चाहिए। जॉर्जिया की HOV लेनों के लिए न्यूनतम संख्या में सवार चाहिए, माल का वज़न नहीं।"},"71":{"q":"Georgia CDL Manual के अनुसार किन वाणिज्यिक वाहनों को हर रेलरोड-हाईवे ग्रेड क्रॉसिंग पर रुकना आवश्यक है?","options":["यात्रियों को ले जाने वाली बसें और खतरनाक-पदार्थ प्लेकार्ड दिखाने वाले वाहन","माल की परवाह किए बिना 26,001 lbs से अधिक के सभी वाणिज्यिक वाहन","केवल खाली कार्गो टैंकर, कभी भी भरे हुए नहीं","डबल या ट्रिपल ट्रेलर खींचने वाला कोई भी ट्रक"],"explanation":"Georgia CDL Manual (और 49 CFR 392.10) के अनुसार, जिन वाणिज्यिक वाहनों को रेलरोड क्रॉसिंग पर हमेशा रुकना चाहिए वे हैं यात्रियों को ले जाने वाली बसें और प्लेकार्ड लगे खतरनाक-पदार्थ वाहन। इसमें किसी भी मात्रा में क्लोरीन ले जाने वाले वाहन और खतरनाक पदार्थों के लिए उपयोग किए जाने वाले कार्गो टैंक भी शामिल हैं, चाहे वे भरे हों या खाली।"},"72":{"q":"जब एक प्लेकार्ड लगे HazMat वाहन या यात्री बस को जॉर्जिया में रेलरोड क्रॉसिंग पर रुकना आवश्यक हो, तो उसे कहाँ रुकना चाहिए?","options":["निकटतम रेल से ठीक 25 फ़ुट","निकटतम रेल से 50 फ़ुट के भीतर पर 15 फ़ुट से अधिक निकट नहीं","निकटतम रेल से कम से कम 100 फ़ुट","क्रॉसिंग गेट के 10 फ़ुट के भीतर कहीं भी"],"explanation":"Georgia CDL Manual में कहा गया है कि रेलरोड क्रॉसिंग पर आवश्यक रुकाव निकटतम रेल से 50 फ़ुट से अधिक और 15 फ़ुट से कम पर नहीं किया जाना चाहिए। ड्राइवर को ट्रेन के लिए देखना और सुनना चाहिए, फिर तभी क्रॉस करना चाहिए जब बिना रुके ट्रैक को पूरी तरह पार करना सुरक्षित हो।"},"73":{"q":"Georgia CDL Manual के अनुसार, रेलरोड ट्रैक पार करते समय एक वाणिज्यिक ड्राइवर को क्या नहीं करना चाहिए?","options":["गियर बदले बिना पार करने के लिए पर्याप्त कम गियर का उपयोग करना","जब वाहन का कोई भी हिस्सा ट्रैक पर हो तब गियर बदलना","पार करना शुरू करने से पहले आती हुई ट्रेन के लिए देखना और सुनना","पार करना शुरू करने से पहले सुनिश्चित करना कि ट्रैक को पूरी तरह पार करने के लिए जगह है"],"explanation":"Georgia CDL Manual ड्राइवरों को चेतावनी देता है कि रेलरोड ट्रैक पार करते समय कभी गियर न बदलें, क्योंकि वाहन क्रॉसिंग पर रुक सकता है। ड्राइवर को ऐसा गियर चुनना चाहिए जो बिना शिफ्ट किए पार करने की अनुमति दे और पार करना शुरू करने से पहले सुनिश्चित करना चाहिए कि ट्रैक को पूरी तरह पार करने के लिए पर्याप्त जगह है।"},"74":{"q":"O.C.G.A. §40-6-163 के तहत, एक वाणिज्यिक वाहन के ड्राइवर को रुकी हुई स्कूल बस के लिए कब रुकना चाहिए जिसकी लाल बत्तियाँ चमक रही हों और स्टॉप आर्म फैला हो?","options":["केवल जब बस के समान दिशा में यात्रा कर रहे हों, कभी भी आती हुई दिशा में नहीं","केवल यदि सड़क किनारे बच्चे दिखाई दे रहे हों","अविभाजित सड़क पर किसी भी दिशा से बस से मिलते या ओवरटेक करते समय, जब तक बस गति फिर से शुरू न करे या संकेत बंद न हो जाएँ","केवल दो-लेन सड़कों पर, चार या अधिक लेन वाली सड़कों पर कभी नहीं"],"explanation":"O.C.G.A. §40-6-163 के अनुसार किसी भी दिशा से हाईवे पर रुकी एक स्कूल बस से मिलते या ओवरटेक करते वाहन के ड्राइवर को, जिसके दृश्य संकेत (चमकती लाल बत्तियाँ/स्टॉप आर्म) सक्रिय हों, बस तक पहुँचने से पहले रुकना होगा और तब तक आगे नहीं बढ़ना होगा जब तक बस गति फिर से शुरू न करे या संकेत बंद न हो जाएँ, अविभाजित सड़कों पर।"},"75":{"q":"जॉर्जिया के स्कूल-बस कानून (O.C.G.A. §40-6-163) के तहत, किस प्रकार की सड़क पर आती हुई दिशा के ड्राइवर को विपरीत ओर बच्चों को चढ़ाती-उतारती स्कूल बस के लिए रुकना आवश्यक नहीं है?","options":["एक चार-लेन सड़क जहाँ एकमात्र विभाजक एक पेंट की हुई केंद्र रेखा हो","केवल एक टू-वे केंद्र मोड़ लेन से अलग की गई सड़क","प्रत्येक दिशा में दो या अधिक लेन वाली कोई भी सड़क","एक हाईवे जिसमें अलग सड़कें घास के मीडियन, बिना पक्की जगह, या भौतिक बाधा द्वारा विभाजित हों"],"explanation":"O.C.G.A. §40-6-163 प्रावधान करता है कि घास के मीडियन, बिना पक्की जगह, या भौतिक बाधा द्वारा विभाजित अलग सड़कों वाले हाईवे पर एक ड्राइवर को दूसरी अलग सड़क पर स्कूल बस के लिए रुकने की आवश्यकता नहीं है। एक पेंट की हुई रेखा या केंद्र मोड़ लेन विभाजक नहीं है, इसलिए उन मामलों में ड्राइवरों को फिर भी रुकना चाहिए।"},"76":{"q":"एक सड़क की प्रत्येक दिशा में दो लेन हैं जो केवल एक टू-वे केंद्र मोड़ लेन (कोई मीडियन या बाधा नहीं) से अलग हैं। विपरीत ओर एक स्कूल बस लाल बत्तियाँ चमकाते हुए रुकती है। O.C.G.A. §40-6-163 के तहत, एक आती हुई दिशा के वाणिज्यिक ड्राइवर को क्या करना चाहिए?","options":["रुकें, क्योंकि एक केंद्र मोड़ लेन सड़कों को अलग करने वाला मीडियन या भौतिक बाधा नहीं है","कम गति पर जारी रखें, क्योंकि मोड़ लेन एक विभाजक के रूप में गिना जाता है","केवल तभी रुकें जब बस ड्राइवर की अपनी यात्रा दिशा में हो","सामान्य रूप से आगे बढ़ें, क्योंकि आती हुई दिशा का यातायात स्कूल बसों के लिए कभी नहीं रुकता"],"explanation":"O.C.G.A. §40-6-163 के तहत, विभाजित-हाईवे अपवाद केवल घास के मीडियन, बिना पक्की जगह, या भौतिक बाधा द्वारा अलग की गई सड़कों पर लागू होता है। एक केंद्र टू-वे मोड़ लेन और पेंट की हुई रेखाएँ योग्य नहीं हैं, इसलिए एक आती हुई दिशा के ड्राइवर को सक्रिय संकेतों वाली स्कूल बस के लिए रुकना चाहिए।"},"77":{"q":"Georgia CDL Manual के अनुसार, शोल्डर पर रुकने के बाद एक दो-लेन, टू-वे सड़क पर एक ट्रक ड्राइवर को तीन आवश्यक आपातकालीन चेतावनी उपकरण (परावर्तक त्रिकोण) कहाँ रखने चाहिए?","options":["तीनों सीधे वाहन के पीछे रियर बंपर के 10 फ़ुट के भीतर","एक छत पर और दो फ्रंट बंपर पर","लगभग 10 फ़ुट वाहन के पीछे यातायात की ओर, लगभग 100 फ़ुट पीछे, और वाहन से लगभग 100 फ़ुट आगे","लगभग 500 फ़ुट पीछे और 500 फ़ुट आगे, वाहन के पास कोई नहीं"],"explanation":"Georgia CDL Manual के अनुसार चेतावनी उपकरण 10 मिनट के भीतर रखे जाने चाहिए: एक लगभग 10 फ़ुट (4 कदम) वाहन से आती हुई यातायात की ओर, एक लगभग 100 फ़ुट (40 कदम) पीछे, और एक लगभग 100 फ़ुट (40 कदम) आगे। पहाड़ियों या मोड़ों पर, पर्याप्त चेतावनी देने के लिए पीछे वाले उपकरण को और दूर ले जाया जाता है।"},"78":{"q":"Georgia CDL Manual के अनुसार, ब्रेक फेड को रोकने के लिए एक लंबे, खड़े उत्तरी जॉर्जिया पर्वतीय ढलान से नीचे जाने की सही तकनीक क्या है?","options":["ढलान से पहले एक कम गियर चुनें और एक सुरक्षित गति पर हल्की, स्थिर ब्रेकिंग के साथ स्नब (लगाओ-फिर-छोड़ो) विधि का उपयोग करें","एक ऊँचे गियर में रहें और गति कम रखने के लिए लगातार ब्रेक पर सवार रहें","ईंधन बचाने के लिए न्यूट्रल में शिफ्ट करें और केवल ब्रेक से गति नियंत्रित करें","इंजन को गर्म रखने के लिए तेज़ी से ब्रेक पंप करते हुए तेज़ हों"],"explanation":"Georgia CDL Manual ड्राइवरों को निर्देश देता है कि खड़े ढलान से नीचे जाना शुरू करने से पहले एक सुरक्षित गति और एक कम गियर चुनें, इंजन ब्रेकिंग पर निर्भर रहें, और स्नब ब्रेकिंग तकनीक का उपयोग करें (लगभग 5 mph धीमा करने के लिए मजबूती से लगाएँ, फिर छोड़ें)। ब्रेक पर सवार रहना या न्यूट्रल में कोस्टिंग करना ब्रेक फेड और नियंत्रण की हानि का कारण बनता है।"},"79":{"q":"एक खड़े उत्तरी जॉर्जिया ढलान पर आपके ब्रेक फेड हो गए हैं और ट्रक की गति बढ़ रही है। Georgia CDL Manual सलाह देता है कि सबसे अच्छा कार्य है:","options":["पक्के दाएँ शोल्डर पर खींचें और पार्किंग ब्रेक को ज़ोर से लगाएँ","एक खुली लेन खोजने के लिए आती हुई दिशा के यातायात में स्टीयर करें","वाहन को तेज़ी से धीमा करने के लिए इंजन बंद कर दें","यदि उपलब्ध हो तो एक रनअवे-ट्रक एस्केप रैंप का उपयोग करें, क्योंकि यह एक भागते वाहन को सुरक्षित रूप से रोकने के लिए बनाया गया है"],"explanation":"Georgia CDL Manual समझाता है कि एस्केप रैंप, जो कई खड़े पर्वतीय ढलानों पर ढीली सामग्री के बेड (और अक्सर एक चढ़ाई) के साथ बनाए जाते हैं, भागते वाहनों को सुरक्षित रूप से रोकने के लिए डिज़ाइन किए गए हैं। यदि किसी ढलान पर आपके ब्रेक फेल हो जाएँ, तो उपलब्ध एस्केप रैंप लेना सबसे सुरक्षित कार्य है; इंजन बंद करना या गति पर पार्किंग ब्रेक का उपयोग करना नियंत्रण की हानि का कारण बन सकता है।"},"80":{"q":"जॉर्जिया में, कौन-सी राज्य एजेंसी वाणिज्यिक ड्राइवर लाइसेंस (CDLs) जारी करती है और CDL परीक्षण का प्रबंधन करती है?","options":["Georgia Department of Public Safety पंजीकरण प्रभाग","Georgia Department of Motor Vehicles (DMV)","Georgia Bureau of Investigation","Georgia Department of Driver Services (DDS)"],"explanation":"जॉर्जिया में 'DMV' नहीं है। Georgia Department of Driver Services (DDS) वह राज्य एजेंसी है जो सभी CDLs जारी करती है और CDL ज्ञान और कौशल परीक्षण का प्रबंधन करती है। स्रोत: GA DDS, Commercial License (CDL) कार्यक्रम पृष्ठ (dds.georgia.gov)।"},"81":{"q":"CDL के लिए आवेदन करते समय अपने जॉर्जिया आवासीय पते को सिद्ध करने वाले कितने दस्तावेज़ आपको GA DDS में लाने होंगे?","options":["CDL के लिए कोई निवास दस्तावेज़ आवश्यक नहीं हैं","आपका जॉर्जिया आवासीय पता दिखाने वाले चार दस्तावेज़","आपका वर्तमान जॉर्जिया आवासीय पता दिखाने वाले दो दस्तावेज़","आपका जॉर्जिया आवासीय पता दिखाने वाला एक दस्तावेज़"],"explanation":"GA DDS आवेदकों से दो स्वीकार्य दस्तावेज़ (जैसे उपयोगिता बिल, बंधक विवरण, या सरकारी दस्तावेज़) प्रदान करने की अपेक्षा करता है जो उनका वर्तमान जॉर्जिया आवासीय पता दिखाते हों। स्रोत: GA DDS, 'Apply for a Commercial (CDL) License' (dds.georgia.gov)।"},"82":{"q":"CDL के लिए पहचान, Social Security नंबर, और वैध स्थिति स्थापित करने के लिए GA DDS को दस्तावेज़ों के किस सेट की आवश्यकता होती है?","options":["केवल एक जॉर्जिया मतदाता पंजीकरण कार्ड","केवल आपके नाम पर एक वाहन पंजीकरण","कोई अन्य प्रमाण के बिना केवल निवास का एक हस्ताक्षरित बयान","पहचान का प्रमाण, आपका पूरा Social Security नंबर, और U.S. नागरिकता या वैध उपस्थिति का प्रमाण"],"explanation":"GA DDS को पहचान का प्रमाण (जैसे U.S. जन्म प्रमाण पत्र, पासपोर्ट, या प्राकृतिकीकरण प्रमाण पत्र), License/ID/Permit फॉर्म पर आपके पूरे Social Security नंबर का सत्यापन, और U.S. नागरिकता या वैध उपस्थिति का दस्तावेज़ीकरण चाहिए, इसके अलावा दो जॉर्जिया निवास दस्तावेज़ भी। स्रोत: GA DDS, CDL आवेदन आवश्यकताएँ (dds.georgia.gov)।"},"83":{"q":"जॉर्जिया में CDL कौशल (सड़क) परीक्षण देने से पहले, एक ड्राइवर को Commercial Learner's/Instructional Permit (CLP) कितने समय तक रखना होगा?","options":["कम से कम 30 दिन","कम से कम 60 दिन","कम से कम 14 दिन","कोई न्यूनतम धारण अवधि नहीं है"],"explanation":"GA DDS के अनुसार एक CDL आवेदक को पूर्ण CDL कौशल परीक्षण के लिए आवेदन करने और देने से पहले Commercial Instructional Permit (CLP) कम से कम 14 दिन तक रखना होगा। यह संघीय 14-दिन धारण को दर्शाता है। स्रोत: GA DDS, CDL Permit पृष्ठ (dds.georgia.gov)।"},"84":{"q":"जॉर्जिया में पहली बार के Class A या Class B CDL आवेदक को CDL कौशल परीक्षण देने की अनुमति मिलने से पहले क्या पूरा करना होगा?","options":["किसी भी निजी ड्राइविंग स्कूल में एक रक्षात्मक ड्राइविंग पाठ्यक्रम","पाँच साल का सत्यापन योग्य गैर-वाणिज्यिक ड्राइविंग इतिहास","एक कॉलेज-स्तरीय लॉजिस्टिक्स प्रमाणपत्र","FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता से Entry-Level Driver Training (ELDT)"],"explanation":"GA DDS द्वारा प्रवर्तित संघीय ELDT नियमों के तहत, पहली बार के Class A और Class B CDL आवेदकों (जिनका CLP 7 फरवरी 2022 को या उसके बाद प्राप्त हुआ हो) को कौशल परीक्षण देने से पहले FMCSA Training Provider Registry पर पंजीकृत प्रदाता से Entry-Level Driver Training पूरा करना होगा। स्रोत: GA DDS CDL पृष्ठ और FMCSA Training Provider Registry (tpr.fmcsa.dot.gov)।"},"85":{"q":"एक मानक (गैर-HazMat) जॉर्जिया CDL नवीनीकरण आवश्यक होने से पहले कितने समय तक वैध रहता है?","options":["अधिकतम 4 साल तक","अधिकतम 2 साल तक","अधिकतम 10 साल तक","अधिकतम 8 साल तक"],"explanation":"एक मानक जॉर्जिया CDL अधिकतम 8 साल तक वैध है। Hazardous Materials (H) एंडोर्समेंट वाले CDLs कम अवधि (5 साल) के लिए वैध होते हैं क्योंकि आवश्यक पृष्ठभूमि जाँच नवीनीकरण होता है। स्रोत: GA DDS, 'Renew a CDL' (dds.georgia.gov)।"},"86":{"q":"वे चार स्व-प्रमाणन (self-certification) श्रेणियाँ कौन-सी हैं जिनमें से एक जॉर्जिया CDL धारक को चुनना होगा?","options":["Class A, Class B, Class C, Class D","Local, Regional, National, International","Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate, Excepted Intrastate","Day, Night, Hazmat, Passenger"],"explanation":"प्रत्येक जॉर्जिया CDL धारक को चार संचालन प्रकारों में से एक का स्व-प्रमाणन करना होगा: Non-excepted Interstate (NI), Excepted Interstate (EI), Non-excepted Intrastate (NA), और Excepted Intrastate (EA)। Non-excepted ड्राइवरों को एक वैध DOT मेडिकल प्रमाणपत्र बनाए रखना होगा। स्रोत: GA DDS, 'CDL Medical Certification and Self-Certification Process' (dds.georgia.gov)।"},"87":{"q":"किस स्व-प्रमाणन श्रेणी में एक जॉर्जिया CDL धारक को एक वैध DOT चिकित्सा परीक्षक का प्रमाणपत्र बनाए रखना आवश्यक है?","options":["Excepted Interstate (EI)","किसी भी श्रेणी में चिकित्सा प्रमाणपत्र आवश्यक नहीं","Non-excepted Interstate (NI)","Excepted Intrastate (EA)"],"explanation":"Non-excepted श्रेणियों (Non-excepted Interstate और Non-excepted Intrastate) के ड्राइवरों को एक वैध DOT चिकित्सा परीक्षक का प्रमाणपत्र बनाए रखना होगा। Excepted श्रेणियों (EI और EA) के लिए इसकी आवश्यकता नहीं है। स्रोत: GA DDS, CDL Medical and Self-Certification process (dds.georgia.gov)।"},"88":{"q":"18 जून 2025 से प्रभावी FMCSA अधिदेश के अनुसार, एक जॉर्जिया CDL धारक का DOT चिकित्सा परीक्षक का प्रमाणपत्र DDS को कैसे प्रेषित किया जाता है?","options":["FMCSA के National Registry से इलेक्ट्रॉनिक रूप से; DDS अब कागज़ी मेड सर्ट स्वीकार नहीं करता","10 दिनों के भीतर DDS मुख्यालय को फैक्स करके","निकटतम DDS Customer Service Center को एक कागज़ी प्रति डाक से भेजकर","एक व्यक्तिगत DDS केसवर्कर को एक स्कैन की गई प्रति ईमेल करके"],"explanation":"18 जून 2025 से प्रभावी, चिकित्सा प्रमाणपत्र FMCSA द्वारा National Registry of Certified Medical Examiners के माध्यम से GA DDS को इलेक्ट्रॉनिक रूप से प्रेषित किए जाते हैं। DDS अब मेड सर्ट डाक, फैक्स, ईमेल, ऑनलाइन, या व्यक्तिगत रूप से स्वीकार नहीं करता। ड्राइवर को केवल एक National Registry परीक्षक का उपयोग करना होगा और प्रमाणन वर्तमान रखना होगा। स्रोत: GA DDS प्रेस विज्ञप्ति और CDL Med Cert पृष्ठ (dds.georgia.gov)।"},"89":{"q":"किसी जॉर्जिया CDL ड्राइवर के लिए शारीरिक परीक्षण किसे करना होगा जिसे DOT चिकित्सा प्रमाणपत्र रखना आवश्यक है?","options":["एक DDS Customer Service Center क्लर्क","कोई भी कायरोप्रैक्टर, प्रमाणन की परवाह किए बिना","FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध एक चिकित्सा परीक्षक","किसी लाइसेंस प्राप्त जॉर्जिया फार्मेसी का कोई भी फार्मासिस्ट"],"explanation":"जॉर्जिया CDL ड्राइवर जिन्हें चिकित्सा प्रमाणन की आवश्यकता है, उनकी जाँच FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध एक चिकित्सा परीक्षक द्वारा की जानी चाहिए। वह परीक्षक फिर प्रमाणपत्र इलेक्ट्रॉनिक रूप से प्रेषित करता है। स्रोत: GA DDS, CDL Medical Certification process (dds.georgia.gov)।"},"90":{"q":"कौन-से तीन घटक जॉर्जिया CDL कौशल परीक्षण बनाते हैं?","options":["कार्गो लोडिंग, ईंधन-अर्थव्यवस्था परीक्षण, और एक गणित परीक्षा","लिखित कानून परीक्षा, नेत्र परीक्षा, और एक व्यक्तित्व साक्षात्कार","Hazmat हैंडलिंग, ग्राहक सेवा, और एक टाइपिंग परीक्षण","प्री-ट्रिप वाहन निरीक्षण, बुनियादी नियंत्रण कौशल, और एक ऑन-रोड ड्राइविंग परीक्षण"],"explanation":"जॉर्जिया CDL कौशल परीक्षण के तीन भाग क्रम में किए जाते हैं: प्री-ट्रिप वाहन निरीक्षण, बुनियादी वाहन नियंत्रण कौशल, और ऑन-रोड ड्राइविंग परीक्षण। CDL प्राप्त करने के लिए तीनों पास करने होंगे। स्रोत: GA DDS CDL Manual और Road Test पृष्ठ (dds.georgia.gov)।"},"91":{"q":"जॉर्जिया में CDL कौशल (सड़क) परीक्षण देते समय, परीक्षण वाहन प्रदान करने की ज़िम्मेदारी किसकी है?","options":["किसी वाहन की आवश्यकता नहीं है; कौशल परीक्षण केवल एक सिम्युलेटर पर किया जाता है","FMCSA साइट पर एक संघीय परीक्षण ट्रक भेजता है","GA DDS हर आवेदक के लिए एक फ्लीट वाहन प्रदान करता है","आवेदक को एक उपयुक्त वाहन प्रदान करना होगा जो DDS सुरक्षा निरीक्षण पास करे"],"explanation":"आवेदक को परीक्षण किए जा रहे CDL वर्ग के लिए एक उपयुक्त वाहन लाना होगा, साथ ही पंजीकरण का प्रमाण और वैध बीमा, और वाहन को सड़क परीक्षण से पहले DDS सुरक्षा निरीक्षण पास करना होगा। स्रोत: GA DDS, Road Test पृष्ठ (dds.georgia.gov)।"},"92":{"q":"जॉर्जिया में CDL के लिए आवेदन करने की न्यूनतम आयु क्या है, और एक निश्चित आयु तक कौन-सा प्रतिबंध लागू होता है?","options":["21 वर्ष, किसी परमिट की आवश्यकता के बिना","16 वर्ष, बिल्कुल भी कोई प्रतिबंध नहीं","18 वर्ष, 21 वर्ष की आयु तक केवल-इंट्रास्टेट प्रतिबंधों के साथ","25 वर्ष, कभी भी कोई इंटरस्टेट ड्राइविंग की अनुमति नहीं"],"explanation":"जॉर्जिया में आप 18 वर्ष की आयु में CDL के लिए आवेदन कर सकते हैं, पर 18 और 21 के बीच के ड्राइवर आम तौर पर अपने 21वें जन्मदिन तक इंट्रास्टेट (राज्य के भीतर) वाणिज्यिक ड्राइविंग तक सीमित होते हैं। स्रोत: GA DDS, CDL आवेदन और परमिट पृष्ठ (dds.georgia.gov)।"},"93":{"q":"1 जुलाई 2021 को या उसके बाद जारी किया गया एक जॉर्जिया Commercial Learner's Permit (CLP) कितने समय तक वैध है?","options":["90 दिन","अनिश्चित काल तक, जब तक CDL जारी न हो जाए","30 दिन","365 दिन (एक साल)"],"explanation":"1 जुलाई 2021 को या उसके बाद जारी किया गया एक जॉर्जिया CLP 365 दिन (एक साल) के लिए वैध है। ड्राइवर को फिर भी कौशल परीक्षण से पहले इसे कम से कम 14 दिन तक रखना होगा। स्रोत: GA DDS, CDL Permit पृष्ठ (dds.georgia.gov)।"},"94":{"q":"जॉर्जिया CDL प्रक्रिया में एक Commercial Instructional Permit (CLP) कब आवश्यक है?","options":["एक नया CDL प्राप्त करते समय, CDL अपग्रेड करते समय, या कुछ एंडोर्समेंट जोड़ते समय","केवल CDL पहले ही जारी हो जाने के बाद","कभी नहीं; जॉर्जिया किसी भी परमिट चरण के बिना CDLs जारी करता है","केवल विदेशी लाइसेंस स्थानांतरित करने वाले ड्राइवरों के लिए"],"explanation":"GA DDS को एक नया CDL प्राप्त करते समय, मौजूदा CDL अपग्रेड करते समय, या कुछ एंडोर्समेंट जोड़ते समय जिनके लिए कौशल परीक्षण आवश्यक हो, एक Commercial Instructional Permit (CLP) की आवश्यकता होती है। CLP को कौशल परीक्षण से पहले 14 दिन रखना होगा। स्रोत: GA DDS, CDL Permit पृष्ठ (dds.georgia.gov)।"},"95":{"q":"जॉर्जिया में पहली बार के Hazardous Materials (H) एंडोर्समेंट के लिए, ELDT प्रशिक्षण कब पूरा किया जाना चाहिए?","options":["केवल TSA पृष्ठभूमि जाँच अस्वीकृत होने के बाद","HazMat ज्ञान परीक्षण देने की अनुमति मिलने से पहले","HazMat एंडोर्समेंट के लिए ELDT कभी आवश्यक नहीं है","केवल HazMat ज्ञान परीक्षण पास करने के बाद"],"explanation":"चूँकि HazMat एंडोर्समेंट का कोई कौशल परीक्षण नहीं है, पहली बार के H आवेदकों के लिए ELDT सिद्धांत प्रशिक्षण आवेदक को HazMat ज्ञान परीक्षण देने की अनुमति मिलने से पहले पूरा किया जाना चाहिए। स्रोत: FMCSA Training Provider Registry / ELDT Applicability (tpr.fmcsa.dot.gov) और GA DDS CDL पृष्ठ।"},"96":{"q":"किन एंडोर्समेंट के लिए जॉर्जिया में पहली बार के आवेदकों को परीक्षण से पहले ELDT पूरा करना आवश्यक है?","options":["केवल Tanker (N), doubles/triples (T), और एयर-ब्रेक हटाना","केवल एयर ब्रेक प्रतिबंध हटाना","कोई भी एंडोर्समेंट कभी ELDT आवश्यक नहीं करता","School bus (S), passenger (P), और hazardous materials (H) एंडोर्समेंट"],"explanation":"GA DDS द्वारा लागू संघीय ELDT नियमों के तहत, School Bus (S), Passenger (P), और Hazardous Materials (H) एंडोर्समेंट के पहली बार के आवेदकों को लागू कौशल या ज्ञान परीक्षण देने से पहले एक पंजीकृत प्रदाता से ELDT पूरा करना होगा। स्रोत: FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) और GA DDS।"},"97":{"q":"कौशल परीक्षण के अलावा, एक जॉर्जिया CDL आवेदक को DDS Customer Service Center पर क्या पास करना होगा?","options":["एक शारीरिक शक्ति परीक्षण और एक तैराकी परीक्षण","केवल एक क्रेडिट जाँच","आवश्यक लिखित ज्ञान परीक्षा(एँ) और एक नेत्र परीक्षा","एक संघीय आयकर फाइलिंग समीक्षा"],"explanation":"कौशल परीक्षण से पहले, एक जॉर्जिया CDL आवेदक को मांगे गए वर्ग और एंडोर्समेंट के लिए आवश्यक लिखित ज्ञान परीक्षा(एँ) पास करनी होंगी और DDS Customer Service Center पर एक नेत्र परीक्षा पास करनी होगी। स्रोत: GA DDS, CDL Permit और आवेदन पृष्ठ (dds.georgia.gov)।"},"98":{"q":"जॉर्जिया CDL शुल्क के बारे में कौन-सा कथन सटीक है?","options":["जॉर्जिया में केवल FMCSA CDL शुल्क एकत्र करता है","शुल्क प्रत्येक चिकित्सा परीक्षक द्वारा व्यक्तिगत रूप से निर्धारित किए जाते हैं","सभी GA DDS CDL सेवाएँ स्थायी रूप से निःशुल्क हैं","सटीक शुल्क राशि GA DDS द्वारा निर्धारित की जाती है और बदल सकती है, इसलिए आवेदकों को DDS के साथ वर्तमान शुल्क सत्यापित करना चाहिए"],"explanation":"GA DDS परमिट, परीक्षण, और लाइसेंसिंग के लिए शुल्क लेता है (उदाहरण के लिए, परमिट और सड़क-परीक्षण शुल्क), पर सटीक राशि DDS द्वारा निर्धारित की जाती है और समय के साथ बदल सकती है। आवेदकों को आवेदन करने से पहले आधिकारिक DDS 'Fees and Terms' जानकारी पर वर्तमान शुल्क की पुष्टि करनी चाहिए। स्रोत: GA DDS (dds.georgia.gov)।"},"99":{"q":"वाणिज्यिक संचालन के प्रकार के संबंध में एक जॉर्जिया CDL ड्राइवर को नवीनीकरण पर क्या करना होगा?","options":["वाणिज्यिक संचालन के एक एकल प्रकार का स्व-प्रमाणन करें और, यदि non-excepted है, तो फाइल पर एक वर्तमान DOT चिकित्सा प्रमाणपत्र रखें","श्रेणी की परवाह किए बिना हर नवीनीकरण पर पूर्ण सड़क कौशल परीक्षण फिर से दें","CDL सरेंडर करें और एक बिल्कुल नए आवेदक के रूप में फिर से आवेदन करें","किसी पूर्व नियोक्ता से एक नोटरीकृत पत्र जमा करें"],"explanation":"नवीनीकरण पर, एक जॉर्जिया CDL धारक को वाणिज्यिक संचालन के एक एकल प्रकार (चार श्रेणियों में से एक) का स्व-प्रमाणन करना होगा, और non-excepted ड्राइवरों को एक वर्तमान DOT चिकित्सा प्रमाणपत्र बनाए रखना होगा, जो अब FMCSA के माध्यम से इलेक्ट्रॉनिक रूप से प्रेषित किया जाता है। स्रोत: GA DDS, 'Renew a CDL' और CDL Med Cert पृष्ठ (dds.georgia.gov)।"}},"ar":{"0":{"q":"على الطرق السريعة في جورجيا، ما هو الحد الأقصى لإجمالي العرض الخارجي للمركبة وحمولتها، باستثناء المرايا والملحقات؟","options":["96 بوصة","102 بوصة","108 بوصة","120 بوصة"],"explanation":"تنص O.C.G.A. §32-6-23 على أنه لا يجوز لأي مركبة أن تتجاوز إجمالي العرض الخارجي، بما في ذلك أي حمولة، 102 بوصة، باستثناء المرايا والملحقات، على أي شارع أو طريق أو طريق سريع في جورجيا. (المصدر: O.C.G.A. §32-6-23؛ دليل GA DDS CDL)"},"1":{"q":"باستثناء الحالات التي يُسمح فيها بحد أعلى، ما هو الحد الأقصى لارتفاع المركبة، فارغة أو محمّلة، على طرق جورجيا؟","options":["12 قدمًا و6 بوصات","13 قدمًا و0 بوصة","14 قدمًا و6 بوصات","13 قدمًا و6 بوصات"],"explanation":"تنص O.C.G.A. §32-6-22(a) على أنه، باستثناء ما يُسمح به بموجب تصريح، لا يجوز لأي مركبة فارغة أو محمّلة أن تتجاوز ارتفاع 13 قدمًا و6 بوصات على طرق جورجيا. (المصدر: O.C.G.A. §32-6-22)"},"2":{"q":"في جورجيا، ما هو الحد الأقصى لطول نصف المقطورة في تركيبة جرّار شاحنة مع نصف مقطورة، في غياب قيود معلنة؟","options":["45 قدمًا","48 قدمًا","53 قدمًا","57 قدمًا"],"explanation":"تنص O.C.G.A. §32-6-24(b)(1)(B) على أن تركيبات جرّار الشاحنة مع نصف المقطورة يجب أن تحتوي على أنصاف مقطورات لا يتجاوز طولها 53 قدمًا، ما لم تُوضع لافتات تشير إلى قيود طول نصف المقطورة. (المصدر: O.C.G.A. §32-6-24)"},"3":{"q":"في تركيبة جورجيا لجرّار شاحنة مع نصف مقطورة ومقطورة (مقطورة مزدوجة)، ما هو الحد الأقصى لطول كل مقطورة ونصف مقطورة؟","options":["24 قدمًا","28 قدمًا","33 قدمًا","40 قدمًا"],"explanation":"تنص O.C.G.A. §32-6-24(b)(1)(A) على أن تركيبات جرّار الشاحنة مع نصف المقطورة والمقطورة يجب أن تحتوي على مقطورات وأنصاف مقطورات لا يتجاوز طول كل منها 28 قدمًا. (المصدر: O.C.G.A. §32-6-24)"},"4":{"q":"على طرق جورجيا غير الطرق السريعة بين الولايات أو نظام STAA، ما هو الحد الأقصى للطول الإجمالي لتركيبة جرّار شاحنة مع نصف مقطورة أو جرّار شاحنة مع نصف مقطورة ومقطورة، في غياب قيود معلنة؟","options":["65 قدمًا","75 قدمًا","100 قدم","110 أقدام"],"explanation":"تنص O.C.G.A. §32-6-24(b)(2)(C) على أنه، على الطرق غير الطرق السريعة بين الولايات أو نظام STAA، يجب ألا يتجاوز الطول الإجمالي لهذه التركيبات 100 قدم، ما لم تُوضع لافتات تشير إلى قيود الطول. (المصدر: O.C.G.A. §32-6-24)"},"5":{"q":"ما هو الحد الأقصى للوزن الإجمالي الكلي المسموح به لأي مركبة وحمولة على الطرق السريعة في جورجيا؟","options":["73,280 رطلًا","88,000 رطل","100,000 رطل","80,000 رطل"],"explanation":"تحدد كل من O.C.G.A. §32-6-26(c)(1)(A) و(d)(1)(A) الحد الأقصى للوزن الإجمالي الكلي المسموح به لأي مركبة وحمولة بـ 80,000 رطل، على الطرق السريعة الوطنية وغير الوطنية على حد سواء. (المصدر: O.C.G.A. §32-6-26؛ دليل GA DDS CDL)"},"6":{"q":"على طريق سريع وطني في جورجيا (مثل طريق سريع بين الولايات)، ما هو الحد الأقصى للحمولة المسموح بها على محور مزدوج؟","options":["30,000 رطل","40,680 رطلًا","46,000 رطل","34,000 رطل"],"explanation":"تحدد O.C.G.A. §32-6-26(d)(1)(B) الحد الأقصى للحمولة على أي محور مزدوج على الطرق السريعة الوطنية في جورجيا بـ 34,000 رطل، بما يتطابق مع الحد الفيدرالي. (المصدر: O.C.G.A. §32-6-26؛ دليل GA DDS CDL)"},"7":{"q":"على الطرق السريعة في جورجيا التي ليست طرقًا سريعة وطنية، ما هو الحد الأقصى للحمولة المسموح بها على محور مزدوج؟","options":["34,000 رطل","37,340 رطلًا","40,680 رطلًا","46,000 رطل"],"explanation":"تحدد O.C.G.A. §32-6-26(c)(1)(A) الحد الأقصى لحمولة المحور المزدوج بـ 40,680 رطلًا على الطرق السريعة في جورجيا التي ليست طرقًا سريعة وطنية. (المصدر: O.C.G.A. §32-6-26)"},"8":{"q":"بموجب O.C.G.A. §32-6-26، كيف يُعرَّف \"المحور المفرد\" لأغراض الوزن في جورجيا؟","options":["جميع العجلات التي تقع مراكزها بين مستويين رأسيين عرضيين متوازيين تفصل بينهما مسافة 40 بوصة","جميع العجلات التي تقع مراكزها ضمن 96 بوصة من بعضها","أي محورين متتاليين تفصل بينهما مسافة أكثر من 40 بوصة","محور التوجيه المفرد لوحدة القدرة فقط"],"explanation":"تُعرِّف O.C.G.A. §32-6-26(a)(4) \"المحور المفرد\" بأنه جميع العجلات التي قد تقع مراكزها بين مستويين رأسيين عرضيين متوازيين تفصل بينهما مسافة 40 بوصة. (المصدر: O.C.G.A. §32-6-26)"},"9":{"q":"بموجب قانون جورجيا الحالي، كيف يُعرَّف \"المحور المزدوج\" لأغراض الوزن؟","options":["محوران متتاليان أو أكثر تكون مراكزهما متباعدة بأكثر من 40 ولكن ليس أكثر من 96 بوصة","محوران متتاليان أو أكثر، باستثناء محور التوجيه، تكون مراكزهما متباعدة بأكثر من 40 ولكن ليس أكثر من 216 بوصة","محوران بالضبط تفصل بينهما مسافة لا تزيد عن 8 أقدام، بما في ذلك محور التوجيه","أي مجموعة من المحاور ضمن 12 قدمًا من بعضها بصرف النظر عن محور التوجيه"],"explanation":"تُعرِّف O.C.G.A. §32-6-26(a)(7) \"المحور المزدوج\" (بعد 1 أبريل 1988) بأنه محوران متتاليان أو أكثر، باستثناء محور التوجيه، قد تقع مراكزهما بين مستويين رأسيين متوازيين تفصل بينهما مسافة أكثر من 40 بوصة ولكن ليس أكثر من 216 بوصة. (المصدر: O.C.G.A. §32-6-26)"},"10":{"q":"أي معادلة تستخدمها جورجيا لتحديد الحد الأقصى للوزن الإجمالي المسموح به على مجموعة من محورين متتاليين أو أكثر؟","options":["معادلة الجسر الفيدرالية","معادلة تصنيف الوزن الإجمالي للتركيبة","تعرفة تباعد المحاور في جورجيا","قاعدة 18,000 رطل لكل محور"],"explanation":"تعتمد O.C.G.A. §32-6-26(a)(1) و(d) معادلة الجسر الفيدرالية، W = 500((LN/N-1) + 12N + 36)، لتحديد الحد الأقصى للوزن الإجمالي على أي مجموعة من محورين متتاليين أو أكثر على الطرق السريعة الوطنية في جورجيا. (المصدر: O.C.G.A. §32-6-26؛ دليل GA DDS CDL)"},"11":{"q":"في معادلة جسر جورجيا W = 500((LN/N-1) + 12N + 36)، ماذا يمثل المتغير \"N\"؟","options":["عدد المحاور في المجموعة قيد النظر","المسافة بالأقدام بين المحاور الطرفية للمجموعة","الوزن الصافي للحمولة بآلاف الأرطال","عدد الإطارات على المحور الأثقل"],"explanation":"في O.C.G.A. §32-6-26(a)(1)، يمثل N عدد المحاور في المجموعة قيد النظر، وL هي المسافة بالأقدام بين المحاور الطرفية للمجموعة، وW هو الوزن الإجمالي على تلك المجموعة. (المصدر: O.C.G.A. §32-6-26)"},"12":{"q":"بموجب O.C.G.A. §32-6-26، ما هو الحد الأقصى للوزن الإجمالي الكلي لمركبة مزودة بأربعة محاور فقط على الطرق السريعة غير الوطنية في جورجيا؟","options":["56,000 رطل","70,000 رطل","73,280 رطلًا","80,000 رطل"],"explanation":"تنص O.C.G.A. §32-6-26(c)(1)(C) على أنه بالنسبة لأي مركبة مزودة بأربعة محاور، يجب أن يكون الحد الأقصى للوزن الإجمالي الكلي المسموح به للمركبة والحمولة 70,000 رطل. (المصدر: O.C.G.A. §32-6-26)"},"13":{"q":"على نظام طرق المقاطعات في جورجيا، ما هو الحد الأقصى للوزن الإجمالي الكلي المسموح به لمركبة لا تقوم بالاستلام أو التسليم على ذلك الطريق؟","options":["46,000 رطل","56,000 رطل","70,000 رطل","80,000 رطل"],"explanation":"تحدد O.C.G.A. §32-6-26(f) الحد الأقصى للوزن الإجمالي الكلي على نظام طرق المقاطعات بـ 56,000 رطل، باستثناء عندما تقوم المركبة بالاستلام أو التسليم على ذلك الطريق (أو على مسار شاحنات محلي معيّن مؤهل). (المصدر: O.C.G.A. §32-6-26)"},"14":{"q":"متى يجوز لمركبة تنقل منتجات الغابات أو الدواجن الحية أو القطن أو العلف أو الجرانيت أو النفايات الصلبة أو الخرسانة الطازجة الممزوجة أن تتجاوز حدود المحور/الوزن الإجمالي العادية في جورجيا على طريق سريع غير وطني بدون تصريح؟","options":["أبدًا؛ فالتصريح مطلوب دائمًا لتجاوز الحدود","فقط في الليل وفقط على الطرق السريعة بين الولايات","عندما يبقى وزن المحور المفرد عند 23,000 رطل أو أقل، والمحور المزدوج عند 46,000 رطل أو أقل، والوزن الإجمالي عند 80,000 رطل أو أقل","عندما يبقى الوزن الإجمالي عند 100,000 رطل أو أقل بصرف النظر عن وزن المحور"],"explanation":"تسمح O.C.G.A. §32-6-26(g)(1) بهذه الشحنات الزراعية والسلعية المحددة على الطرق السريعة غير الوطنية بدون تصريح فقط عندما لا تتجاوز حمولة المحور المفرد 23,000 رطل، ولا يتجاوز المحور المزدوج 46,000 رطل، ولا يتجاوز الوزن الإجمالي الكلي 80,000 رطل. (المصدر: O.C.G.A. §32-6-26)"},"15":{"q":"يُطبَّق إعفاء جورجيا من حدود الحجم لمعدات الزراعة أو الفلاحة أو إدارة الغابات (الذي يسمح لها بتجاوز حدود العرض والطول بدون تصريح) بموجب أي شرط؟","options":["فقط على نظام الطرق بين الولايات وفقط في الليل","خلال ساعات النهار على الطرق غير المشمولة بنظام الطرق بين الولايات، ضمن مسافة 40 ميلًا من ممتلكات المالك أو التاجر","في أي مكان في الولاية في أي ساعة دون حد للمسافة","فقط عندما ترافقها مركبة مرافقة بأضواء كهرمانية على الطريق السريع بين الولايات"],"explanation":"تعفي O.C.G.A. §32-6-25 معدات الزراعة/الفلاحة أو إدارة الغابات من حدود العرض والطول، بدون تصريح، عند تشغيلها خلال ساعات النهار على طريق عام غير مشمول بنظام الطرق بين الولايات ضمن نطاق قطره 40 ميلًا من ممتلكات المالك أو التاجر. ولا يُطبَّق الإعفاء على المركبات التي تنقل أو تحمل منتجات الغابات. (المصدر: O.C.G.A. §32-6-25)"},"16":{"q":"من يصدر في جورجيا تصريحًا يخوّل مركبة أو حمولة لتجاوز الحد الأقصى للحجم أو الوزن المحدد بموجب القانون؟","options":["وزارة النقل (GDOT)، بناءً على طلب خطي وإثبات سبب وجيه","عمدة المقاطعة التي تبدأ منها الرحلة","أي ضابط في محطة الوزن وقت التفتيش","وزارة خدمات السائقين مع طلب CDL"],"explanation":"تخوّل O.C.G.A. §32-6-28(a) مفوض GDOT (أو مسؤولًا معيّنًا) بأن يصدر، بناءً على طلب خطي وإثبات سبب وجيه، تصريحًا يسمح لمركبة وحمولة يتجاوز وزنها أو عرضها أو طولها أو ارتفاعها الحد الأقصى القانوني. وتُستخرج التصاريح عبر GDOT/وزارة السلامة العامة (نظام GAPROS). (المصدر: O.C.G.A. §32-6-28؛ GDOT)"},"17":{"q":"بموجب O.C.G.A. §32-6-28، لا يجوز إصدار تصريح سنوي بزيادة الحجم/الوزن في جورجيا لتخويل مركبة يتجاوز وزنها الإجمالي الكلي أي مقدار؟","options":["80,000 رطل","120,000 رطل","150,000 رطل","100,000 رطل"],"explanation":"تنص O.C.G.A. §32-6-28(b)(1)(A) على أن التصريح السنوي لا يجوز أن يخوّل تشغيل مركبة يتجاوز وزنها الإجمالي الكلي 100,000 رطل (ولا يتجاوز وزن المحور المفرد 25,000 رطل، أو الطول 100 قدم، أو العرض 102 بوصة / عرض الحمولة 144 بوصة، أو الارتفاع 14 قدمًا و6 بوصات). (المصدر: O.C.G.A. §32-6-28؛ GDOT)"},"18":{"q":"بموجب قاعدة الوزن الأساسية في جورجيا، ما هو الحد الأقصى الأساسي للحمولة على محور مفرد (بإطارات هوائية عالية الضغط) قبل تطبيق الهامش القانوني؟","options":["12,000 رطل","18,000 رطل","20,000 رطل","16,000 رطل"],"explanation":"تحظر O.C.G.A. §32-6-26(b)(1) وجود حمولة على أي محور مفرد (بإطارات هوائية عالية الضغط أو مطاط صلب أو إطارات وسادية) تتجاوز 16,000 رطل بأكثر من 13 بالمئة — لذا فإن الرقم الأساسي هو 16,000 رطل ويعطي هامش الـ 13٪ نحو 18,080 رطلًا. (المصدر: O.C.G.A. §32-6-26)"},"19":{"q":"بموجب O.C.G.A. §32-6-27، قبل أن يُسمح لمركبة زائدة الوزن في جورجيا بالتحرك، يجب على المُشغِّل تفريغ كل الوزن الإجمالي الذي يتجاوز الحد القانوني بأكثر من أي مقدار؟","options":["2,000 رطل","4,000 رطل","6,000 رطل","10,000 رطل"],"explanation":"تتطلب O.C.G.A. §32-6-27(e) من مالك/مُشغِّل المركبة زائدة الوزن، بالإضافة إلى دفع الأضرار المقدّرة، تفريغ كل الوزن الإجمالي الزائد على 6,000 رطل فوق الحد القانوني للوزن قبل السماح للمركبة بالتحرك. (المصدر: O.C.G.A. §32-6-27)"},"20":{"q":"في جورجيا، أي فئة من CDL مطلوبة لتشغيل تركيبة من المركبات بتصنيف وزن إجمالي للتركيبة (GCWR) يبلغ 26,001 رطل أو أكثر، حيث يكون للمركبة المقطورة تصنيف وزن إجمالي للمركبة (GVWR) يزيد عن 10,000 رطل؟","options":["الفئة B","الفئة C","الفئة D","الفئة A"],"explanation":"تغطي CDL من الفئة A في جورجيا أي تركيبة من المركبات بتصنيف GCWR يبلغ 26,001 رطل أو أكثر حيث تتجاوز الوحدة المقطورة 10,000 رطل من GVWR. ويجوز لحامل الفئة A أيضًا تشغيل مركبات الفئتين B وC بالمصادقات المناسبة. المصدر: Georgia DDS، 'Apply for a Commercial (CDL) License (Class A, B, C).'"},"21":{"q":"بموجب قواعد Georgia DDS، تخوّل CDL من الفئة B السائق لتشغيل أي مما يلي؟","options":["أي تركيبة من المركبات حيث تتجاوز الوحدة المقطورة 10,000 رطل","أي مركبة مفردة بتصنيف GVWR يبلغ 26,001 رطل أو أكثر، تقطر وحدة لا تتجاوز 10,000 رطل","فقط المركبات المصممة لنقل 16 راكبًا أو أكثر","فقط المركبات الحاملة لافتات المواد الخطرة"],"explanation":"تغطي CDL من الفئة B في جورجيا المركبات المفردة بتصنيف GVWR يبلغ 26,001 رطل أو أكثر، بما في ذلك تلك التي تقطر مركبة لا تتجاوز 10,000 رطل من GVWR. ويجوز لحامل الفئة B أيضًا تشغيل مركبات الفئة C بالمصادقات المناسبة. المصدر: Georgia DDS، 'Apply for a Commercial (CDL) License.'"},"22":{"q":"في جورجيا، تُصدر CDL من الفئة C تحديدًا لأي نوع من المركبات؟","options":["أي تركيبة من المركبات تزيد عن 26,001 رطل من GCWR","أي مركبة مفردة تزيد عن 26,001 رطل من GVWR","مركبة مفردة (أو تركيبة) لا تستوفي تعريف الفئة A أو B وتنقل 16 راكبًا أو أكثر بما في ذلك السائق، أو تحمل لافتات للمواد الخطرة","أي سيارة ركاب أو شاحنة بيك أب أقل من 26,001 رطل"],"explanation":"تنطبق CDL من الفئة C في جورجيا على مركبة مفردة، أو تركيبة، لا تستوفي تعريف الفئة A أو B ولكنها مصممة لنقل 16 راكبًا أو أكثر (بما في ذلك السائق) أو تُستخدم لنقل مواد خطرة تتطلب لافتات. المصدر: Georgia DDS، 'Apply for a Commercial (CDL) License.'"},"23":{"q":"ما هو الحد الأدنى للعمر للتقدم بطلب الحصول على أي CDL في جورجيا؟","options":["18 عامًا","16 عامًا","21 عامًا","25 عامًا"],"explanation":"تتطلب Georgia DDS أن يكون عمر المتقدمين للحصول على CDL 18 عامًا على الأقل. ويُقيَّد المتقدمون الذين تتراوح أعمارهم بين 18 و21 عامًا بالقيادة داخل الولاية (جورجيا فقط) حتى يبلغوا 21 عامًا. المصدر: Georgia DDS، 'Apply for a Commercial (CDL) License.'"},"24":{"q":"بأي طريقة يُقيَّد حامل CDL في جورجيا يبلغ من العمر 19 عامًا؟","options":["مُقيَّد من حمل أي مصادقة","مُقيَّد بالقيادة داخل الولاية (جورجيا فقط) حتى بلوغ سن 21","مُقيَّد بمركبات الفئة C فقط","مُقيَّد من القيادة ليلًا"],"explanation":"تُصدر جورجيا CDL للمتقدمين البالغين 18 عامًا فأكثر، لكن السائقين الذين تتراوح أعمارهم بين 18 و21 عامًا يحملون قيد 'جورجيا فقط' (داخل الولاية). ويجب على السائق أن يبلغ 21 عامًا ويزور مركز خدمة العملاء لإزالة القيد للقيادة بين الولايات. المصدر: Georgia DDS، 'Apply for a Commercial (CDL) License.'"},"25":{"q":"يرغب حامل CDL في جورجيا في إزالة قيد القيادة داخل الولاية فقط ليتمكن من القيادة عبر حدود الولايات. ماذا يجب أن يحدث؟","options":["يجب أن يحمل CDL لمدة خمس سنوات على الأقل أولًا","يجب أن يبلغ عيد ميلاده الحادي والعشرين ويزور مركز خدمة العملاء التابع لـ DDS لإزالة قيد 'جورجيا فقط'","يجب أن يضيف مصادقة HazMat","يجب أن يجتاز اختبار مهارات إضافيًا للقيادة بين الولايات في سن 18"],"explanation":"يُقيَّد السائقون الذين تتراوح أعمارهم بين 18 و21 عامًا بالقيادة داخل الولاية. ولاكتساب امتيازات القيادة بين الولايات، يجب على السائق أن يبلغ 21 عامًا ويزور مركز خدمة العملاء التابع لـ DDS لإزالة قيد 'جورجيا فقط'. المصدر: Georgia DDS، 'Apply for a Commercial (CDL) License.'"},"26":{"q":"أي مصادقة مطلوبة في جورجيا لقيادة مركبة تنقل مواد خطرة بكميات تتطلب لافتات؟","options":["مصادقة N (الصهريج)","مصادقة T (المقطورات المزدوجة/الثلاثية)","مصادقة P (الركاب)","مصادقة H (HazMat)"],"explanation":"تُطلب مصادقة H (HazMat) لنقل المواد الخطرة التي تتطلب لافتات. وفي جورجيا تتطلب اجتياز اختبار معرفي وفحص خلفية من TSA وأخذ بصمات الأصابع لكل من الإصدار لأول مرة والتجديدات. المصدر: Georgia DDS، 'Adding CDL Endorsements.'"},"27":{"q":"في جورجيا، ما هو المتطلب الفيدرالي الإضافي الذي يجب استيفاؤه لمصادقة HazMat (H) والذي لا يُطلب لمصادقة الصهريج (N)؟","options":["اجتياز اختبار مهارات (طريق) منفصل","حمل المصادقة لمدة 14 يومًا قبل استخدامها","اجتياز تقييم تهديد أمني من TSA مع أخذ بصمات الأصابع","الحصول على مصادقة الركاب أولًا"],"explanation":"تتطلب مصادقة HazMat اجتياز فحص خلفية من TSA (تقييم تهديد أمني)، وتُطلب بصمات الأصابع للإصدار لأول مرة وكذلك للتجديدات. أما مصادقة الصهريج فتتطلب اختبارًا معرفيًا فقط. المصدر: Georgia DDS، 'Adding CDL Endorsements.'"},"28":{"q":"وفقًا لـ Georgia DDS، كيف يتم الحصول على مصادقة N (الصهريج)؟","options":["باجتياز كل من اختبار معرفي واختبار مهارات","باجتياز اختبار مهارات فقط","باجتياز اختبار معرفي فقط","باجتياز فحص خلفية من TSA فقط"],"explanation":"في جورجيا تتطلب مصادقة N (الصهريج) اجتياز اختبار معرفي فقط وهي صالحة لـ CDL من الفئتين A وB. المصدر: Georgia DDS، 'Adding CDL Endorsements.'"},"29":{"q":"أي مصادقة CDL في جورجيا صالحة لـ CDL من الفئة A فقط ويتم الحصول عليها باجتياز اختبار معرفي؟","options":["مصادقة T (المقطورات المزدوجة/الثلاثية)","مصادقة P (الركاب)","مصادقة S (حافلة المدرسة)","مصادقة N (الصهريج)"],"explanation":"مصادقة T (المقطورة المزدوجة/الثلاثية) صالحة لـ CDL من الفئة A فقط وتتطلب اختبارًا معرفيًا. ولا يمكن الحصول عليها بتصريح متعلّم تجاري؛ بل يجب أن يكون المتقدم حاملًا بالفعل لـ CDL صالحة. المصدر: Georgia DDS، 'Adding CDL Endorsements.'"},"30":{"q":"ماذا تتطلب جورجيا للحصول على مصادقة P (الركاب)؟","options":["اجتياز اختبار معرفي فقط","اجتياز كل من اختبار معرفي واختبار مهارات","اجتياز اختبار مهارات فقط","اجتياز فحص خلفية من TSA فقط"],"explanation":"في جورجيا، تتطلب مصادقة P (الركاب) اجتياز كل من اختبار معرفي واختبار مهارات، وهي صالحة لـ CDL من الفئات A وB وC. المصدر: Georgia DDS، 'Adding CDL Endorsements.'"},"31":{"q":"أي مصادقتين تتطلب Georgia DDS لكلتيهما اختبارًا معرفيًا واختبار مهارات معًا؟","options":["N (الصهريج) وT (المقطورات المزدوجة/الثلاثية)","H (HazMat) وN (الصهريج)","P (الركاب) وS (حافلة المدرسة)","T (المقطورات المزدوجة/الثلاثية) وH (HazMat)"],"explanation":"في جورجيا، تتطلب مصادقتا الركاب (P) وحافلة المدرسة (S) كل منهما اجتياز اختبار معرفي واختبار مهارات معًا. أما مصادقات N وT وH فتتطلب اختبارًا معرفيًا فقط. المصدر: Georgia DDS، 'Adding CDL Endorsements.'"},"32":{"q":"اعتبارًا من 7 فبراير 2022، أي مجموعة من المتقدمين للحصول على CDL في جورجيا تخضع لمتطلبات تدريب السائقين المبتدئين (ELDT)؟","options":["فقط المتقدمون الذين يسعون للحصول على CDL من الفئة C","المتقدمون الذين يحصلون على الفئة A أو B لأول مرة، أو يرتقون إلى فئة أعلى، أو يضيفون مصادقة حافلة المدرسة أو الركاب أو HazMat","فقط السائقون الذين تزيد أعمارهم عن 21 عامًا","فقط المتقدمون لتجديد CDL قائمة دون تغييرات"],"explanation":"بموجب قواعد ELDT الصادرة عن FMCSA والمعتمدة من جورجيا، اعتبارًا من 7 فبراير 2022، يجب على جميع السائقين المبتدئين الذين يحصلون على CDL من الفئة A أو B لأول مرة، أو يرتقون إلى فئة أعلى، أو يضيفون مصادقة حافلة المدرسة (S) أو الركاب (P) أو HazMat (H)، إكمال ELDT. المصدر: Georgia DDS، 'Apply for a Commercial (CDL) License' / 'Adding CDL Endorsements.'"},"33":{"q":"أين يجب أن يُكمَل ويُسجَّل تدريب السائقين المبتدئين (ELDT) للمتقدم للحصول على CDL في جورجيا؟","options":["في أي مدرسة قيادة خاصة يختارها المتقدم دون سجل","فقط في مركز خدمة العملاء التابع لـ Georgia DDS","عبر اختبار قصير على الإنترنت دون مزوّد رسمي","لدى مزوّد تدريب مُدرَج في سجل مزوّدي التدريب التابع لـ FMCSA (TPR)"],"explanation":"يجب أن يُقدَّم ELDT من قبل مزوّد مُدرَج في سجل مزوّدي التدريب التابع لـ FMCSA (TPR)، ويُبلَّغ عن إتمامه للسجل قبل أن يتمكن السائق من إجراء اختبار مهارات CDL أو اختبار معرفة HazMat. المصدر: لوائح ELDT الصادرة عن FMCSA والمشار إليها من Georgia DDS."},"34":{"q":"قبل التقدم بطلب الحصول على CDL كاملة في جورجيا، كم من الوقت يجب على المتقدم أن يحمل تصريح المتعلّم التجاري (CLP)؟","options":["30 يومًا على الأقل","60 يومًا على الأقل","14 يومًا على الأقل","6 أشهر على الأقل"],"explanation":"تتطلب جورجيا من المتقدمين للحصول على CDL حمل تصريح المتعلّم التجاري (CLP) لمدة لا تقل عن 14 يومًا قبل إجراء اختبار مهارات CDL / التقدم بطلب الحصول على CDL الكاملة. المصدر: Georgia DDS، 'CDL Permit' والأسئلة الشائعة حول ترخيص CDL."},"35":{"q":"ماذا يجب على المتقدم في جورجيا أن يجتاز ليُصدَر له تصريح المتعلّم التجاري (CLP)؟","options":["اختبار(ات) المعرفة الكتابية المطلوبة","فقط اختبار مهارات CDL (الطريق)","فحص خلفية من TSA","اختبار نظر فقط"],"explanation":"للحصول على CLP في جورجيا (الفئة AP أو BP)، يجب على المتقدم حمل رخصة قيادة جورجية عادية صالحة واجتياز اختبار(ات) المعرفة الكتابية المطلوبة. ويأتي اختبار المهارات لاحقًا، بعد فترة الانتظار البالغة 14 يومًا. المصدر: Georgia DDS، 'Apply for a Commercial Permit (Class AP or BP).'"},"36":{"q":"بالنسبة لـ CLP الصادر في جورجيا في 1 يوليو 2021 أو بعده، ما مدة صلاحية التصريح؟","options":["30 يومًا","180 يومًا","5 سنوات","365 يومًا"],"explanation":"تصريح المتعلّم التجاري (CLP) الصادر في جورجيا في 1 يوليو 2021 أو بعده صالح لمدة 365 يومًا. المصدر: Georgia DDS، 'CDL Permit.'"},"37":{"q":"أي مما يلي مطلوب قبل أن يتمكن شخص من الحصول على تصريح المتعلّم التجاري (CLP) في جورجيا؟","options":["حمل رخصة قيادة جورجية عادية صالحة","حمل مصادقة HazMat بالفعل","إكمال فحص خلفية من TSA","حمل CDL من الفئة A"],"explanation":"تتطلب Georgia DDS من المتقدمين للحصول على CLP حمل رخصة قيادة جورجية عادية صالحة قبل التقدم بطلب الحصول على التصريح التجاري. المصدر: Georgia DDS، 'Apply for a Commercial Permit (Class AP or BP).'"},"38":{"q":"عند التقدم بطلب الحصول على CDL في جورجيا، أي مجموعة من الوثائق تطلب DDS من المتقدم تقديمها؟","options":["إثبات الهوية، ورقم الضمان الاجتماعي، والوجود القانوني، وإثباتين للإقامة في جورجيا","فقط بطاقة الضمان الاجتماعي","فقط بطاقة تسجيل الناخبين في جورجيا","جواز سفر فقط، دون إثبات للإقامة"],"explanation":"تتطلب Georgia DDS إثبات الهوية (مثل شهادة ميلاد موثقة أو جواز سفر أمريكي)، وإثبات رقم الضمان الاجتماعي، وإثبات الوجود القانوني، ووثيقتين من مصدرين منفصلين تثبتان الإقامة في جورجيا. المصدر: Georgia DDS، 'Apply for a Commercial (CDL) License.'"},"39":{"q":"سائق CDL في جورجيا يعمل داخل جورجيا فقط ويجب أن يستوفي متطلبات تأهيل السائقين الصادرة عن FMCSA، أي فئة من التصديق الطبي الذاتي ينبغي أن يختار؟","options":["غير المستثنى بين الولايات (NI)","المستثنى بين الولايات (EI)","المستثنى داخل الولاية (EA)","غير المستثنى داخل الولاية (NA)"],"explanation":"تستخدم Georgia DDS أربع فئات للتصديق الذاتي: غير المستثنى بين الولايات (NI)، والمستثنى بين الولايات (EI)، وغير المستثنى داخل الولاية (NA)، والمستثنى داخل الولاية (EA). والسائق الذي يعمل داخل جورجيا فقط (داخل الولاية) ويجب أن يستوفي متطلبات التأهيل الطبي يختار غير المستثنى داخل الولاية (NA). ويجب على جميع حاملي CDL تقديم تصديق ذاتي لدى DDS. المصدر: Georgia DDS، 'CDL Medical Certification and Self-Certification Process.'"},"40":{"q":"في جورجيا، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده لشخص أن يشغّل مركبة تجارية (CMV) بشكل قانوني؟","options":["0.08 أو أعلى هو الحد","يكون غير قانوني عند 0.04 أو أعلى","0.10 أو أعلى هو الحد","أي كمية تزيد عن 0.02 غير قانونية"],"explanation":"من غير القانوني تشغيل CMV في جورجيا بتركيز BAC يبلغ 0.04 أو أعلى، أي نصف حد 0.08 للسائقين غير التجاريين. المصدر: دليل Georgia CDL (DDS)، حالات استبعاد CDL؛ 49 CFR 383.51(b)."},"41":{"q":"يُدان حامل CDL في جورجيا بأول مخالفة كبرى، مثل القيادة تحت التأثير في CMV، بينما لا ينقل مواد خطرة. لكم من الوقت تُستبعد CDL؟","options":["60 يومًا على الأقل","6 أشهر على الأقل","سنة واحدة على الأقل","3 سنوات على الأقل"],"explanation":"تؤدي أول مخالفة كبرى (القيادة تحت التأثير، أو BAC بنسبة 0.04 فأعلى، أو الرفض، أو مغادرة مكان الحادث، أو الاستخدام الجنائي لـ CMV، إلخ) إلى استبعاد لمدة سنة واحدة على الأقل. المصدر: دليل Georgia CDL (DDS)؛ 49 CFR 383.51(b) Table 1."},"42":{"q":"كيف تتغير فترة الاستبعاد إذا ارتكب سائق CDL في جورجيا أول مخالفة كبرى أثناء تشغيل CMV حامل للافتات المواد الخطرة؟","options":["تزيد إلى 3 سنوات كحد أدنى","تبقى عند سنة واحدة كحد أدنى","تزيد إلى 5 سنوات كحد أدنى","تؤدي إلى حظر فوري مدى الحياة"],"explanation":"عندما تقع أول مخالفة كبرى أثناء نقل مواد خطرة تتطلب لافتات، يرتفع الحد الأدنى للاستبعاد من سنة واحدة إلى 3 سنوات. المصدر: دليل Georgia CDL (DDS)؛ 49 CFR 383.51(b) Table 1."},"43":{"q":"ما هي فترة الاستبعاد لحامل CDL في جورجيا يُدان بمخالفة كبرى ثانية في حادثة منفصلة؟","options":["3 سنوات إضافية","10 سنوات إضافية","120 يومًا إضافيًا","الاستبعاد مدى الحياة"],"explanation":"تؤدي إدانة ثانية بأي توليفة من المخالفات الكبرى في حوادث منفصلة إلى استبعاد CDL مدى الحياة. المصدر: دليل Georgia CDL (DDS)؛ 49 CFR 383.51(b) Table 1."},"44":{"q":"بموجب قانون الموافقة الضمنية في جورجيا، ماذا يحدث لحامل CDL الذي يرفض الخضوع لفحص كيميائي للكحول أو المخدرات بعد طلب قانوني؟","options":["لا شيء، لأن الرفض لا يمكن استخدامه كدليل","تُفرض غرامة فقط ولكن لا تتأثر CDL","يُستبعد السائق بالطريقة نفسها كما لو أُدين بالقيادة تحت التأثير","يحصل السائق على عقوبة مخالفة خطيرة لمدة 60 يومًا"],"explanation":"يُعامَل رفض الفحص الكيميائي كمخالفة كبرى، ويحمل الاستبعاد نفسه كإدانة القيادة تحت التأثير: سنة واحدة على الأقل للمخالفة الأولى ومدى الحياة للمخالفة الثانية. المصدر: دليل Georgia CDL (DDS)؛ O.C.G.A. 40-5-67.1 (الموافقة الضمنية)؛ 49 CFR 383.51(b)."},"45":{"q":"يتبيّن أن سائق CDL في جورجيا لديه أي كمية يمكن اكتشافها من الكحول دون 0.04 أثناء أداء الواجب. ما هي العاقبة؟","options":["أمر بالإيقاف عن الخدمة يضع السائق خارج الخدمة لمدة 24 ساعة","استبعاد فوري لـ CDL لمدة سنة واحدة","استبعاد مخالفة خطيرة لمدة 60 يومًا","لا عاقبة لأن BAC أقل من 0.04"],"explanation":"أي كحول يمكن اكتشافه دون 0.04 لا يطلق استبعاد مخالفة كبرى ولكنه يتطلب وضع السائق خارج الخدمة لمدة 24 ساعة. المصدر: دليل Georgia CDL (DDS)؛ 49 CFR 392.5."},"46":{"q":"أي مما يلي يُصنَّف على أنه \"مخالفة مرورية خطيرة\" لحامل CDL في جورجيا بدلًا من مخالفة كبرى؟","options":["قيادة CMV بتركيز BAC يبلغ 0.04 أو أعلى","استخدام CMV لارتكاب جناية","الإفراط في السرعة بمقدار 15 ميلًا في الساعة أو أكثر فوق الحد المعلن","مغادرة مكان حادث يشمل CMV"],"explanation":"الإفراط في السرعة (15 ميلًا في الساعة أو أكثر فوق الحد) مخالفة مرورية خطيرة. أما القيادة تحت التأثير والاستخدام الجنائي والهروب بعد الحادث فهي مخالفات كبرى بعقوبات أشد بكثير. المصدر: دليل Georgia CDL (DDS)؛ 49 CFR 383.51(c) Table 2."},"47":{"q":"يُدان حامل CDL في جورجيا بمخالفتين مروريتين خطيرتين في حادثتين منفصلتين خلال فترة 3 سنوات. ما هي فترة الاستبعاد؟","options":["30 يومًا على الأقل","60 يومًا على الأقل","120 يومًا على الأقل","سنة واحدة على الأقل"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال 3 سنوات إلى استبعاد لمدة 60 يومًا على الأقل. المصدر: دليل Georgia CDL (DDS)؛ 49 CFR 383.51(c) Table 2."},"48":{"q":"يُدان حامل CDL في جورجيا بثلاث مخالفات مرورية خطيرة في حوادث منفصلة خلال فترة 3 سنوات. ما هي فترة الاستبعاد؟","options":["60 يومًا على الأقل","90 يومًا على الأقل","120 يومًا على الأقل","سنة واحدة على الأقل"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة خلال 3 سنوات إلى استبعاد لمدة 120 يومًا على الأقل. المصدر: دليل Georgia CDL (DDS)؛ 49 CFR 383.51(c) Table 2."},"49":{"q":"أي مما يلي لا يُحتسب كمخالفة مرورية خطيرة يمكن أن تؤدي إلى استبعاد CDL في جورجيا؟","options":["اتباع المركبة الأمامية عن قرب شديد","إجراء تغيير غير سليم أو متقلّب للمسار","القيادة المتهورة","ركن CMV طوال الليل في منطقة استراحة"],"explanation":"تشمل المخالفات المرورية الخطيرة الاتباع عن قرب شديد، وتغييرات المسار غير السليمة، والقيادة المتهورة، والإفراط في السرعة. أما الركن القانوني في منطقة استراحة فليس مخالفة. المصدر: دليل Georgia CDL (DDS)؛ 49 CFR 383.51(c) Table 2."},"50":{"q":"ما هي مدة الإيقاف لأول إدانة لسائق CDL في جورجيا بمخالفة معبر السكة الحديدية مع الطريق السريع؟","options":["30 يومًا على الأقل","60 يومًا على الأقل","120 يومًا على الأقل","سنة واحدة على الأقل"],"explanation":"تؤدي أول مخالفة لمعبر السكة الحديدية مع الطريق السريع إلى إيقاف لا يقل عن 60 يومًا. المصدر: دليل CDL لجورجيا (DDS)؛ 49 CFR 383.51(d) الجدول 3."},"51":{"q":"يرتكب حامل CDL في جورجيا مخالفة ثانية لمعبر السكة الحديدية مع الطريق السريع خلال فترة 3 سنوات. ما هو الحد الأدنى للإيقاف؟","options":["60 يومًا على الأقل","120 يومًا على الأقل","6 أشهر على الأقل","سنة واحدة على الأقل"],"explanation":"تؤدي مخالفة ثانية لمعبر السكة الحديدية مع الطريق السريع خلال 3 سنوات إلى إيقاف لا يقل عن 120 يومًا. المصدر: دليل CDL لجورجيا (DDS)؛ 49 CFR 383.51(d) الجدول 3."},"52":{"q":"يرتكب حامل CDL في جورجيا مخالفة ثالثة لمعبر السكة الحديدية مع الطريق السريع خلال فترة 3 سنوات. ما هو الحد الأدنى للإيقاف؟","options":["120 يومًا على الأقل","6 أشهر على الأقل","سنة واحدة على الأقل","الإيقاف مدى الحياة"],"explanation":"تؤدي مخالفة ثالثة أو لاحقة لمعبر السكة الحديدية مع الطريق السريع خلال 3 سنوات إلى إيقاف لا يقل عن سنة واحدة. المصدر: دليل CDL لجورجيا (DDS)؛ 49 CFR 383.51(d) الجدول 3."},"53":{"q":"ما هي مدة الإيقاف لأول إدانة لسائق CDL في جورجيا بمخالفة أمر إيقاف الخدمة (OOS)، عندما لا تكون هناك مواد خطرة أو ركاب؟","options":["60 يومًا على الأقل","90 يومًا على الأقل","180 يومًا على الأقل","سنتان على الأقل"],"explanation":"تؤدي أول إدانة بمخالفة أمر إيقاف الخدمة إلى إيقاف لا يقل عن 180 يومًا (حتى سنة واحدة). المصدر: دليل CDL لجورجيا (DDS)؛ 49 CFR 383.51(e) الجدول 4."},"54":{"q":"يُدان حامل CDL في جورجيا بمخالفة ثانية لأمر إيقاف الخدمة في حوادث منفصلة خلال فترة 10 سنوات. ما هو الحد الأدنى للإيقاف؟","options":["180 يومًا على الأقل","سنة واحدة على الأقل","سنتان على الأقل","الإيقاف مدى الحياة"],"explanation":"تؤدي مخالفة ثانية لأمر إيقاف الخدمة خلال فترة 10 سنوات إلى إيقاف لا يقل عن سنتين (حتى 5 سنوات). المصدر: دليل CDL لجورجيا (DDS)؛ 49 CFR 383.51(e) الجدول 4."},"55":{"q":"كيف تتغير العقوبة لأول مخالفة لأمر إيقاف الخدمة إذا كان سائق CDL في جورجيا ينقل مواد خطرة موضوعة عليها لافتات أو 16 راكبًا أو أكثر؟","options":["تُخفَّض إلى 60 يومًا","يبقى الحد الأدنى 180 يومًا لكن يرتفع الحد الأقصى إلى سنتين","تصبح إيقافًا مدى الحياة","تبقى دون تغيير عند 180 يومًا إلى سنة واحدة"],"explanation":"بالنسبة لأول مخالفة OOS أثناء نقل مواد خطرة موضوعة عليها لافتات أو 16 راكبًا أو أكثر، يكون الإيقاف لا يقل عن 180 يومًا لكن حتى سنتين، وهو حد أقصى أطول من الحالة القياسية. المصدر: دليل CDL لجورجيا (DDS)؛ 49 CFR 383.51(e) الجدول 4."},"56":{"q":"بموجب قانون Super Speeder في جورجيا (O.C.G.A. §40-6-189)، عند أي سرعات يُصنَّف السائق على أنه \"Super Speeder\"؟","options":["65 mph على أي طريق أو 75 mph على طريق ذي مسارين","75 mph على طريق ذي مسارين أو 85 mph على أي طريق أو طريق سريع","80 mph على طريق ذي مسارين أو 90 mph على طريق سريع بين الولايات","15 mph أو أكثر فوق أي حد سرعة موضوع"],"explanation":"يصنّف قانون Super Speeder في جورجيا السائق المُدان بسرعة 75 mph أو أكثر على طريق ذي مسارين، أو 85 mph أو أكثر على أي طريق أو طريق سريع، على أنه Super Speeder. المصدر: O.C.G.A. §40-6-189."},"57":{"q":"بموجب قانون Super Speeder في جورجيا، ما هي الرسوم الحكومية الإضافية التي تفرضها إدارة خدمات السائقين على من يُدان كـ Super Speeder، وماذا يحدث إذا لم تُدفع؟","options":["رسوم 200 دولار؛ تعليق الرخصة إذا لم تُدفع خلال 120 يومًا من الإشعار","رسوم 500 دولار؛ السجن إذا لم تُدفع خلال 30 يومًا","رسوم 100 دولار؛ رسالة تحذير إذا لم تُدفع خلال 90 يومًا","رسوم 200 دولار دون أي عاقبة أخرى لعدم الدفع"],"explanation":"يضيف قانون Super Speeder رسومًا حكومية قدرها 200 دولار فوق أي غرامات تفرضها المحكمة. إذا لم تُدفع خلال 120 يومًا من إشعار DDS، يُعلَّق ترخيص السائق وتُطبَّق رسوم إعادة تفعيل قدرها 50 دولارًا. المصدر: O.C.G.A. §40-6-189."},"58":{"q":"بموجب القواعد الفيدرالية التي تنفذها جورجيا، ماذا يحدث لسائق CDL يُدان بإرسال الرسائل النصية أو استخدام هاتف محمول باليد أثناء تشغيل مركبة تجارية (CMV)؟","options":["لا يحمل أي عقوبة بالنسبة لحاملي CDL تحديدًا","يكون إيقافًا تلقائيًا لمخالفة كبرى لمدة سنة واحدة","يُحتسب كمخالفة مرورية خطيرة باتجاه الإيقاف","يؤدي إلى إيقاف فوري مدى الحياة"],"explanation":"يُعد إرسال الرسائل النصية أو استخدام هاتف محمول باليد أثناء قيادة CMV مخالفة مرورية خطيرة؛ مخالفتان خلال 3 سنوات تؤديان إلى إيقاف 60 يومًا وثلاث مخالفات تؤدي إلى 120 يومًا. المصدر: 49 CFR 383.51(c)؛ دليل CDL لجورجيا (DDS)."},"59":{"q":"ينطبق قانون Hands-Free في جورجيا (O.C.G.A. §40-6-241) على جميع السائقين. أي إجراء يحظره أثناء تشغيل مركبة، بما في ذلك CMV؟","options":["استخدام اتصال Bluetooth أو مكبر صوت بدون استخدام اليدين","الإمساك بالهاتف فعليًا أو إسناده بأي جزء من الجسم","وجود جهاز GPS مثبَّت ظاهر على الزجاج الأمامي","التحدث إلى راكب جالس في المركبة"],"explanation":"يمنع قانون Hands-Free Georgia السائقين من إمساك الهاتف أو الجهاز الإلكتروني أو إسناده بأي جزء من الجسم؛ يبقى الاستخدام بدون اليدين مثل Bluetooth أو مكبر الصوت مسموحًا به. المصدر: O.C.G.A. §40-6-241."},"60":{"q":"على طريق سريع بين الولايات في جورجيا به مساران أو أكثر في اتجاهك، تقترب من وحدة HERO ثابتة على الكتف تعرض أضواء كهرمانية وامضة. ماذا يتطلب قانون Move Over في جورجيا من السائق التجاري؟","options":["الحفاظ على حد السرعة الموضوع لأن الوحدة خارج الطريق على الكتف","التوقف التام في مسارك والانتظار حتى تتحرك الوحدة قبل المتابعة","الانتقال مسارًا واحدًا بعيدًا عن الوحدة إذا كان ذلك آمنًا؛ إذا لم تتمكن من تغيير المسار بأمان، أبطئ إلى ما دون حد السرعة الموضوع وكن مستعدًا للتوقف","الانتقال فقط من أجل مركبات الشرطة والإطفاء، لأن وحدات HERO والمرافق غير مشمولة"],"explanation":"يتطلب قانون Move Over في جورجيا (O.C.G.A. §40-6-16) من السائقين على الطرق ذات المسارين أو أكثر في الاتجاه نفسه الانتقال مسارًا واحدًا بعيدًا عن وحدة طوارئ أو مرافق أو قطر/إنقاذ أو صيانة طرق أو نظافة أو HERO ثابتة تعرض أضواء وامضة. إذا تعذّر تغيير المسار بأمان، يجب على السائق تقليل السرعة إلى ما دون الحد الموضوع وأن يكون مستعدًا للتوقف."},"61":{"q":"ينطبق قانون Move Over في جورجيا على المركبات الثابتة التي تعرض أضواء وامضة. أي من المركبات التالية غير مشمول بـ O.C.G.A. §40-6-16؟","options":["وحدة HERO (مشغّل الاستجابة لطوارئ الطرق السريعة) تساعد مركبة معطلة","مركبة خدمة مرافق تصلح خطوط الكهرباء بأضواء كهرمانية وامضة","سيارة ركاب متوقفة على الكتف بأضواء التحذير القياسية (الأضواء الرباعية) مشغّلة بعد ثقب إطار","شاحنة قطر تنقذ مركبة محطمة بأضواء كهرمانية وامضة"],"explanation":"يحمي O.C.G.A. §40-6-16 وحدات الطوارئ والقطر/الإنقاذ وصيانة الطرق السريعة وخدمة المرافق والنظافة و HERO الثابتة التي تعرض أضواء وامضة. سيارة الركاب العادية التي تستخدم فقط أضواء التحذير الرباعية القياسية ليست من فئات المركبات المحمية بموجب قانون Move Over."},"62":{"q":"بموجب قانون Hands-Free Georgia (O.C.G.A. §40-6-241)، ما هو القيد الإضافي الذي ينطبق تحديدًا على سائق يشغّل مركبة تجارية على طريق سريع في جورجيا؟","options":["يجوز للسائق إرسال الرسائل النصية يدويًا طالما كانت المركبة تتحرك بسرعة أقل من 15 mph","يجوز للسائق استخدام زر واحد فقط على الجهاز اللاسلكي لبدء أو إنهاء مكالمة صوتية","يجوز للسائق إمساك الهاتف على الأذن طالما كانت المكالمة متعلقة بالعمل","السائق معفى تمامًا من قانون Hands-Free أثناء الخدمة"],"explanation":"بموجب O.C.G.A. §40-6-241، أثناء تشغيل مركبة تجارية لا يجوز لأي سائق استخدام أكثر من زر واحد على جهاز اتصالات لاسلكي لبدء أو إنهاء اتصال صوتي، ولا الوصول إلى جهاز بطريقة تتطلب مغادرة وضعية القيادة الجالسة. الإمساك بالجهاز أو إسناده بأي جزء من الجسم محظور على جميع السائقين."},"63":{"q":"أي جهاز أو نشاط مسموح به بموجب قانون Hands-Free Georgia (O.C.G.A. §40-6-241) أثناء قيادة مركبة تجارية في جورجيا؟","options":["إمساك هاتف ذكي بيدك لقراءة رسالة نصية","استخدام جهاز راديو تجاري ثنائي الاتجاه أو راديو CB للتواصل","مشاهدة فيديو على جهاز لوحي مسنود على لوحة القيادة","إسناد هاتف خلوي على كتفك مقابل أذنك أثناء مكالمة"],"explanation":"يستثني O.C.G.A. §40-6-241 صراحةً أجهزة الراديو التجارية ثنائية الاتجاه، وأجهزة راديو CB، وأجهزة الراديو الهواة/ham، وأجهزة الاتصال الطارئ القائمة على الاشتراك، والأجهزة الطبية الموصوفة، وأنظمة الملاحة/التشخيص المصنعية. الإمساك بالهاتف أو إسناده بأي جزء من الجسم، وإرسال الرسائل النصية يدويًا، ومشاهدة الفيديو كلها محظورة."},"64":{"q":"أنت تقود جرارًا بمقطورة في أقصى مسار اليسار للتجاوز على طريق سريع بين الولايات في جورجيا وتلاحظ مركبة أسرع تقترب خلفك. بموجب قانون 'Slowpoke' / مسار اليسار في جورجيا (O.C.G.A. §40-6-184)، ماذا يجب أن تفعل؟","options":["الحفاظ على موقعك في مسار التجاوز طالما كنت عند حد السرعة الموضوع أو فوقه","التسريع لمطابقة المركبة المتجاوزة بحيث لا تعود بحاجة إلى التجاوز","لا ينطبق القانون على المركبات التجارية، لذا يجوز لك البقاء في المسار الأيسر","الخروج من مسار التجاوز للسماح للمركبة المتجاوزة بالمرور، ما لم تتطلب ظروف الطريق أو حركة المرور أو الطقس أو جهاز التحكم في المرور بقاءك هناك"],"explanation":"يتطلب قانون 'Slowpoke' في جورجيا (O.C.G.A. §40-6-184) من السائق في مسار التجاوز (المسار الأقصى إلى اليسار غير مسار HOV) أن ينتقل بمجرد أن يعلم أو ينبغي أن يعلم أنه يجري تجاوزه من الخلف بمركبة أسرع، ما لم تتطلب ظروف الطريق/حركة المرور أو الطقس أو الأخطار أو جهاز التحكم في المرور البقاء في ذلك المسار. ينطبق بصرف النظر عما إذا كنت عند حد السرعة."},"65":{"q":"لأغراض قانون مسار اليسار / 'Slowpoke' في جورجيا (O.C.G.A. §40-6-184)، كيف يُعرَّف 'مسار التجاوز'؟","options":["المسار الأقصى إلى اليسار، غير مسار المركبات عالية الإشغال (HOV)","أي مسار تتجاوز فيه مركبة مركبةً أخرى حاليًا","المسار الأقرب إلى الكتف الأيمن","فقط المسار الأوسط لطريق ذي ثلاثة مسارات"],"explanation":"يُعرّف O.C.G.A. §40-6-184 'مسار التجاوز' بأنه المسار الأقصى إلى اليسار غير مسار المركبات عالية الإشغال (HOV). يجب على السائق ألا يستمر في ذلك المسار بمجرد أن يجري تجاوزه بمركبة أسرع من الخلف."},"66":{"q":"بموجب O.C.G.A. §40-6-52، يجوز عمومًا لـ 'شاحنة' (أي مركبة بأكثر من ست عجلات، باستثناء الحافلات وحافلات النقل) على طريق في جورجيا به ثلاثة مسارات أو أكثر في الاتجاه نفسه أن تسير في أي مسارات؟","options":["أي مسار، طالما واكبت تدفق حركة المرور","فقط المسار الأقصى إلى اليمين الواحد في جميع الأوقات","فقط المسارين الأقصيين إلى اليمين، باستثناء عند الاستعداد لانعطاف يسار أو حيث تُخصَّص المسارات خلاف ذلك","فقط المسارات الوسطى، تاركةً المسار الأيمن مفتوحًا لحركة الاندماج"],"explanation":"يجعل O.C.G.A. §40-6-52 من غير القانوني لشاحنة (مركبة بأكثر من ست عجلات، باستثناء الحافلات وحافلات النقل) على طريق به ثلاثة مسارات أو أكثر في الاتجاه نفسه أن تسير في أي مسار غير المسارين الأقصيين إلى اليمين، باستثناء عند الاستعداد لانعطاف يسار أو حيث خصصت إدارة النقل مسارات أخرى."},"67":{"q":"على طريق سريع في جورجيا به بالضبط مساران في اتجاهك، متى يجوز قانونيًا لشاحنة خاضعة لـ O.C.G.A. §40-6-52 استخدام مسار اليسار؟","options":["كلما كان المسار الأيمن أكثر ازدحامًا من المسار الأيسر","عند التجاوز الفعلي ومرور مركبة أخرى أو الاستعداد لانعطاف يسار","فقط بين شروق الشمس وغروبها","أبدًا، تحت أي ظرف"],"explanation":"بموجب O.C.G.A. §40-6-52، على طريق به مساران في الاتجاه نفسه يكون من غير القانوني لشاحنة أن تسير في المسار الأيسر إلا عند التجاوز الفعلي ومرور مركبة أخرى، أو الاستعداد لانعطاف يسار، أو حسبما ينص القانون خلاف ذلك."},"68":{"q":"ما هو الحد الأقصى للسرعة الذي يحدده O.C.G.A. §40-6-181 لأي مركبة، بما في ذلك الجرار بمقطورة، على طريق سريع بين الولايات في جورجيا حيث يكون موضوعًا؟","options":["55 ميلًا في الساعة","65 ميلًا في الساعة","75 ميلًا في الساعة","70 ميلًا في الساعة"],"explanation":"يحدد O.C.G.A. §40-6-181 حدًا أقصى قدره 70 mph على الطرق السريعة التي تشكل جزءًا من النظام الفيدرالي بين الولايات وعلى الطرق السريعة للولاية المقسّمة فعليًا ذات التحكم الكامل في الوصول حيث يُحدَّد ذلك بإشارات. لا تفرض جورجيا حد سرعة منفصلًا أدنى على مستوى الولاية للشاحنات؛ ينطبق الحد الأقصى الموضوع على جميع المركبات."},"69":{"q":"الشاحنات الثقيلة العابرة المسافرة على I-75 أو I-85 أو I-20 باتجاه أتلانتا مطلوب منها عمومًا أن تفعل ماذا، بموجب قواعد توجيه الشاحنات في أتلانتا بجورجيا؟","options":["استخدام I-75/I-85 Downtown Connector خلال ساعات النهار فقط","السفر فقط في مسارات HOV عبر وسط مدينة أتلانتا","التوقف عند محطة وزن تابعة للولاية قبل دخول I-285","الالتفاف حول المدينة على I-285 ما لم تكن تستلم/تسلّم، أو تذهب إلى محطة أو منشأة إصلاح، أو إلى مكان إقامة السائق داخل المحيط"],"explanation":"يجب على الشاحنات المسافرة عبر (وليس إلى) أتلانتا أن تسلك I-285 حول المدينة بدلًا من I-75/I-85 Downtown Connector. توجد استثناءات للشاحنات التي تستلم أو تسلّم لشاحن داخل I-285، أو تذهب إلى/من محطة أو منشأة إصلاح داخل I-285، أو لسائق يذهب إلى/من مكان إقامة داخل المحيط. هذا قيد على الشاحنات العابرة موضّح بالإشارات ومُنفَّذ."},"70":{"q":"على I-75/I-85 Downtown Connector في أتلانتا، تكون المسارات الداخلية (الأقصى إلى اليسار) محجوزة كمسارات HOV. ماذا يعني هذا لسائق شاحنة تجارية؟","options":["يجب على الشاحنة البقاء خارج مسار HOV، وبسبب قيود استخدام المسارات، تبقى عمومًا في المسارات اليمنى","يجوز للشاحنة استخدام مسار HOV في أي وقت تحمل فيه أكثر من 6,000 رطل من الشحن","يجوز للشاحنة استخدام مسار HOV إذا دفعت رسومًا كمسار HOT","يجوز للشاحنة استخدام مسار HOV لأن المركبات التجارية تُعد دائمًا عالية الإشغال"],"explanation":"المسارات الداخلية لـ I-75/I-85 Downtown Connector مقيدة بـ HOV. الشحن ليس راكبًا، لذا لا تتأهل الشاحنة كمركبة عالية الإشغال، وبموجب O.C.G.A. §40-6-52 يجب على الشاحنات استخدام المسارات اليمنى. تتطلب مسارات HOV في جورجيا الحد الأدنى من عدد الركاب، وليس وزن الحمولة."},"71":{"q":"أي المركبات التجارية مطلوب منها التوقف عند كل معبر للسكة الحديدية مع الطريق السريع وفقًا لدليل CDL لجورجيا؟","options":["الحافلات التي تنقل ركابًا والمركبات التي تعرض لافتات مواد خطرة","جميع المركبات التجارية التي تزيد عن 26,001 رطل بصرف النظر عن الحمولة","فقط ناقلات الحمولة الفارغة، وليس المحمّلة أبدًا","أي شاحنة تجر مقطورة مزدوجة أو ثلاثية"],"explanation":"وفقًا لدليل CDL لجورجيا (و 49 CFR 392.10)، المركبات التجارية التي يجب أن تتوقف دائمًا عند معابر السكة الحديدية هي الحافلات التي تنقل ركابًا ومركبات المواد الخطرة الموضوعة عليها لافتات. يشمل ذلك أيضًا المركبات التي تحمل أي كمية من الكلور وناقلات الحمولة المستخدمة للمواد الخطرة، سواء كانت محمّلة أو فارغة."},"72":{"q":"عندما يُطلب من مركبة HazMat موضوعة عليها لافتات أو حافلة ركاب التوقف عند معبر سكة حديدية في جورجيا، أين يجب أن تتوقف؟","options":["على بُعد 25 قدمًا بالضبط من أقرب قضيب","ضمن 50 قدمًا ولكن ليس أقرب من 15 قدمًا من أقرب قضيب","100 قدم على الأقل من أقرب قضيب","في أي مكان ضمن 10 أقدام من بوابة المعبر"],"explanation":"ينص دليل CDL لجورجيا على أن التوقف المطلوب عند معبر سكة حديدية يجب أن يتم على بُعد لا يزيد عن 50 قدمًا ولا يقل عن 15 قدمًا من أقرب قضيب. ينبغي على السائق أن ينظر ويستمع لقطار، ثم يعبر فقط عندما يكون آمنًا اجتياز القضبان تمامًا دون توقف."},"73":{"q":"وفقًا لدليل CDL لجورجيا، ما الذي يجب على السائق التجاري ألا يفعله أثناء عبور قضبان السكة الحديدية؟","options":["استخدام ترس منخفض بما يكفي للعبور دون تغيير التروس","تغيير التروس بينما يكون أي جزء من المركبة على القضبان","النظر والاستماع لقطار مقترب قبل البدء بالعبور","التأكد من وجود مساحة لاجتياز القضبان تمامًا قبل البدء بالعبور"],"explanation":"يحذّر دليل CDL لجورجيا السائقين من تغيير التروس أبدًا أثناء عبور قضبان السكة الحديدية، لأن المركبة قد تتعطل على المعبر. ينبغي على السائق اختيار ترس يسمح بالعبور دون تغيير وأن يتأكد من وجود مساحة كافية لاجتياز القضبان تمامًا قبل البدء بالعبور."},"74":{"q":"بموجب O.C.G.A. §40-6-163، متى يجب على سائق مركبة تجارية التوقف لحافلة مدرسية متوقفة أضواؤها الحمراء وامضة وذراع التوقف ممدودة؟","options":["فقط عند السير في الاتجاه نفسه للحافلة، وليس عند القدوم من الاتجاه المقابل أبدًا","فقط إذا كان الأطفال ظاهرين على جانب الطريق","عند مقابلة أو تجاوز الحافلة من أي اتجاه على طريق غير مقسّم، حتى تستأنف الحافلة الحركة أو تتوقف الإشارات","فقط على الطرق ذات المسارين، وليس على الطرق ذات الأربعة مسارات أو أكثر أبدًا"],"explanation":"يتطلب O.C.G.A. §40-6-163 من سائق مركبة يقابل أو يتجاوز من أي اتجاه حافلة مدرسية متوقفة على الطريق السريع وإشاراتها المرئية (الأضواء الحمراء الوامضة/ذراع التوقف) مُفعَّلة أن يتوقف قبل الوصول إلى الحافلة وألا يتابع حتى تستأنف الحافلة الحركة أو تُطفأ الإشارات، على الطرق غير المقسّمة."},"75":{"q":"بموجب قانون الحافلات المدرسية في جورجيا (O.C.G.A. §40-6-163)، على أي نوع من الطرق لا يُطلب من السائق القادم من الاتجاه المقابل التوقف لحافلة مدرسية تُحمّل أطفالًا على الجانب المقابل؟","options":["طريق بأربعة مسارات حيث يكون الفاصل الوحيد خطًا مركزيًا مرسومًا","طريق مفصول فقط بمسار انعطاف مركزي ثنائي الاتجاه","أي طريق به مساران أو أكثر في كل اتجاه","طريق سريع بطرق منفصلة مفصولة بفاصل عشبي أو منطقة غير معبَّدة أو حاجز مادي"],"explanation":"ينص O.C.G.A. §40-6-163 على أن السائق على طريق سريع بطرق منفصلة مفصولة بفاصل عشبي أو منطقة غير معبَّدة أو حاجز مادي لا يحتاج إلى التوقف لحافلة مدرسية على الطريق المنفصل الآخر. الخط المرسوم أو مسار الانعطاف المركزي ليس فاصلًا، لذا يجب على السائقين التوقف في تلك الحالات."},"76":{"q":"طريق به مساران في كل اتجاه مفصولان فقط بمسار انعطاف مركزي ثنائي الاتجاه (لا فاصل ولا حاجز). تتوقف حافلة مدرسية على الجانب المقابل بأضواء حمراء وامضة. بموجب O.C.G.A. §40-6-163، ماذا يجب على السائق التجاري القادم من الاتجاه المقابل أن يفعل؟","options":["التوقف، لأن مسار الانعطاف المركزي ليس فاصلًا أو حاجزًا ماديًا يفصل الطرق","المتابعة بسرعة مخفّضة، لأن مسار الانعطاف يُحتسب كفاصل","التوقف فقط إذا كانت الحافلة في اتجاه سير السائق نفسه","المتابعة بشكل طبيعي، لأن حركة المرور القادمة من الاتجاه المقابل لا تتوقف للحافلات المدرسية أبدًا"],"explanation":"بموجب O.C.G.A. §40-6-163، ينطبق استثناء الطريق المقسّم فقط على الطرق المفصولة بفاصل عشبي أو منطقة غير معبَّدة أو حاجز مادي. لا يتأهل مسار الانعطاف المركزي ثنائي الاتجاه والخطوط المرسومة، لذا يجب على السائق القادم من الاتجاه المقابل التوقف للحافلة المدرسية وإشاراتها مُفعَّلة."},"77":{"q":"وفقًا لدليل CDL لجورجيا، أين يجب على سائق الشاحنة وضع أجهزة التحذير الطارئة الثلاثة المطلوبة (المثلثات العاكسة) على طريق ذي مسارين باتجاهين بعد التوقف على الكتف؟","options":["الثلاثة جميعها خلف المركبة مباشرة ضمن 10 أقدام من المصد الخلفي","واحد على السقف واثنان على المصد الأمامي","حوالي 10 أقدام خلف المركبة باتجاه حركة المرور، وحوالي 100 قدم خلفها، وحوالي 100 قدم أمام المركبة","حوالي 500 قدم خلفها و500 قدم أمامها، دون أي منها بالقرب من المركبة"],"explanation":"يتطلب دليل CDL لجورجيا وضع أجهزة التحذير خلال 10 دقائق: واحد على بُعد حوالي 10 أقدام (4 خطوات) من المركبة باتجاه حركة المرور المقتربة، وواحد على بُعد حوالي 100 قدم (40 خطوة) خلفها، وواحد على بُعد حوالي 100 قدم (40 خطوة) أمامها. على التلال أو المنعطفات، يُنقل الجهاز الخلفي إلى الخلف أكثر لإعطاء تحذير كافٍ."},"78":{"q":"وفقًا لدليل CDL لجورجيا، ما هي التقنية الصحيحة للنزول على منحدر جبلي طويل وحاد في شمال جورجيا لمنع تلاشي الفرامل؟","options":["اختيار ترس منخفض قبل النزول واستخدام كبح خفيف وثابت بطريقة الكبح المتقطّع (التطبيق ثم التحرير) بسرعة آمنة","البقاء في ترس مرتفع والضغط على الفرامل باستمرار لإبقاء السرعة منخفضة","التحويل إلى الوضع المحايد لتوفير الوقود والتحكم في السرعة بالفرامل وحدها","الضغط على الفرامل بسرعة أثناء التسريع لإبقاء المحرك دافئًا"],"explanation":"يوجّه دليل CDL لجورجيا السائقين إلى اختيار سرعة آمنة وترس منخفض قبل البدء بالنزول على منحدر حاد، بالاعتماد على كبح المحرك، واستخدام تقنية الكبح المتقطّع (التطبيق بثبات للإبطاء حوالي 5 mph، ثم التحرير). الضغط المستمر على الفرامل أو الانزلاق في الوضع المحايد يسبب تلاشي الفرامل وفقدان السيطرة."},"79":{"q":"على منحدر حاد في شمال جورجيا تلاشت فراملك والشاحنة تكتسب سرعة. ينصح دليل CDL لجورجيا بأن أفضل إجراء هو:","options":["الانعطاف إلى الكتف الأيمن المعبَّد وتطبيق فرملة الانتظار بقوة","التوجيه نحو حركة المرور القادمة من الاتجاه المقابل للعثور على مسار مفتوح","إيقاف تشغيل المحرك لإبطاء المركبة بسرعة","استخدام منحدر هروب للشاحنات الهاربة إن توفر، لأنه مصمم لإيقاف مركبة هاربة بأمان"],"explanation":"يوضّح دليل CDL لجورجيا أن منحدرات الهروب، المبنية على العديد من المنحدرات الجبلية الحادة بأسرّة من مواد رخوة (وغالبًا منحدر صاعد)، مصممة لإيقاف المركبات الهاربة بأمان. إذا تعطّلت فراملك على منحدر، فإن سلوك منحدر هروب متاح هو الإجراء الأكثر أمانًا؛ إيقاف تشغيل المحرك أو استخدام فرملة الانتظار بسرعة قد يسبب فقدان السيطرة."},"80":{"q":"في جورجيا، أي وكالة حكومية تصدر رخص القيادة التجارية (CDL) وتدير اختبار CDL؟","options":["قسم التسجيل في إدارة السلامة العامة بجورجيا","إدارة المركبات الآلية في جورجيا (DMV)","مكتب التحقيقات في جورجيا","إدارة خدمات السائقين في جورجيا (DDS)"],"explanation":"لا يوجد في جورجيا 'DMV'. إدارة خدمات السائقين في جورجيا (DDS) هي الوكالة الحكومية التي تصدر جميع رخص CDL وتدير اختبارات المعرفة والمهارات لـ CDL. المصدر: GA DDS، صفحات برنامج الرخصة التجارية (CDL) (dds.georgia.gov)."},"81":{"q":"كم عدد المستندات التي تثبت عنوان إقامتك في جورجيا التي يجب أن تحضرها إلى GA DDS عند التقدم للحصول على CDL؟","options":["لا يُطلب أي مستندات إقامة للحصول على CDL","أربعة مستندات تُظهر عنوان إقامتك في جورجيا","مستندان يُظهران عنوان إقامتك الحالي في جورجيا","مستند واحد يُظهر عنوان إقامتك في جورجيا"],"explanation":"تتطلب GA DDS من المتقدمين تقديم مستندين مقبولين (مثل فواتير المرافق أو كشوف الرهن العقاري أو المستندات الحكومية) تُظهر عنوان إقامتهم الحالي في جورجيا. المصدر: GA DDS، 'التقدم للحصول على رخصة تجارية (CDL)' (dds.georgia.gov)."},"82":{"q":"أي مجموعة من المستندات تتطلبها GA DDS لإثبات الهوية ورقم الضمان الاجتماعي والوضع القانوني للحصول على CDL؟","options":["فقط بطاقة تسجيل ناخب في جورجيا","فقط تسجيل مركبة باسمك","فقط بيان إقامة موقّع دون أي إثبات آخر","إثبات الهوية، ورقم الضمان الاجتماعي الكامل، وإثبات الجنسية الأمريكية أو الوجود القانوني"],"explanation":"تتطلب GA DDS إثبات الهوية (مثل شهادة ميلاد أمريكية أو جواز سفر أو شهادة تجنيس)، والتحقق من رقم الضمان الاجتماعي الكامل على نموذج الرخصة/الهوية/التصريح، وتوثيق الجنسية الأمريكية أو الوجود القانوني، بالإضافة إلى مستندي إقامة في جورجيا. المصدر: GA DDS، متطلبات التقدم لـ CDL (dds.georgia.gov)."},"83":{"q":"قبل إجراء اختبار مهارات CDL (الطريق) في جورجيا، كم يجب على السائق الاحتفاظ بتصريح التعلّم/التعليمات التجاري (CLP)؟","options":["30 يومًا على الأقل","60 يومًا على الأقل","14 يومًا على الأقل","لا يوجد حد أدنى لمدة الاحتفاظ"],"explanation":"تتطلب GA DDS أن يحتفظ المتقدم لـ CDL بالتصريح التعليمي التجاري (CLP) لمدة 14 يومًا على الأقل قبل التقدم لاختبار مهارات CDL الكامل وإجرائه. يعكس هذا فترة الاحتفاظ الفيدرالية البالغة 14 يومًا. المصدر: GA DDS، صفحة تصريح CDL (dds.georgia.gov)."},"84":{"q":"ماذا يجب على المتقدم لأول مرة للحصول على CDL من الفئة A أو الفئة B في جورجيا أن يكمل قبل السماح له بإجراء اختبار مهارات CDL؟","options":["دورة قيادة دفاعية في أي مدرسة قيادة خاصة","خمس سنوات من تاريخ قيادة غير تجاري قابل للتحقق","شهادة لوجستيات على مستوى جامعي","تدريب السائق المبتدئ (ELDT) من مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA"],"explanation":"بموجب قواعد ELDT الفيدرالية التي تنفذها GA DDS، يجب على المتقدمين لأول مرة للحصول على CDL من الفئة A والفئة B (مع CLP تم الحصول عليه في أو بعد 7 فبراير 2022) إكمال تدريب السائق المبتدئ من مزوّد مسجل في سجل مزوّدي التدريب التابع لـ FMCSA قبل إجراء اختبار المهارات. المصدر: صفحات CDL لـ GA DDS وسجل مزوّدي التدريب التابع لـ FMCSA (tpr.fmcsa.dot.gov)."},"85":{"q":"كم تبلغ مدة صلاحية CDL القياسية (غير HazMat) في جورجيا قبل أن تتطلب التجديد؟","options":["حتى 4 سنوات","حتى سنتين","حتى 10 سنوات","حتى 8 سنوات"],"explanation":"تكون CDL القياسية في جورجيا صالحة لمدة تصل إلى 8 سنوات. رخص CDL التي تحمل تصديق المواد الخطرة (H) صالحة لفترة أقصر (5 سنوات) بسبب تجديد فحص الخلفية المطلوب. المصدر: GA DDS، 'تجديد CDL' (dds.georgia.gov)."},"86":{"q":"ما هي فئات التصديق الذاتي الأربع التي يجب على حامل CDL في جورجيا الاختيار من بينها؟","options":["الفئة A، الفئة B، الفئة C، الفئة D","محلي، إقليمي، وطني، دولي","بين الولايات غير المستثنى، بين الولايات المستثنى، داخل الولاية غير المستثنى، داخل الولاية المستثنى","نهاري، ليلي، Hazmat، ركاب"],"explanation":"يجب على كل حامل CDL في جورجيا التصديق ذاتيًا على أحد أنواع التشغيل الأربعة: بين الولايات غير المستثنى (NI)، بين الولايات المستثنى (EI)، داخل الولاية غير المستثنى (NA)، وداخل الولاية المستثنى (EA). يجب على السائقين غير المستثنين الاحتفاظ بشهادة طبية صالحة من DOT. المصدر: GA DDS، 'عملية التصديق الطبي والتصديق الذاتي لـ CDL' (dds.georgia.gov)."},"87":{"q":"أي فئة من فئات التصديق الذاتي تتطلب من حامل CDL في جورجيا الاحتفاظ بشهادة فاحص طبي صالحة من DOT؟","options":["بين الولايات المستثنى (EI)","لا تتطلب أي فئة شهادة طبية","بين الولايات غير المستثنى (NI)","داخل الولاية المستثنى (EA)"],"explanation":"يجب على السائقين في الفئات غير المستثناة (بين الولايات غير المستثنى وداخل الولاية غير المستثنى) الاحتفاظ بشهادة فاحص طبي صالحة من DOT. الفئات المستثناة (EI و EA) لا تتطلب واحدة. المصدر: GA DDS، عملية التصديق الطبي والتصديق الذاتي لـ CDL (dds.georgia.gov)."},"88":{"q":"اعتبارًا من تفويض FMCSA الساري في 18 يونيو 2025، كيف تُنقل شهادة الفاحص الطبي من DOT لحامل CDL في جورجيا إلى DDS؟","options":["إلكترونيًا من السجل الوطني لـ FMCSA؛ لم تعد DDS تقبل الشهادات الطبية الورقية","عبر إرسالها بالفاكس إلى مقر DDS خلال 10 أيام","عبر إرسال نسخة ورقية بالبريد إلى أقرب مركز خدمة عملاء لـ DDS","عبر إرسال نسخة ممسوحة ضوئيًا بالبريد الإلكتروني إلى موظف حالة شخصي في DDS"],"explanation":"اعتبارًا من 18 يونيو 2025، تُنقل الشهادات الطبية إلكترونيًا إلى GA DDS بواسطة FMCSA عبر السجل الوطني للفاحصين الطبيين المعتمدين. لم تعد DDS تقبل الشهادات الطبية بالبريد أو الفاكس أو البريد الإلكتروني أو عبر الإنترنت أو شخصيًا. يجب على السائق ببساطة استخدام فاحص من السجل الوطني والحفاظ على التصديق محدّثًا. المصدر: بيان صحفي من GA DDS وصفحة الشهادة الطبية لـ CDL (dds.georgia.gov)."},"89":{"q":"من يجب أن يجري الفحص البدني لسائق CDL في جورجيا الذي يُطلب منه حمل شهادة طبية من DOT؟","options":["موظف في مركز خدمة عملاء DDS","أي معالج تقويم العمود الفقري بصرف النظر عن التصديق","فاحص طبي مدرج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA","أي صيدلي في صيدلية مرخّصة في جورجيا"],"explanation":"يجب فحص سائقي CDL في جورجيا الذين يحتاجون إلى تصديق طبي بواسطة فاحص طبي مدرج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA. يقوم ذلك الفاحص بعد ذلك بنقل الشهادة إلكترونيًا. المصدر: GA DDS، عملية التصديق الطبي لـ CDL (dds.georgia.gov)."},"90":{"q":"ما هي المكونات الثلاثة التي تشكل اختبار مهارات CDL في جورجيا؟","options":["تحميل الحمولة، واختبار اقتصاد الوقود، واختبار رياضيات","اختبار قانون كتابي، وفحص بصري، ومقابلة شخصية","التعامل مع Hazmat، وخدمة العملاء، واختبار طباعة","فحص المركبة قبل الرحلة، ومهارات التحكم الأساسية، واختبار قيادة على الطريق"],"explanation":"يتكوّن اختبار مهارات CDL في جورجيا من ثلاثة أجزاء تُجرى بالترتيب: فحص المركبة قبل الرحلة، ومهارات التحكم الأساسية في المركبة، واختبار القيادة على الطريق. يجب اجتياز الثلاثة جميعها للحصول على CDL. المصدر: دليل CDL لـ GA DDS وصفحات اختبار الطريق (dds.georgia.gov)."},"91":{"q":"عند إجراء اختبار مهارات CDL (الطريق) في جورجيا، من المسؤول عن توفير مركبة الاختبار؟","options":["لا حاجة لمركبة؛ يُجرى اختبار المهارات على محاكاة فقط","تشحن FMCSA شاحنة اختبار فيدرالية إلى الموقع","توفر GA DDS مركبة أسطول لكل متقدم","يجب على المتقدم توفير مركبة مناسبة تجتاز فحص سلامة من DDS"],"explanation":"يجب على المتقدم إحضار مركبة مناسبة لفئة CDL التي يجري اختبارها، مع إثبات التسجيل والتأمين الصالح، ويجب أن تجتاز المركبة فحص سلامة من DDS قبل اختبار الطريق. المصدر: GA DDS، صفحة اختبار الطريق (dds.georgia.gov)."},"92":{"q":"ما هو الحد الأدنى للسن للتقدم للحصول على CDL في جورجيا، وما القيد الذي ينطبق حتى سن معينة؟","options":["21 عامًا، دون الحاجة إلى تصريح","16 عامًا، دون أي قيود على الإطلاق","18 عامًا، مع قيود داخل الولاية فقط حتى سن 21","25 عامًا، دون السماح بالقيادة بين الولايات أبدًا"],"explanation":"في جورجيا يجوز لك التقدم للحصول على CDL في سن 18، لكن السائقين بين 18 و21 عامًا مقيّدون عمومًا بالقيادة التجارية داخل الولاية (في الولاية) حتى عيد ميلادهم الحادي والعشرين. المصدر: GA DDS، صفحات التقدم لـ CDL والتصريح (dds.georgia.gov)."},"93":{"q":"كم تبلغ مدة صلاحية تصريح التعلّم التجاري (CLP) في جورجيا الصادر في أو بعد 1 يوليو 2021؟","options":["90 يومًا","إلى أجل غير مسمى، حتى إصدار CDL","30 يومًا","365 يومًا (سنة واحدة)"],"explanation":"يكون CLP في جورجيا الصادر في أو بعد 1 يوليو 2021 صالحًا لمدة 365 يومًا (سنة واحدة). لا يزال يتعين على السائق الاحتفاظ به لمدة 14 يومًا على الأقل قبل اختبار المهارات. المصدر: GA DDS، صفحة تصريح CDL (dds.georgia.gov)."},"94":{"q":"متى يكون التصريح التعليمي التجاري (CLP) مطلوبًا في عملية CDL في جورجيا؟","options":["عند التقدم لـ CDL جديد، أو ترقية CDL، أو إضافة تصديقات معينة","فقط بعد إصدار CDL بالفعل","أبدًا؛ تصدر جورجيا رخص CDL دون أي مرحلة تصريح","فقط للسائقين الذين ينقلون رخصة من خارج البلاد"],"explanation":"تتطلب GA DDS تصريحًا تعليميًا تجاريًا (CLP) عند التقدم لـ CDL جديد، أو ترقية CDL موجود، أو إضافة تصديقات معينة تتطلب اختبار مهارات. يجب الاحتفاظ بـ CLP لمدة 14 يومًا قبل اختبار المهارات. المصدر: GA DDS، صفحة تصريح CDL (dds.georgia.gov)."},"95":{"q":"للحصول على تصديق المواد الخطرة (H) لأول مرة في جورجيا، متى يجب إكمال تدريب ELDT؟","options":["فقط بعد رفض فحص خلفية TSA","قبل السماح بإجراء اختبار معرفة HazMat","لا يُطلب ELDT أبدًا لتصديق HazMat","فقط بعد اجتياز اختبار معرفة HazMat"],"explanation":"نظرًا لأن تصديق HazMat ليس له اختبار مهارات، يجب إكمال التدريب النظري لـ ELDT للمتقدمين لأول مرة على H قبل السماح للمتقدم بإجراء اختبار معرفة HazMat. المصدر: سجل مزوّدي التدريب التابع لـ FMCSA / قابلية تطبيق ELDT (tpr.fmcsa.dot.gov) وصفحات CDL لـ GA DDS."},"96":{"q":"أي التصديقات تتطلب من المتقدمين لأول مرة في جورجيا إكمال ELDT قبل الاختبار؟","options":["الناقلة (N)، والمزدوجة/الثلاثية (T)، وإزالة قيد الفرامل الهوائية فقط","فقط إزالة قيد الفرامل الهوائية","لا تتطلب أي تصديقات ELDT أبدًا","تصديقات الحافلة المدرسية (S)، والركاب (P)، والمواد الخطرة (H)"],"explanation":"بموجب قواعد ELDT الفيدرالية المطبَّقة من GA DDS، يجب على المتقدمين لأول مرة لتصديقات الحافلة المدرسية (S)، والركاب (P)، والمواد الخطرة (H) إكمال ELDT من مزوّد مسجل قبل إجراء اختبار المهارات أو المعرفة المعمول به. المصدر: سجل مزوّدي التدريب التابع لـ FMCSA (tpr.fmcsa.dot.gov) و GA DDS."},"97":{"q":"بالإضافة إلى اختبار المهارات، ماذا يجب على المتقدم لـ CDL في جورجيا اجتيازه في مركز خدمة عملاء DDS؟","options":["اختبار قوة بدنية واختبار سباحة","فقط فحص ائتماني","اختبار(ات) المعرفة الكتابية المطلوبة وفحص بصري","مراجعة إقرار ضريبة الدخل الفيدرالية"],"explanation":"قبل اختبار المهارات، يجب على المتقدم لـ CDL في جورجيا اجتياز اختبار(ات) المعرفة الكتابية المطلوبة للفئة والتصديقات المطلوبة واجتياز فحص بصري في مركز خدمة عملاء DDS. المصدر: GA DDS، صفحات تصريح CDL والتقدم (dds.georgia.gov)."},"98":{"q":"أي عبارة عن رسوم CDL في جورجيا دقيقة؟","options":["فقط FMCSA تجمع رسوم CDL في جورجيا","تُحدَّد الرسوم بشكل فردي من قبل كل فاحص طبي","جميع خدمات CDL في GA DDS مجانية بشكل دائم","تُحدَّد مبالغ الرسوم الدقيقة من قبل GA DDS ويمكن أن تتغير، لذا ينبغي على المتقدمين التحقق من الرسوم الحالية مع DDS"],"explanation":"تفرض GA DDS رسومًا على التصاريح والاختبار والترخيص (على سبيل المثال، رسوم التصريح واختبار الطريق)، لكن المبالغ الدقيقة تُحدَّد من قبل DDS ويمكن أن تتغير مع الوقت. ينبغي على المتقدمين تأكيد الرسوم الحالية على معلومات 'الرسوم والشروط' الرسمية لـ DDS قبل التقديم. المصدر: GA DDS (dds.georgia.gov)."},"99":{"q":"ماذا يجب على سائق CDL في جورجيا أن يفعل عند التجديد فيما يتعلق بنوع التشغيل التجاري؟","options":["التصديق ذاتيًا على نوع واحد من التشغيل التجاري، وإذا كان غير مستثنى، الاحتفاظ بشهادة طبية حالية من DOT في الملف","إعادة إجراء اختبار مهارات الطريق الكامل في كل تجديد بصرف النظر عن الفئة","تسليم CDL وإعادة التقديم كمتقدم جديد تمامًا","تقديم رسالة موثّقة من صاحب عمل سابق"],"explanation":"عند التجديد، يجب على حامل CDL في جورجيا التصديق ذاتيًا على نوع واحد من التشغيل التجاري (إحدى الفئات الأربع)، ويجب على السائقين غير المستثنين الاحتفاظ بشهادة طبية حالية من DOT، تُنقل الآن إلكترونيًا عبر FMCSA. المصدر: GA DDS، 'تجديد CDL' وصفحات الشهادة الطبية لـ CDL (dds.georgia.gov)."}}};
